import { useState } from "react";
import { cn } from "@/utils/css";
import { formatAccountId } from "@/utils";
import { formatBalance } from "../utils";
import type { SubAccount } from "../types";
import {
  PLSelect,
  PLSelectTrigger,
  PLSelectValue,
  PLSelectContent,
  PLSelectItem,
  PLSelectSeparator,
} from "./PLSelect";

interface SubAccountDropdownProps {
  accounts: SubAccount[];
  value: string;
  onChange: (id: string) => void;
  onCreate?: () => void;
  placeholder?: string;
  className?: string;
  disabled?: boolean;
  /** Highlights the trigger (e.g. red border) for validation / bind-error feedback. */
  invalid?: boolean;
  onOpenChange?: (open: boolean) => void;
}

const EMPTY_VALUE = "__no_sub_account__";

export function SubAccountDropdown({
  accounts,
  value,
  onChange,
  onCreate,
  placeholder = "Select sub-account",
  className,
  disabled,
  invalid,
  onOpenChange: onOpenChangeProp,
}: SubAccountDropdownProps) {
  const [open, setOpen] = useState(false);
  const showCreateSeparator = onCreate != null;

  const handleOpenChange = (next: boolean) => {
    if (onCreate != null) setOpen(next);
    onOpenChangeProp?.(next);
  };

  const handleCreateClick = () => {
    if (disabled) return;
    onCreate?.();
    setOpen(false);
  };

  return (
    <PLSelect
      value={value || undefined}
      onValueChange={disabled ? () => {} : onChange}
      open={onCreate != null ? open : undefined}
      onOpenChange={
        onCreate != null || onOpenChangeProp != null
          ? handleOpenChange
          : undefined
      }
    >
      <PLSelectTrigger
        disabled={disabled}
        className={cn(
          "w-full min-h-[40px] gap-3 py-2",
          "[&>div>span]:justify-between",
          "[&>div>span>*]:w-full",
          // When no value, value-area span shows placeholder — use 50% white (selector targets the span that wraps SelectValue)
          !value && "[&>div>span]:text-base-contrast-50!",
          disabled && "opacity-60 pointer-events-none",
          invalid && "border-danger hover:border-danger",
          className
        )}
      >
        <PLSelectValue placeholder={placeholder} />
      </PLSelectTrigger>
      <PLSelectContent className="max-h-[320px]">
        <div
          className={cn(
            // Let Radix Select's viewport handle scrolling to avoid rendering
            // multiple scrollbars (viewport + inner list).
            "sub-account-dropdown-scroll"
          )}
        >
          {accounts.length === 0 && (
            <PLSelectItem
              value={EMPTY_VALUE}
              disabled
              className="text-base-contrast-36 cursor-default hover:bg-transparent focus:bg-transparent"
            >
              <span className="text-2xs text-base-contrast-36">
                No sub-accounts
              </span>
            </PLSelectItem>
          )}
          {accounts.map(acc => {
            return (
              <PLSelectItem
                key={acc.sub_account_id}
                value={acc.sub_account_id}
                disabled={disabled}
                className={cn(
                  "hover:bg-[rgba(255,255,255,0.06)] focus:bg-primary/6 focus:text-base-contrast-98 focus:outline-none",
                  "data-disabled:opacity-50 data-disabled:pointer-events-none data-disabled:hover:bg-transparent data-disabled:focus:bg-transparent"
                )}
              >
                <div className="flex flex-1 items-center justify-between min-w-0 w-full gap-3">
                  <div className="min-w-0 truncate">
                    <span className="font-medium text-base-contrast-98">
                      {acc.description}
                    </span>
                    <span className="font-normal text-base-contrast-50">
                      {" "}
                      ({formatAccountId(acc.sub_account_id)})
                    </span>
                  </div>
                  <span className="text-base-contrast-98 shrink-0 whitespace-nowrap">
                    ${formatBalance(acc.balance || 0)}
                  </span>
                </div>
              </PLSelectItem>
            );
          })}
        </div>
        {onCreate != null && (
          <>
            {showCreateSeparator && (
              <PLSelectSeparator className="bg-base-contrast-12 my-0" />
            )}
            <button
              type="button"
              disabled={disabled}
              onClick={handleCreateClick}
              className={cn(
                "w-full px-3 py-2.5 text-left text-2xs text-base-contrast-50 transition-colors",
                showCreateSeparator && "border-t border-base-contrast-12",
                disabled
                  ? "opacity-60 cursor-not-allowed"
                  : "hover:bg-[rgba(255,255,255,0.06)]"
              )}
            >
              Add new sub-account?{" "}
              <span className="text-primary-light">Create sub-account </span>
              or{" "}
              <a
                href="https://app.orderly.network/vaults/create"
                target="_blank"
                rel="noopener noreferrer"
                className="text-primary-light hover:underline"
              >
                Create vault
              </a>{" "}
            </button>
          </>
        )}
      </PLSelectContent>
    </PLSelect>
  );
}
