import * as React from "react";
import Tooltip from "@/components/tooltip";
import { cn } from "@/utils";

export type Align = "left" | "center" | "right";

export interface InputProps
  extends Omit<
    React.InputHTMLAttributes<HTMLInputElement>,
    "size" | "prefix" | "suffix"
  > {
  size?: "default" | "large";
  prefix?: React.ReactNode;
  suffix?: React.ReactNode;
  align?: Align;
  tooltip?: React.ReactNode;
  validateStatus?: "error";
}

function getAlignClassName(align?: Align) {
  if (align === "left") return "text-left";
  if (align === "center") return "text-center";
  if (align === "right") return "text-right";
  return undefined;
}

const Input = React.forwardRef<HTMLInputElement, InputProps>((props, ref) => {
  const {
    className,
    type,
    size = "default",
    prefix,
    suffix,
    align,
    validateStatus,
    tooltip,
    ...rest
  } = props;
  const prefixElement =
    typeof prefix === "string" ? (
      <div className="whitespace-nowrap text-base-contrast-54">{prefix}</div>
    ) : (
      prefix
    );
  const suffixElement =
    typeof suffix === "string" ? (
      <div className="whitespace-nowrap text-base-contrast-54">{suffix}</div>
    ) : (
      suffix
    );
  const showTooltip = validateStatus === "error" && Boolean(tooltip);

  return (
    <Tooltip
      open={showTooltip}
      content={tooltip}
      side="top"
      align="center"
      className="max-w-[348px] bg-danger"
      arrowClassName="fill-danger"
      sideOffset={8}
    >
      <div
        className={cn(
          "flex w-full items-center rounded-lg bg-base-500 px-[16px] text-xs",
          validateStatus === "error" && "border border-danger",
          className
        )}
      >
        {prefixElement}
        <input
          type={type}
          className={cn(
            "flex w-full bg-transparent placeholder:text-base-contrast-36 focus-visible:outline-none disabled:cursor-not-allowed disabled:opacity-50",
            size === "large" ? "h-[56px]" : "h-[48px]",
            prefixElement && "pl-[8px]",
            suffixElement && "pr-[8px]",
            getAlignClassName(align)
          )}
          ref={ref}
          {...rest}
        />
        {suffixElement}
      </div>
    </Tooltip>
  );
});
Input.displayName = "Input";

export { Input };
