import { FC, useMemo, useState } from "react";
import type { ReactNode } from "react";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogBody,
  DialogFooter,
} from "@/components/dialog";
import { Button } from "@/components/button";
import { cn } from "@/utils/css";
import { IconStaking } from "../components/icons";
import type { EligibilityGate, SettingsTab } from "../types";
import { getIfRequiredForNewSymbol } from "../constants";
import { TransferModal } from "./TransferModal";
import { useListingServerData } from "../hooks/useListingServerData";
import { useMergedIfAccounts } from "../sections/onboarding/hooks/useMergedIfAccounts";

interface EligibilityModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  gates: EligibilityGate[];
  onManage: (tab?: SettingsTab) => void;
}

export const EligibilityModal: FC<EligibilityModalProps> = ({
  open,
  onOpenChange,
  gates,
  onManage,
}) => {
  const { riskSnapshot, subAccounts, listingAccounts, listingSymbols } =
    useListingServerData();
  const { mergedIfAccounts } = useMergedIfAccounts(subAccounts);
  const ifAccountId = listingAccounts?.if_account?.account_id ?? null;

  const { ifRequired, ifBalance, ifBalanceMissing } = useMemo(() => {
    const sub = ifAccountId
      ? mergedIfAccounts.find(a => a.sub_account_id === ifAccountId)
      : undefined;
    return {
      ifRequired: getIfRequiredForNewSymbol(riskSnapshot, listingSymbols),
      ifBalance: sub?.balance ?? 0,
      ifBalanceMissing: Boolean(ifAccountId && !sub),
    };
  }, [ifAccountId, listingSymbols, mergedIfAccounts, riskSnapshot]);

  const requiredTransferAmount = ifBalanceMissing
    ? ifRequired
    : Math.max(0, ifRequired - ifBalance);

  const [transferOpen, setTransferOpen] = useState(false);
  const failingGates = gates.filter(gate => !gate.passed);
  const tips = failingGates
    .map(gate => gate.tipText)
    .filter((tip): tip is string => Boolean(tip));

  const renderGateDescription = (description: ReactNode) => {
    if (typeof description === "string") {
      const [primary, secondary] = description.split(" / ");
      return (
        <p className="text-3xs font-medium text-base-contrast-72 mt-0.5">
          <span className="text-warning">{primary}</span>
          {secondary ? (
            <span className="text-base-contrast-54">{` / ${secondary}`}</span>
          ) : null}
        </p>
      );
    }
    return <div className="mt-0.5">{description}</div>;
  };

  return (
    <>
      <Dialog open={open} onOpenChange={onOpenChange}>
        <DialogContent className="max-w-[480px] p-8">
          <DialogHeader className="flex flex-col items-start gap-2 border-b-0 pb-0 px-0">
            <DialogTitle className="text-lg font-medium text-base-contrast-98">
              Unable to create listing
            </DialogTitle>
            <p className="text-xs font-medium text-base-contrast-54">
              The following requirements are not met. Please resolve them before
              creating a new listing.
            </p>
          </DialogHeader>

          <DialogBody className="flex flex-col gap-4 mt-4 max-h-[400px] overflow-y-auto custom-scrollbar px-0">
            {tips.length > 0 && (
              <div className="rounded-lg border border-base-contrast-12 bg-primary/10 px-4 py-3">
                <div className="flex items-start gap-3">
                  <div className="mt-0.5 flex shrink-0 items-center justify-center">
                    <svg
                      width="18"
                      height="18"
                      viewBox="0 0 20 20"
                      fill="none"
                      aria-hidden="true"
                    >
                      <circle
                        cx="10"
                        cy="10"
                        r="9"
                        stroke="currentColor"
                        strokeWidth="1.5"
                        className="text-primary-light"
                      />
                      <path
                        d="M10 9v4.5"
                        stroke="currentColor"
                        strokeWidth="1.5"
                        strokeLinecap="round"
                        className="text-primary-light"
                      />
                      <circle
                        cx="10"
                        cy="6.5"
                        r="1"
                        className="fill-current text-primary-light"
                      />
                    </svg>
                  </div>
                  <div className="space-y-0.5 text-[12px] leading-relaxed text-base-contrast-54 font-normal">
                    {tips.map(tip => (
                      <p key={tip}>{tip}</p>
                    ))}
                  </div>
                </div>
              </div>
            )}

            {failingGates.map(gate => (
              <div
                key={gate.key}
                className={cn(
                  "flex items-center gap-3 rounded-lg px-4 py-4 bg-base-200",
                  gate.isWarning && "opacity-70"
                )}
              >
                <div className="h-8 w-8 shrink-0 overflow-hidden rounded-xl">
                  <IconStaking className="h-full w-full" />
                </div>

                <div className="flex-1 min-w-0">
                  <p className="text-sm font-medium text-base-contrast-98 leading-snug">
                    {gate.label}{" "}
                    {gate.isWarning && (
                      <span className="text-[11px] font-normal text-warning">
                        (optional)
                      </span>
                    )}
                  </p>
                  {renderGateDescription(gate.description)}
                  {typeof gate.progressPct === "number" && (
                    <div className="mt-1 h-1 rounded-full bg-base-contrast-12">
                      <div
                        className={cn(
                          "h-full rounded-full",
                          gate.progressPct >= 100 ? "bg-success" : "bg-warning"
                        )}
                        style={{
                          width: `${Math.max(
                            0,
                            Math.min(100, gate.progressPct)
                          )}%`,
                        }}
                      />
                    </div>
                  )}
                </div>

                {!gate.passed && gate.action && (
                  <button
                    type="button"
                    className="ml-3 shrink-0 text-xs font-medium text-primary-light hover:underline cursor-pointer"
                    onClick={() => {
                      if (gate.action === "manage" && gate.targetTab) {
                        onManage(gate.targetTab);
                      } else if (gate.action === "transfer") {
                        onOpenChange(false);
                        if (ifAccountId) {
                          setTransferOpen(true);
                        }
                      }
                    }}
                  >
                    {gate.actionLabel ??
                      (gate.action === "manage" ? "Manage" : "Transfer")}
                  </button>
                )}
              </div>
            ))}
          </DialogBody>

          <DialogFooter className="justify-end border-t-0 pt-2">
            <Button
              size="md"
              variant="outline"
              color="primary"
              onClick={() => onOpenChange(false)}
            >
              Close
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      <TransferModal
        open={transferOpen}
        onOpenChange={setTransferOpen}
        targetAccountId={ifAccountId}
        requiredTransferAmount={requiredTransferAmount}
      />
    </>
  );
};
