import type { RwaMarketSessionRow } from "../services/types";

/**
 * Resolves the market session row for a stored template id (`market_session`).
 */
export function findRwaMarketSessionRow(
  marketSession: string | null | undefined,
  rows: RwaMarketSessionRow[] | null | undefined
): RwaMarketSessionRow | null {
  if (!marketSession || !rows?.length) return null;
  return rows.find(r => r.market_session === marketSession) ?? null;
}
