import type { ReactNode } from "react";

import type { RwaMarketSessionRow } from "./services/types";

// ---- Status ----

export type SymbolStatus =
  | "NEW"
  | "PENDING"
  | "POST_ONLY"
  | "ACTIVE"
  | "REDUCE_ONLY"
  | "DELISTING"
  | "DELISTED";

export enum AlertLevel {
  Normal = "NORMAL",
  Warning = "WARNING",
  Limit = "LIMIT",
}

// ---- Symbol / Detail ----

export interface SymbolItem {
  symbol: string;
  displayName: string;
  status: SymbolStatus;
  /**
   * Presence indicates this symbol is an RWA listing (backend field: `market_session`).
   * When missing, treat as Crypto.
   */
  marketSession?: RwaMarketSessionTemplate | null;
  /** Index source count (may be missing from some APIs). */
  sources?: number | null;
  /** 24h trading volume (USDC). */
  vol?: number | null;
  /** Per-symbol alert level derived from risk snapshot (may be missing). */
  alertLevel?: AlertLevel | null;
  /** 24h trading fee revenue (USDC). */
  feeRevenue?: number | null;
  /** 24h liquidation count. */
  liqCount?: number | null;
  /** 24h liquidation revenue (USDC). */
  liqRevenue?: number | null;
  /** ±2% bid/ask depth (USDC). */
  depthBid?: number | null;
  depthAsk?: number | null;
  /** Derived: max(long_oi, short_oi) (USDC). */
  openInterest?: number | null;
  /** Not provided by current Phase 1 APIs; will render as missing. */
  liqFee?: number | null;
  maxOi?: number | null;
  funding?: number | null;
  bid?: number | null;
  ask?: number | null;
  targetDepth?: number | null;
  depthQualifyingSince?: string | null;
  /** Listing time (ISO 8601). */
  listedAt?: string | null;
}

export interface SymbolParam {
  value: string;
  editable: boolean;
}

export enum MarketType {
  Spot = "spot",
  Perp = "perp",
}

export interface IndexSource {
  source: string;
  sourceSymbol: string;
  priceMultiplier: number;
  latestPrice: number;
  type?: IndexSourceType | string;
  sourceId?: string;
  marketType?: MarketType;
  /**
   * Datasource weight in integer percent (1~100; selected sources sum to 100).
   */
  weight?: number;
}

export interface SymbolDetail {
  status: SymbolStatus;
  listingTime: string | null;
  params: Record<string, SymbolParam>;
  indexSources: IndexSource[];
  feeShareRate: number;
  fundingPeriodPending?: string;
  fundingPeriodEffectiveAt?: string;
  volume24h: number;
  feeRevenue24h: number;
  liquidationCount24h: number;
  liquidationRevenue24h: number;
  mmAccounts: string[];
  delistTime: string | null;
  isRwa?: boolean;
  marketSession?: RwaMarketSessionTemplate | null;
  /** Row from `/v1/public/rwa/market_sessions` matched by `marketSession`. */
  rwaMarket?: RwaMarketSessionRow | null;
}

// ---- Sub-Account ----

export interface SubAccount {
  sub_account_id: string;
  description: string;
  balance: number;
}

export interface MMAccount {
  account_id: string;
  balance: number;
}

export enum SettingsTab {
  If = "if",
  Mm = "mm",
  Tier = "tier",
  Notifications = "notifications",
}

export enum IndexSourceType {
  Cex = "cex",
  Futures = "futures",
  Oracle = "oracle",
  BuilderOracle = "builder_oracle",
  Byok = "byok_oracle",
}

export function isSpotIndexSourceType(type: IndexSourceType): boolean {
  return type !== IndexSourceType.Futures;
}

// ---- Onboarding ----

export interface OnboardingStep {
  key: string;
  title: string;
  description: string;
  done: boolean;
  expanded: boolean;
  statusLabel?: string;
}

// ---- Source / Price Sources ----

/** Listing index_sources row enriched with display name (store catalog). */
export type IndexSourceMeta = {
  source: string;
  type: IndexSourceType;
  name: string;
};

export interface SourceItem extends IndexSourceMeta {
  id: string;
  found: boolean;
  sourceSymbol: string;
  /**
   * Frontend-only marker: this row was selected when hydrated from listing detail.
   * Used to allow re-selecting notFound rows in edit mode without including them
   * in the header "select all" pool.
   */
  selectedFromDetail?: boolean;
  /**
   * Original `source_symbol` from broker listing `index_sources` API.
   * Used to keep UI symbol display stable for builder-like sources.
   */
  indexSourceSymbol?: string;
  /** Frontend-only marker: sourceSymbol was entered manually by the user. */
  sourceSymbolManual?: boolean;
  // When source is Pyth (oracle), feedId is the id of the Pyth price feed.
  feedId?: string;
  multiplier: number;
  price: number;
  volume24h: number;
  sourceId?: string;
  uptime7dPct?: number | null;
  skips7d?: number | null;
  latestPriceTs?: number | null;
  marketClosed?: boolean;
  riskNotice?: string | null;
  health?: string | null;
  priceLoading?: boolean;
  volumeLoading?: boolean;
  weight: number;
  selected: boolean;
  loading?: boolean;
  notFound?: boolean;
}

export enum ListingAssetType {
  Crypto = "crypto",
  Rwa = "rwa",
}

export type RwaMarketSessionTemplate = string;

// ---- Trading Params ----

export interface TradingParamsForm {
  max_leverage: string;
  global_max_oi: string;
  max_notional_user: string;
  funding_period: string;
  std_liquidation_fee: string;
  claim_IF_discount: string;
  base_symbol: string;
  listing_asset_type: ListingAssetType;
  rwa_market_session: RwaMarketSessionTemplate | "";
}

// ---- Eligibility ----

export interface EligibilityGate {
  key: string;
  label: string;
  passed: boolean;
  description: ReactNode;
  action?: "manage" | "transfer";
  targetTab?: SettingsTab;
  subInfo?: string;
  progressPct?: number;
  isWarning?: boolean;
  actionLabel?: string;
  tipText?: string;
}

// ---- View / Page ----

export enum PageView {
  Dashboard = "dashboard",
  Settings = "settings",
  Onboarding = "onboarding",
  Listing = "listing",
  CustomOracle = "custom-oracle",
  SymbolDetail = "symbol-detail",
}

export const ListingSubStep = {
  PriceSources: "price-sources",
  TradingParams: "trading-params",
} as const;

export type ListingSubStep =
  (typeof ListingSubStep)[keyof typeof ListingSubStep];

export type DashView = "card";

export type PeriodFilter = "all-time" | "30d" | "7d" | "24h";

// ---- Recent Events ----

export interface RecentEvent {
  /** ISO 8601, used for sorting + relative time label. */
  eventTime: string;
  time: string;
  description: string;
}

export type BrokerInfo = {
  broker_id: string;
  total_staked_balance: number;
  volume_last30_days: number;
  type: string;
  base_maker_fee_rate: number;
  base_taker_fee_rate: number;
};
