import { useEffect, useState } from "react";
import { cn } from "@/utils/css";
import { OdsCheckbox } from "@/components/orderly/OdsCheckbox";
import Tooltip from "@/components/tooltip";
import { PLSelectField } from "../../../components/PLSelect";
import { fmtUSDShort } from "../../../utils";
import {
  IndexSourceType,
  isSpotIndexSourceType,
  type SourceItem,
} from "../../../types";
import Decimal from "decimal.js";
import {
  InfoIcon,
  MULTIPLIER_SELECT_OPTIONS,
  NotFoundSourceRow,
  SPOT_MULTIPLIER_TOOLTIP,
  SourceLoadingRow,
  SourceNameCell,
  SourceSymbolInputCell,
  SourceTypeCell,
  getFormattedSourceType,
} from "./SourceRowParts";

interface SourceRowProps {
  item: SourceItem;
  builderOracleSourceId?: string | null;
  byokSourceIdSet?: Set<string>;
  /** When true (e.g. edit listing), not-found rows still allow checkbox selection. */
  allowSelectWhenNotFound?: boolean;
  /** When true (edit listing), price multiplier cannot be changed. */
  editMode?: boolean;
  onToggle: (id: string) => void;
  onSymbolChange: (id: string, symbol: string) => void;
  onSymbolBlur: (id: string) => void;
  onMultiplierChange: (id: string, multiplier: number) => void;
  onWeightChange: (id: string, weightPercent: number) => void;
}

export function SourceRow({
  item,
  builderOracleSourceId = null,
  byokSourceIdSet,
  allowSelectWhenNotFound = false,
  editMode = false,
  onToggle,
  onSymbolChange,
  onSymbolBlur,
  onMultiplierChange,
  onWeightChange,
}: SourceRowProps) {
  const isOracle = item.type === IndexSourceType.Oracle;
  const isBuilderLike =
    item.type === IndexSourceType.BuilderOracle ||
    item.type === IndexSourceType.Byok;
  const isBuilderOracle = item.type === IndexSourceType.BuilderOracle;

  const derivedSourceId = item.sourceId ?? item.source;
  const isOwnBuilderOracle =
    isBuilderOracle &&
    Boolean(builderOracleSourceId) &&
    derivedSourceId.toUpperCase() ===
      String(builderOracleSourceId).toUpperCase();
  const isOwnByok =
    item.type === IndexSourceType.Byok &&
    Boolean(byokSourceIdSet?.size) &&
    Boolean(byokSourceIdSet?.has(derivedSourceId));
  const isOwnCustom = isBuilderLike
    ? isBuilderOracle
      ? isOwnBuilderOracle
      : isOwnByok
    : false;
  const isThirdPartyCustom = isBuilderLike && !isOwnCustom;

  const formattedItemType = getFormattedSourceType(item);

  const effectiveMultiplier = item.multiplier > 0 ? item.multiplier : 1;
  const displayedPrice = new Decimal(item.price || 0)
    .mul(effectiveMultiplier)
    .toFixed();
  const displayWeight =
    typeof item.weight === "number" && Number.isFinite(item.weight)
      ? Math.round(item.weight)
      : 0;
  const [weightInput, setWeightInput] = useState(
    item.selected && displayWeight > 0 ? String(displayWeight) : ""
  );

  useEffect(() => {
    setWeightInput(
      item.selected && displayWeight > 0 ? String(displayWeight) : ""
    );
  }, [item.selected, displayWeight]);

  if (item.loading) {
    return <SourceLoadingRow />;
  }

  if (item.notFound) {
    // Builder-like notFound rows (e.g. no price) should never be selectable,
    // even in edit mode.
    const canSelectNotFound =
      allowSelectWhenNotFound &&
      Boolean(item.selected || item.selectedFromDetail) &&
      !isBuilderLike;
    return (
      <NotFoundSourceRow
        item={item}
        canSelect={canSelectNotFound}
        isBuilderOracle={isBuilderOracle}
        isBuilderLike={isBuilderLike}
        isOwnCustom={isOwnCustom}
        isThirdPartyCustom={isThirdPartyCustom}
        formattedItemType={formattedItemType}
        onToggle={onToggle}
        onSymbolChange={onSymbolChange}
        onSymbolBlur={onSymbolBlur}
      />
    );
  }

  return (
    <tr
      className={cn(
        "h-[52px] transition-colors",
        item.selected
          ? "bg-primary/5 hover:bg-primary/[0.07]"
          : "hover:bg-base-contrast-4"
      )}
    >
      <td className="px-6 py-4 align-middle border-b border-base-contrast-6">
        <span className="inline-flex items-center h-[32px]">
          <OdsCheckbox
            checked={item.selected}
            onCheckedChange={() => onToggle(item.id)}
          />
        </span>
      </td>
      <SourceNameCell
        item={item}
        isBuilderOracle={isBuilderOracle}
        isBuilderLike={isBuilderLike}
        isOwnCustom={isOwnCustom}
        isThirdPartyCustom={isThirdPartyCustom}
      />
      <SourceTypeCell>{formattedItemType}</SourceTypeCell>
      <SourceSymbolInputCell
        value={item.sourceSymbol}
        onChange={value => onSymbolChange(item.id, value)}
      />
      <td className="px-6 py-4 border-b border-base-contrast-6">
        <div className="flex items-center gap-2">
          {item.priceLoading ? (
            <div className="h-4 w-[88px] bg-base-contrast-8 rounded animate-pulse" />
          ) : (
            <>
              <PLSelectField<number>
                value={item.multiplier}
                onChange={v => onMultiplierChange(item.id, v)}
                options={MULTIPLIER_SELECT_OPTIONS}
                placeholder="-"
                size="sm"
                itemClassName="py-2 px-3"
                disabled={editMode}
                // triggerClassName="w-full min-w-[88px] max-w-[96px]"
              />
              {isSpotIndexSourceType(item.type) && (
                <Tooltip
                  content={SPOT_MULTIPLIER_TOOLTIP}
                  side="top"
                  sideOffset={6}
                  className="max-w-[min(320px,90vw)] whitespace-normal text-left"
                >
                  <button
                    type="button"
                    className="inline-flex p-0.5 -m-0.5 rounded text-base-contrast-50 hover:text-base-contrast-70"
                    aria-label="More information: Spot price multiplier"
                  >
                    <InfoIcon />
                  </button>
                </Tooltip>
              )}
            </>
          )}
        </div>
      </td>
      <td className="px-6 py-4 align-middle text-xs tabular-nums border-b border-base-contrast-6">
        {item.priceLoading ? (
          <div className="h-4 w-16 bg-base-contrast-8 rounded animate-pulse" />
        ) : (isOracle || isBuilderLike) && item.price <= 0 ? (
          <span className="text-base-contrast-36">-</span>
        ) : item.marketClosed ? (
          <span className="text-warning">
            ${displayedPrice} · Market Closed
          </span>
        ) : item.price > 0 ? (
          <span className="text-base-contrast-98">${displayedPrice}</span>
        ) : (
          <span className="text-danger">Not found on {item.name}</span>
        )}
      </td>
      <td className="px-6 py-4 align-middle text-xs text-base-contrast-98 tabular-nums border-b border-base-contrast-6">
        {item.volumeLoading ? (
          <div className="h-4 w-20 bg-base-contrast-8 rounded animate-pulse" />
        ) : item.volume24h == null ||
          !Number.isFinite(item.volume24h) ||
          item.volume24h <= 0 ? (
          <span className="text-base-contrast-36">-</span>
        ) : (
          fmtUSDShort(item.volume24h)
        )}
      </td>
      <td
        className={cn(
          "px-4 py-4 align-middle text-xs tabular-nums border-b border-base-contrast-6 w-[92px] text-left",
          item.weight > 0 ? "text-primary" : "text-base-contrast-98"
        )}
      >
        {item.selected ? (
          <input
            type="text"
            inputMode="numeric"
            value={weightInput}
            onChange={e => {
              const next = e.target.value.replace(/[^\d]/g, "");
              setWeightInput(next);
            }}
            onBlur={() => {
              const normalized = Math.max(
                1,
                Math.min(100, Math.round(Number(weightInput) || 1))
              );
              setWeightInput(String(normalized));
              onWeightChange(item.id, normalized);
            }}
            onKeyDown={e => {
              if (e.key === "Enter") {
                (e.currentTarget as HTMLInputElement).blur();
              }
            }}
            className={cn(
              "w-full h-8 px-2 rounded text-3xs text-left",
              "[appearance:textfield] [&::-webkit-outer-spin-button]:appearance-none [&::-webkit-inner-spin-button]:appearance-none",
              "bg-base-300 text-base-contrast-98",
              "border border-base-contrast-12 outline-none",
              "focus:border-primary/50"
            )}
            aria-label={`Weight for ${item.name}`}
          />
        ) : (
          <div className="w-full h-8 px-2 flex items-center text-3xs text-base-contrast-36">
            -
          </div>
        )}
      </td>
    </tr>
  );
}
