import { useMemo, useRef } from "react";
import Tooltip from "@/components/tooltip";
import { cn } from "@/utils/css";
import { deriveBrokerSymbolLogoFileBaseName } from "@/utils/brokerSymbolLogoUpload";
import { InfoIcon } from "./ParamFormFields";

export function SymbolIconField({
  baseSymbol,
  hasStagedSymbolIcon,
  symbolIconDisplayUrl,
  symbolIconLabel,
  onStageSymbolIcon,
  onRemoveSymbolIcon,
}: {
  baseSymbol: string;
  hasStagedSymbolIcon: boolean;
  symbolIconDisplayUrl: string | null;
  symbolIconLabel: string;
  onStageSymbolIcon: (file: File) => Promise<boolean>;
  onRemoveSymbolIcon: () => void;
}) {
  const inputRef = useRef<HTMLInputElement>(null);
  const fallback = useMemo(() => {
    const source = deriveBrokerSymbolLogoFileBaseName(
      symbolIconLabel || baseSymbol
    );
    const firstChar = source.trim().charAt(0);
    return firstChar ? firstChar.toUpperCase() : "?";
  }, [symbolIconLabel, baseSymbol]);

  return (
    <div className="mb-6 border-b border-base-contrast-8 pb-6">
      <div className="flex items-center gap-1">
        <div className="text-xs font-medium text-base-contrast-98">
          Symbol icon
        </div>
        <span className="ml-1 text-3xs font-medium text-base-contrast-50">
          Optional
        </span>
        <Tooltip
          content="Asset icon shown next to the symbol on Orderly products. Skip for now and add it from the symbol detail page later - non-blocking for listing."
          side="top"
          sideOffset={6}
          className="max-w-[min(320px,90vw)] whitespace-normal text-left"
        >
          <button
            type="button"
            className="inline-flex p-0.5 -m-0.5 rounded text-base-contrast-50 hover:text-base-contrast-70"
            aria-label="More information: Symbol icon"
          >
            <InfoIcon />
          </button>
        </Tooltip>
      </div>

      <div className="mt-4 flex flex-col gap-4 sm:flex-row sm:items-center">
        <div className="flex h-16 w-16 items-center justify-center overflow-hidden rounded-full border border-base-contrast-12 bg-primary/10 text-[22px] font-semibold text-primary">
          {symbolIconDisplayUrl ? (
            <img
              src={symbolIconDisplayUrl}
              alt="Symbol icon preview"
              className="h-full w-full object-cover"
            />
          ) : (
            <span>{fallback}</span>
          )}
        </div>

        <div className="flex flex-1 flex-col gap-3">
          <div className="flex flex-wrap gap-2">
            <input
              ref={inputRef}
              type="file"
              accept="image/png"
              className="hidden"
              onChange={event => {
                const file = event.target.files?.[0];
                event.currentTarget.value = "";
                if (file) {
                  void onStageSymbolIcon(file);
                }
              }}
            />
            <button
              type="button"
              onClick={() => inputRef.current?.click()}
              className={cn(
                "inline-flex h-8 items-center justify-center rounded-full px-4 text-2xs font-medium",
                "border border-primary bg-transparent text-white/80 transition-colors hover:bg-primary/10"
              )}
            >
              Choose file
            </button>
            {hasStagedSymbolIcon ? (
              <button
                type="button"
                onClick={onRemoveSymbolIcon}
                className={cn(
                  "inline-flex h-8 items-center justify-center rounded-full px-4 text-2xs font-medium",
                  "border border-danger/40 bg-transparent text-danger transition-colors hover:bg-danger/10"
                )}
              >
                Remove
              </button>
            ) : null}
          </div>
          <div className="text-3xs text-base-contrast-36">
            PNG · 64×64 · max 50KB
          </div>
        </div>
      </div>
    </div>
  );
}
