import { useCallback, useEffect } from "react";
import { useSelectListingStore } from "../../store/useListingStore";
import { ListingSubStep, PageView } from "../../types";
import type { CustomOracleModalState } from "./types";
import { useListingAccountContext } from "../../hooks/useListingAccountContext";
import { storageKey } from "@/utils/storage";

function getOnboardingSeenStorageKey(accountId: string) {
  return storageKey(
    `permissionlessListing:customOracle:onboardingSeen:${accountId}`
  );
}

function hasSeenOnboardingInStorage(accountId: string) {
  if (typeof window === "undefined") return false;
  if (!accountId) return false;

  try {
    return (
      window.localStorage.getItem(getOnboardingSeenStorageKey(accountId)) ===
      "1"
    );
  } catch {
    return false;
  }
}

function setSeenOnboardingInStorage(accountId: string) {
  if (typeof window === "undefined") return;
  if (!accountId) return;

  try {
    window.localStorage.setItem(getOnboardingSeenStorageKey(accountId), "1");
  } catch {
    // ignore storage errors (e.g. disabled storage)
  }
}

function cloneModal(
  current: CustomOracleModalState,
  patch: Partial<CustomOracleModalState>
): CustomOracleModalState {
  return {
    ...current,
    ...patch,
  };
}

export function useCustomOracleScript() {
  const {
    currentTab,
    customOracleOrigin,
    customOracleHasSeenOnboarding,
    modal,
    setPage,
    setCustomOracleTab,
    setCustomOracleHasSeenOnboarding,
    setBuilderExpandedSymbolId,
    setCustomOracleModal,
  } = useSelectListingStore(state => ({
    currentTab: state.customOracleTab,
    customOracleOrigin: state.customOracleOrigin,
    customOracleHasSeenOnboarding: state.customOracleHasSeenOnboarding,
    modal: state.customOracleModal,
    setPage: state.setPage,
    setCustomOracleTab: state.setCustomOracleTab,
    setCustomOracleHasSeenOnboarding: state.setCustomOracleHasSeenOnboarding,
    setBuilderExpandedSymbolId: state.setBuilderExpandedSymbolId,
    setCustomOracleModal: state.setCustomOracleModal,
  }));
  const { accountId } = useListingAccountContext();

  useEffect(() => {
    if (!accountId) return;
    setCustomOracleHasSeenOnboarding(hasSeenOnboardingInStorage(accountId));
  }, [accountId, setCustomOracleHasSeenOnboarding]);

  useEffect(() => {
    if (customOracleHasSeenOnboarding) return;
    if (!accountId) return;

    if (hasSeenOnboardingInStorage(accountId)) {
      setCustomOracleHasSeenOnboarding(true);
      return;
    }

    if (modal.onboardingOpen) return;
    setCustomOracleModal(cloneModal(modal, { onboardingOpen: true }));
  }, [
    accountId,
    customOracleHasSeenOnboarding,
    modal,
    setCustomOracleHasSeenOnboarding,
    setCustomOracleModal,
  ]);

  const onBack = useCallback(() => {
    if (customOracleOrigin === "listing-price-sources") {
      setPage(PageView.Listing, { listingStep: ListingSubStep.PriceSources });
      return;
    }
    setPage(PageView.Dashboard);
  }, [customOracleOrigin, setPage]);

  const onSwitchTab = useCallback(
    (tab: "builder" | "byok") => {
      setCustomOracleTab(tab);
      setBuilderExpandedSymbolId(null);
    },
    [setBuilderExpandedSymbolId, setCustomOracleTab]
  );

  const onOpenOnboarding = useCallback(() => {
    setCustomOracleModal(cloneModal(modal, { onboardingOpen: true }));
  }, [modal, setCustomOracleModal]);

  const onCloseOnboarding = useCallback(() => {
    setCustomOracleModal(cloneModal(modal, { onboardingOpen: false }));
    if (accountId) {
      setSeenOnboardingInStorage(accountId);
      setCustomOracleHasSeenOnboarding(true);
    }
  }, [
    accountId,
    modal,
    setCustomOracleHasSeenOnboarding,
    setCustomOracleModal,
  ]);

  return {
    currentTab,
    onboardingOpen: modal.onboardingOpen,
    onBack,
    onSwitchTab,
    onOpenOnboarding,
    onCloseOnboarding,
  };
}

export type CustomOracleScriptReturn = ReturnType<typeof useCustomOracleScript>;
