import { type FormEvent, useMemo, useState } from "react";
import { Button } from "@/components/button";
import {
  Dialog,
  DialogBody,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/dialog";
import { toast } from "@/components/toast";
import Tooltip from "@/components/tooltip";
import { cn } from "@/utils/css";
import { PLInput } from "../../components/Input";
import {
  type BrokerWhitelistIpRow,
  useBrokerWhitelistIpList,
  useDeleteBrokerWhitelistIp,
  useUpsertBrokerWhitelistIp,
} from "../../services";

const WHITELIST_QUOTA = 5;
const DESCRIPTION_MAX_LENGTH = 255;

const COPY = {
  title: "IP whitelist",
  quotaReached: "Quota reached. Delete unused IPs first.",
  quotaError: "Whitelist quota reached (5 IPs). Delete unused IPs first.",
  description:
    "Optional. Without whitelisting, requests use the standard rate limit (300 req/min/IP). Whitelisted IPs get 900 req/min/IP. Only IPv4 / IPv6 single addresses. CIDR ranges not supported.",
  emptyTitle: "No IPs configured yet",
  emptyDescription: "Add your market maker's egress IP to lift rate limits.",
  ipHint: "IPv4 / IPv6 single address. CIDR not supported.",
  descriptionHint: "Up to 255 characters.",
  syncHint: "Allow up to 20 minutes for whitelist changes to take effect.",
  loadFailed: "Failed to load.",
  invalidIp: "Invalid IP. Use an IPv4 or IPv6 single address.",
  invalidIpWithCidr:
    "Invalid IP. Use an IPv4 or IPv6 single address (CIDR not supported).",
  cidrNotSupported: "Invalid IP. CIDR ranges are not supported.",
  ipRequired: "IP address is required.",
  duplicateIp: "This IP is already in your whitelist.",
  descriptionTooLong: "Description must be 255 characters or less.",
  genericError: "Something went wrong. Please try again.",
};

const normalizeIpForCompare = (ip: string) => ip.trim().toLowerCase();

function isValidIpv4(input: string) {
  const parts = input.split(".");
  if (parts.length !== 4) return false;

  return parts.every(part => {
    if (!/^\d{1,3}$/.test(part)) return false;
    const value = Number(part);
    return value >= 0 && value <= 255;
  });
}

const IPV6_SEGMENT = /^[0-9a-f]{1,4}$/i;

function isValidIpv6(input: string) {
  if (!input.includes(":")) return false;

  const parts = input.split("::");
  if (parts.length > 2) return false;

  if (parts.length === 2) {
    const left = parts[0] ? parts[0].split(":") : [];
    const right = parts[1] ? parts[1].split(":") : [];
    if (left.length + right.length > 7) return false;
    return [...left, ...right].every(segment => IPV6_SEGMENT.test(segment));
  }

  const groups = input.split(":");
  if (groups.length !== 8) return false;
  return groups.every(segment => IPV6_SEGMENT.test(segment));
}

function isValidIpAddress(input: string) {
  if (
    /\s/.test(input) ||
    input.includes("/") ||
    input.includes("[") ||
    input.includes("]")
  ) {
    return false;
  }
  return isValidIpv4(input) || isValidIpv6(input);
}

function formatUpdatedDate(value?: string) {
  if (!value) return "-";
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return value.slice(0, 10);
  const mm = String(date.getMonth() + 1).padStart(2, "0");
  const dd = String(date.getDate()).padStart(2, "0");
  return `${date.getFullYear()}-${mm}-${dd}`;
}

function getApiErrorMessage(error: unknown) {
  if (error instanceof Error) return error.message;
  if (error && typeof error === "object" && "message" in error) {
    const message = (error as { message?: unknown }).message;
    if (typeof message === "string" && message.trim()) return message;
  }
  return COPY.genericError;
}

function getIpFieldError(error: unknown) {
  const message = getApiErrorMessage(error);
  return message === COPY.invalidIpWithCidr ? message : null;
}

function mutationFailed(result: unknown) {
  return Boolean(
    result &&
      typeof result === "object" &&
      "success" in result &&
      (result as { success?: boolean }).success === false
  );
}

export function IPWhitelistSection() {
  const {
    data,
    error: listError,
    isLoading,
    mutate,
  } = useBrokerWhitelistIpList();
  const [upsertIp, upsertState] = useUpsertBrokerWhitelistIp();
  const [deleteIp] = useDeleteBrokerWhitelistIp();

  const [addOpen, setAddOpen] = useState(false);
  const [ip, setIp] = useState("");
  const [description, setDescription] = useState("");
  const [ipError, setIpError] = useState<string | null>(null);
  const [descriptionError, setDescriptionError] = useState<string | null>(null);
  const [deleteTarget, setDeleteTarget] = useState<BrokerWhitelistIpRow | null>(
    null
  );
  const [deletingId, setDeletingId] = useState<number | null>(null);

  const items = useMemo(() => data?.items ?? [], [data?.items]);
  const usedQuota = items.length;
  const isQuotaReached = usedQuota >= WHITELIST_QUOTA;
  const isApproachingQuota =
    usedQuota >= WHITELIST_QUOTA - 2 && usedQuota < WHITELIST_QUOTA;

  const existingIps = useMemo(
    () => new Set(items.map(item => normalizeIpForCompare(item.ip))),
    [items]
  );

  function resetAddForm() {
    setIp("");
    setDescription("");
    setIpError(null);
    setDescriptionError(null);
  }

  function openAddDialog() {
    if (isQuotaReached) return;
    resetAddForm();
    setAddOpen(true);
  }

  function validateAddForm() {
    const nextIp = ip.trim();
    const nextDescription = description.trim();

    if (!nextIp) {
      setIpError(COPY.ipRequired);
      return null;
    }
    if (nextIp.includes("/")) {
      setIpError(COPY.cidrNotSupported);
      return null;
    }
    if (!isValidIpAddress(nextIp)) {
      setIpError(COPY.invalidIp);
      return null;
    }
    if (existingIps.has(normalizeIpForCompare(nextIp))) {
      setIpError(COPY.duplicateIp);
      return null;
    }
    if (isQuotaReached) {
      setIpError(COPY.quotaError);
      return null;
    }
    if (nextDescription.length > DESCRIPTION_MAX_LENGTH) {
      setDescriptionError(COPY.descriptionTooLong);
      return null;
    }

    setIpError(null);
    setDescriptionError(null);
    return { ip: nextIp, description: nextDescription };
  }

  async function handleAdd(event: FormEvent) {
    event.preventDefault();
    const payload = validateAddForm();
    if (!payload) return;

    try {
      const result = await upsertIp({
        entries: [
          {
            ip: payload.ip,
            description: payload.description,
          },
        ],
      });
      if (mutationFailed(result)) throw result;
      toast.success("IP added");
      setAddOpen(false);
      resetAddForm();
      await mutate();
    } catch (error) {
      const fieldError = getIpFieldError(error);
      if (fieldError) {
        setIpError(fieldError);
        return;
      }
      toast.error(getApiErrorMessage(error));
    }
  }

  async function handleDelete() {
    if (!deleteTarget) return;
    setDeletingId(deleteTarget.id);
    try {
      const result = await deleteIp([deleteTarget.id]);
      if (mutationFailed(result)) throw result;
      toast.success("IP deleted");
      setDeleteTarget(null);
      await mutate();
    } catch (error) {
      toast.error(getApiErrorMessage(error));
    } finally {
      setDeletingId(null);
    }
  }

  return (
    <section className="flex flex-col gap-0">
      <div className="mb-2 flex items-center justify-between gap-4">
        <label className="m-0 text-xs font-medium text-base-contrast-50">
          {COPY.title}
        </label>
        <div className="flex shrink-0 items-center gap-3">
          <div className="flex flex-wrap items-center justify-end gap-2">
            <span
              className={cn(
                "text-3xs font-medium",
                isQuotaReached
                  ? "text-danger"
                  : isApproachingQuota
                    ? "text-warning"
                    : "text-base-contrast-50"
              )}
            >
              {usedQuota} / {WHITELIST_QUOTA} used
            </span>
            {isApproachingQuota && (
              <span className="rounded-full bg-warning/10 px-2 py-0.5 text-3xs font-medium text-warning">
                Approaching quota
              </span>
            )}
          </div>
          <Tooltip
            disabled={!isQuotaReached}
            content={COPY.quotaReached}
            side="top"
            className="bg-base-500 text-base-contrast-98"
            arrowClassName="fill-base-500"
          >
            <span>
              <Button
                type="button"
                size="sm"
                rounded="lg"
                disabled={isQuotaReached}
                onClick={openAddDialog}
                className="h-8 px-3 text-2xs font-medium"
              >
                + Add IP
              </Button>
            </span>
          </Tooltip>
        </div>
      </div>

      <span className="mb-3 block text-3xs leading-5 text-base-contrast-50">
        {COPY.description}
      </span>

      {isLoading ? (
        <div className="flex min-h-[96px] items-center justify-center rounded-lg border border-dashed border-base-contrast-8 text-2xs text-base-contrast-50">
          Loading...
        </div>
      ) : listError ? (
        <div className="flex min-h-[96px] flex-col items-center justify-center gap-3 rounded-lg border border-dashed border-base-contrast-8 text-2xs text-base-contrast-50">
          <span>{COPY.loadFailed}</span>
          <Button
            type="button"
            size="sm"
            variant="outline"
            color="primary"
            onClick={() => void mutate()}
          >
            Retry
          </Button>
        </div>
      ) : items.length === 0 ? (
        <div className="rounded-lg border border-dashed border-base-contrast-8 px-5 py-8 text-center text-2xs text-base-contrast-50">
          <div className="mb-1 font-medium text-base-contrast-98">
            {COPY.emptyTitle}
          </div>
          <div>{COPY.emptyDescription}</div>
        </div>
      ) : (
        <div className="overflow-hidden rounded-lg border border-base-contrast-8">
          <table className="w-full table-fixed border-collapse text-left">
            <thead className="bg-base-300 text-[11px] uppercase tracking-[0.04em] text-base-contrast-50">
              <tr>
                <th className="px-3 py-2.5 font-medium">IP</th>
                <th className="hidden px-3 py-2.5 font-medium lg:table-cell">
                  Description
                </th>
                <th className="hidden w-[116px] px-3 py-2.5 font-medium lg:table-cell">
                  Updated
                </th>
                <th className="w-[92px] px-3 py-2.5 text-right font-medium">
                  Action
                </th>
              </tr>
            </thead>
            <tbody className="divide-y divide-base-contrast-8 text-2xs">
              {items.map(item => (
                <tr key={item.id} className="align-top">
                  <td className="px-3 py-2.5">
                    <div className="font-mono text-[13px] text-base-contrast-98">
                      {item.ip}
                    </div>
                    <div className="mt-1 text-base-contrast-36 lg:hidden">
                      {item.description || "-"} -{" "}
                      {formatUpdatedDate(item.updated_time)}
                    </div>
                  </td>
                  <td className="hidden px-3 py-2.5 text-base-contrast-50 lg:table-cell">
                    {item.description || "-"}
                  </td>
                  <td className="hidden whitespace-nowrap px-3 py-2.5 text-base-contrast-50 lg:table-cell">
                    {formatUpdatedDate(item.updated_time)}
                  </td>
                  <td className="px-3 py-2.5 text-right">
                    <Button
                      type="button"
                      size="sm"
                      variant="outline"
                      rounded="lg"
                      loading={deletingId === item.id}
                      disabled={deletingId === item.id}
                      onClick={() => setDeleteTarget(item)}
                      className="h-[26px] border-base-contrast-12 bg-transparent px-2.5 text-3xs font-medium text-base-contrast-50 hover:bg-base-contrast-8 hover:text-base-contrast-98"
                    >
                      Delete
                    </Button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      <span className="mt-3 block text-3xs leading-5 text-base-contrast-50">
        {COPY.syncHint}
      </span>

      <Dialog
        open={addOpen}
        onOpenChange={nextOpen => {
          setAddOpen(nextOpen);
          if (!nextOpen) resetAddForm();
        }}
      >
        <DialogContent className="max-w-[480px]">
          <DialogHeader className="h-auto flex-col items-stretch gap-2 border-b-0 px-6 pb-0 pt-6">
            <DialogTitle className="text-lg font-medium leading-[1.2] text-base-contrast-98">
              Add IP
            </DialogTitle>
            <DialogDescription className="text-xs leading-[1.5] text-base-contrast-50">
              Add one market maker egress IP. Only IPv4 / IPv6 single addresses
              are supported.
            </DialogDescription>
          </DialogHeader>
          <DialogBody className="px-6 py-5">
            <form
              id="add-ip-form"
              className="flex flex-col gap-4"
              onSubmit={handleAdd}
            >
              <div>
                <label className="mb-2 block text-xs font-medium text-base-contrast-50">
                  IP address <span className="text-primary">*</span>
                </label>
                <PLInput
                  value={ip}
                  disabled={upsertState.isMutating}
                  error={Boolean(ipError)}
                  placeholder="e.g. 203.0.113.10"
                  autoComplete="off"
                  onChange={event => {
                    setIp(event.target.value);
                    setIpError(null);
                  }}
                />
                <p
                  className={cn(
                    "mt-1 text-3xs text-base-contrast-50",
                    ipError && "font-medium text-danger"
                  )}
                >
                  {ipError || COPY.ipHint}
                </p>
              </div>

              <div>
                <label className="mb-2 block text-xs font-medium text-base-contrast-50">
                  Description (optional)
                </label>
                <PLInput
                  value={description}
                  disabled={upsertState.isMutating}
                  error={Boolean(descriptionError)}
                  placeholder="e.g. sg-prod-egress"
                  maxLength={DESCRIPTION_MAX_LENGTH + 1}
                  autoComplete="off"
                  onChange={event => {
                    setDescription(event.target.value);
                    setDescriptionError(null);
                  }}
                />
                <p
                  className={cn(
                    "mt-1 text-3xs text-base-contrast-50",
                    descriptionError && "font-medium text-danger"
                  )}
                >
                  {descriptionError || COPY.descriptionHint}
                </p>
              </div>
            </form>
          </DialogBody>
          <DialogFooter className="justify-end gap-2 px-6 pb-6 pt-0">
            <Button
              type="button"
              variant="outline"
              color="primary"
              rounded="full"
              className="bg-transparent px-5"
              onClick={() => setAddOpen(false)}
            >
              Cancel
            </Button>
            <Button
              type="submit"
              form="add-ip-form"
              rounded="full"
              className="px-5"
              loading={upsertState.isMutating}
              disabled={upsertState.isMutating}
            >
              Add
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      <Dialog
        open={Boolean(deleteTarget)}
        onOpenChange={nextOpen => {
          if (!nextOpen && deletingId === null) setDeleteTarget(null);
        }}
      >
        <DialogContent className="max-w-[440px]">
          <DialogHeader className="h-auto flex-col items-stretch gap-2 border-b-0 px-6 pb-0 pt-6">
            <DialogTitle className="text-lg font-medium leading-[1.2] text-base-contrast-98">
              Delete IP
            </DialogTitle>
            <DialogDescription className="text-xs leading-[1.5] text-base-contrast-50">
              Delete{" "}
              <span className="font-mono text-base-contrast-98">
                {deleteTarget?.ip}
              </span>{" "}
              from whitelist?
            </DialogDescription>
          </DialogHeader>
          <DialogFooter className="justify-end gap-2 px-6 py-6">
            <Button
              type="button"
              variant="outline"
              color="primary"
              rounded="full"
              className="bg-transparent px-5"
              disabled={deletingId !== null}
              onClick={() => setDeleteTarget(null)}
            >
              Cancel
            </Button>
            <Button
              type="button"
              variant="danger"
              rounded="full"
              className="px-5"
              loading={deletingId !== null}
              disabled={deletingId !== null}
              onClick={() => void handleDelete()}
            >
              Delete
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </section>
  );
}
