import { cn } from "@/utils/css";
import { ListingAssetType } from "../../types";

export function AssetTypePill({
  assetType,
  className,
}: {
  assetType: ListingAssetType;
  className?: string;
}) {
  return (
    <span
      className={cn(
        "inline-flex items-center rounded-full border px-2.5 py-0.5 text-[11px] font-medium uppercase tracking-[0.04em]",
        assetType === ListingAssetType.Rwa
          ? "border-warning bg-warning/10 text-warning"
          : "border-primary bg-primary/10 text-primary-light",
        className
      )}
    >
      {assetType === ListingAssetType.Rwa ? "RWA" : "Crypto"}
    </span>
  );
}
