import { useCallback, useMemo } from "react";
import { toast } from "@/components/toast";
import { useSelectListingStore } from "../../../store/useListingStore";
import type {
  BuilderOracleSource,
  CustomOracleSymbolTarget,
  VisibilityMode,
} from "../types";
import {
  useByokFeeds,
  useByokKeys,
  useByokProviders,
  useUpsertByokKey,
  useUpsertOracleFeed,
} from "../../../services";
import {
  cloneModal,
  getByokFeedIdentity,
  mapByokProviders,
} from "./hooks/shared";
import { PERMISSIONLESS_LISTING_CUSTOM_ORACLE_FLOW_DOC_URL } from "../docsLinks";

const EMPTY_BUILDER_ORACLE_SOURCE: BuilderOracleSource = {
  name: "",
  endpoint: "",
  topic: "",
  guideUrl: PERMISSIONLESS_LISTING_CUSTOM_ORACLE_FLOW_DOC_URL,
  symbols: [],
};

export function useByokProvidersScript() {
  const { modal, setCustomOracleModal } = useSelectListingStore(state => ({
    modal: state.customOracleModal,
    setCustomOracleModal: state.setCustomOracleModal,
  }));

  const byokFeedsQuery = useByokFeeds({
    revalidateOnFocus: false,
    refreshInterval: 5000,
  });
  const byokProvidersQuery = useByokProviders({ revalidateOnFocus: false });
  const byokKeysQuery = useByokKeys({ revalidateOnFocus: false });
  const [upsertOracleFeed, { isMutating: isOracleFeedMutating }] =
    useUpsertOracleFeed();
  const [upsertByokKey, { isMutating: isByokKeyMutating }] = useUpsertByokKey();

  const closeModal = useCallback(
    (patch: Partial<typeof modal>) => {
      setCustomOracleModal(cloneModal(modal, patch));
    },
    [modal, setCustomOracleModal]
  );

  const loading = Boolean(
    (!byokFeedsQuery.data || !byokProvidersQuery.data || !byokKeysQuery.data) &&
      !byokFeedsQuery.error &&
      !byokProvidersQuery.error &&
      !byokKeysQuery.error &&
      (byokFeedsQuery.isLoading ||
        byokFeedsQuery.isValidating ||
        byokProvidersQuery.isLoading ||
        byokProvidersQuery.isValidating ||
        byokKeysQuery.isLoading ||
        byokKeysQuery.isValidating)
  );

  const providers = useMemo(
    () =>
      mapByokProviders(
        byokProvidersQuery.data?.rows ?? [],
        byokKeysQuery.data?.rows ?? [],
        byokFeedsQuery.data?.rows ?? []
      ),
    [byokFeedsQuery.data, byokKeysQuery.data, byokProvidersQuery.data]
  );

  const refetchAll = useCallback(async () => {
    await Promise.allSettled([
      byokFeedsQuery.mutate(),
      byokKeysQuery.mutate(),
      byokProvidersQuery.mutate(),
    ]);
  }, [byokFeedsQuery, byokKeysQuery, byokProvidersQuery]);

  const withErrorToast = useCallback((error: unknown, fallback: string) => {
    toast.error((error as { message?: string })?.message || fallback);
  }, []);

  const onActivateByokKey = useCallback(
    async (providerId: string) => {
      try {
        const res = await upsertByokKey({
          oracle: providerId,
          status: "active",
        });
        if (!res?.success) throw res;
        toast.success(`${providerId.toUpperCase()} key activated`);
        await refetchAll();
      } catch (error: unknown) {
        withErrorToast(error, "Failed to activate key.");
      }
    },
    [refetchAll, upsertByokKey, withErrorToast]
  );

  const onConfirmAddByokSource = useCallback(
    async (providerId: string, key: string) => {
      const normalizedKey = key.trim();
      if (!normalizedKey) {
        return "Please enter a valid API key.";
      }

      try {
        const res = await upsertByokKey({
          oracle: providerId,
          api_key: normalizedKey,
        });
        if (!res?.success) throw res;
        closeModal({ addByokSourceProvider: null });
        toast.success(`${providerId.toUpperCase()} key configured`);
        await refetchAll();
        return null;
      } catch (error: unknown) {
        return (
          (error as { message?: string })?.message ||
          "Failed to configure API key."
        );
      }
    },
    [closeModal, refetchAll, upsertByokKey]
  );

  const onConfirmUpdateKey = useCallback(
    async (providerId: string, key: string) => {
      const normalizedKey = key.trim();
      if (!normalizedKey) {
        return "Please enter a valid API key.";
      }

      try {
        const res = await upsertByokKey({
          oracle: providerId,
          api_key: normalizedKey,
        });
        if (!res?.success) throw res;
        closeModal({ updateByokKeyProvider: null });
        toast.success(`${providerId.toUpperCase()} API key updated`);
        await refetchAll();
        return null;
      } catch (error: unknown) {
        return (
          (error as { message?: string })?.message ||
          "Failed to update API key."
        );
      }
    },
    [closeModal, refetchAll, upsertByokKey]
  );

  const onConfirmDeactivateKey = useCallback(
    async (providerId: string) => {
      try {
        const res = await upsertByokKey({
          oracle: providerId,
          status: "inactive",
        });
        if (!res?.success) throw res;
        closeModal({ deactivateByokKeyProvider: null });
        toast.success(
          `${providerId.toUpperCase()} key deactivated. Feeds will remain inactive until you reactivate them individually.`
        );
        await refetchAll();
      } catch (error: unknown) {
        withErrorToast(error, "Failed to deactivate key.");
      }
    },
    [closeModal, refetchAll, upsertByokKey, withErrorToast]
  );

  const onConfirmAddByokSymbol = useCallback(
    async (providerId: string, rawSymbol: string) => {
      const symbol = rawSymbol.trim().toUpperCase();
      if (!symbol) return "Symbol cannot be empty.";

      try {
        const res = await upsertOracleFeed({
          base_ccy: symbol,
          oracle: providerId,
        });
        if (!res?.success) throw res;
        closeModal({ addByokSymbolProvider: null });
        toast.success(`${symbol} added to ${providerId.toUpperCase()}`);
        await byokFeedsQuery.mutate();
        return null;
      } catch (error: unknown) {
        return (
          (error as { message?: string })?.message || "Failed to add BYOK feed."
        );
      }
    },
    [byokFeedsQuery, closeModal, upsertOracleFeed]
  );

  const onSaveVisibility = useCallback(
    async (target: CustomOracleSymbolTarget, visibility: VisibilityMode) => {
      if (!target.providerId) return;

      try {
        const res = await upsertOracleFeed({
          ...getByokFeedIdentity(target.providerId, target.symbolId, providers),
          visibility,
        });
        if (!res?.success) throw res;
        closeModal({ visibilityTarget: null });
        toast.success(`Visibility updated to ${visibility}`);
        await byokFeedsQuery.mutate();
      } catch (error: unknown) {
        withErrorToast(error, "Failed to update visibility.");
      }
    },
    [byokFeedsQuery, closeModal, providers, upsertOracleFeed, withErrorToast]
  );

  const onConfirmRemove = useCallback(
    async (target: CustomOracleSymbolTarget) => {
      if (!target.providerId) return;

      const identity = getByokFeedIdentity(
        target.providerId,
        target.symbolId,
        providers
      );
      const currentStatus = providers
        .find(item => item.id === target.providerId)
        ?.symbols.find(item => item.id === target.symbolId)?.status;
      const nextStatus = currentStatus === "inactive" ? "active" : "inactive";

      try {
        const res = await upsertOracleFeed({
          ...identity,
          status: nextStatus,
        });
        if (!res?.success) throw res;
        closeModal({ removeTarget: null });
        toast.success(
          `${identity.base_ccy} ${
            nextStatus === "inactive" ? "deactivated" : "activated"
          }`
        );
        await byokFeedsQuery.mutate();
      } catch (error: unknown) {
        withErrorToast(
          error,
          `Failed to ${
            nextStatus === "inactive" ? "deactivate" : "activate"
          } feed.`
        );
      }
    },
    [byokFeedsQuery, closeModal, providers, upsertOracleFeed, withErrorToast]
  );

  return {
    providers,
    loading,
    modal,
    isOracleFeedMutating,
    isByokKeyMutating,
    emptyBuilderOracleSource: EMPTY_BUILDER_ORACLE_SOURCE,
    onOpenAddProvider: (providerId: string) =>
      closeModal({ addByokSourceProvider: providerId }),
    onOpenUpdateKey: (providerId: string) =>
      closeModal({ updateByokKeyProvider: providerId }),
    onOpenDeactivateKey: (providerId: string) =>
      closeModal({ deactivateByokKeyProvider: providerId }),
    onActivateKey: onActivateByokKey,
    onOpenAddSymbol: (providerId: string) =>
      closeModal({ addByokSymbolProvider: providerId }),
    onOpenVisibility: (providerId: string, symbolId: string) =>
      closeModal({
        visibilityTarget: {
          source: "byok",
          providerId,
          symbolId,
        },
      }),
    onOpenRemove: (providerId: string, symbolId: string) =>
      closeModal({
        removeTarget: {
          source: "byok",
          providerId,
          symbolId,
        },
      }),
    onCloseAddByokSource: () => closeModal({ addByokSourceProvider: null }),
    onConfirmAddByokSource,
    onCloseUpdateKey: () => closeModal({ updateByokKeyProvider: null }),
    onConfirmUpdateKey,
    onCloseDeactivateKey: () => closeModal({ deactivateByokKeyProvider: null }),
    onConfirmDeactivateKey,
    onCloseAddByokSymbol: () => closeModal({ addByokSymbolProvider: null }),
    onConfirmAddByokSymbol,
    onCloseVisibility: () => closeModal({ visibilityTarget: null }),
    onSaveVisibility,
    onCloseRemove: () => closeModal({ removeTarget: null }),
    onConfirmRemove,
  };
}

export type ByokProvidersScriptReturn = ReturnType<
  typeof useByokProvidersScript
>;
