import { useState } from "react";
import { cn } from "@/utils/css";
import { formatBalance } from "../utils";
import { TransferModal } from "../modals";

interface BalanceBarProps {
  balance: number;
  minBalance: number;
  /** Target sub-account id to transfer to (when balance is below minimum). */
  targetAccountId?: string | null;
  /** When false, hide Transfer action even if below minimum. */
  transferEnabled?: boolean;
  className?: string;
}

export function BalanceBar({
  balance,
  minBalance,
  targetAccountId,
  transferEnabled = true,
  className,
}: BalanceBarProps) {
  const pct =
    minBalance > 0 ? Math.min((balance / minBalance) * 100, 100) : 100;
  const sufficient = balance >= minBalance;

  // Fee account has no minimum requirement — only show Balance row, no progress bar
  const showMinimumRequirement = minBalance > 0;
  // Show warning when balance is below minimum (match mockup balance-bar-warning)
  const showBelowMinimum = minBalance > 0 && !sufficient;
  // Transfer action can be optionally disabled by caller
  const showTransfer = showBelowMinimum && !!targetAccountId && transferEnabled;

  const [transferOpen, setTransferOpen] = useState(false);

  // Match mockup: .balance-bar-labels (flex space-between, 14px, mb-8px), .bal-label (secondary), .bal-value (primary font-medium)
  const rowClass = "flex justify-between items-baseline text-sm mb-2 last:mb-0";
  const labelClass = "text-base-contrast-50";
  const valueClass = "font-medium text-base-contrast-98";

  return (
    <div className={cn("flex flex-col mt-1", className)}>
      {/* Row 1: Balance/Amount and value on same line — match mockup .balance-bar-labels */}
      <div className={rowClass}>
        <span className={labelClass}>Balance</span>
        <span className={valueClass}>{formatBalance(balance)}</span>
      </div>
      {/* Row 2: Minimum requirement — hidden for Fee account (required === 0) */}
      {showMinimumRequirement && (
        <div className={rowClass}>
          <span className={labelClass}>Minimum requirement</span>
          <span className={valueClass}>{formatBalance(minBalance)}</span>
        </div>
      )}
      {/* Progress bar above warning text — match mockup order: bar then warn */}
      {showMinimumRequirement && (
        <div className="w-full h-1.5 rounded-full bg-base-contrast-8 overflow-hidden mt-1">
          <div
            className={cn(
              "h-full rounded-full transition-all",
              sufficient ? "bg-success" : "bg-warning"
            )}
            style={{ width: `${pct}%` }}
          />
        </div>
      )}
      {/* Warning + Transfer when below minimum — match mockup .balance-bar-warning (12px) */}
      {showBelowMinimum && (
        <div className="flex justify-between items-center text-3xs text-warning mt-1">
          <span>
            {transferEnabled
              ? "Balance is below the minimum requirement. Please transfer funds."
              : "Balance is below the minimum requirement."}
          </span>
          {showTransfer && (
            <button
              type="button"
              onClick={() => setTransferOpen(true)}
              className="text-primary-light font-medium hover:underline shrink-0 ml-2"
            >
              Transfer
            </button>
          )}
        </div>
      )}

      <TransferModal
        open={transferOpen}
        onOpenChange={open => setTransferOpen(open)}
        targetAccountId={targetAccountId ?? null}
        requiredTransferAmount={Math.max(0, minBalance - balance)}
      />
    </div>
  );
}
