import { DelistModalUI } from "./DelistModal.ui";
import { useDelistForm } from "./useDelistForm";
import { useDelistSubmit } from "./useDelistSubmit";
import { useSelectListingStore } from "../../store/useListingStore";
import type { DelistMode } from "./types";
import { useListingServerData } from "../../hooks/useListingServerData";

export type { DelistModalProps } from "./types";

export function DelistModal() {
  const { targetDelistSymbol, symbolDetails } = useSelectListingStore(s => ({
    targetDelistSymbol: s.targetDelistSymbol,
    symbolDetails: s.symbolDetails,
  }));
  const { listingSymbols, riskSnapshot } = useListingServerData();

  const open = !!targetDelistSymbol;
  const symbol = targetDelistSymbol ?? "";

  const mode: DelistMode = (() => {
    if (!symbol) return "delist";

    const statusFromDetails = symbolDetails[symbol]?.status;
    const statusFromList = listingSymbols?.find(
      r => r.symbol === symbol
    )?.status;
    const statusFromRisk = riskSnapshot?.symbols?.find(
      r => r.symbol === symbol
    )?.status;

    const status = statusFromDetails ?? statusFromList ?? statusFromRisk;
    if (status === "NEW" || status === "PENDING" || status === "POST_ONLY") {
      return "cancel";
    }

    // Default to existing behavior when status is missing/unknown.
    return "delist";
  })();

  const { closeDelistModal, onConfirmDelist } = useDelistSubmit(mode);

  const state = useDelistForm({
    open,
    symbol,
    mode,
    onConfirm: onConfirmDelist,
    onOpenChange: next => {
      if (!next) closeDelistModal();
    },
  });

  return <DelistModalUI open={open} symbol={symbol} mode={mode} {...state} />;
}
