import { useMemo } from "react";
import {
  DASHBOARD_OVERVIEW_SWR,
  useBrokerListingFeeShareRate,
  useBrokerListingOverview,
  useBrokerListingSymbolDetail,
  useRwaMarketSessions,
  whenDashboardPollingEnabled,
} from "../services";
import type { BrokerListingRiskSnapshotData } from "../services/types";
import type { IndexSourceMeta, SymbolDetail } from "../types";
import { buildListingSymbolItemFromRiskOverview } from "../utils/buildListingSymbolItem";
import { mapBrokerListingSymbolDetailToSymbolDetail } from "../utils/mapBrokerListingSymbolDetailData";
import { deriveBaseSymbolFromPerpKey } from "../utils/mapBrokerListingSymbolDetailData";

function buildEmptySymbolDetail(symbol: string): SymbolDetail {
  const baseSymbol = deriveBaseSymbolFromPerpKey(symbol);
  return {
    status: "NEW",
    listingTime: null,
    params: {
      Symbol: { value: symbol, editable: false },
      base_symbol: { value: baseSymbol, editable: false },
      base_token: { value: baseSymbol, editable: false },
      quote_token: { value: "USDC", editable: false },
    },
    indexSources: [],
    feeShareRate: NaN,
    volume24h: NaN,
    feeRevenue24h: NaN,
    liquidationCount24h: NaN,
    liquidationRevenue24h: NaN,
    mmAccounts: [],
    delistTime: null,
  };
}

function findRowBySymbolKeys<T extends { symbol?: string }>(
  rows: T[] | undefined,
  ...keys: Array<string | null | undefined>
): T | undefined {
  return rows?.find(row => keys.some(key => key && row.symbol === key));
}

export function useListingSymbolDetailData(input: {
  symbol: string | null | undefined;
  indexSources: IndexSourceMeta[];
  riskSnapshot?: BrokerListingRiskSnapshotData;
}) {
  const { symbol, indexSources, riskSnapshot } = input;

  const symbolDetailQuery = useBrokerListingSymbolDetail(symbol, {
    revalidateOnFocus: false,
  });
  const feeShareRateQuery = useBrokerListingFeeShareRate({
    revalidateOnFocus: false,
    dedupingInterval: 30_000,
  });
  const overviewQuery = useBrokerListingOverview(
    whenDashboardPollingEnabled(false, DASHBOARD_OVERVIEW_SWR)
  );
  const { data: rwaMarketSessionsData } = useRwaMarketSessions({
    revalidateOnFocus: false,
  });

  const symbolDetailResolved = symbolDetailQuery.data;
  const listingSymbolKey = useMemo((): string | null => {
    if (!symbol) return null;
    return symbolDetailResolved?.symbol ?? symbol;
  }, [symbol, symbolDetailResolved?.symbol]);

  const detail = useMemo(() => {
    if (!symbol || !symbolDetailResolved) return null;

    const lookupSymbol = symbolDetailResolved.symbol ?? symbol;
    const feeRow =
      feeShareRateQuery.data?.find(row => row.symbol === lookupSymbol) ??
      feeShareRateQuery.data?.find(row => row.symbol === symbol) ??
      null;
    const rawFeeShareRate = feeRow?.fee_share_rate;
    const feeShareRateNum = (() => {
      const n = Number(rawFeeShareRate);
      if (!Number.isFinite(n)) return NaN;
      if (n > 1) return n / 100;
      return n;
    })();

    const overviewRow =
      overviewQuery.data?.symbols?.find(row => row.symbol === lookupSymbol) ??
      overviewQuery.data?.symbols?.find(row => row.symbol === symbol) ??
      null;

    try {
      return mapBrokerListingSymbolDetailToSymbolDetail({
        data: symbolDetailResolved,
        listingSymbolKey: symbol,
        feeShareRateNum,
        overviewRow,
        indexSourcesCatalog: indexSources,
        rwaMarketSessions: rwaMarketSessionsData ?? undefined,
      });
    } catch {
      return null;
    }
  }, [
    feeShareRateQuery.data,
    indexSources,
    overviewQuery.data,
    rwaMarketSessionsData,
    symbol,
    symbolDetailResolved,
  ]);

  const emptyDetail = useMemo(
    () => (symbol ? buildEmptySymbolDetail(symbol) : null),
    [symbol]
  );

  const symbolItem = useMemo(() => {
    if (!symbol) return null;

    const riskSym = findRowBySymbolKeys(
      riskSnapshot?.symbols,
      listingSymbolKey,
      symbol
    );
    const overviewSym = findRowBySymbolKeys(
      overviewQuery.data?.symbols,
      listingSymbolKey,
      symbol
    );

    return buildListingSymbolItemFromRiskOverview({
      symbol,
      listedAt: symbolDetailResolved?.listing_time ?? null,
      risk: riskSym,
      overview: overviewSym,
    });
  }, [
    listingSymbolKey,
    overviewQuery.data?.symbols,
    riskSnapshot?.symbols,
    symbol,
    symbolDetailResolved?.listing_time,
  ]);

  return {
    detail,
    emptyDetail,
    symbolItem,
    listingSymbolKey,
    symbolDetailQuery,
    feeShareRateQuery,
    overviewQuery,
    isLoading:
      symbolDetailQuery.isLoading ||
      feeShareRateQuery.isLoading ||
      overviewQuery.isLoading,
    error: symbolDetailQuery.error,
    mutateSymbolDetail: symbolDetailQuery.mutate,
  };
}
