import { deriveBrokerSymbolLogoFileBaseName } from "@/utils/brokerSymbolLogoUpload";
import { cn } from "@/utils/css";
import { DASH } from "../../dashboard/formatters";
import { ArrowBackIcon, StatusBadge } from "../../../components";
import { Button } from "@/components/button";
import type { AlertLevel, SymbolStatus } from "../../../types";
import { ALERT_CONFIG } from "./SymbolDetailPanel.shared";
import { useBrokerSymbolLogoUpload } from "../../listing/trading-params/hooks";

export function SymbolDetailHeader(props: {
  displayName: string;
  logoSymbolPreview: string;
  status: SymbolStatus;
  apiHydratedDetail: boolean;
  alertLabel: string;
  alertLevel: AlertLevel | null;
  isEditable: boolean;
  onBack: () => void;
  onDelist: () => void;
  onEdit: () => void;
}) {
  const {
    displayName,
    logoSymbolPreview,
    status,
    apiHydratedDetail,
    alertLabel,
    alertLevel,
    isEditable,
    onBack,
    onDelist,
    onEdit,
  } = props;
  const {
    uploading,
    logoUrl,
    fileInputRef,
    onFileChange,
    openFilePicker,
    disabled,
  } = useBrokerSymbolLogoUpload({
    symbolPreview: logoSymbolPreview,
  });
  const logoFallback = (() => {
    const source = deriveBrokerSymbolLogoFileBaseName(
      logoSymbolPreview || displayName
    );
    const firstChar = source.trim().charAt(0);
    return firstChar ? firstChar.toUpperCase() : "?";
  })();

  const alertBadgeStyle =
    alertLevel && ALERT_CONFIG[alertLevel]
      ? ALERT_CONFIG[alertLevel]
      : {
          color: "text-base-contrast-50",
          bg: "bg-base-contrast-12",
        };

  return (
    <div className="flex items-start justify-between gap-4">
      <div className="flex items-center gap-4 min-w-0 flex-1">
        <button
          onClick={onBack}
          className="shrink-0 p-0 border-0 bg-transparent cursor-pointer opacity-70 hover:opacity-100 transition-opacity"
          type="button"
          aria-label="Back"
        >
          <ArrowBackIcon className="w-6 h-6 text-base-contrast-98" />
        </button>
        <div className="relative shrink-0">
          {isEditable ? (
            <>
              <input
                ref={fileInputRef}
                type="file"
                accept="image/png"
                className="hidden"
                onChange={onFileChange}
                disabled={disabled}
              />
              <button
                type="button"
                onClick={() => {
                  if (disabled) return;
                  openFilePicker();
                }}
                disabled={disabled}
                aria-label="Upload symbol icon"
                aria-busy={uploading}
                className={cn(
                  "relative flex h-16 w-16 items-center justify-center overflow-hidden rounded-full border border-base-contrast-12 bg-primary/10 text-[22px] font-semibold text-primary",
                  "cursor-pointer transition-colors hover:border-primary/50"
                )}
              >
                {logoUrl ? (
                  <img
                    src={logoUrl}
                    alt={`${displayName} icon`}
                    className={cn(
                      "h-full w-full object-cover",
                      uploading && "opacity-40"
                    )}
                  />
                ) : (
                  <span className={cn(uploading && "opacity-40")}>
                    {logoFallback}
                  </span>
                )}
                {uploading ? (
                  <span className="absolute inset-0 flex items-center justify-center bg-base-100/40">
                    <span className="h-5 w-5 animate-spin rounded-full border-2 border-base-contrast-20 border-t-primary" />
                  </span>
                ) : null}
              </button>
            </>
          ) : (
            <div className="flex h-16 w-16 items-center justify-center overflow-hidden rounded-full border border-base-contrast-12 bg-primary/10 text-[22px] font-semibold text-primary">
              {logoUrl ? (
                <img
                  src={logoUrl}
                  alt={`${displayName} icon`}
                  className="h-full w-full object-cover"
                />
              ) : (
                <span>{logoFallback}</span>
              )}
            </div>
          )}
          {isEditable ? (
            <button
              type="button"
              onClick={() => {
                if (disabled) return;
                openFilePicker();
              }}
              disabled={disabled}
              aria-label="Upload symbol icon"
              className={cn(
                "absolute -bottom-0.5 -right-0.5 inline-flex h-6 w-6 items-center justify-center rounded-full border-[1.5px] bg-base-100 text-primary",
                uploading
                  ? "cursor-not-allowed border-base-contrast-12 bg-base-contrast-8 text-base-contrast-50 opacity-60"
                  : "cursor-pointer border-base-contrast-20"
              )}
            >
              <svg
                width="12"
                height="12"
                viewBox="0 0 24 24"
                fill="none"
                xmlns="http://www.w3.org/2000/svg"
                aria-hidden
              >
                <path
                  d="M21.174 6.812a1 1 0 0 0-3.986-3.987L3.842 16.174a2 2 0 0 0-.5.83l-1.321 4.352a.5.5 0 0 0 .623.622l4.353-1.32a2 2 0 0 0 .83-.497z"
                  stroke="currentColor"
                  strokeWidth="2.5"
                  strokeLinecap="round"
                  strokeLinejoin="round"
                />
                <path
                  d="m15 5 4 4"
                  stroke="currentColor"
                  strokeWidth="2.5"
                  strokeLinecap="round"
                  strokeLinejoin="round"
                />
              </svg>
            </button>
          ) : null}
        </div>
        <div className="flex flex-col gap-1.5 min-w-0">
          <span className="text-lg font-medium text-base-contrast-98 leading-tight truncate">
            {displayName}
          </span>
          <div className="flex flex-wrap items-center gap-1.5">
            {apiHydratedDetail ? (
              <StatusBadge status={status} />
            ) : (
              <span className="inline-flex items-center text-3xs font-medium px-2.5 py-0.5 rounded-full bg-base-contrast-8 text-base-contrast-50">
                {DASH}
              </span>
            )}
            <span
              className={cn(
                "inline-flex items-center text-3xs font-medium px-2.5 py-0.5 rounded-full",
                alertBadgeStyle.bg,
                alertBadgeStyle.color
              )}
            >
              {alertLabel}
            </span>
          </div>
        </div>
      </div>
      {isEditable && (
        <div className="flex items-center gap-2 shrink-0">
          <Button
            onClick={onDelist}
            type="button"
            size="sm"
            variant="outline"
            color="primary"
            rounded="full"
            className="px-4 text-xs text-base-contrast-98"
          >
            Delist
          </Button>
          <Button
            onClick={onEdit}
            type="button"
            size="sm"
            rounded="full"
            className="px-4 text-xs"
          >
            Edit
          </Button>
        </div>
      )}
    </div>
  );
}

export function SymbolDetailListingTimeRow(props: { listingTime: string }) {
  return (
    <div className="flex items-center gap-2 text-2xs text-base-contrast-50">
      <span>Listed</span>
      <span className="font-medium text-base-contrast-98">
        {props.listingTime}
      </span>
    </div>
  );
}
