import type { SWRConfiguration } from "swr";
import { useBrokerListingSymbols } from "../services";

export function useListingSymbolsData(options?: SWRConfiguration) {
  const query = useBrokerListingSymbols(undefined, options);

  return {
    ...query,
    listingSymbols: query.data,
    isLoadingListingSymbols: query.isLoading,
  };
}
