import { useMemo } from "react";
import type { TradingParam } from "../../../../services";
import {
  clamp,
  DEFAULT_FUNDING_CAP,
  DEFAULT_FUNDING_INTERVAL_SEC,
  MAIN_CEX_PRIORITY,
  MAX_FUNDING_CAP,
  MIN_FUNDING_CAP,
} from "./shared";

type UseFundingCapFloorInput = {
  fundingPeriod: string;
  cexFundingMetas: TradingParam[];
};

const FUNDING_PERIOD_TO_SEC: Record<string, number> = {
  "1h": 3600,
  "4h": 4 * 3600,
  "8h": 8 * 3600,
};

export function useFundingCapFloor({
  fundingPeriod,
  cexFundingMetas,
}: UseFundingCapFloorInput) {
  return useMemo(() => {
    const orderlyPeriodSec = FUNDING_PERIOD_TO_SEC[fundingPeriod] ?? 8 * 3600;

    const mainMeta =
      MAIN_CEX_PRIORITY.map(source =>
        cexFundingMetas.find(m => m.found && m.source === source)
      ).find(Boolean) ?? null;

    const capFallback = DEFAULT_FUNDING_CAP;
    const intervalFallback = DEFAULT_FUNDING_INTERVAL_SEC;

    const capCandidate =
      mainMeta?.fundingCap && mainMeta.fundingCap > 0
        ? mainMeta.fundingCap
        : mainMeta?.fundingFloor && mainMeta.fundingFloor < 0
          ? Math.abs(mainMeta.fundingFloor)
          : capFallback;

    const intervalSec =
      mainMeta?.fundingIntervalSec && mainMeta.fundingIntervalSec > 0
        ? mainMeta.fundingIntervalSec
        : intervalFallback;

    const rawCap = capCandidate * (orderlyPeriodSec / intervalSec);
    const normalizedCap = clamp(rawCap, MIN_FUNDING_CAP, MAX_FUNDING_CAP);

    return {
      fundingCap: normalizedCap,
      fundingFloor: -normalizedCap,
    };
  }, [fundingPeriod, cexFundingMetas]);
}
