import { create } from "zustand";
import type {
  SymbolStatus,
  SymbolItem,
  SymbolDetail,
  SourceItem,
  RecentEvent,
  IndexSourceMeta,
  ListingAssetType,
} from "../types";
import { PageView, ListingSubStep, SettingsTab } from "../types";
import type {
  BuilderOracleSource,
  ByokProvider,
  CustomOracleModalState,
  CustomOracleOrigin,
  CustomOracleTab,
} from "../sections/custom-oracle/types";
import { useShallow } from "zustand/react/shallow";

const EMPTY_CUSTOM_ORACLE_MODAL_STATE: CustomOracleModalState = {
  onboardingOpen: false,
  builderAddSymbolOpen: false,
  addByokSourceProvider: null,
  updateByokKeyProvider: null,
  deactivateByokKeyProvider: null,
  addByokSymbolProvider: null,
  visibilityTarget: null,
  removeTarget: null,
};

const EMPTY_BUILDER_ORACLE_SOURCE: BuilderOracleSource = {
  name: "ORACLE",
  endpoint: "",
  topic: "",
  guideUrl: "#",
  symbols: [],
};

export enum ListingOrigin {
  Dashboard = "dashboard",
  SymbolDetail = "symbol-detail",
}

// ---- State ----
export interface ListingState {
  // --- Navigation & shell ---
  currentPage: PageView;
  forceOnboarding: boolean;
  settingsTab: SettingsTab;
  customOracleTab: CustomOracleTab;
  customOracleOrigin: CustomOracleOrigin;
  customOracleHasSeenOnboarding: boolean;
  // --- Dashboard filter ---
  statusFilter: SymbolStatus[];
  // --- Listing flow / form ---
  editMode: boolean;
  editSymbol: string | null;
  currentListingBase: string;
  listingAssetType: ListingAssetType | null;
  listingAssetTypeModalOpen: boolean;
  priceSources: SourceItem[];
  listingStep: ListingSubStep;
  listingOrigin: ListingOrigin | null;
  indexSources: IndexSourceMeta[];
  builderOracleSource: BuilderOracleSource;
  byokProviders: ByokProvider[];
  builderExpandedSymbolId: string | null;
  customOracleModal: CustomOracleModalState;
  savedListingAssetType: ListingAssetType | null;
  // --- Symbols & events ---
  listedSymbols: SymbolItem[];
  symbolDetails: Record<string, SymbolDetail>;
  currentDetailSymbol: string | null;
  targetDelistSymbol: string | null;
  recentEvents: RecentEvent[];
}

const initialState: ListingState = {
  // --- Navigation & shell ---
  currentPage: PageView.Dashboard,
  listingStep: ListingSubStep.PriceSources,
  forceOnboarding: false,
  settingsTab: SettingsTab.If,
  customOracleTab: "builder",
  customOracleOrigin: "dashboard",
  customOracleHasSeenOnboarding: false,
  // --- Dashboard filter ---
  statusFilter: [
    "NEW",
    "PENDING",
    "POST_ONLY",
    "ACTIVE",
    "REDUCE_ONLY",
    "DELISTING",
    "DELISTED",
  ],
  // --- Listing flow / form ---
  editMode: false,
  editSymbol: null,
  currentListingBase: "",
  listingAssetType: null,
  listingAssetTypeModalOpen: false,
  priceSources: [],
  listingOrigin: null,
  builderOracleSource: EMPTY_BUILDER_ORACLE_SOURCE,
  byokProviders: [],
  builderExpandedSymbolId: null,
  customOracleModal: EMPTY_CUSTOM_ORACLE_MODAL_STATE,
  savedListingAssetType: null,
  // --- Symbols & events ---
  listedSymbols: [],
  symbolDetails: {},
  currentDetailSymbol: null,
  targetDelistSymbol: null,
  recentEvents: [],
  indexSources: [],
};

type ListingFlowResetState = Pick<
  ListingState,
  | "editMode"
  | "editSymbol"
  | "currentListingBase"
  | "listingAssetType"
  | "listingAssetTypeModalOpen"
  | "priceSources"
  | "listingStep"
  | "listingOrigin"
>;

function getListingFlowResetState(): ListingFlowResetState {
  return {
    editMode: false,
    editSymbol: null,
    currentListingBase: "",
    listingAssetType: null,
    listingAssetTypeModalOpen: false,
    priceSources: [],
    listingStep: ListingSubStep.PriceSources,
    listingOrigin: null,
  };
}

function getEnterListingState(
  preservedListingAssetType: ListingAssetType | null,
  options?: {
    listingStep?: ListingSubStep;
    editMode?: boolean;
    editSymbol?: string | null;
    priceSources?: SourceItem[];
    listingAssetType?: ListingAssetType | null;
    listingOrigin?: ListingOrigin;
  }
): Pick<
  ListingState,
  | "currentPage"
  | "listingStep"
  | "editMode"
  | "editSymbol"
  | "currentListingBase"
  | "listingAssetType"
  | "listingAssetTypeModalOpen"
  | "priceSources"
  | "currentDetailSymbol"
  | "listingOrigin"
  | "savedListingAssetType"
> {
  const assetType =
    options?.listingAssetType ?? preservedListingAssetType ?? null;
  return {
    currentPage: PageView.Listing,
    listingStep: options?.listingStep ?? ListingSubStep.PriceSources,
    editMode: options?.editMode ?? false,
    editSymbol: options?.editSymbol ?? null,
    currentListingBase: "",
    listingAssetType: assetType,
    listingAssetTypeModalOpen: false,
    priceSources: options?.priceSources ?? [],
    currentDetailSymbol: null,
    listingOrigin: options?.listingOrigin ?? null,
    savedListingAssetType: null,
  };
}

function getLeaveListingState(
  page: Exclude<PageView, PageView.Listing>,
  currentListingAssetType: ListingAssetType | null
): Pick<
  ListingState,
  | "currentPage"
  | "editMode"
  | "editSymbol"
  | "currentListingBase"
  | "listingAssetType"
  | "listingAssetTypeModalOpen"
  | "priceSources"
  | "listingStep"
  | "currentDetailSymbol"
  | "listingOrigin"
  | "savedListingAssetType"
> {
  return {
    currentPage: page,
    ...getListingFlowResetState(),
    currentDetailSymbol: null,
    savedListingAssetType: currentListingAssetType,
  };
}

// ---- Store ----

export interface ListingStore extends ListingState {
  // --- Navigation & shell ---
  setPage: {
    (
      page: PageView.Listing,
      options?: {
        listingStep?: ListingSubStep;
        editMode?: boolean;
        editSymbol?: string | null;
        priceSources?: SourceItem[];
        listingAssetType?: ListingAssetType | null;
        listingOrigin?: ListingOrigin;
      }
    ): void;
    (
      page: PageView.CustomOracle,
      options?: {
        tab?: CustomOracleTab;
        origin?: CustomOracleOrigin;
      }
    ): void;
    (page: PageView.SymbolDetail, options: { symbol: string }): void;
    (page: PageView.Settings, options?: { settingsTab?: SettingsTab }): void;
    (
      page: Exclude<
        PageView,
        | PageView.Listing
        | PageView.Settings
        | PageView.SymbolDetail
        | PageView.CustomOracle
      >
    ): void;
  };
  setListingStep: (step: ListingSubStep) => void;
  setForceOnboarding: (value: boolean) => void;
  setSettingsTab: (tab: SettingsTab) => void;
  setCustomOracleTab: (tab: CustomOracleTab) => void;
  setCustomOracleOrigin: (origin: CustomOracleOrigin) => void;
  setCustomOracleHasSeenOnboarding: (value: boolean) => void;
  // --- Dashboard filter ---
  setStatusFilter: (filter: SymbolStatus[]) => void;
  // --- Listing flow / form ---
  setCurrentListingBase: (baseSymbol: string) => void;
  setListingAssetType: (assetType: ListingAssetType | null) => void;
  setListingAssetTypeModalOpen: (open: boolean) => void;
  setPriceSources: (sources: SourceItem[]) => void;
  setBuilderOracleSource: (source: BuilderOracleSource) => void;
  setByokProviders: (providers: ByokProvider[]) => void;
  setBuilderExpandedSymbolId: (symbolId: string | null) => void;
  setCustomOracleModal: (modal: CustomOracleModalState) => void;
  // --- Symbols & events ---
  setSymbols: (symbols: SymbolItem[]) => void;
  updateSymbolDetail: (symbol: string, detail: SymbolDetail) => void;
  addEvent: (event: RecentEvent) => void;
  setTargetDelist: (symbol: string | null) => void;
  // --- Listing-flow catalog cache ---
  setIndexSources: (indexSources: IndexSourceMeta[]) => void;
}

export const useListingStore = create<ListingStore>(set => ({
  ...initialState,

  // --- Navigation & shell ---
  setPage: ((
    page: PageView,
    options?: {
      listingStep?: ListingSubStep;
      settingsTab?: SettingsTab;
      tab?: CustomOracleTab;
      origin?: CustomOracleOrigin;
      editMode?: boolean;
      editSymbol?: string | null;
      priceSources?: SourceItem[];
      listingAssetType?: ListingAssetType | null;
      listingOrigin?: ListingOrigin;
      symbol?: string;
    }
  ) => {
    if (page === PageView.Listing) {
      set(state => getEnterListingState(state.savedListingAssetType, options));
    } else if (page === PageView.CustomOracle) {
      set(state => ({
        ...getLeaveListingState(page, state.listingAssetType),
        customOracleTab: options?.tab ?? "builder",
        customOracleOrigin: options?.origin ?? "dashboard",
        builderExpandedSymbolId: null,
        customOracleModal: EMPTY_CUSTOM_ORACLE_MODAL_STATE,
      }));
    } else if (page === PageView.SymbolDetail) {
      set(state => ({
        ...getLeaveListingState(page, state.listingAssetType),
        currentDetailSymbol: options?.symbol ?? null,
      }));
    } else if (page === PageView.Settings) {
      set(state => ({
        ...getLeaveListingState(page, state.listingAssetType),
        settingsTab: options?.settingsTab ?? SettingsTab.If,
      }));
    } else {
      set(state => getLeaveListingState(page, state.listingAssetType));
    }
  }) as ListingStore["setPage"],
  setListingStep: step => set({ listingStep: step }),
  setForceOnboarding: value => set({ forceOnboarding: value }),
  setSettingsTab: tab => set({ settingsTab: tab }),
  setCustomOracleTab: tab => set({ customOracleTab: tab }),
  setCustomOracleOrigin: origin => set({ customOracleOrigin: origin }),
  setCustomOracleHasSeenOnboarding: customOracleHasSeenOnboarding =>
    set({ customOracleHasSeenOnboarding }),

  // --- Dashboard filter ---
  setStatusFilter: filter => set({ statusFilter: filter }),

  // --- Listing flow / form ---
  setCurrentListingBase: currentListingBase => {
    const base = currentListingBase.trim().toUpperCase();
    set({ currentListingBase: base });
  },
  setListingAssetType: listingAssetType => set({ listingAssetType }),
  setListingAssetTypeModalOpen: listingAssetTypeModalOpen =>
    set({ listingAssetTypeModalOpen }),
  setPriceSources: sources => set({ priceSources: sources }),
  setBuilderOracleSource: builderOracleSource => set({ builderOracleSource }),
  setByokProviders: byokProviders => set({ byokProviders }),
  setBuilderExpandedSymbolId: builderExpandedSymbolId =>
    set({ builderExpandedSymbolId }),
  setCustomOracleModal: customOracleModal => set({ customOracleModal }),

  // --- Symbols & events ---
  setSymbols: symbols => set({ listedSymbols: symbols }),
  updateSymbolDetail: (symbol, detail) =>
    set(state => ({
      symbolDetails: { ...state.symbolDetails, [symbol]: detail },
    })),
  addEvent: event =>
    set(state => ({
      recentEvents: [event, ...state.recentEvents],
    })),
  setTargetDelist: symbol => set({ targetDelistSymbol: symbol }),

  // --- Listing-flow catalog cache ---
  setIndexSources: indexSources => set({ indexSources }),
}));

export function useSelectListingStore<U>(
  selector: (state: ListingStore) => U
): U {
  return useListingStore(useShallow(selector));
}
