import { useState, useCallback, useEffect } from "react";
import { useSelectListingStore } from "../../store/useListingStore";
import type { ListingStore } from "../../store/useListingStore";
import type { EligibilityGate, SourceItem, SymbolDetail } from "../../types";
import {
  getIfRequiredForNewSymbol,
  getSymbolListingLimit,
  getSymbolSlotUsedCountFromListingStats,
  getTierRequired,
  isSymbolSlotUsed,
  TIER_REQUIREMENT_WAIVED,
} from "../../constants";
import { PageView, SettingsTab } from "../../types";
import { ListingOrigin } from "../../store/useListingStore";
import { useSymbolCardView } from "./SymbolCardView/useSymbolCardView";
import { toast } from "@/components/toast";
import {
  DASHBOARD_OVERVIEW_SWR,
  getSourceDisplayMeta,
  matchIndexSourceCatalog,
  normalizeSourceKey,
  resolveApiSource,
  sourceKeyToItemId,
  useBrokerListingOverview,
  useBrokerListingSymbolDetail,
  useRwaMarketSessions,
  whenDashboardPollingEnabled,
} from "../../services";
import { mapBrokerListingSymbolDetailToSymbolDetail } from "../../utils/mapBrokerListingSymbolDetailData";
import type { IndexSourceMeta } from "../../types";
import { IndexSourceType } from "../../types";
import {
  TierIcon,
  TierKey,
  formatTierLabel,
} from "../onboarding/components/BrokerTierStep";
import { useListingServerData } from "../../hooks/useListingServerData";
import { useMergedIfAccounts } from "../onboarding/hooks/useMergedIfAccounts";

export interface EligibilityState {
  open: boolean;
  gates: EligibilityGate[];
}

export function useDashboardScript() {
  const {
    statusFilter,
    setPage,
    setStatusFilter,
    setTargetDelist,
    setListingAssetType,
    setListingAssetTypeModalOpen,
    updateSymbolDetail,
    isDashboardActive,
  } = useSelectListingStore(s => ({
    statusFilter: s.statusFilter,
    setPage: s.setPage,
    setStatusFilter: s.setStatusFilter,
    setTargetDelist: s.setTargetDelist,
    setListingAssetType: s.setListingAssetType,
    setListingAssetTypeModalOpen: s.setListingAssetTypeModalOpen,
    updateSymbolDetail: s.updateSymbolDetail,
    isDashboardActive: s.currentPage === PageView.Dashboard,
  }));
  const {
    subAccounts,
    listingAccounts,
    brokerInfo,
    indexSources,
    listingSymbols,
    isLoading: serverDataLoading,
  } = useListingServerData();

  const [editHydrateSymbol, setEditHydrateSymbol] = useState<string | null>(
    null
  );
  const editDetailQuery = useBrokerListingSymbolDetail(editHydrateSymbol, {
    revalidateOnFocus: false,
    keepPreviousData: false,
  });
  const { data: rwaMarketSessionsData } = useRwaMarketSessions({
    revalidateOnFocus: false,
  });

  useEffect(() => {
    if (!editHydrateSymbol) return;
    if (editDetailQuery.isLoading) return;
    if (editDetailQuery.error) {
      toast.error("Failed to load symbol for editing.");
      setEditHydrateSymbol(null);
      return;
    }
    const data = editDetailQuery.data;
    if (!data) {
      setEditHydrateSymbol(null);
      return;
    }

    const symbolKey = editHydrateSymbol;
    try {
      const mapped = mapBrokerListingSymbolDetailToSymbolDetail({
        data,
        listingSymbolKey: symbolKey,
        feeShareRateNum: NaN,
        overviewRow: null,
        indexSourcesCatalog: indexSources,
        rwaMarketSessions: rwaMarketSessionsData ?? undefined,
      });
      updateSymbolDetail(symbolKey, mapped);
      const priceSources = sourceItemsFromDetailForEdit(mapped, indexSources);
      setPage(PageView.Listing, {
        editMode: true,
        editSymbol: symbolKey,
        priceSources,
        listingOrigin: ListingOrigin.Dashboard,
      });
    } catch {
      toast.error("Failed to process symbol detail for editing.");
    } finally {
      setEditHydrateSymbol(null);
    }
  }, [
    editHydrateSymbol,
    editDetailQuery.isLoading,
    editDetailQuery.data,
    editDetailQuery.error,
    updateSymbolDetail,
    indexSources,
    rwaMarketSessionsData,
    setPage,
  ]);

  const { riskSnapshot, isLoading: apiLoading } = useSymbolCardView();
  const overview = useBrokerListingOverview(
    whenDashboardPollingEnabled(isDashboardActive, DASHBOARD_OVERVIEW_SWR)
  );
  const { mergedIfAccounts } = useMergedIfAccounts(subAccounts);

  const [eligibility, setEligibility] = useState<EligibilityState>({
    open: false,
    gates: [],
  });

  const onCreateListing = useCallback(() => {
    const symbolsLimit = getSymbolListingLimit();
    let usedSymbolSlotCount = riskSnapshot?.active_symbol_count ?? 0;
    if (listingSymbols) {
      usedSymbolSlotCount = listingSymbols.filter(symbol =>
        isSymbolSlotUsed(symbol.status)
      ).length;
    }
    if (overview.data?.listing_stats) {
      usedSymbolSlotCount = getSymbolSlotUsedCountFromListingStats(
        overview.data.listing_stats
      );
    }

    const ifAccountId = listingAccounts?.if_account?.account_id;
    const insuranceFundSubAccount = ifAccountId
      ? (mergedIfAccounts.find(s => s.sub_account_id === ifAccountId) ?? null)
      : null;
    const ifId = ifAccountId ?? "";
    const ifBalance = insuranceFundSubAccount?.balance ?? 0;

    const ifRequired = getIfRequiredForNewSymbol(riskSnapshot, listingSymbols);

    const fmtCurrency = (v: number) =>
      new Intl.NumberFormat("en-US", {
        style: "currency",
        currency: "USD",
        minimumFractionDigits: 2,
        maximumFractionDigits: 2,
      }).format(v);
    const ifProgress =
      ifRequired > 0 ? Math.min(100, (ifBalance / ifRequired) * 100) : 100;

    const tierPassed = getTierRequired(brokerInfo?.type);
    const effectiveTier = (brokerInfo?.type as TierKey) ?? TierKey.PUBLIC;
    const showTierWaiverOffer =
      TIER_REQUIREMENT_WAIVED && effectiveTier !== TierKey.DIAMOND;

    const gates: EligibilityGate[] = [
      {
        key: "if",
        label: "Insurance fund account",
        passed: ifId !== "",
        description: `Balance ${fmtCurrency(
          ifBalance
        )} / Requirement: ${fmtCurrency(ifRequired)}`,
        action: "transfer",
        targetTab: SettingsTab.If,
        subInfo: insuranceFundSubAccount
          ? `${insuranceFundSubAccount.description} (${insuranceFundSubAccount.sub_account_id})`
          : undefined,
        progressPct: ifProgress,
        tipText: `Insurance Fund: ≥ $25k × active symbols including the new listing = ${fmtCurrency(
          ifRequired
        )}`,
      },
      {
        key: "tier",
        label: "Builder tier",
        passed: tierPassed,
        description: showTierWaiverOffer ? (
          <div className="space-y-0.5">
            <div className="flex gap-1 items-center">
              <div className="flex size-5 shrink-0 items-center justify-center">
                <TierIcon tier={effectiveTier} className="size-4" />
              </div>
              <span className="text-success text-3xs font-medium leading-none">
                {formatTierLabel(effectiveTier)} tier accepted during waiver
              </span>
            </div>
            <p className="text-3xs font-medium text-base-contrast-54">
              Exclusive offer: list permissionless at any tier.
            </p>
          </div>
        ) : tierPassed ? (
          `Tier: ${formatTierLabel(effectiveTier)}`
        ) : (
          <div className="space-y-0.5">
            <div className="flex gap-1 items-center">
              <div className="flex size-5 shrink-0 items-center justify-center">
                <TierIcon tier={effectiveTier} className="size-4" />
              </div>
              <span className="text-warning text-3xs font-medium leading-none">
                {formatTierLabel(effectiveTier)}
              </span>
            </div>
            <p className="text-3xs font-medium text-[#d9ab52]">
              Your builder must be Diamond tier to proceed.
            </p>
          </div>
        ),
        action: showTierWaiverOffer ? undefined : "manage",
        targetTab: SettingsTab.Tier,
        actionLabel: showTierWaiverOffer ? undefined : "Upgrade",
        tipText: showTierWaiverOffer
          ? undefined
          : `Upgrade to Diamond tier to list symbols`,
      },
      {
        key: "limit",
        label: "Symbol listing limit",
        passed: usedSymbolSlotCount < symbolsLimit,
        description: `${usedSymbolSlotCount} / ${symbolsLimit}`,
        tipText: `Symbol limit: max ${symbolsLimit} symbols in PENDING, POST_ONLY, ACTIVE, or REDUCE_ONLY status allowed`,
      },
    ];

    if (gates.every(g => g.passed)) {
      setPage(PageView.Listing);
      setListingAssetType(null);
      setListingAssetTypeModalOpen(true);
    } else {
      setEligibility({ open: true, gates });
    }
  }, [
    riskSnapshot,
    overview.data,
    listingSymbols,
    mergedIfAccounts,
    listingAccounts,
    setPage,
    setListingAssetType,
    setListingAssetTypeModalOpen,
    brokerInfo,
  ]);

  const setStatusFilterAction = useCallback(
    (filter: ListingStore["statusFilter"]) => setStatusFilter(filter),
    [setStatusFilter]
  );

  const closeEligibility = useCallback(
    () => setEligibility({ open: false, gates: [] }),
    []
  );

  const onGoToSettings = useCallback<(tab?: SettingsTab) => void>(
    tab => {
      setPage(PageView.Settings, { settingsTab: tab });
    },
    [setPage]
  );

  const onEdit = useCallback((symbol: string) => {
    setEditHydrateSymbol(symbol);
  }, []);

  const onOpenCustomOracle = useCallback(() => {
    setPage(PageView.CustomOracle, {
      origin: "dashboard",
      tab: "builder",
    });
  }, [setPage]);

  const onDelist = useCallback(
    (symbol: string) => {
      setTargetDelist(symbol);
    },
    [setTargetDelist]
  );

  return {
    statusFilter,
    setStatusFilter: setStatusFilterAction,
    loading: serverDataLoading || apiLoading,
    eligibility,
    closeEligibility,
    onCreateListing,
    onOpenCustomOracle,
    onGoToSettings,
    onEdit,
    onDelist,
  };
}

/** Same shape as the pre-fetch Edit path (card footer); keeps diff small vs PriceSources PYTH handling. */
function sourceItemsFromDetailForEdit(
  detail: SymbolDetail,
  catalog: IndexSourceMeta[]
): SourceItem[] {
  const rows = detail.indexSources;
  if (!rows.length) return [];
  const w = Math.round(100 / rows.length);
  return rows.map(is => {
    const catRow = matchIndexSourceCatalog(catalog, is.source);
    const def = getSourceDisplayMeta(catRow?.source ?? is.source);
    const apiKey =
      def?.source ??
      catRow?.source ??
      resolveApiSource(is.source) ??
      normalizeSourceKey(is.source);
    return {
      id: sourceKeyToItemId(apiKey),
      source: apiKey,
      name: catRow?.name ?? def?.name ?? is.source,
      type:
        (is.type as SourceItem["type"]) ?? catRow?.type ?? IndexSourceType.Cex,
      found: true,
      sourceSymbol: is.sourceSymbol,
      multiplier: is.priceMultiplier,
      price: is.latestPrice,
      volume24h: 0,
      weight: w,
      selected: true,
      loading: false,
    };
  });
}

type DashboardScriptReturnBase = ReturnType<typeof useDashboardScript>;

export type DashboardScriptReturn = Omit<
  DashboardScriptReturnBase,
  "onGoToSettings"
> & {
  onGoToSettings: (tab?: SettingsTab) => void;
};
