import { useMemo } from "react";
import type { SymbolItem } from "../../../types";
import { ALL_STATUSES } from "../../../constants";
import {
  useBrokerListingOverview,
  DASHBOARD_OVERVIEW_SWR,
  whenDashboardPollingEnabled,
} from "../../../services";
import { useSelectListingStore } from "../../../store/useListingStore";
import { buildListingSymbolItem } from "../../../utils/buildListingSymbolItem";
import { PageView } from "../../../types";
import { useListingServerData } from "../../../hooks/useListingServerData";
import { useListingRefreshActions } from "../../../hooks/useListingRefreshActions";

export function useSymbolCardView() {
  const isDashboardActive = useSelectListingStore(
    s => s.currentPage === PageView.Dashboard
  );
  const overview = useBrokerListingOverview(
    whenDashboardPollingEnabled(isDashboardActive, DASHBOARD_OVERVIEW_SWR)
  );
  const { statusFilter } = useSelectListingStore(state => ({
    statusFilter: state.statusFilter,
  }));
  const {
    listingSymbols,
    riskSnapshot,
    isLoading: isLoadingServerData,
  } = useListingServerData();
  const { refreshListingSymbols, refreshRiskSnapshot } =
    useListingRefreshActions();

  const symbolsAll = useMemo(() => {
    const rows = listingSymbols ?? [];
    const overviewBySymbol = new Map(
      (overview.data?.symbols ?? []).map(s => [s.symbol, s] as const)
    );
    const riskBySymbol = new Map(
      (riskSnapshot?.symbols ?? []).map(s => [s.symbol, s] as const)
    );

    return rows
      .map(row =>
        buildListingSymbolItem({ row, overviewBySymbol, riskBySymbol })
      )
      .filter((x): x is SymbolItem => x != null);
  }, [listingSymbols, overview.data, riskSnapshot]);

  const symbols = useMemo(
    () => symbolsAll.filter(s => statusFilter.includes(s.status)),
    [symbolsAll, statusFilter]
  );

  const isEmpty =
    symbols.length === 0 && statusFilter.length === ALL_STATUSES.length;

  const isLoading = isLoadingServerData || overview.isLoading;

  return {
    symbols,
    overview,
    listingSymbols,
    mutateListingSymbols: refreshListingSymbols,
    riskSnapshot,
    mutateRiskSnapshot: refreshRiskSnapshot,
    isEmpty,
    isLoading,
  };
}
