import { useMemo } from "react";
import { useBrokerAvailableIfAccounts } from "@/permissionless-listing/services/brokerListing";
import {
  useStrategyVaultFundInfoMap,
  useStrategyVaultVaultInfo,
} from "@/permissionless-listing/services/strategyVault";
import type { SubAccount } from "@/permissionless-listing/types";

export function useMergedIfAccounts(subAccounts: SubAccount[]) {
  const { data: availableIfData, mutate: mutateAvailableIfAccounts } =
    useBrokerAvailableIfAccounts();

  const { data: svVaultInfoEnvelope } = useStrategyVaultVaultInfo();

  const vaultInfoMap = useMemo(() => {
    const rows = svVaultInfoEnvelope ?? [];
    return new Map(rows.map(r => [r.sp_account_id, r]));
  }, [svVaultInfoEnvelope]);

  const fundInfoInputs = useMemo(() => {
    const subIds = new Set(subAccounts.map(s => s.sub_account_id));
    return (availableIfData ?? [])
      .filter(row => !subIds.has(row.account_id))
      .flatMap(row => {
        const vault = vaultInfoMap.get(row.account_id);
        if (!vault?.vault_id || !vault?.sp_address) return [];
        return [
          {
            sp_account_id: row.account_id,
            vault_id: vault.vault_id,
            wallet_address: vault.sp_address,
          },
        ];
      });
  }, [availableIfData, subAccounts, vaultInfoMap]);

  const { data: orderlyBalanceMap } =
    useStrategyVaultFundInfoMap(fundInfoInputs);

  const { mergedIfAccounts, vaultSpAccountIdSet } = useMemo(() => {
    const subIds = new Set(subAccounts.map(s => s.sub_account_id));

    const extras: SubAccount[] = (availableIfData ?? [])
      .filter(row => !subIds.has(row.account_id))
      .map(row => {
        const vault = vaultInfoMap.get(row.account_id);
        const balance = orderlyBalanceMap?.get(row.account_id) ?? 0;
        return {
          sub_account_id: row.account_id,
          description: vault?.vault_name ?? "Vault SP account",
          balance,
        };
      });

    const mergedIfAccounts = [...subAccounts, ...extras];
    const vaultSpAccountIdSet = new Set(extras.map(e => e.sub_account_id));

    return { mergedIfAccounts, vaultSpAccountIdSet };
  }, [subAccounts, availableIfData, vaultInfoMap, orderlyBalanceMap]);

  return { mergedIfAccounts, vaultSpAccountIdSet, mutateAvailableIfAccounts };
}
