import { buildBrokerSymbolLogoSymbolPreview } from "@/utils/brokerSymbolLogoUpload";
import { ListingAssetType, isSpotIndexSourceType } from "../../../../types";
import type {
  SourceItem,
  SymbolDetail,
  TradingParamsForm,
} from "../../../../types";
import type { RwaMarketSessionRow } from "../../../../services/types";
import { getListingBaseFromSymbol } from "../../price-sources/hooks/shared";

export function getSelectedPriceSources(priceSources: SourceItem[]) {
  return priceSources.filter(source => source.selected);
}

export function getEffectiveListingBase(input: {
  editMode: boolean;
  editSymbol: string | null;
  currentListingBase: string;
}) {
  const { editMode, editSymbol, currentListingBase } = input;
  if (editMode && editSymbol) {
    const fromKey = getListingBaseFromSymbol(editSymbol);
    if (fromKey) return fromKey;
  }
  return currentListingBase;
}

export function getFundingPeriodPendingState(input: {
  editMode: boolean;
  editSymbol: string | null;
  symbolDetails: Record<string, SymbolDetail>;
}) {
  const detail =
    input.editMode && input.editSymbol
      ? input.symbolDetails[input.editSymbol]
      : undefined;
  return {
    fundingPeriodPending: detail?.fundingPeriodPending,
    fundingPeriodEffectiveAt: detail?.fundingPeriodEffectiveAt,
  };
}

/** Spot price multiplier prefixes the listing base (e.g. 1000x -> 1000SHIB). */
export function getPrefixedListingBase(input: {
  base: string;
  selectedSources: SourceItem[];
}) {
  const spot = input.selectedSources.find(source =>
    isSpotIndexSourceType(source.type)
  );
  const effectiveMult = spot && spot.multiplier > 0 ? spot.multiplier : 1;
  return effectiveMult > 1 ? `${effectiveMult}${input.base}` : input.base;
}

export function buildListingLogoSymbolPreview(input: {
  selectedSources: SourceItem[];
  effectiveListingBase: string;
  brokerId?: string;
}) {
  const prefixedBase = input.effectiveListingBase
    ? getPrefixedListingBase({
        base: input.effectiveListingBase,
        selectedSources: input.selectedSources,
      })
    : "";

  if (!prefixedBase) return "";
  return buildBrokerSymbolLogoSymbolPreview(
    `PERP_${prefixedBase}_USDC`,
    input.brokerId
  );
}

export function getAdjustedSourcePrices(sources: SourceItem[]) {
  return sources
    .map(
      source => source.price * (source.multiplier > 0 ? source.multiplier : 1)
    )
    .filter(price => Number.isFinite(price) && price > 0);
}

export function getAveragePrice(prices: number[]) {
  return prices.length > 0
    ? prices.reduce((sum, price) => sum + price, 0) / prices.length
    : 0;
}

export function applyRwaTradingLimits(input: {
  listingAssetType: TradingParamsForm["listing_asset_type"];
  avgSelectedPrice: number;
  quoteTick: number;
  baseTick: number;
  baseMin: number;
  baseMax: number;
}) {
  const {
    listingAssetType,
    avgSelectedPrice,
    quoteTick,
    baseTick,
    baseMin,
    baseMax,
  } = input;
  const isRwa = listingAssetType === ListingAssetType.Rwa;
  const effectiveQuoteTick = isRwa
    ? avgSelectedPrice > 100
      ? 1
      : avgSelectedPrice > 10
        ? 0.1
        : 0.01
    : quoteTick;
  const effectiveBaseMin =
    isRwa && avgSelectedPrice > 0 ? 1 / avgSelectedPrice : baseMin;
  const effectiveBaseTick = isRwa ? effectiveBaseMin : baseTick;
  const effectiveBaseMax =
    isRwa && avgSelectedPrice > 0 ? 2_000_000 / avgSelectedPrice : baseMax;

  return {
    quoteTick: effectiveQuoteTick,
    baseTick: effectiveBaseTick,
    baseMin: effectiveBaseMin,
    baseMax: effectiveBaseMax,
  };
}

export function toRwaMarketSessionOptions(rows: RwaMarketSessionRow[]) {
  return rows.map(row => ({
    ...row,
    value: row.market_session,
    label: row.name ?? row.market_session,
  }));
}
