import { cn } from "@/utils/css";
import { FadeInEnter } from "@/components/fade-in-enter";
import { StepIndicator } from "../../components";
import { useListingStore } from "../../store/useListingStore";
import { ListingSubStep, PageView } from "../../types";
import { PriceSourcesPanel } from "./price-sources";
import { TradingParamsPanel } from "./trading-params";
import { ListingAssetTypeModal } from "./ListingAssetTypeModal";

export function Listing() {
  const listingStep = useListingStore(s => s.listingStep);
  const listingAssetTypeModalOpen = useListingStore(
    s => s.listingAssetTypeModalOpen
  );
  const setListingAssetType = useListingStore(s => s.setListingAssetType);
  const setListingAssetTypeModalOpen = useListingStore(
    s => s.setListingAssetTypeModalOpen
  );
  const setPage = useListingStore(s => s.setPage);

  return (
    <div className="flex min-h-0 flex-1 flex-col">
      <FadeInEnter className="shrink-0">
        <StepIndicator listingStep={listingStep} />
      </FadeInEnter>
      <FadeInEnter className="relative flex min-h-0 flex-1 flex-col">
        <div className="relative min-h-0 min-w-0 flex-1 overflow-hidden">
          {/*
            Stack both steps for enter transitions, but only the active step stays in-flow
            (`relative`). The inactive step is `absolute` so it does not participate in layout —
            otherwise a shared grid row height would be max(Step1, Step2) and Step 1 would get a
            huge empty scroll area when Step 2’s form is taller.
            `overflow-hidden` on the stack clips the inactive step: absolutely positioned
            descendants still extend scroll overflow of ancestors, so without clipping, a short
            active step would still allow scrolling past empty space when the hidden step is tall.
          */}
          <div
            className={cn(
              "min-h-0 w-full transition-[opacity,transform] duration-200 ease-out",
              listingStep === ListingSubStep.PriceSources
                ? "relative z-10 opacity-100 translate-y-0"
                : "pointer-events-none absolute inset-x-0 top-0 z-0 overflow-hidden opacity-0 translate-y-2"
            )}
          >
            <PriceSourcesPanel />
          </div>
          <div
            className={cn(
              "min-h-0 w-full transition-[opacity,transform] duration-200 ease-out",
              listingStep === ListingSubStep.TradingParams
                ? "relative z-10 opacity-100 translate-y-0"
                : "pointer-events-none absolute inset-x-0 top-0 z-0 overflow-hidden opacity-0 translate-y-2"
            )}
          >
            {listingStep === ListingSubStep.TradingParams ? (
              <TradingParamsPanel />
            ) : null}
          </div>
        </div>
      </FadeInEnter>
      <ListingAssetTypeModal
        open={listingAssetTypeModalOpen}
        onCancel={() => {
          setListingAssetTypeModalOpen(false);
          setPage(PageView.Dashboard);
        }}
        onSelect={assetType => {
          setListingAssetType(assetType);
          setListingAssetTypeModalOpen(false);
        }}
      />
    </div>
  );
}
