import { useEffect, useRef, useState } from "react";
import { cn } from "@/utils/css";
import Tooltip from "@/components/tooltip";
import { fmtUSDShort, fmtNum, fmtPct } from "../../../utils";
import type { PeriodFilter } from "../../../types";
import type { StatGridStats } from "./useStatGrid";

interface StatGridUIProps {
  stats: StatGridStats;
  period: PeriodFilter;
  onPeriodChange: (p: PeriodFilter) => void;
}

const PERIODS: { value: PeriodFilter; label: string }[] = [
  { value: "all-time", label: "All-time" },
  { value: "30d", label: "30d" },
  { value: "7d", label: "7d" },
  { value: "24h", label: "1d" },
];

function periodLabel(period: PeriodFilter): string {
  return PERIODS.find(p => p.value === period)?.label ?? "All-time";
}

export function StatGridUI({ stats, period, onPeriodChange }: StatGridUIProps) {
  const [periodOpen, setPeriodOpen] = useState(false);
  const periodRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    function handleClick(e: MouseEvent) {
      if (periodRef.current && !periodRef.current.contains(e.target as Node)) {
        setPeriodOpen(false);
      }
    }
    document.addEventListener("mousedown", handleClick);
    return () => document.removeEventListener("mousedown", handleClick);
  }, []);

  return (
    <div className="flex flex-col gap-4 mb-6">
      <div className="flex items-center justify-between relative">
        <span className="text-xs font-medium text-base-contrast-98">
          Overview
        </span>
        <div ref={periodRef} className="relative">
          <button
            type="button"
            onClick={() => setPeriodOpen(o => !o)}
            className={cn(
              "inline-flex items-center gap-1.5 rounded-full border cursor-pointer font-medium text-2xs transition-colors",
              "bg-base-200 border-base-contrast-8 text-base-contrast-50 hover:text-base-contrast-98 hover:border-base-contrast-20",
              "py-1.5 px-3.5"
            )}
          >
            <span>{periodLabel(period)}</span>
            <svg className="w-3 h-3" viewBox="0 0 12 12" fill="none">
              <path
                d="M3 4.5L6 7.5L9 4.5"
                stroke="currentColor"
                strokeWidth="1.5"
                strokeLinecap="round"
                strokeLinejoin="round"
              />
            </svg>
          </button>
          {periodOpen && (
            <div
              className="absolute top-[calc(100%+6px)] right-0 z-100 min-w-[120px] rounded-xl border border-base-contrast-8 bg-base-400 p-1.5 shadow-lg"
              role="listbox"
            >
              {PERIODS.map(p => (
                <button
                  key={p.value}
                  type="button"
                  role="option"
                  aria-selected={period === p.value}
                  onClick={() => {
                    onPeriodChange(p.value);
                    setPeriodOpen(false);
                  }}
                  className={cn(
                    "w-full text-left py-2 px-3 rounded-lg text-2xs font-medium cursor-pointer transition-colors",
                    period === p.value
                      ? "text-base-contrast-98"
                      : "text-base-contrast-50 hover:text-base-contrast-98"
                  )}
                >
                  {p.label}
                </button>
              ))}
            </div>
          )}
        </div>
      </div>

      <div className="grid grid-cols-5 gap-4">
        <StatCard
          label={
            <Tooltip
              side="top"
              sideOffset={4}
              content="Counts symbols in PENDING, POST_ONLY, ACTIVE, or REDUCE_ONLY status toward the 50-symbol limit."
            >
              <span className="border-b border-dashed border-base-contrast-50 cursor-help">
                Active symbols
              </span>
            </Tooltip>
          }
          value={
            <>
              <span className="text-primary-light">
                {stats.symbolsUsed != null ? stats.symbolsUsed : "—"}
              </span>
              <span className="text-base-contrast-50 text-base font-medium">
                {" "}
                / {stats.symbolsLimit != null ? stats.symbolsLimit : "—"} Slots
                used
              </span>
            </>
          }
        />

        <StatCard
          label={periodLabel(period) + " volume"}
          value={
            stats.totalVolume != null ? fmtUSDShort(stats.totalVolume) : "—"
          }
          valueClassName="text-primary-light"
        />

        <StatCard
          label={periodLabel(period) + " liquidation"}
          value={
            <>
              <span className="text-primary-light">
                {stats.totalLiqRevenue != null
                  ? fmtUSDShort(stats.totalLiqRevenue)
                  : "—"}
              </span>
              <span className="text-base-contrast-50 text-base font-medium">
                {" "}
                /{" "}
                {period === "24h"
                  ? stats.totalLiq != null
                    ? `${fmtNum(stats.totalLiq)} times`
                    : "—"
                  : "—"}
              </span>
            </>
          }
        />

        <StatCard
          label={periodLabel(period) + " fee revenue"}
          value={
            stats.totalFeeRevenue != null
              ? fmtUSDShort(stats.totalFeeRevenue)
              : "—"
          }
          gradient="positive"
        />

        <StatCard
          label={periodLabel(period) + " APR"}
          value={stats.avgApr != null ? fmtPct(stats.avgApr) : "—"}
          gradient="positive"
        />
      </div>
    </div>
  );
}

function StatCard({
  label,
  value,
  valueClassName,
  gradient,
}: {
  label: React.ReactNode;
  value: React.ReactNode;
  valueClassName?: string;
  gradient?: "positive";
}) {
  return (
    <div className="flex flex-col p-4 rounded-xl bg-base-200">
      <div className="text-[14px] font-medium text-base-contrast-98 leading-tight">
        {label}
      </div>
      <span
        className={cn(
          "text-2xl font-medium mt-2 text-base-contrast-98",
          valueClassName,
          gradient === "positive" &&
            "bg-linear-to-br from-[rgb(29,246,181)] to-[rgb(134,237,146)] bg-clip-text text-transparent"
        )}
      >
        {value}
      </span>
    </div>
  );
}
