export function LLMHelperBanner({
  onCopyForLLM,
  onOpenInLLM,
  className,
}: LLMHelperBannerProps) {
  const [menuOpen, setMenuOpen] = useState(false);
  const [copied, setCopied] = useState(false);
  /** Increments on each copy/check icon swap so `key` remounts and CSS animation reliably replays. */
  const [iconSwapNonce, setIconSwapNonce] = useState(0);
  const menuRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!copied) return;
    const t = setTimeout(() => {
      setCopied(false);
      setIconSwapNonce(n => n + 1);
    }, 2000);
    return () => clearTimeout(t);
  }, [copied]);

  useEffect(() => {
    function handleClickOutside(e: MouseEvent) {
      if (menuRef.current && !menuRef.current.contains(e.target as Node)) {
        setMenuOpen(false);
      }
    }
    if (menuOpen) {
      document.addEventListener("mousedown", handleClickOutside);
      return () =>
        document.removeEventListener("mousedown", handleClickOutside);
    }
  }, [menuOpen]);

  const handleCopy = () => {
    onCopyForLLM?.();
    setCopied(true);
    setIconSwapNonce(n => n + 1);
  };

  const handleCopyAndClose = () => {
    handleCopy();
    setMenuOpen(false);
  };

  const handleOpenInLLM = (
    provider: "chatgpt" | "claude" | "perplexity" | "grok"
  ) => {
    onCopyForLLM?.();
    onOpenInLLM?.(provider);
    window.open(LLM_URLS[provider], "_blank", "noopener,noreferrer");
    setMenuOpen(false);
  };

  return (
    <div
      className={cn(
        "flex items-center gap-4 p-4 rounded-2xl border border-base-contrast-20",
        "bg-transparent",
        className
      )}
    >
      <div className="w-8 h-8 shrink-0 flex items-center justify-center rounded-xl bg-base-300">
        <AiHelperIcon className="w-8 h-8" />
      </div>
      <div className="flex-1 min-w-0 flex flex-col gap-2">
        <span className="text-xs font-medium text-base-contrast-98 leading-tight">
          Need help with these parameters?
        </span>
        <span className="text-3xs font-medium text-base-contrast-50 leading-tight">
          Configuring a new pair can be complex. Copy your current setup to an
          AI assistant like ChatGPT or Claude to review your risk model or
          explain specific fields.
        </span>
      </div>
      <div className="relative shrink-0" ref={menuRef}>
        <button
          type="button"
          onClick={e => {
            const target = e.target as HTMLElement;
            if (target.closest("[data-dropdown-trigger]")) {
              setMenuOpen(o => !o);
            } else {
              handleCopy();
            }
          }}
          className={cn(
            "inline-flex items-center justify-center gap-0 h-7 px-0",
            "bg-transparent border border-base-contrast-20 rounded-[46px]",
            "cursor-pointer hover:bg-base-contrast-8 transition-colors"
          )}
        >
          <span className="inline-flex shrink-0 items-center gap-2 pl-3 pr-2">
            <span
              key={iconSwapNonce}
              className={cn(
                "inline-flex shrink-0",
                iconSwapNonce > 0 &&
                  "animate-[fade-in_0.22s_ease-out] motion-reduce:animate-none"
              )}
            >
              {copied ? (
                <CheckIcon className="text-primary-light" />
              ) : (
                <CopyIcon className="text-primary-light" />
              )}
            </span>
            <span className="text-3xs font-medium text-primary-light whitespace-nowrap leading-tight">
              Copy for LLM
            </span>
          </span>
          <span
            data-dropdown-trigger
            className={cn(
              "flex min-w-0 flex-1 items-center self-stretch gap-2 pr-3"
            )}
          >
            <div
              className="w-px h-6 shrink-0 bg-base-contrast-20"
              aria-hidden
            />
            <span
              className={cn(
                "inline-flex shrink-0 items-center justify-center text-base-contrast-50",
                "transition-transform duration-200 ease-out motion-reduce:transition-none",
                menuOpen && "rotate-180"
              )}
            >
              <DropdownArrowIcon />
            </span>
          </span>
        </button>
        <div
          aria-hidden={!menuOpen}
          className={cn(
            "absolute top-[calc(100%+8px)] right-0 w-[280px] z-100",
            "bg-base-300 border border-base-contrast-20 rounded-xl py-2",
            "shadow-[0_8px_32px_rgba(0,0,0,0.5)]",
            "origin-top-right",
            "transition-[opacity,transform] duration-200 ease-out",
            "motion-reduce:transition-none",
            menuOpen
              ? "pointer-events-auto opacity-100 scale-100 translate-y-0"
              : "pointer-events-none opacity-0 scale-95 -translate-y-1"
          )}
        >
          <button
            type="button"
            onClick={handleCopyAndClose}
            className={cn(
              "w-full flex items-center gap-3 px-4 py-2.5 cursor-pointer",
              "hover:bg-base-contrast-8 transition-colors text-left"
            )}
          >
            <CopyPageIcon className="text-base-contrast-50" />
            <div className="flex-1 min-w-0 flex flex-col gap-0.5">
              <span className="text-xs font-medium text-base-contrast-98">
                Copy page
              </span>
              <span className="text-3xs font-medium text-base-contrast-36">
                Copy page as Markdown for LLMs
              </span>
            </div>
          </button>
          <div className="h-px bg-base-contrast-12 my-1 mx-4" />
          <button
            type="button"
            onClick={() => handleOpenInLLM("chatgpt")}
            className={cn(
              "w-full flex items-center gap-3 px-4 py-2.5 cursor-pointer",
              "hover:bg-base-contrast-8 transition-colors text-left"
            )}
          >
            <ChatGPTIcon className="text-base-contrast-50" />
            <div className="flex-1 min-w-0 flex flex-col gap-0.5">
              <span className="text-xs font-medium text-base-contrast-98">
                Open in ChatGPT <span className="text-3xs">↗</span>
              </span>
              <span className="text-3xs font-medium text-base-contrast-36">
                Ask questions about this config
              </span>
            </div>
          </button>
          <button
            type="button"
            onClick={() => handleOpenInLLM("claude")}
            className={cn(
              "w-full flex items-center gap-3 px-4 py-2.5 cursor-pointer",
              "hover:bg-base-contrast-8 transition-colors text-left"
            )}
          >
            <ClaudeIcon className="text-base-contrast-50" />
            <div className="flex-1 min-w-0 flex flex-col gap-0.5">
              <span className="text-xs font-medium text-base-contrast-98">
                Open in Claude <span className="text-3xs">↗</span>
              </span>
              <span className="text-3xs font-medium text-base-contrast-36">
                Ask questions about this config
              </span>
            </div>
          </button>
          <button
            type="button"
            onClick={() => handleOpenInLLM("perplexity")}
            className={cn(
              "w-full flex items-center gap-3 px-4 py-2.5 cursor-pointer",
              "hover:bg-base-contrast-8 transition-colors text-left"
            )}
          >
            <PerplexityIcon className="text-base-contrast-50" />
            <div className="flex-1 min-w-0 flex flex-col gap-0.5">
              <span className="text-xs font-medium text-base-contrast-98">
                Open in Perplexity <span className="text-3xs">↗</span>
              </span>
              <span className="text-3xs font-medium text-base-contrast-36">
                Ask questions about this config
              </span>
            </div>
          </button>
          <button
            type="button"
            onClick={() => handleOpenInLLM("grok")}
            className={cn(
              "w-full flex items-center gap-3 px-4 py-2.5 cursor-pointer",
              "hover:bg-base-contrast-8 transition-colors text-left"
            )}
          >
            <GrokIcon className="text-base-contrast-50" />
            <div className="flex-1 min-w-0 flex flex-col gap-0.5">
              <span className="text-xs font-medium text-base-contrast-98">
                Open in Grok <span className="text-3xs">↗</span>
              </span>
              <span className="text-3xs font-medium text-base-contrast-36">
                Ask questions about this config
              </span>
            </div>
          </button>
        </div>
      </div>
    </div>
  );
}
