import { useCallback, useEffect, useMemo } from "react";
import { useBrokerInfo } from "@/components/provider/BrokerInfoProvider";
import { ListingSubStep } from "../../../types";
import { DEFAULT_TRADING_PARAMS_FORM } from "../../../constants";
import { useSelectListingStore } from "../../../store/useListingStore";
import {
  useCexPerpMetas,
  useFundingCapFloor,
  useTickAndLimits,
  useTradingParamsDerived,
  useTradingParamsForm,
  useTradingParamsImportAndCopy,
  useTradingParamsSubmit,
  useTradingParamsValidation,
} from "./hooks";
import {
  useGetBrokerListingSymbolContext,
  useRwaMarketSessions,
} from "@/permissionless-listing/services";
import { ListingAssetType } from "../../../types";
import {
  applyRwaTradingLimits,
  buildListingLogoSymbolPreview,
  getAdjustedSourcePrices,
  getAveragePrice,
  getEffectiveListingBase,
  getFundingPeriodPendingState,
  getSelectedPriceSources,
  toRwaMarketSessionOptions,
} from "./hooks/derived.helpers";
import { useListingIndexSourcesData } from "../../../hooks/useListingIndexSourcesData";

export function useTradingParamsScript() {
  const { brokerId } = useBrokerInfo();
  const {
    priceSources,
    editMode,
    editSymbol,
    currentListingBase,
    listingAssetType,
    symbolDetails,
    listedSymbols,
    listingStep,
    indexSources: storeIndexSources,
    updateSymbolDetail,
    addEvent,
    setPage,
    setSymbols,
    setListingStep,
  } = useSelectListingStore(s => ({
    priceSources: s.priceSources,
    editMode: s.editMode,
    editSymbol: s.editSymbol,
    currentListingBase: s.currentListingBase,
    listingAssetType: s.listingAssetType,
    symbolDetails: s.symbolDetails,
    listedSymbols: s.listedSymbols,
    updateSymbolDetail: s.updateSymbolDetail,
    addEvent: s.addEvent,
    setPage: s.setPage,
    setSymbols: s.setSymbols,
    setListingStep: s.setListingStep,
    listingStep: s.listingStep,
    indexSources: s.indexSources,
  }));
  const { indexSources: apiIndexSources } = useListingIndexSourcesData();
  const indexSources = storeIndexSources.length
    ? storeIndexSources
    : apiIndexSources;

  const selectedSources = useMemo(
    () => getSelectedPriceSources(priceSources),
    [priceSources]
  );

  const effectiveListingBase = useMemo(() => {
    return getEffectiveListingBase({
      editMode,
      editSymbol,
      currentListingBase,
    });
  }, [editMode, editSymbol, currentListingBase]);

  const { fundingPeriodPending, fundingPeriodEffectiveAt } = useMemo(() => {
    return getFundingPeriodPendingState({
      editMode,
      editSymbol,
      symbolDetails,
    });
  }, [editMode, editSymbol, symbolDetails]);

  const { data: symbolContext } = useGetBrokerListingSymbolContext({
    symbol:
      listingStep === ListingSubStep.TradingParams
        ? effectiveListingBase
        : undefined,
  });
  const {
    data: rwaMarketSessions,
    error: rwaMarketSessionsError,
    isLoading: rwaMarketSessionsLoading,
  } = useRwaMarketSessions({ revalidateOnFocus: false });

  const logoSymbolPreview = useMemo(() => {
    return buildListingLogoSymbolPreview({
      selectedSources,
      effectiveListingBase,
      brokerId,
    });
  }, [effectiveListingBase, selectedSources, brokerId]);

  const {
    form,
    setForm,
    errors,
    setErrors,
    warnings,
    setWarnings,
    updateField,
    symbolIconFile,
    hasStagedSymbolIcon,
    symbolIconDisplayUrl,
    stageSymbolIcon,
    removeSymbolIcon,
    markSymbolIconUploaded,
  } = useTradingParamsForm({
    params: {
      ...DEFAULT_TRADING_PARAMS_FORM,
      listing_asset_type: listingAssetType ?? ListingAssetType.Crypto,
    },
    editMode,
    editSymbol,
    symbolDetails,
    symbolContext,
    logoSymbolPreview,
  });

  useEffect(() => {
    if (listingAssetType !== ListingAssetType.Rwa) return;
    if (editMode) return;
    if (!rwaMarketSessions || rwaMarketSessions.length === 0) return;
    setForm(prev => {
      if (prev.rwa_market_session) return prev;
      return {
        ...prev,
        rwa_market_session: rwaMarketSessions[0].market_session,
      };
    });
  }, [listingAssetType, editMode, rwaMarketSessions, setForm]);

  const { leverage, imr, mmr, prettySymbol } = useTradingParamsDerived({
    form,
    editSymbol,
  });

  const {
    cexFundingParamsLoading,
    cexTickParamsLoading,
    cexMetasForTick,
    cexFundingMetas,
    cexStepSizeCandidates,
  } = useCexPerpMetas({
    priceSources,
    baseSymbol: effectiveListingBase,
  });

  const { quoteTick, baseTick, baseMin, baseMax } = useTickAndLimits({
    symbolContext,
    selectedSources,
    globalMaxOi: form.global_max_oi,
    baseSymbol: effectiveListingBase,
    cexTickParamsLoading,
    cexMetasForTick,
    cexStepSizeCandidates,
  });

  const { fundingCap, fundingFloor } = useFundingCapFloor({
    fundingPeriod: form.funding_period,
    cexFundingMetas,
  });

  const selectedAdjustedPrices = useMemo(
    () => getAdjustedSourcePrices(selectedSources),
    [selectedSources]
  );

  const avgSelectedPrice = useMemo(
    () => getAveragePrice(selectedAdjustedPrices),
    [selectedAdjustedPrices]
  );

  const {
    quoteTick: effectiveQuoteTick,
    baseTick: effectiveBaseTick,
    baseMin: effectiveBaseMin,
    baseMax: effectiveBaseMax,
  } = applyRwaTradingLimits({
    listingAssetType: form.listing_asset_type,
    avgSelectedPrice,
    quoteTick,
    baseTick,
    baseMin,
    baseMax,
  });

  const { validateFields, validateForSubmit } = useTradingParamsValidation({
    form,
    selectedSources,
    setErrors,
    setWarnings,
    symbolContext,
  });

  const {
    submitting,
    submitModalOpen,
    setSubmitModalOpen,
    submitSymbolLabel,
    defaultListingDate,
    onPrimarySubmitClick,
    onSubmitFromModal,
  } = useTradingParamsSubmit({
    form,
    selectedSources,
    editMode,
    editSymbol,
    symbolDetails,
    listedSymbols,
    indexSourcesCatalog: indexSources,
    brokerId,
    updateSymbolDetail,
    addEvent,
    setPage,
    setSymbols,
    validate: validateForSubmit,
    fundingCap,
    fundingFloor,
    quoteTick: effectiveQuoteTick,
    baseTick: effectiveBaseTick,
    baseMin: effectiveBaseMin,
    baseMax: effectiveBaseMax,
    prettySymbol,
    listingBase: effectiveListingBase,
    listingAssetType: form.listing_asset_type,
    rwaMarketSession: form.rwa_market_session,
    rwaMarketSessions: rwaMarketSessions ?? [],
    symbolIconFile,
    logoSymbolPreview,
    markSymbolIconUploaded,
  });

  const onBack = useCallback(() => {
    setListingStep(ListingSubStep.PriceSources);
  }, [setListingStep]);

  const { importJSON, copyForLLM } = useTradingParamsImportAndCopy({
    setForm,
  });

  return {
    form,
    updateField,
    errors,
    warnings,
    leverage,
    imr,
    mmr,
    fundingCap,
    fundingFloor,
    quoteTick: effectiveQuoteTick,
    baseTick: effectiveBaseTick,
    baseMin: effectiveBaseMin,
    baseMax: effectiveBaseMax,
    selectedSources,
    submitting,
    onPrimarySubmitClick,
    onSubmitFromModal,
    submitModalOpen,
    setSubmitModalOpen,
    submitSymbolLabel,
    defaultListingDate,
    brokerId,
    onBack,
    onValidateFields: validateFields,
    importJSON,
    copyForLLM,
    editMode,
    prettySymbol,
    effectiveListingBase,
    cexFundingParamsLoading,
    cexTickParamsLoading,
    fundingPeriodPending,
    fundingPeriodEffectiveAt,
    symbolContext,
    listingAssetType: form.listing_asset_type,
    rwaMarketSession: form.rwa_market_session,
    rwaMarketSessionOptions: toRwaMarketSessionOptions(rwaMarketSessions ?? []),
    rwaMarketSessionError: rwaMarketSessionsError
      ? "Failed to load market sessions."
      : undefined,
    rwaMarketSessionLoading: rwaMarketSessionsLoading,
    hasStagedSymbolIcon,
    symbolIconDisplayUrl,
    stageSymbolIcon,
    removeSymbolIcon,
  };
}
