import {
  IndexSourceType,
  ListingAssetType,
  type IndexSourceMeta,
  type SourceItem,
} from "../types";
import type {
  BrokerListingBuilderSourceRow,
  BrokerListingIndexSourceRow,
} from "./types";

const BUILDER_RISK_NOTICE =
  "This Source is provided by a third party and may go offline at any time.";

export type ExternalSourceQuote = {
  found: boolean;
  sourceSymbol: string;
  // When source is Pyth (oracle), feedId is the id of the Pyth price feed.
  feedId?: string;
  latestPrice: number;
  volume24h: number;
  suggestedMultiplier: number;
};

function createNotFoundQuote(input: {
  sourceSymbol: string;
  suggestedMultiplier: number;
}): ExternalSourceQuote {
  return {
    found: false,
    sourceSymbol: input.sourceSymbol,
    latestPrice: 0,
    volume24h: 0,
    suggestedMultiplier: input.suggestedMultiplier,
  };
}

/** Only API source key -> user-visible name. Source type comes from API/catalog data. */
const SOURCE_DISPLAY_NAMES = {
  BINANCE: "Binance",
  OKX: "OKX",
  BYBIT: "Bybit",
  GATEIO: "Gate.io",
  KUCOIN: "KuCoin",
  COINBASE: "Coinbase",
  MEXC: "MEXC",
  BITGET: "Bitget",
  BINGX: "BingX",
  HYPERLIQUID: "HyperLiquid",
  LBANK: "LBank",
  PYTH: "Pyth",
  STORK: "Stork",
  BINANCEFUTURESINDEX: "Binance Futures",
  HYPERLIQUIDPERP: "HyperLiquid Perp",
} as const;

type KnownApiSource = keyof typeof SOURCE_DISPLAY_NAMES;

function isKnownApiSource(key: string): key is KnownApiSource {
  return Object.prototype.hasOwnProperty.call(SOURCE_DISPLAY_NAMES, key);
}

const REQUEST_TIMEOUT_MS = 20000;

/**
 * Fetcher for external full URLs. Used by useSWR and internally for sub-requests.
 * Supports timeout and JSON response.
 */
export async function externalUrlFetcher<T>(
  url: string,
  init?: RequestInit
): Promise<T> {
  const controller = new AbortController();
  const timer = window.setTimeout(() => controller.abort(), REQUEST_TIMEOUT_MS);
  try {
    const res = await fetch(url, {
      ...init,
      signal: controller.signal,
      headers: {
        "Content-Type": "application/json",
        ...(init?.headers ?? {}),
      },
    });
    if (!res.ok) throw new Error(`HTTP_${res.status}`);
    return (await res.json()) as T;
  } finally {
    window.clearTimeout(timer);
  }
}

const fetchJsonWithTimeout = externalUrlFetcher;

export function normalizeSourceKey(raw: string): string {
  const key = raw.trim().toUpperCase().replace(/\s+/g, "");
  return key;
}

export function formatIndexSourceName(source: string): string {
  const apiSource = normalizeSourceKey(source);
  return isKnownApiSource(apiSource) ? SOURCE_DISPLAY_NAMES[apiSource] : source;
}

/** Stable row id for SourceItem (lowercase slug, e.g. binance). */
export function sourceKeyToItemId(source: string): string {
  return normalizeSourceKey(source).toLowerCase();
}

function normalizeSymbol(raw: string): string {
  return raw.toUpperCase().replace(/[-_/]/g, "");
}

function extractBaseToken(sourceSymbol: string): string {
  const upper = sourceSymbol.toUpperCase();
  const dexSeparator = upper.indexOf(":");
  if (dexSeparator >= 0) {
    return upper.slice(dexSeparator + 1).replace(/[^A-Z0-9]/g, "");
  }
  const cleaned = upper.replace(/[-_/]/g, "");
  if (cleaned.endsWith("USDT")) return cleaned.slice(0, -4);
  if (cleaned.endsWith("USDC")) return cleaned.slice(0, -4);
  if (cleaned.endsWith("USD")) return cleaned.slice(0, -3);
  return cleaned.replace(/[^A-Z0-9]/g, "");
}

function extractLeadingMultiplier(symbol: string): number {
  const m = symbol
    .trim()
    .toUpperCase()
    .match(/^(\d+)[A-Z]/);
  if (!m) return 1;
  const n = Number(m[1]);
  return Number.isFinite(n) && n > 0 ? n : 1;
}

function inferSuggestedMultiplier(
  listingBaseSymbol: string,
  sourceSymbol: string
): number {
  const desiredUnit = extractLeadingMultiplier(listingBaseSymbol);
  if (desiredUnit <= 1) return 1;

  const normalizedSource = normalizeSymbol(sourceSymbol);
  const sourceLeading = extractLeadingMultiplier(normalizedSource);
  if (sourceLeading === desiredUnit) return 1;
  return desiredUnit;
}

export function inferDefaultSymbols(
  apiSource: string,
  base: string
): { spot: string; perp: string } {
  switch (apiSource) {
    case "HYPERLIQUID":
    case "HYPERLIQUIDPERP":
      // Hyperliquid spotMeta is USDC-based; perp meta uses base token names (e.g. BTC).
      return { spot: `${base}/USDC`, perp: base };
    case "OKX":
      return { spot: `${base}-USDT`, perp: `${base}-USDT-SWAP` };
    case "GATEIO":
      return { spot: `${base}_USDT`, perp: `${base}_USDT` };
    case "KUCOIN":
      return { spot: `${base}-USDT`, perp: `${base}USDTM` };
    case "COINBASE":
      // Retail Exchange spot ticker uses *-USD; *-USDC pairs are often delisted.
      return { spot: `${base}-USD`, perp: `${base}-PERP` };
    case "BINGX":
      return { spot: `${base}-USDT`, perp: `${base}-USDT` };
    case "LBANK":
      return {
        spot: `${base.toLowerCase()}_usdt`,
        perp: `${base.toLowerCase()}usdt`,
      };
    case "PYTH":
      return { spot: `${base}/USD`, perp: `${base}/USD` };
    default:
      // BINANCE、BYBIT、MEXC、BITGET、BINANCEFUTURESINDEX
      return { spot: `${base}USDT`, perp: `${base}USDT` };
  }
}

function inferHyperliquidPerpSymbol(
  base: string,
  assetType?: ListingAssetType,
  sourceSymbol?: string
): string {
  const symbol = sourceSymbol?.trim() || base;
  if (assetType !== ListingAssetType.Rwa) return symbol;
  return symbol.includes(":") ? symbol : `xyz:${symbol}`;
}

function inferQuoteSymbol(input: {
  apiSource: string;
  base: string;
  type: IndexSourceType;
  sourceSymbol?: string;
  listingAssetType?: ListingAssetType;
}): string {
  const manual = input.sourceSymbol?.trim();

  if (input.apiSource === "HYPERLIQUIDPERP") {
    return inferHyperliquidPerpSymbol(
      input.base,
      input.listingAssetType,
      manual
    );
  }

  if (manual) return manual;

  const defaults = inferDefaultSymbols(input.apiSource, input.base);
  return input.type === IndexSourceType.Futures ? defaults.perp : defaults.spot;
}

/**
 * Maps GET /v1/broker/listing/index_sources rows into store items with friendly
 * `name` from SOURCE_DISPLAY_NAMES when available. `type` is preserved from the API.
 */
export function enrichIndexSources(
  rows: BrokerListingIndexSourceRow[]
): IndexSourceMeta[] {
  const out: IndexSourceMeta[] = [];
  for (const row of rows) {
    out.push({
      ...row,
      name: formatIndexSourceName(row.source),
    });
  }
  return out;
}

export function matchIndexSourceCatalog(
  catalog: IndexSourceMeta[],
  raw: string
): IndexSourceMeta | undefined {
  const key = normalizeSourceKey(raw);
  return (
    catalog.find(c => normalizeSourceKey(c.source) === key) ??
    catalog.find(c => c.name.toLowerCase() === raw.trim().toLowerCase())
  );
}

export function resolveApiSource(nameOrSource: string): string | null {
  const source = normalizeSourceKey(nameOrSource);
  if (isKnownApiSource(source)) return source;

  const upper = nameOrSource.toUpperCase();
  for (const [key, name] of Object.entries(SOURCE_DISPLAY_NAMES) as [
    KnownApiSource,
    string,
  ][]) {
    if (name.toUpperCase() === upper) return key;
  }
  return null;
}

export function getSourceDisplayMeta(
  nameOrSource: string
): Pick<IndexSourceMeta, "source" | "name"> | null {
  if (
    nameOrSource.startsWith("ORACLE_") ||
    nameOrSource.startsWith("PYTH_") ||
    nameOrSource.startsWith("STORK_")
  ) {
    return {
      source: nameOrSource,
      name: nameOrSource,
    };
  }
  const apiSource = resolveApiSource(nameOrSource);
  if (!apiSource || !isKnownApiSource(apiSource)) return null;
  return {
    source: apiSource,
    name: formatIndexSourceName(apiSource),
  };
}

export function getSourceMeta(
  nameOrSource: string,
  type: IndexSourceType
): IndexSourceMeta | null {
  const display = getSourceDisplayMeta(nameOrSource);
  if (!display) return null;
  return {
    ...display,
    type,
  };
}

export function buildIndexSourceCandidateRows(
  rows: BrokerListingIndexSourceRow[],
  baseSymbol: string
): SourceItem[] {
  const normalizedBase = baseSymbol.trim().toUpperCase();
  return rows.map(row => {
    const meta = getSourceDisplayMeta(row.source);
    const isBuilderLike =
      row.type === "builder_oracle" || row.type === "byok_oracle";
    const indexSourceSymbol = row.source_symbol ?? normalizedBase;
    return {
      id: sourceKeyToItemId(row.source),
      source: row.source,
      name: meta?.name ?? row.source,
      type: row.type,
      found: !isBuilderLike,
      sourceSymbol: indexSourceSymbol,
      indexSourceSymbol,
      multiplier: 1,
      price: row.latest_price ?? 0,
      volume24h: 0,
      sourceId: row.source_id,
      uptime7dPct: row.uptime_7d_pct ?? null,
      skips7d: row.skips_7d ?? null,
      latestPriceTs:
        typeof row.last_update === "number"
          ? row.last_update
          : row.last_update
            ? Date.parse(String(row.last_update))
            : null,
      marketClosed: Boolean(row.market_closed),
      riskNotice:
        row.type === "builder_oracle"
          ? "This Source is provided by a third party and may go offline at any time."
          : null,
      health: row.health ?? null,
      weight: 0,
      selected: false,
      loading: isBuilderLike,
      priceLoading: isBuilderLike,
      volumeLoading: false,
      notFound: false,
    };
  });
}

export function mergeBuilderSourceRows(
  items: SourceItem[],
  rows: BrokerListingBuilderSourceRow[]
): SourceItem[] {
  const toKey = (sourceId: string, symbol?: string | null) =>
    `${String(sourceId).trim().toUpperCase()}::${String(symbol ?? "")
      .trim()
      .toUpperCase()}`;

  const rowMap = new Map<string, BrokerListingBuilderSourceRow>();
  for (const row of rows) {
    const baseCcy = (row as BrokerListingBuilderSourceRow).base_ccy;
    const symbols = new Set(
      [row.source_symbol, baseCcy]
        .filter(Boolean)
        .map(s => String(s).trim())
        .filter(Boolean)
    );

    // Always index by source_id only as last-resort fallback.
    rowMap.set(toKey(row.source_id), row);

    symbols.forEach(sym => {
      rowMap.set(toKey(row.source_id, sym), row);
    });
  }

  return items.map(item => {
    if (
      item.type !== IndexSourceType.BuilderOracle &&
      item.type !== IndexSourceType.Byok
    ) {
      return item;
    }

    const sourceId = item.sourceId ?? item.source;
    const itemSymbol = String(item.sourceSymbol ?? "")
      .trim()
      .toUpperCase();
    const matched =
      item.sourceSymbolManual && itemSymbol
        ? rowMap.get(toKey(sourceId, item.sourceSymbol))
        : (rowMap.get(toKey(sourceId, item.sourceSymbol)) ??
          rowMap.get(toKey(sourceId)));

    if (!matched) {
      return {
        ...item,
        found: false,
        loading: false,
        priceLoading: false,
        notFound: true,
        // Auto search failures clear the default symbol. Manual attempts keep
        // the user's input so they can continue editing and retry.
        sourceSymbol: item.sourceSymbolManual ? item.sourceSymbol : "",
      };
    }

    const price =
      matched.latest_price ??
      (matched as BrokerListingBuilderSourceRow).price ??
      0;
    const hasPrice = Number.isFinite(price) && price > 0;

    return {
      ...item,
      found: hasPrice,
      notFound: !hasPrice,
      loading: false,
      priceLoading: false,
      price,
      sourceId: matched.source_id,
      // When price is available, keep UI symbol aligned with broker listing
      // `index_sources` rows (source_symbol). Builder sources are only used for
      // pricing/health fields.
      sourceSymbol: hasPrice
        ? (item.indexSourceSymbol ?? item.sourceSymbol)
        : item.sourceSymbolManual
          ? item.sourceSymbol
          : "",
      sourceSymbolManual: hasPrice ? false : item.sourceSymbolManual,
      uptime7dPct: matched.uptime_7d_pct ?? null,
      skips7d: matched.skips_7d ?? null,
      latestPriceTs: matched.last_update ?? null,
      marketClosed: Boolean(matched.market_closed),
      health: matched.health ?? item.health ?? null,
      // If no price, ensure it can't remain selected in edit flows.
      selected: hasPrice ? item.selected : false,
      weight: hasPrice ? item.weight : 0,
    };
  });
}

export function appendBuilderSourceRows(input: {
  items: SourceItem[];
  rows: BrokerListingBuilderSourceRow[];
  /** Listing base symbol (already normalized). Used as fallback for sourceSymbol. */
  baseSymbol: string;
}): SourceItem[] {
  const { items, rows, baseSymbol } = input;
  if (rows.length === 0) return items;

  const existingIds = new Set(items.map(i => i.id));

  const appended: SourceItem[] = [];
  for (const row of rows) {
    const sourceId = row.source_id;
    if (!sourceId) continue;
    const id = sourceKeyToItemId(sourceId);
    if (existingIds.has(id)) continue;

    const meta = getSourceDisplayMeta(sourceId);
    const type = row.type ?? IndexSourceType.BuilderOracle;
    const sourceSymbol =
      row.source_symbol ?? row.base_ccy ?? baseSymbol.trim().toUpperCase();
    const price =
      row.latest_price ?? (row as BrokerListingBuilderSourceRow).price ?? 0;
    const hasPrice = Number.isFinite(price) && price > 0;

    appended.push({
      id,
      source: sourceId,
      name: meta?.name ?? sourceId,
      type,
      found: hasPrice,
      sourceSymbol,
      multiplier: 1,
      price,
      volume24h: 0,
      sourceId,
      uptime7dPct: row.uptime_7d_pct ?? null,
      skips7d: row.skips_7d ?? null,
      latestPriceTs: row.last_update ?? null,
      marketClosed: Boolean(row.market_closed),
      riskNotice:
        type === IndexSourceType.BuilderOracle ? BUILDER_RISK_NOTICE : null,
      health: row.health ?? null,
      loading: false,
      priceLoading: false,
      volumeLoading: false,
      notFound: !hasPrice,
      weight: 0,
      selected: false,
    });

    existingIds.add(id);
  }

  if (appended.length === 0) return items;
  return [...items, ...appended];
}

enum SourceProvider {
  Binance = "binance",
  Okx = "okx",
  Bybit = "bybit",
  Gateio = "gateio",
  Kucoin = "kucoin",
  Coinbase = "coinbase",
  Mexc = "mexc",
  Bitget = "bitget",
  Bingx = "bingx",
  Hyperliquid = "hyperliquid",
  Lbank = "lbank",
  Pyth = "pyth",
  Stork = "stork",
  BinanceFutures = "binance-futures",
  HyperliquidPerp = "hyperliquid-perp",
}

const API_SOURCE_TO_PROVIDER: Record<KnownApiSource, SourceProvider> = {
  BINANCE: SourceProvider.Binance,
  OKX: SourceProvider.Okx,
  BYBIT: SourceProvider.Bybit,
  GATEIO: SourceProvider.Gateio,
  KUCOIN: SourceProvider.Kucoin,
  COINBASE: SourceProvider.Coinbase,
  MEXC: SourceProvider.Mexc,
  BITGET: SourceProvider.Bitget,
  BINGX: SourceProvider.Bingx,
  HYPERLIQUID: SourceProvider.Hyperliquid,
  LBANK: SourceProvider.Lbank,
  PYTH: SourceProvider.Pyth,
  STORK: SourceProvider.Stork,
  BINANCEFUTURESINDEX: SourceProvider.BinanceFutures,
  HYPERLIQUIDPERP: SourceProvider.HyperliquidPerp,
};

function buildAggregatedQuoteUrl(
  provider: SourceProvider,
  base: string,
  symbol?: string,
  assetType?: ListingAssetType
) {
  const search = new URLSearchParams({ base });
  if (symbol) {
    search.set("symbol", symbol);
  }
  if (assetType) {
    search.set("assetType", assetType);
  }
  return `/api/price-sources/${provider}?${search.toString()}`;
}

function fetchQuoteFromProxy(
  provider: SourceProvider,
  base: string,
  symbol?: string,
  assetType?: ListingAssetType
) {
  return fetchJsonWithTimeout<ExternalSourceQuote>(
    buildAggregatedQuoteUrl(provider, base, symbol, assetType)
  );
}

export async function fetchExternalSourceQuote(input: {
  source: string;
  type: IndexSourceType;
  baseSymbol: string;
  sourceSymbol?: string;
  listingAssetType?: ListingAssetType;
}): Promise<ExternalSourceQuote> {
  const apiSource = normalizeSourceKey(input.source);
  const base = input.baseSymbol.trim().toUpperCase();
  const symbol = inferQuoteSymbol({
    apiSource,
    base,
    type: input.type,
    sourceSymbol: input.sourceSymbol,
    listingAssetType: input.listingAssetType,
  });
  const inferredBase = extractBaseToken(symbol) || base;
  const suggestedMultiplier = inferSuggestedMultiplier(
    input.baseSymbol,
    symbol
  );

  try {
    const provider = isKnownApiSource(apiSource)
      ? API_SOURCE_TO_PROVIDER[apiSource]
      : undefined;
    if (!provider) {
      return createNotFoundQuote({
        sourceSymbol: symbol,
        suggestedMultiplier,
      });
    }

    const quote = await fetchQuoteFromProxy(
      provider,
      inferredBase,
      symbol,
      input.listingAssetType
    );

    return {
      ...quote,
      suggestedMultiplier:
        apiSource === "PYTH" || apiSource === "STORK" ? 1 : suggestedMultiplier,
    };
  } catch {
    return createNotFoundQuote({
      sourceSymbol: symbol,
      suggestedMultiplier,
    });
  }
}
