import { useCallback, useState } from "react";
import { PLInput } from "../../components/Input";
import { Button } from "@/components/button";
import { useListingServerData } from "../../hooks/useListingServerData";
import { IPWhitelistSection } from "./IPWhitelistSection";

const VIP_BULLETS = [
  "Dedicated order execution gateway designed for faster and more reliable trading performance",
  "Supports both CROSS and ISOLATED orders for your market",
  "Not restricted by Reduce-Only rules",
];

export function MMAccountsSection() {
  const { listingConfig } = useListingServerData();

  const [copied, setCopied] = useState(false);

  const apiGateway = listingConfig.api_gateway ?? "";

  const copyGateway = useCallback(() => {
    if (!apiGateway) return;
    void navigator.clipboard.writeText(apiGateway).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 1500);
    });
  }, [apiGateway]);

  return (
    <div className="flex flex-col">
      <div className="bg-base-200 rounded-xl p-6 flex flex-col">
        <h4 className="text-xs font-semibold text-base-contrast-98 mb-4">
          VIP order gateway
        </h4>

        <ul className="flex flex-col gap-1.5 mb-5">
          {VIP_BULLETS.map(text => (
            <li
              key={text}
              className="flex items-start gap-2 text-3xs text-base-contrast-50 leading-relaxed"
            >
              <span className="mt-1.5 w-1 h-1 rounded-full bg-base-contrast-50 shrink-0" />
              {text}
            </li>
          ))}
        </ul>

        <div className="flex flex-col gap-2 mb-4">
          <label className="text-xs font-medium text-base-contrast-50">
            API gateway endpoint
          </label>
          <div className="flex gap-2">
            <PLInput
              type="text"
              readOnly
              disabled
              value={apiGateway}
              placeholder="—"
              className="cursor-not-allowed disabled:opacity-100 text-sm text-base-contrast-50 font-inherit"
            />
            {apiGateway && (
              <Button
                type="button"
                size="md"
                variant="ghost"
                rounded="lg"
                onClick={copyGateway}
                className="h-11 shrink-0 border border-base-contrast-12 bg-base-300 text-base-contrast-80 whitespace-nowrap hover:bg-base-300/90"
              >
                <span
                  key={copied ? "copied" : "copy"}
                  className="inline-flex min-w-[60px] justify-center animate-[fade-in_0.22s_ease-out]"
                >
                  {copied ? "Copied!" : "Copy"}
                </span>
              </Button>
            )}
          </div>
          <span className="text-3xs font-medium text-base-contrast-50">
            Provided by Orderly. Use this endpoint for VIP order execution.
          </span>
          {!apiGateway && (
            <span className="text-3xs text-danger font-medium mt-1">
              API Gateway is required
            </span>
          )}
        </div>

        <IPWhitelistSection />
      </div>
    </div>
  );
}
