import { useCallback, useMemo } from "react";
import type { SourceItem } from "../../../../types";
import { PriceSourceWeightMode, preserveOrRecalcWeights } from "./shared";
import {
  applyMultiplierUpdate,
  applyToggleAllSources,
  applyToggleSource,
  applyWeightUpdate,
  getSelectableSourcePool,
} from "./rules.helpers";

export type UsePriceSourcesSelectionParams = {
  priceSources: SourceItem[];
  setPriceSources: (sources: SourceItem[]) => void;
  editMode: boolean;
};

export function usePriceSourcesSelection({
  priceSources,
  setPriceSources,
  editMode,
}: UsePriceSourcesSelectionParams) {
  const toggleSource = useCallback(
    (id: string) => {
      setPriceSources(applyToggleSource(priceSources, id));
    },
    [priceSources, setPriceSources]
  );

  const toggleAll = useCallback(() => {
    setPriceSources(applyToggleAllSources(priceSources, editMode));
  }, [editMode, priceSources, setPriceSources]);

  const updateMultiplier = useCallback(
    (id: string, multiplier: number) => {
      setPriceSources(applyMultiplierUpdate(priceSources, id, multiplier));
    },
    [priceSources, setPriceSources]
  );

  const selectedCount = useMemo(
    () => priceSources.filter(s => s.selected).length,
    [priceSources]
  );

  const updateWeight = useCallback(
    (id: string, weightPercent: number) => {
      setPriceSources(applyWeightUpdate(priceSources, id, weightPercent));
    },
    [priceSources, setPriceSources]
  );

  const resetToEqual = useCallback(() => {
    setPriceSources(
      preserveOrRecalcWeights(priceSources, PriceSourceWeightMode.Equal)
    );
  }, [priceSources, setPriceSources]);

  const selectedWeightTotal = useMemo(
    () =>
      priceSources
        .filter(s => s.selected)
        .reduce((sum, source) => sum + (Number(source.weight) || 0), 0),
    [priceSources]
  );

  const weightsValid = useMemo(() => {
    if (selectedCount === 0) return false;
    return selectedWeightTotal === 100;
  }, [selectedCount, selectedWeightTotal]);

  const allFoundSelected = useMemo(() => {
    const pool = getSelectableSourcePool(priceSources, editMode);
    if (pool.length === 0) return false;
    const selectedInPool = pool.filter(s => s.selected).length;
    return selectedInPool === pool.length;
  }, [editMode, priceSources]);

  return {
    toggleSource,
    toggleAll,
    updateMultiplier,
    updateWeight,
    resetToEqual,
    selectedCount,
    selectedWeightTotal,
    weightsValid,
    allFoundSelected,
  };
}
