import { useMemo } from "react";
import { cn } from "@/utils/css";
import { OdsCheckbox } from "@/components/orderly/OdsCheckbox";
import { ArrowBackIcon } from "../../../components";
import { Button } from "@/components/button";
import { AssetTypePill } from "../AssetTypePill";
import { usePriceSourcesScript } from "./PriceSources.script";
import { SourceRow } from "./SourceRow";
import { getSelectableSourcePool } from "./hooks/rules.helpers";

/** Search icon (magnifying glass) for the symbol search input. */
function SearchIcon({ className }: { className?: string }) {
  return (
    <svg
      className={cn("shrink-0", className)}
      width={20}
      height={20}
      viewBox="0 0 20 20"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      aria-hidden
    >
      <path
        fillRule="evenodd"
        clipRule="evenodd"
        d="M9 3.5a5.5 5.5 0 1 0 0 11 5.5 5.5 0 0 0 0-11zM2 9a7 7 0 1 1 12.452 4.391l3.328 3.329a.75.75 0 1 1-1.06 1.06l-3.329-3.328A7 7 0 0 1 2 9z"
        fill="currentColor"
      />
    </svg>
  );
}

export function PriceSourcesPanel() {
  const {
    sources,
    searchTerm,
    setSearchTerm,
    searching,
    searchSources,
    toggleSource,
    toggleAll,
    updateSourceSymbol,
    refetchSourceQuoteNow,
    updateMultiplier,
    updateWeight,
    resetToEqual,
    selectedCount,
    selectedWeightTotal,
    weightsValid,
    allFoundSelected,
    onNext,
    onBack,
    onOpenCustomSymbol,
    listingAssetType,
    editMode,
    editSymbol,
    editTokenName,
    builderOracleSourceId,
    byokSourceIds,
  } = usePriceSourcesScript();

  const prettySymbol = editSymbol?.replace(/_broker\d+.*$/, "") ?? "";
  const searchInputValue = editMode ? editTokenName : searchTerm;
  const byokSourceIdSet = useMemo(
    () => new Set(byokSourceIds),
    [byokSourceIds]
  );

  const selectableForHeader = getSelectableSourcePool(sources, editMode);
  const someFoundSelected =
    selectableForHeader.length > 0 &&
    selectableForHeader.some(s => s.selected) &&
    !selectableForHeader.every(s => s.selected);

  const handleSearch = () => {
    searchSources(searchTerm.trim());
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === "Enter") handleSearch();
  };

  return (
    <div className="flex flex-col">
      {/* Header row: back arrow, title + description, Next */}
      <div className="flex items-center gap-4 mb-6">
        <button
          type="button"
          onClick={onBack}
          className="shrink-0 p-0 border-0 bg-transparent cursor-pointer opacity-70 hover:opacity-100 transition-opacity text-base-contrast-98"
          aria-label="Go back"
        >
          <ArrowBackIcon className="w-6 h-6" />
        </button>
        <div className="flex-1 min-w-0 flex flex-col gap-2">
          <div className="flex items-center gap-2.5">
            <span className="text-lg font-medium text-base-contrast-98 leading-tight">
              {editMode
                ? `Edit ${prettySymbol} — Price Sources`
                : "Step 1: Symbol Search & Sources"}
            </span>
            <AssetTypePill assetType={listingAssetType} className="shrink-0" />
          </div>
          <span className="text-xs font-medium text-base-contrast-50 leading-tight">
            Enter a base symbol to search unified CEX, Oracle, BYOK, and Builder
            Oracle sources. Please select at least 1 source.
          </span>
        </div>
        <Button
          type="button"
          size="sm"
          variant="outline"
          color="primary"
          rounded="full"
          className="shrink-0 bg-transparent px-5 text-xs"
          onClick={onOpenCustomSymbol}
        >
          <span className="mr-1 text-sm leading-none">+</span>
          Add custom symbol
        </Button>
        <Button
          type="button"
          size="sm"
          onClick={onNext}
          disabled={selectedCount === 0 || !weightsValid || searching}
          rounded="full"
          className={cn(
            "shrink-0 px-5 text-xs",
            "disabled:opacity-40 disabled:cursor-not-allowed"
          )}
        >
          Next
        </Button>
      </div>

      {/* Search area: panel with input + Search button + Selected count */}
      <div className="flex items-center gap-4 p-5 bg-base-200 rounded-xl mb-6">
        <div className="flex items-center gap-2 w-[400px] max-w-full h-10 rounded-lg pl-5 pr-3 bg-base-300 shrink-0">
          <SearchIcon className="w-5 h-5 text-base-contrast-36" />
          <input
            value={searchInputValue}
            onChange={e => setSearchTerm(e.target.value)}
            onKeyDown={handleKeyDown}
            readOnly={editMode}
            placeholder="e.g. BTC, ETH, SOL"
            className={cn(
              "flex-1 min-w-0 bg-transparent border-0 outline-none",
              "text-xs font-medium text-base-contrast-98 placeholder:text-base-contrast-36",
              editMode && "cursor-default text-base-contrast-50"
            )}
          />
        </div>
        <Button
          type="button"
          size="sm"
          variant="outline"
          color="primary"
          onClick={handleSearch}
          // if edit mode, allow research to update data
          disabled={!searchTerm.trim() || searching}
          rounded="full"
          className={cn(
            "shrink-0 px-5 text-xs",
            "bg-transparent text-white",
            "disabled:opacity-50 disabled:cursor-not-allowed",
            "hover:bg-primary/10"
          )}
        >
          Search
        </Button>
        <div className="ml-auto shrink-0 flex items-center gap-1.5 text-xs font-medium text-base-contrast-50">
          <span>Selected: {selectedCount}</span>
          {selectedCount > 0 ? (
            <>
              <span>&middot;</span>
              <span>
                Weights:{" "}
                <span
                  className={cn(
                    weightsValid ? "text-base-contrast-98" : "text-danger"
                  )}
                >
                  {selectedWeightTotal} / 100
                  {!weightsValid
                    ? ` (${selectedWeightTotal > 100 ? "+" : ""}${
                        selectedWeightTotal - 100
                      })`
                    : ""}
                </span>
              </span>
            </>
          ) : null}
          {selectedCount > 1 || (selectedCount > 0 && !weightsValid) ? (
            <>
              <span>&middot;</span>
              <button
                type="button"
                onClick={resetToEqual}
                className="border-0 bg-transparent p-0 text-xs font-medium text-primary cursor-pointer hover:underline"
              >
                Reset to equal
              </button>
            </>
          ) : null}
        </div>
      </div>

      {/* Table panel: always show, empty state or rows */}
      <div className="bg-base-200 rounded-[20px] mb-10 overflow-hidden">
        <table className="w-full border-collapse text-xs">
          <thead>
            <tr>
              <th className="w-5 py-6 px-6 text-left font-medium text-base-contrast-50 border-b border-base-contrast-6 align-middle whitespace-nowrap">
                <span className="inline-flex items-center h-[32px]">
                  <OdsCheckbox
                    checked={
                      someFoundSelected
                        ? "indeterminate"
                        : sources.length > 0
                          ? allFoundSelected
                          : false
                    }
                    onCheckedChange={toggleAll}
                    disabled={sources.length === 0}
                    aria-label="Select all sources"
                  />
                </span>
              </th>
              <th className="py-8 px-6 text-left font-medium text-base-contrast-50 border-b border-base-contrast-6 align-middle whitespace-nowrap">
                Source
              </th>
              <th className="py-8 px-6 text-left font-medium text-base-contrast-50 border-b border-base-contrast-6 align-middle whitespace-nowrap">
                Type
              </th>
              <th className="py-8 px-6 text-left font-medium text-base-contrast-50 border-b border-base-contrast-6 min-w-[140px] align-middle whitespace-nowrap">
                Source symbol
              </th>
              <th className="py-8 px-6 text-left font-medium text-base-contrast-50 border-b border-base-contrast-6 align-middle whitespace-nowrap">
                Price multiplier
              </th>
              <th className="py-8 px-6 text-left font-medium text-base-contrast-50 border-b border-base-contrast-6 align-middle whitespace-nowrap">
                Latest Price
              </th>
              <th className="py-8 px-6 text-left font-medium text-base-contrast-50 border-b border-base-contrast-6 align-middle whitespace-nowrap">
                24h Volume
              </th>
              <th className="py-8 px-4 text-left font-medium text-base-contrast-50 border-b border-base-contrast-6 w-[92px] align-middle whitespace-nowrap">
                Weight(%)
              </th>
            </tr>
          </thead>
          <tbody>
            {sources.length === 0 ? (
              <tr>
                <td
                  colSpan={8}
                  className="text-center text-xs font-medium text-base-contrast-50 py-12"
                >
                  Please enter a Base Symbol to search
                </td>
              </tr>
            ) : (
              sources.map(item => (
                <SourceRow
                  key={item.id}
                  item={item}
                  builderOracleSourceId={builderOracleSourceId}
                  byokSourceIdSet={byokSourceIdSet}
                  allowSelectWhenNotFound={editMode}
                  editMode={editMode}
                  onToggle={toggleSource}
                  onSymbolChange={updateSourceSymbol}
                  onSymbolBlur={refetchSourceQuoteNow}
                  onMultiplierChange={updateMultiplier}
                  onWeightChange={updateWeight}
                />
              ))
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}
