import { useMemo } from "react";
import { Button } from "@/components/button";
import {
  Dialog,
  DialogBody,
  DialogContent,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/dialog";
import type {
  BuilderOracleSource,
  ByokProvider,
  CustomOracleSymbolTarget,
} from "../../types";
import { findTargetName, footerClassName } from "./shared";

interface RemoveFeedModalProps {
  target: CustomOracleSymbolTarget | null;
  builderOracleSource: BuilderOracleSource;
  byokProviders: ByokProvider[];
  isMutating: boolean;
  onClose: () => void;
  onConfirm: (target: CustomOracleSymbolTarget) => Promise<void> | void;
}

export function RemoveFeedModal({
  target,
  builderOracleSource,
  byokProviders,
  isMutating,
  onClose,
  onConfirm,
}: RemoveFeedModalProps) {
  const targetName = useMemo(
    () => findTargetName(target, builderOracleSource, byokProviders),
    [target, builderOracleSource, byokProviders]
  );

  return (
    <Dialog
      open={target !== null}
      onOpenChange={nextOpen => {
        if (!nextOpen) onClose();
      }}
    >
      <DialogContent className="max-w-[440px]">
        <DialogHeader className="h-auto flex-col items-stretch gap-2 border-b-0 px-6 pt-6 pb-0">
          <DialogTitle className="text-lg font-medium text-base-contrast-98">
            Update feed status
          </DialogTitle>
        </DialogHeader>
        <DialogBody className="px-6 pb-0 text-2xs leading-6 text-base-contrast-54">
          Confirm the status change for {targetName}. This will update the feed
          through the oracle management API.
        </DialogBody>
        <DialogFooter className={`${footerClassName} mt-6`}>
          <Button
            variant="outline"
            color="primary"
            className="flex-1"
            disabled={isMutating}
            onClick={onClose}
          >
            Cancel
          </Button>
          <Button
            variant="outline"
            color="danger"
            className="flex-1"
            loading={isMutating}
            disabled={isMutating}
            onClick={() => {
              if (!target) return;
              onConfirm(target);
            }}
          >
            Confirm
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}
