import type { SymbolStatus } from "../../types";
import type { DashboardScriptReturn } from "./Dashboard.script";
import { StatGrid } from "./StatGrid";
import { AccountHealth } from "./AccountHealth";
import { SymbolCardView } from "./SymbolCardView";
import { RecentEvents } from "./RecentEvents";
import { EligibilityModal } from "../../modals";
import { Button } from "@/components/button";

export function DashboardPanelUI({
  statusFilter,
  setStatusFilter,
  loading,
  eligibility,
  closeEligibility,
  onCreateListing,
  onOpenCustomOracle,
  onGoToSettings,
  onEdit,
  onDelist,
}: DashboardScriptReturn) {
  if (loading) {
    return <DashboardPanelSkeleton />;
  }

  return (
    <div className="flex flex-col gap-6">
      <div className="flex items-center justify-between">
        <h2 className="text-xl font-medium text-base-contrast-98">
          Listing dashboard
        </h2>
        <div className="flex items-center gap-3">
          <Button
            size="md"
            variant="outline"
            color="primary"
            onClick={onOpenCustomOracle}
            className="bg-transparent"
          >
            Add custom oracle
          </Button>
          <Button
            size="md"
            variant="outline"
            color="primary"
            onClick={() => onGoToSettings()}
          >
            Account setting
          </Button>
          <Button onClick={onCreateListing} size="md">
            <span className="text-base leading-none mr-1">+</span>
            Create listing
          </Button>
        </div>
      </div>

      <StatGrid />

      <AccountHealth />

      <div className="flex flex-col gap-3">
        <div className="flex items-center justify-between">
          <h3 className="text-xs font-medium text-base-contrast-98">Symbols</h3>
          <StatusFilterDropdown
            active={statusFilter}
            onChange={setStatusFilter}
          />
        </div>
        <SymbolCardView
          onCreateListing={onCreateListing}
          onEdit={onEdit}
          onDelist={onDelist}
        />
      </div>

      <RecentEvents />

      {/* Keep mounted so internal TransferModal state survives closing the eligibility dialog. */}
      <EligibilityModal
        open={eligibility.open}
        onOpenChange={open => {
          if (!open) {
            closeEligibility();
          }
        }}
        gates={eligibility.gates}
        onManage={tab => {
          closeEligibility();
          onGoToSettings(tab);
        }}
      />
    </div>
  );
}

function statusFilterLabel(active: SymbolStatus[]): string {
  if (active.length === ALL_STATUSES.length) return "All Status";
  if (active.length === 0) return "None";
  if (active.length === 1) return STATUS_CONFIG[active[0]].label;
  return `${active.length} selected`;
}

function StatusFilterDropdown({
  active,
  onChange,
}: {
  active: SymbolStatus[];
  onChange: (f: SymbolStatus[]) => void;
}) {
  const [open, setOpen] = useState(false);
  const [pending, setPending] = useState<SymbolStatus[]>(active);
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    function handleClick(e: MouseEvent) {
      if (ref.current && !ref.current.contains(e.target as Node)) {
        setOpen(false);
      }
    }
    document.addEventListener("mousedown", handleClick);
    return () => document.removeEventListener("mousedown", handleClick);
  }, []);

  useEffect(() => {
    if (open) setPending(active);
  }, [open, active]);

  const togglePending = (status: SymbolStatus) => {
    setPending(prev =>
      prev.includes(status) ? prev.filter(s => s !== status) : [...prev, status]
    );
  };

  const handleReset = () => {
    setPending([...ALL_STATUSES]);
  };

  const handleApply = () => {
    onChange(pending);
    setOpen(false);
  };

  return (
    <div ref={ref} className="relative">
      <Button
        type="button"
        size="sm"
        variant="ghost"
        rounded="full"
        onClick={() => setOpen(o => !o)}
        className={cn(
          "gap-1.5 border text-2xs",
          "bg-base-200 border-base-contrast-8 text-base-contrast-50 hover:text-base-contrast-98 hover:border-base-contrast-20",
          "py-1.5 px-3.5"
        )}
      >
        <span>{statusFilterLabel(active)}</span>
        <svg className="w-3 h-3" viewBox="0 0 12 12" fill="none">
          <path
            d="M3 4.5L6 7.5L9 4.5"
            stroke="currentColor"
            strokeWidth="1.5"
            strokeLinecap="round"
            strokeLinejoin="round"
          />
        </svg>
      </Button>
      {open && (
        <div
          className="absolute top-[calc(100%+6px)] right-0 z-100 min-w-[170px] rounded-xl border border-base-contrast-8 bg-base-400 py-0 shadow-lg"
          role="dialog"
          aria-label="Status filter"
        >
          <div className="py-0">
            {ALL_STATUSES.map(st => (
              <label
                key={st}
                className={cn(
                  "flex items-center gap-2 px-3.5 py-2 text-2xs text-base-contrast-50 cursor-pointer transition-colors hover:bg-base-300"
                )}
              >
                <OdsCheckbox
                  checked={pending.includes(st)}
                  onCheckedChange={() => togglePending(st)}
                  className="size-4"
                />
                {STATUS_CONFIG[st].label}
              </label>
            ))}
          </div>
          <div className="flex gap-2 px-3.5 pt-2 pb-2.5 mt-0 border-t border-base-contrast-8">
            <Button
              type="button"
              size="sm"
              variant="ghost"
              rounded="lg"
              onClick={handleReset}
              className="flex-1 py-1.5 text-3xs text-base-contrast-50 hover:bg-base-contrast-[0.06] hover:text-base-contrast-98"
            >
              Reset
            </Button>
            <Button
              type="button"
              size="sm"
              onClick={handleApply}
              rounded="lg"
              className="flex-1 py-1.5 text-3xs"
            >
              Apply
            </Button>
          </div>
        </div>
      )}
    </div>
  );
}

