import * as React from "react";
import * as TooltipPrimitive from "@radix-ui/react-tooltip";
import { cn } from "@/utils";

export interface TooltipProps
  extends React.ComponentPropsWithoutRef<typeof TooltipPrimitive.Root> {
  className?: string;
  content?: React.ReactNode;
  disabled?: boolean;
  arrowClassName?: string;
}

type TooltipContentProps = Omit<
  React.ComponentPropsWithoutRef<typeof TooltipPrimitive.Content>,
  "content"
>;

const Tooltip: React.FC<TooltipProps & TooltipContentProps> = ({
  className,
  open,
  defaultOpen,
  onOpenChange,
  children,
  content,
  disabled,
  arrowClassName,
  ...props
}) => {
  if (disabled) return children as React.ReactElement;

  return (
    <TooltipPrimitive.Provider delayDuration={200}>
      <TooltipPrimitive.Root
        open={open}
        defaultOpen={defaultOpen}
        onOpenChange={onOpenChange}
      >
        <TooltipPrimitive.Trigger asChild className="cursor-pointer">
          {children}
        </TooltipPrimitive.Trigger>
        <TooltipPrimitive.Content
          side="right"
          align="start"
          sideOffset={26}
          className={cn(
            "rounded-xl bg-primary px-[12px] py-[11px] text-xs leading-[18px]",
            className
          )}
          {...props}
        >
          {content}
          <TooltipPrimitive.Arrow
            width={11}
            height={5}
            className={cn("fill-primary", arrowClassName)}
          />
        </TooltipPrimitive.Content>
      </TooltipPrimitive.Root>
    </TooltipPrimitive.Provider>
  );
};

export default Tooltip;
