/** Max symbol slots per broker. */
export function getSymbolListingLimit(): number {
  return 50;
}

const ACTIVE_IF_SYMBOL_STATUSES: SymbolStatus[] = [
  "NEW",
  "PENDING",
  "POST_ONLY",
  "ACTIVE",
  "REDUCE_ONLY",
];

type SymbolStatusRow = { status?: string | null };

export function isSymbolSlotUsed(status?: string | null): boolean {
  return ACTIVE_IF_SYMBOL_STATUSES.includes(status as SymbolStatus);
}

export function getSymbolSlotUsedCountFromListingStats(
  stats?: BrokerListingOverviewListingStats | null
): number {
  if (!stats) return 0;
  return (
    stats.new +
    stats.pending +
    stats.post_only +
    stats.active +
    stats.reduce_only
  );
}

export function getActiveIfSymbolCountFromRows(
  symbols?: readonly SymbolStatusRow[] | null
): number {
  return symbols?.filter(symbol => isSymbolSlotUsed(symbol.status)).length ?? 0;
}

export function getActiveIfSymbolCount(
  riskSnapshot?: BrokerListingRiskSnapshotData,
  listingSymbols?: readonly SymbolStatusRow[] | null
): number {
  if (listingSymbols) return getActiveIfSymbolCountFromRows(listingSymbols);
  if (riskSnapshot?.symbols?.length) {
    return getActiveIfSymbolCountFromRows(riskSnapshot.symbols);
  }
  return riskSnapshot?.active_symbol_count ?? 0;
}

