const IF_REQUIRED_PER_ACTIVE_SYMBOL = 25_000;

export function getIfRequired(
  riskSnapshot?: BrokerListingRiskSnapshotData,
  listingSymbols?: readonly SymbolStatusRow[] | null
) {
  return (
    IF_REQUIRED_PER_ACTIVE_SYMBOL *
    Math.max(getActiveIfSymbolCount(riskSnapshot, listingSymbols), 1)
  );
}

export function getIfRequiredPerSymbol() {
  return IF_REQUIRED_PER_ACTIVE_SYMBOL;
}

export function getIfRequiredForNewSymbol(
  riskSnapshot?: BrokerListingRiskSnapshotData,
  listingSymbols?: readonly SymbolStatusRow[] | null
) {
  return (
    IF_REQUIRED_PER_ACTIVE_SYMBOL *
    (getActiveIfSymbolCount(riskSnapshot, listingSymbols) + 1)
  );
}

export function getTierRequired(tier?: string) {
  if (TIER_REQUIREMENT_WAIVED) return true;
  if (!tier) return false;
  return (Object.values(TierKey) as string[]).includes(tier);
}
