import type { IndexSource } from "../../../types";
import { cn } from "@/utils/css";

function formatWeight(weight: number | undefined): string {
  if (weight === undefined) return "—";
  const pctInt = Math.round(weight);
  return Number.isFinite(pctInt) && pctInt > 0 ? `${pctInt}%` : "—";
}

function TypeBadge({
  className,
  children,
}: {
  className?: string;
  children: React.ReactNode;
}) {
  return (
    <span
      className={cn(
        "inline-flex items-center rounded-sm px-2 py-0.5",
        "text-4xs font-semibold leading-normal whitespace-nowrap",
        // migrated from mockup `.src-type-badge` (purple-06 + accent)
        "bg-primary/10 text-primary-light",
        className
      )}
    >
      {children}
    </span>
  );
}

function renderType(type: IndexSource["type"] | undefined): React.ReactNode {
  if (!type) return "—";
  if (type === "builder_oracle") return <TypeBadge>Builder Oracle</TypeBadge>;
  if (type === "byok_oracle") return <TypeBadge>BYOK</TypeBadge>;
  return String(type).toUpperCase();
}

export function SymbolDetailDataSourcesPanel(props: {
  indexSources: IndexSource[];
}) {
  const { indexSources } = props;
  const n = indexSources.length;

  return (
    <div className="bg-base-200 rounded-xl p-4 flex flex-col gap-3">
      <h3 className="text-xs font-medium text-base-contrast-98">
        Data sources ({n})
      </h3>
      <div className="overflow-x-auto overflow-y-auto max-h-[280px]">
        <table className="w-full min-w-[320px]">
          <thead>
            <tr className="border-b border-base-contrast-6">
              <th className="px-0 py-2 text-left text-3xs font-semibold text-base-contrast-50">
                Source
              </th>
              <th className="px-3 py-2 text-left text-3xs font-semibold text-base-contrast-50">
                Type
              </th>
              <th className="px-3 py-2 text-left text-3xs font-semibold text-base-contrast-50">
                Symbol
              </th>
              <th className="px-3 py-2 text-right text-3xs font-semibold text-base-contrast-50">
                Weight
              </th>
            </tr>
          </thead>
          <tbody>
            {n === 0 ? (
              <tr>
                <td
                  colSpan={4}
                  className="px-0 py-3 text-xs text-base-contrast-50"
                >
                  No sources configured.
                </td>
              </tr>
            ) : (
              indexSources.map((src, i) => (
                <tr
                  key={i}
                  className="border-b border-base-contrast-6 last:border-0"
                >
                  <td className="px-0 py-2.5 text-xs text-base-contrast-98">
                    <div className="flex flex-col">
                      <span>{src.source}</span>
                      {src.sourceId ? (
                        <span className="text-3xs text-base-contrast-50">
                          {src.sourceId}
                        </span>
                      ) : null}
                    </div>
                  </td>
                  <td className="px-3 py-2.5 text-xs text-base-contrast-98">
                    {renderType(src.type)}
                  </td>
                  <td className="px-3 py-2.5 text-xs font-medium text-base-contrast-98">
                    {src.sourceSymbol}
                  </td>
                  <td className="px-3 py-2.5 text-xs text-base-contrast-98 text-right tabular-nums">
                    {formatWeight(src.weight)}
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}
