import { useMemo } from "react";
import type { TradingParamsForm } from "../../../../types";

type UseTradingParamsDerivedInput = {
  form: TradingParamsForm;
  editSymbol: string | null;
};

export function useTradingParamsDerived({
  form,
  editSymbol,
}: UseTradingParamsDerivedInput) {
  const leverage = useMemo(() => {
    const v = parseFloat(form.max_leverage);
    return Number.isNaN(v) ? 0 : v;
  }, [form.max_leverage]);

  const imr = useMemo(() => (leverage > 0 ? 1 / leverage : 0), [leverage]);
  const mmr = useMemo(() => imr / 2, [imr]);

  const prettySymbol = useMemo(
    () => editSymbol?.replace(/_broker\d+.*$/, "") ?? "",
    [editSymbol]
  );

  return {
    leverage,
    imr,
    mmr,
    prettySymbol,
  };
}
