import { fmtUSDShort } from "../../utils";
import { AlertLevel } from "../../types";

export const DASH = "-";

export function formatUsdShortOrDash(v: number | null | undefined): string {
  if (v == null || Number.isNaN(v)) return DASH;
  return fmtUSDShort(v);
}

/** Notional USD for display: `openInterest * lastPrice`. Preserves null/NaN OI as absent. */
export function openInterestUsdValue(
  openInterest: number | null | undefined,
  lastPrice: number
): number | null {
  if (openInterest == null || Number.isNaN(openInterest)) return null;
  return openInterest * lastPrice;
}

export function formatIntOrDash(v: number | null | undefined): string {
  if (v == null || Number.isNaN(v)) return DASH;
  return new Intl.NumberFormat("en-US", { maximumFractionDigits: 0 }).format(v);
}

export function formatDepthOrDash(args: {
  bid: number | null | undefined;
  ask: number | null | undefined;
}): string {
  const { bid, ask } = args;
  if (bid == null && ask == null) return DASH;

  const fmtK = (n: number | null | undefined) =>
    n == null || Number.isNaN(n) ? DASH : `$${(n / 1000).toFixed(1)}K`;

  return `Bid ${fmtK(bid)} / Ask ${fmtK(ask)}`;
}

export function formatAlertLabelOrDash(
  level: AlertLevel | null | undefined
): string {
  if (!level) return DASH;
  switch (level) {
    case AlertLevel.Normal:
      return "Normal";
    case AlertLevel.Warning:
      return "Warning";
    case AlertLevel.Limit:
      return "Limit";
    default:
      return DASH;
  }
}

export function formatListedAtLabel(listedAt?: string | null): string | null {
  if (!listedAt) return null;

  const date = new Date(listedAt);
  if (Number.isNaN(date.getTime())) return listedAt;

  const formatted = new Intl.DateTimeFormat("en-US", {
    month: "short",
    day: "2-digit",
    year: "numeric",
    hour: "2-digit",
    minute: "2-digit",
    hour12: false,
  }).format(date);

  // Show local timezone offset, e.g. "UTC+8" or "UTC-3.5".
  const offsetMinutes = -date.getTimezoneOffset();
  const sign = offsetMinutes >= 0 ? "+" : "-";
  const offsetHours = Math.abs(offsetMinutes) / 60;
  const offsetStr = Number.isInteger(offsetHours)
    ? String(offsetHours)
    : offsetHours.toFixed(1);

  return `${formatted} UTC${sign}${offsetStr}`;
}
