import useSWR, { type SWRConfiguration, type SWRResponse } from "swr";
import { get } from "@orderly.network/net";
import { useSvQuery } from "@/hooks/useSvQuery";
import { useAppContext } from "@/components/provider/AppProvider";
import type { StrategyVaultFundInfoData, StrategyVaultInfoRow } from "./types";

/**
 * Public: Strategy Vault vault info.
 * GET /v1/public/strategy_vault/vault/info
 */
export function useStrategyVaultVaultInfo(options?: SWRConfiguration) {
  return useSvQuery<StrategyVaultInfoRow[]>(
    "/v1/public/strategy_vault/vault/info",
    {
      ...options,
      revalidateOnFocus: false,
    }
  );
}

export type StrategyVaultFundInfoInput = {
  sp_account_id: string;
  vault_id: string;
  wallet_address: string;
};

/**
 * Public: Strategy Vault fund info.
 * GET /v1/public/strategy_vault/fund/info?vault_id=...&wallet_address=...
 *
 * Returns a map (key: sp_account_id) -> orderly balance.
 */
export function useStrategyVaultFundInfoMap(
  inputs: StrategyVaultFundInfoInput[] | null | undefined,
  options?: SWRConfiguration
): SWRResponse<Map<string, number>> {
  const { configStore } = useAppContext();
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const svUrl = configStore.get("svUrl" as any) as string | undefined;

  const key =
    svUrl && inputs?.length
      ? [
          "sv:fund-info-map",
          svUrl,
          inputs.map(i => ({
            sp_account_id: i.sp_account_id,
            vault_id: i.vault_id,
            wallet_address: i.wallet_address,
          })),
        ]
      : null;

  return useSWR<Map<string, number>>(
    key,
    async ([, baseUrl, items]: [
      string,
      string,
      StrategyVaultFundInfoInput[],
    ]) => {
      const results = await Promise.allSettled(
        items.map(async i => {
          const qs = new URLSearchParams({
            vault_id: i.vault_id,
            wallet_address: i.wallet_address,
          });
          const res = (await get(
            `${baseUrl}/v1/public/strategy_vault/fund/info?${qs.toString()}`
          )) as StrategyVaultFundInfoData;

          return {
            sp_account_id: i.sp_account_id,
            orderlyBalance: res.balance?.orderly ?? 0,
          };
        })
      );

      const map = new Map<string, number>();
      results.forEach(r => {
        if (r.status !== "fulfilled") return;
        map.set(r.value.sp_account_id, r.value.orderlyBalance);
      });
      return map;
    },
    {
      revalidateOnFocus: false,
      dedupingInterval: 30_000,
      ...options,
    }
  );
}
