import { OnboardCheckIcon } from "@/permissionless-listing/components/icons";
import {
  TelegramChatIdField,
  type TelegramChatIdFieldHandle,
} from "@/permissionless-listing/components/TelegramChatIdField";
import { useRef, useState } from "react";

type OnboardingCompleteViewProps = {
  onSkip: () => void;
  onViewDashboard: () => Promise<void> | void;
};

export function OnboardingCompleteView({
  onSkip,
  onViewDashboard,
}: OnboardingCompleteViewProps) {
  const fieldRef = useRef<TelegramChatIdFieldHandle>(null);
  const [isSavingChatId, setIsSavingChatId] = useState(false);
  const [isViewPending, setIsViewPending] = useState(false);

  const handleViewDashboard = async () => {
    setIsViewPending(true);
    try {
      await fieldRef.current?.saveIfDirty();
      await onViewDashboard();
    } finally {
      setIsViewPending(false);
    }
  };

  const isSaving = isSavingChatId || isViewPending;

  return (
    <div className="max-w-[688px] mx-auto px-0">
      <div className="flex flex-col items-center justify-center text-center py-[120px] px-4">
        <div className="mb-4 flex items-center justify-center text-success">
          <OnboardCheckIcon className="w-12 h-12" />
        </div>
        <h2 className="text-lg font-medium text-base-contrast-98 mb-2">
          Account setup complete!
        </h2>
        <p className="text-xs text-base-contrast-50 mb-6 max-w-[480px]">
          You&apos;re all set to list your first perpetual contract.
        </p>

        <div className="w-full max-w-[480px] text-left bg-base-200 rounded-xl p-6 mb-6 border border-base-contrast-8">
          <h4 className="text-xs font-semibold text-base-contrast-98 mb-1">
            Telegram notification{" "}
            <span className="text-3xs font-normal text-base-contrast-50">
              (Optional)
            </span>
          </h4>
          <p className="text-2xs text-base-contrast-50 mb-4 leading-snug">
            Get real-time alerts for liquidations, depth warnings, and status
            changes.
          </p>
          <ol className="text-2xs text-base-contrast-50 mb-4 ml-4 list-decimal space-y-1 leading-relaxed">
            <li>
              Add bot:{" "}
              <a
                href="https://t.me/orderly_listing_bot"
                target="_blank"
                rel="noopener noreferrer"
                className="text-primary-light hover:underline"
              >
                https://t.me/orderly_listing_bot ↗
              </a>
            </li>
            <li>
              Send{" "}
              <code className="bg-base-300 px-1.5 py-0.5 rounded text-3xs">
                /start
              </code>{" "}
              in the group
            </li>
            <li>Enter the group&apos;s Chat ID below</li>
          </ol>
          <div className="flex flex-col gap-2">
            <TelegramChatIdField
              ref={fieldRef}
              onSavingChange={setIsSavingChatId}
              labelClassName="text-3xs"
              inputClassName="h-10"
            />
          </div>
        </div>

        <div className="flex gap-3 justify-center">
          <button
            type="button"
            onClick={onSkip}
            className="h-8 px-5 rounded-full border border-primary text-base-contrast-80 text-xs font-medium hover:bg-primary/10 transition-colors"
          >
            Skip
          </button>
          <button
            type="button"
            onClick={handleViewDashboard}
            disabled={isSaving}
            className="h-8 px-5 rounded-full bg-primary text-white text-xs font-medium hover:bg-primary/90 transition-colors"
          >
            View dashboard
          </button>
        </div>
      </div>
    </div>
  );
}
