import { useRef, type ReactNode } from "react";
import type { OnboardingStep } from "@/permissionless-listing/types";
import { cn } from "@/utils/css";
import {
  OnboardInsuranceIcon,
  OnboardCheckIcon,
} from "@/permissionless-listing/components/icons";
import { OrderlyIcon } from "@/permissionless-listing/components/icons/OrderlyIcon";
import { InsuranceFundStep } from "./InsuranceFundStep";
import { BrokerTierStep } from "./BrokerTierStep";
import type { UseInsuranceFundBindReturn } from "../hooks/useInsuranceFundBind";

type OnboardingCardProps = {
  step: OnboardingStep;
  onToggle: () => void;
  /** From `useInsuranceFundBind()` in onboarding script; only used for insurance-fund step. */
  ifBind: UseInsuranceFundBindReturn;
};

const STEP_ICONS: Record<string, ReactNode> = {
  tier: <OrderlyIcon />,
  "insurance-fund": <OnboardInsuranceIcon />,
};

export function OnboardingCard({
  step,
  onToggle,
  ifBind,
}: OnboardingCardProps) {
  const isTierStep = step.key === "tier";
  const hasExpandedBodyRef = useRef(false);
  if (step.expanded) {
    hasExpandedBodyRef.current = true;
  }
  const showExpandableBody = hasExpandedBodyRef.current;

  return (
    <div
      className={cn(
        "rounded-xl border bg-base-200 transition-colors",
        step.done
          ? "border-base-contrast-8"
          : "border-transparent hover:border-base-contrast-8",
        step.expanded && "z-10"
      )}
    >
      <button
        type="button"
        onClick={onToggle}
        className="flex items-center gap-3 w-full p-4 text-left cursor-pointer"
      >
        <div
          className={cn(
            "flex items-center justify-center w-9 h-9 rounded-[10px] shrink-0",
            isTierStep
              ? step.done
                ? "bg-[rgba(255,255,255,0.06)] text-success"
                : "bg-transparent"
              : step.done
                ? "bg-success/6 text-success"
                : "bg-primary/10 text-primary-light"
          )}
        >
          {step.done ? <OnboardCheckIcon /> : STEP_ICONS[step.key]}
        </div>

        <div className="flex min-w-0 flex-1 flex-col justify-center gap-0.5">
          <h4 className="text-sm font-medium text-base-contrast-98 leading-tight">
            {step.title}
          </h4>
          <p className="text-xs font-medium text-base-contrast-50 leading-tight">
            {step.description}
          </p>
        </div>

        <span
          className={cn(
            "shrink-0 text-3xs font-medium py-0.5 px-2.5 rounded-full",
            isTierStep
              ? step.done
                ? "bg-[rgba(255,255,255,0.06)] bg-linear-to-br from-[rgb(29,246,181)] to-[rgb(134,237,146)] bg-clip-text text-transparent"
                : "bg-[rgba(255,255,255,0.06)] text-[#D9AB52]"
              : step.done
                ? "bg-success/6 text-success"
                : "bg-[rgba(246,174,29,0.15)] text-[#D9AB52]"
          )}
        >
          {step.statusLabel ?? (step.done ? "Done" : "Required")}
        </span>

        <svg
          className={cn(
            "h-6 w-6 text-base-contrast-50 shrink-0 transition-transform duration-200 ease-out",
            step.expanded && "rotate-180"
          )}
          fill="none"
          viewBox="0 0 16 16"
          stroke="currentColor"
          strokeWidth={1.5}
        >
          <path
            d="M4 6L8 10L12 6"
            strokeLinecap="round"
            strokeLinejoin="round"
          />
        </svg>
      </button>

      {showExpandableBody && (
        <div
          className={cn(
            "grid transition-[grid-template-rows] duration-200 ease-out",
            step.expanded ? "grid-rows-[1fr]" : "grid-rows-[0fr]"
          )}
        >
          <div className="min-h-0 overflow-hidden">
            <div className="border-t border-base-contrast-8 px-4 pb-4 pt-0">
              <div className="pt-3 animate-[fade-in_0.2s_ease-out]">
                {step.key === "tier" && <BrokerTierStep />}
                {step.key === "insurance-fund" && (
                  <InsuranceFundStep bind={ifBind} hideInlineBind />
                )}
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
