import { useCallback, useMemo } from "react";
import { useNavigate } from "react-router-dom";
import { useSelectListingStore } from "../../../store/useListingStore";
import { ListingAssetType, ListingSubStep, PageView } from "../../../types";
import { ListingOrigin } from "../../../store/useListingStore";
import { toast } from "@/components/toast";
import {
  usePriceSourcesQuotes,
  usePriceSourcesSearch,
  usePriceSourcesSelection,
} from "./hooks";
import { getListingBaseFromSymbol } from "./hooks/shared";
import { useBuilderOracleFeeds, useByokKeys } from "../../../services";
import { useListingIndexSourcesData } from "../../../hooks/useListingIndexSourcesData";

export function usePriceSourcesScript() {
  const navigate = useNavigate();
  const {
    priceSources,
    listingAssetType,
    listingOrigin,
    editMode,
    editSymbol,
    symbolDetails,
    indexSources: storeIndexSources,
    setPriceSources,
    setListingStep,
    setPage,
  } = useSelectListingStore(s => ({
    priceSources: s.priceSources,
    listingAssetType: s.listingAssetType,
    listingOrigin: s.listingOrigin,
    editMode: s.editMode,
    editSymbol: s.editSymbol,
    symbolDetails: s.symbolDetails,
    indexSources: s.indexSources,
    setPriceSources: s.setPriceSources,
    setListingStep: s.setListingStep,
    setPage: s.setPage,
  }));
  const { indexSources: apiIndexSources } = useListingIndexSourcesData();
  const indexSources = storeIndexSources.length
    ? storeIndexSources
    : apiIndexSources;

  const { data: builderOracleFeeds } = useBuilderOracleFeeds({
    revalidateOnFocus: false,
  });
  const { data: byokKeysData } = useByokKeys({ revalidateOnFocus: false });

  const builderOracleSourceId = builderOracleFeeds?.source_id ?? null;
  const byokSourceIds = useMemo(() => {
    const rows = byokKeysData?.rows ?? [];
    return rows.map(r => r.source_id).filter(Boolean);
  }, [byokKeysData?.rows]);
  const editDetail =
    editMode && editSymbol ? symbolDetails[editSymbol] : undefined;
  const editTokenName = useMemo(() => {
    if (!editMode || !editSymbol) return "";
    const tokenName = String(
      editDetail?.params?.base_token?.value ??
        editDetail?.params?.base_symbol?.value ??
        ""
    ).trim();
    return tokenName || getListingBaseFromSymbol(editSymbol);
  }, [
    editDetail?.params?.base_symbol?.value,
    editDetail?.params?.base_token?.value,
    editMode,
    editSymbol,
  ]);

  const {
    searchTerm,
    setSearchTerm,
    searching,
    searchSources,
    sourcesRef,
    refetchBuilderSources,
  } = usePriceSourcesSearch({
    priceSources,
    setPriceSources,
    editMode,
    editSymbol,
    symbolDetails,
    indexSources,
  });

  const effectiveBase = useMemo(
    () => searchTerm.trim().toUpperCase(),
    [searchTerm]
  );

  const searchSourcesWithBuilderRefetch = useCallback(
    (
      baseSymbol: Parameters<typeof searchSources>[0],
      options?: Parameters<typeof searchSources>[1]
    ) => {
      const res = searchSources(baseSymbol, options);
      const normalizedBase = baseSymbol.trim().toUpperCase();
      if (normalizedBase && normalizedBase === effectiveBase) {
        void refetchBuilderSources(normalizedBase);
      }
      return res;
    },
    [effectiveBase, refetchBuilderSources, searchSources]
  );

  const { updateSourceSymbol, refetchSourceQuoteNow } = usePriceSourcesQuotes({
    priceSources,
    sourcesRef,
    setPriceSources,
    searchTerm,
    editMode,
    editSymbol,
    symbolDetails,
    refetchBuilderSources,
    listingAssetType: listingAssetType ?? undefined,
  });

  const {
    toggleSource,
    toggleAll,
    updateMultiplier,
    updateWeight,
    resetToEqual,
    selectedCount,
    selectedWeightTotal,
    weightsValid,
    allFoundSelected,
  } = usePriceSourcesSelection({
    priceSources,
    setPriceSources,
    editMode,
  });

  const onNext = useCallback(() => {
    if (selectedCount === 0) {
      toast.error("Please select at least one price source.");
      return;
    }
    if (!weightsValid) {
      toast.error("Source weights must add up to 100 before continuing.");
      return;
    }
    setListingStep(ListingSubStep.TradingParams);
  }, [selectedCount, weightsValid, setListingStep]);

  const onBack = useCallback(() => {
    if (
      editMode &&
      editSymbol &&
      listingOrigin === ListingOrigin.SymbolDetail
    ) {
      setPage(PageView.SymbolDetail, { symbol: editSymbol });
      navigate(`/permissionless-listing/${encodeURIComponent(editSymbol)}`);
      return;
    }
    setPage(PageView.Dashboard);
  }, [editMode, editSymbol, listingOrigin, navigate, setPage]);

  const onOpenCustomSymbol = useCallback(() => {
    setPage(PageView.CustomOracle, {
      origin: "listing-price-sources",
      tab: "builder",
    });
  }, [setPage]);

  return {
    sources: priceSources,
    searchTerm,
    setSearchTerm,
    searching,
    searchSources: searchSourcesWithBuilderRefetch,
    toggleSource,
    toggleAll,
    updateSourceSymbol,
    refetchSourceQuoteNow,
    updateMultiplier,
    updateWeight,
    resetToEqual,
    selectedCount,
    selectedWeightTotal,
    weightsValid,
    allFoundSelected,
    onNext,
    onBack,
    onOpenCustomSymbol,
    listingAssetType: listingAssetType ?? ListingAssetType.Crypto,
    editMode,
    editSymbol,
    editTokenName,
    builderOracleSourceId,
    byokSourceIds,
  };
}
