import { useCallback } from "react";
import type { Dispatch, SetStateAction } from "react";
import { toast } from "@/components/toast";
import { ListingAssetType, type TradingParamsForm } from "../../../../types";
import { normalizeTradingParamsForm, parseRateFormValue } from "./shared";
import { COPY_LLM_PROMPT } from "@/permissionless-listing/copyLLMText";

type UseTradingParamsImportAndCopyInput = {
  setForm: Dispatch<SetStateAction<TradingParamsForm>>;
};

export function useTradingParamsImportAndCopy({
  setForm,
}: UseTradingParamsImportAndCopyInput) {
  const importJSON = useCallback(() => {
    const input = document.createElement("input");
    input.type = "file";
    input.accept = ".json";
    input.onchange = async e => {
      const file = (e.target as HTMLInputElement).files?.[0];
      if (!file) return;
      try {
        const text = await file.text();
        const raw = JSON.parse(text) as unknown;
        if (!raw || typeof raw !== "object") {
          toast.error("Failed to parse JSON file");
          return;
        }

        const obj = raw as Record<string, unknown>;
        const pickString = (key: string): string | undefined => {
          const v = obj[key];
          if (typeof v === "string") return v;
          if (typeof v === "number" && Number.isFinite(v)) return String(v);
          return undefined;
        };

        // {
        //   "max_leverage": 10,
        //   "global_max_oi": 1000000,
        //   "max_notional_user": 200000,
        //   "funding_period": "8h",
        //   "std_liquidation_fee": 0.015,
        //   "claim_IF_discount": 0.0075
        // }
        const data: Partial<TradingParamsForm> = {
          max_leverage: pickString("max_leverage"),
          global_max_oi: pickString("global_max_oi"),
          max_notional_user: pickString("max_notional_user"),
          funding_period: pickString("funding_period"),
          std_liquidation_fee: pickString("std_liquidation_fee"),
          claim_IF_discount: pickString("claim_IF_discount"),
          listing_asset_type:
            pickString("listing_asset_type") === ListingAssetType.Rwa
              ? ListingAssetType.Rwa
              : undefined,
          rwa_market_session: pickString("rwa_market_session") as
            | TradingParamsForm["rwa_market_session"]
            | undefined,
          // base_symbol: pickString("base_symbol"),
        };

        if (typeof data.max_leverage === "string") {
          data.max_leverage = data.max_leverage.trim().replace(/x$/i, "");
        }
        if (typeof data.std_liquidation_fee === "string") {
          data.std_liquidation_fee = parseRateFormValue(
            data.std_liquidation_fee
          );
        }
        if (typeof data.claim_IF_discount === "string") {
          data.claim_IF_discount = parseRateFormValue(data.claim_IF_discount);
        }

        setForm(prev => normalizeTradingParamsForm(data, prev));
        toast.success("Parameters imported");
      } catch {
        toast.error("Failed to parse JSON file");
      }
    };
    input.click();
  }, [setForm]);

  const copyForLLM = useCallback(async () => {
    try {
      await navigator.clipboard.writeText(COPY_LLM_PROMPT);
      toast.success("Copied to clipboard");
    } catch {
      toast.error("Failed to copy to clipboard");
    }
  }, []);

  return { importJSON, copyForLLM };
}
