import type { ReactNode } from "react";

import { cn } from "@/utils/css";
import { AlertLevel } from "../../../types";

export const ALERT_CONFIG: Record<
  AlertLevel,
  { label: string; color: string; bg: string }
> = {
  [AlertLevel.Normal]: {
    label: "Normal",
    color: "text-success",
    bg: "bg-success/15",
  },
  [AlertLevel.Warning]: {
    label: "Warning",
    color: "text-warning",
    bg: "bg-warning/15",
  },
  [AlertLevel.Limit]: {
    label: "Limit",
    color: "text-danger",
    bg: "bg-danger/15",
  },
};

export function MetricCard({
  label,
  value,
  valueClassName,
}: {
  label: string;
  value: string;
  valueClassName?: string;
}) {
  return (
    <div className="bg-base-200 rounded-xl p-4 flex flex-col gap-1.5">
      <span className="text-2xs font-medium text-base-contrast-50">
        {label}
      </span>
      <span
        className={cn(
          "text-xs font-medium text-base-contrast-98 tabular-nums min-h-[40px]",
          valueClassName
        )}
      >
        {value}
      </span>
    </div>
  );
}

export function DetailSection({
  title,
  rows,
}: {
  title: string;
  rows: { label: string; value: string }[];
}) {
  return (
    <div className="flex flex-col gap-2">
      <span className="text-xs font-medium text-base-contrast-98">{title}</span>
      {rows.map(r => (
        <DetailRow key={r.label} label={r.label} value={r.value} />
      ))}
    </div>
  );
}

export function DetailRow({
  label,
  value,
  valueClassName,
}: {
  label: string;
  value: ReactNode;
  valueClassName?: string;
}) {
  return (
    <div className="flex justify-between items-center gap-4">
      <span className="text-xs font-medium text-base-contrast-50 w-1/3 shrink-0">
        {label}
      </span>
      {typeof value === "string" ? (
        <span
          className={cn(
            "text-xs font-medium text-base-contrast-98 tabular-nums",
            valueClassName
          )}
        >
          {value}
        </span>
      ) : (
        <div
          className={cn(
            "min-w-0 flex justify-end text-xs font-medium text-base-contrast-98",
            valueClassName
          )}
        >
          {value}
        </div>
      )}
    </div>
  );
}

export function DetailInfoCard({
  label,
  value,
  className,
}: {
  label: string;
  value: string;
  className?: string;
}) {
  return (
    <div
      className={cn(
        "bg-base-300 rounded-xl p-4 flex flex-col gap-2 min-w-0",
        className
      )}
    >
      <span className="text-xs font-medium text-base-contrast-98">{label}</span>
      <span className="text-base font-medium text-primary-light truncate tabular-nums">
        {value}
      </span>
    </div>
  );
}
