import { useState, useMemo, useCallback, useEffect } from "react";
import { PageView, type OnboardingStep } from "../../types";
import { useSelectListingStore } from "../../store/useListingStore";
import { getTierRequired, TIER_REQUIREMENT_WAIVED } from "../../constants";
import { useInsuranceFundBind } from "./hooks/useInsuranceFundBind";
import { useListingServerData } from "../../hooks/useListingServerData";

export function useOnboardingScript() {
  const [expandedKeys, setExpandedKeys] = useState<Set<string>>(
    () => new Set()
  );
  const [hasInteracted, setHasInteracted] = useState(false);

  const { setPage, setForceOnboarding } = useSelectListingStore(s => ({
    setPage: s.setPage,
    setForceOnboarding: s.setForceOnboarding,
  }));
  const { brokerInfo, listingAccounts } = useListingServerData();

  const ifBind = useInsuranceFundBind();
  const { isCompleting, canCompleteIfBind, completeIfBindIfNeeded } = ifBind;

  const tierRequired = useMemo(
    () => getTierRequired(brokerInfo?.type),
    [brokerInfo?.type]
  );
  const showTierWaiverOffer =
    TIER_REQUIREMENT_WAIVED && brokerInfo?.type !== "DIAMOND";

  const hasIfAccount = Boolean(listingAccounts?.if_account?.account_id);

  const canCompleteOnboarding = useMemo(() => {
    return tierRequired && canCompleteIfBind;
  }, [tierRequired, canCompleteIfBind]);

  const completeOnboardingIfNeeded = useCallback(async (): Promise<boolean> => {
    if (!tierRequired) return false;
    return completeIfBindIfNeeded();
  }, [tierRequired, completeIfBindIfNeeded]);

  const steps: OnboardingStep[] = useMemo(() => {
    return [
      {
        key: "tier",
        title: "Builder tier",
        description: showTierWaiverOffer
          ? "Exclusive offer: list permissionless at any tier."
          : "Diamond tier is required to list symbols.",
        done: tierRequired,
        expanded: expandedKeys.has("tier"),
        statusLabel: showTierWaiverOffer ? "Waived" : undefined,
      },
      {
        key: "insurance-fund",
        title: "Insurance fund account",
        description:
          "Required to cover user positions during liquidation events.",
        done: hasIfAccount,
        expanded: expandedKeys.has("insurance-fund"),
      },
    ];
  }, [expandedKeys, tierRequired, hasIfAccount, showTierWaiverOffer]);

  const completedCount = useMemo(
    () => steps.filter(s => s.done).length,
    [steps]
  );

  const progress = useMemo(
    () => (steps.length > 0 ? (completedCount / steps.length) * 100 : 0),
    [completedCount, steps.length]
  );

  const allDone = useMemo(
    () => completedCount === steps.length,
    [completedCount, steps.length]
  );

  useEffect(() => {
    if (hasInteracted) return;
    if (expandedKeys.size > 0) return;
    const firstIncompleteKey = !tierRequired
      ? "tier"
      : !hasIfAccount
        ? "insurance-fund"
        : undefined;
    const targetKey = firstIncompleteKey ?? "tier";
    setExpandedKeys(new Set([targetKey]));
  }, [tierRequired, hasIfAccount, expandedKeys.size, hasInteracted]);

  const toggleExpand = useCallback((key: string) => {
    setHasInteracted(true);
    setExpandedKeys(prev => {
      if (prev.has(key)) return new Set<string>();
      return new Set([key]);
    });
  }, []);

  const onDone = useCallback(() => {
    setPage(PageView.Dashboard);
    setForceOnboarding(false);
  }, [setPage, setForceOnboarding]);

  return {
    steps,
    completedCount,
    progress,
    allDone,
    canCompleteOnboarding,
    completeOnboardingIfNeeded,
    isCompleting,
    ifBind,
    toggleExpand,
    onDone,
  };
}

export type OnboardingScriptReturn = ReturnType<typeof useOnboardingScript>;
