import {
  buildIndexSourceCandidateRows,
  fetchExternalSourceQuote,
  normalizeSourceKey,
  sourceKeyToItemId,
} from "../../../../services";
import type { BrokerListingIndexSourceRow } from "../../../../services";
import { ListingAssetType } from "../../../../types";
import type {
  IndexSourceMeta,
  SourceItem,
  SymbolDetail,
} from "../../../../types";
import {
  PriceSourceWeightMode,
  getListingBaseFromSymbol,
  type SavedRowMerge,
} from "./shared";
import { isBuilderLikeSourceType } from "./rules.helpers";

export function getSearchEditContext(input: {
  editMode: boolean;
  editSymbol: string | null;
  symbolDetails: Record<string, SymbolDetail>;
  normalizedBase: string;
}) {
  const listingBase =
    input.editMode && input.editSymbol
      ? getListingBaseFromSymbol(input.editSymbol)
      : "";
  const detail =
    input.editMode && input.editSymbol
      ? input.symbolDetails[input.editSymbol]
      : undefined;
  const sameListingBase = Boolean(
    listingBase && detail && input.normalizedBase === listingBase
  );

  return {
    detail,
    mergeDetail: input.editMode && sameListingBase,
  };
}

function isIndexSourceApiRow(row: unknown): row is BrokerListingIndexSourceRow {
  return (
    typeof row === "object" &&
    row !== null &&
    typeof (row as { source?: unknown }).source === "string"
  );
}

export function normalizeIndexSourceApiRows(
  rawRows: unknown
): BrokerListingIndexSourceRow[] {
  return (Array.isArray(rawRows) ? rawRows : []).filter(
    (source): source is BrokerListingIndexSourceRow =>
      isIndexSourceApiRow(source) && source.source !== "HYPERLIQUID"
  );
}

export function buildInitialSourceRows(input: {
  apiRows: BrokerListingIndexSourceRow[];
  normalizedBase: string;
  savedMap: Map<string, SavedRowMerge> | null;
}): SourceItem[] {
  return buildIndexSourceCandidateRows(input.apiRows, input.normalizedBase).map(
    row => {
      const saved = input.savedMap?.get(row.id);
      const isBuilderOrByok = isBuilderLikeSourceType(row.type);
      return {
        ...row,
        name: row.name,
        found: Boolean(saved) || row.found,
        sourceSymbol: saved?.sourceSymbol ?? row.sourceSymbol,
        feedId: saved?.feedId ?? row.feedId,
        multiplier: saved?.multiplier ?? row.multiplier,
        price: saved?.price ?? row.price,
        volume24h: saved?.volume24h ?? row.volume24h,
        weight: saved?.weight ?? row.weight,
        selected: Boolean(saved),
        selectedFromDetail: Boolean(saved),
        // Builder Oracle / BYOK volume does not use external quote fetching.
        volumeLoading: isBuilderOrByok ? false : true,
        priceLoading: true,
        loading: true,
      };
    }
  );
}

export function getSearchWeightMode(input: {
  mergeDetail: boolean;
  preserveExistingWeights: boolean;
}) {
  return input.mergeDetail && input.preserveExistingWeights
    ? PriceSourceWeightMode.Preserve
    : PriceSourceWeightMode.Equal;
}

export function applySourcePatch(input: {
  sources: SourceItem[];
  rowId: string;
  patch: Partial<SourceItem>;
}) {
  const { sources, rowId, patch } = input;
  return sources.map(source =>
    source.id === rowId
      ? {
          ...source,
          ...patch,
          sourceSymbol:
            patch.sourceSymbol !== undefined
              ? patch.sourceSymbol
              : source.sourceSymbol,
          feedId: patch.feedId !== undefined ? patch.feedId : source.feedId,
          multiplier:
            patch.multiplier !== undefined
              ? patch.multiplier
              : source.multiplier,
          price: patch.price !== undefined ? patch.price : source.price,
          volume24h:
            patch.volume24h !== undefined ? patch.volume24h : source.volume24h,
        }
      : source
  );
}

export async function fetchQuotePatchForSource(input: {
  row: IndexSourceMeta;
  normalizedBase: string;
  saved: SavedRowMerge | undefined;
  mergeDetail: boolean;
  listingAssetType?: ListingAssetType;
}): Promise<{ rowId: string; patch: Partial<SourceItem> }> {
  const { row, normalizedBase, saved, mergeDetail, listingAssetType } = input;
  const rowId = sourceKeyToItemId(row.source);
  const apiSource = normalizeSourceKey(row.source);

  const quoteSymbol =
    apiSource === "PYTH" && saved?.feedId ? saved.feedId : saved?.sourceSymbol;
  const forceListedSavedRow = mergeDetail && saved !== undefined;
  const basePatch: Partial<SourceItem> = {
    loading: false,
    priceLoading: false,
    volumeLoading: false,
  };

  try {
    const quote = await fetchExternalSourceQuote({
      source: row.source,
      type: row.type,
      baseSymbol: normalizedBase,
      ...(quoteSymbol ? { sourceSymbol: quoteSymbol } : {}),
      listingAssetType,
    });

    return {
      rowId,
      patch: {
        ...basePatch,
        found: forceListedSavedRow || quote.found,
        notFound: forceListedSavedRow ? false : !quote.found,
        sourceSymbol: forceListedSavedRow
          ? undefined
          : quote.found
            ? quote.sourceSymbol
            : "",
        feedId: quote.found ? quote.feedId : undefined,
        multiplier:
          !forceListedSavedRow && quote.found
            ? quote.suggestedMultiplier
            : undefined,
        price: quote.found ? quote.latestPrice : undefined,
        volume24h: quote.found ? quote.volume24h : undefined,
      },
    };
  } catch {
    return {
      rowId,
      patch: basePatch,
    };
  }
}
