import {
  useCallback,
  useEffect,
  useRef,
  useState,
  type ChangeEvent,
  type RefObject,
} from "react";
import { toast } from "@/components/toast";
import { useAppContext } from "@/components/provider/AppProvider";
import {
  BROKER_SYMBOL_LOGO_MAX_BYTES,
  brokerSymbolLogoUploadSizeExceededMessage,
  buildBrokerSymbolLogoPublicUrl,
  deriveBrokerSymbolLogoFileBaseName,
} from "@/utils/brokerSymbolLogoUpload";
import { useAdminAuthHeaders } from "@/hooks/useAdminAuthHeaders";

const ADMIN_INFO_API_URL = "/v1/referral/admin_info";

export interface BrokerSymbolLogoUploadController {
  uploading: boolean;
  logoUrl: string | null;
  fileInputRef: RefObject<HTMLInputElement | null>;
  onFileChange: (e: ChangeEvent<HTMLInputElement>) => void;
  disabled: boolean;
  openFilePicker: () => void;
}

type UploadBrokerSymbolLogoFileParams = {
  symbolPreview: string;
  file: File;
  logged: boolean;
  buildGetHeaders: (requestUrl: string) => Promise<HeadersInit>;
};

export function validateBrokerSymbolLogoFile(file: File): string | null {
  const isPng =
    file.type === "image/png" || file.name.toLowerCase().endsWith(".png");
  if (!isPng) {
    return "Please select a PNG image.";
  }
  if (file.size > BROKER_SYMBOL_LOGO_MAX_BYTES) {
    return brokerSymbolLogoUploadSizeExceededMessage();
  }
  return null;
}

async function validateBrokerSymbolLogoDimensions(
  file: File
): Promise<string | null> {
  const DIMENSION = 64;
  const objectUrl = URL.createObjectURL(file);

  try {
    const dimensions = await new Promise<{ width: number; height: number }>(
      (resolve, reject) => {
        const img = new Image();
        img.onload = () => {
          resolve({
            width: img.naturalWidth,
            height: img.naturalHeight,
          });
        };
        img.onerror = () => reject(new Error("invalid-image"));
        img.src = objectUrl;
      }
    );

    if (dimensions.width !== DIMENSION || dimensions.height !== DIMENSION) {
      return `Please upload a ${DIMENSION}×${DIMENSION} PNG image.`;
    }

    return null;
  } catch {
    return "Unable to read the selected image. Please try another PNG.";
  } finally {
    URL.revokeObjectURL(objectUrl);
  }
}

export function getBrokerSymbolLogoFileName(
  symbolPreview: string
): string | null {
  const baseName = deriveBrokerSymbolLogoFileBaseName(symbolPreview.trim());
  if (!baseName) return null;
  return `${baseName}.png`;
}

export async function fetchBrokerSymbolLogoObjectPathPrefix(): Promise<
  string | null
> {
  try {
    const res = await fetch("/api/upload/broker-symbol-logo");
    const json: unknown = await res.json();
    const parsed = json as {
      success?: boolean;
      objectPathPrefix?: string;
    };
    if (
      parsed.success &&
      typeof parsed.objectPathPrefix === "string" &&
      parsed.objectPathPrefix.length > 0
    ) {
      return parsed.objectPathPrefix;
    }
  } catch {
    // Ignore probe/bootstrap errors; callers can treat them as "no remote logo".
  }
  return null;
}

export async function probeBrokerSymbolLogoUrl(options: {
  symbolPreview: string;
  objectPathPrefix: string | null;
}): Promise<string | null> {
  const { symbolPreview, objectPathPrefix } = options;
  if (!objectPathPrefix) return null;

  const fileName = getBrokerSymbolLogoFileName(symbolPreview);
  if (!fileName) return null;

  const url = buildBrokerSymbolLogoPublicUrl(`${objectPathPrefix}/${fileName}`);
  const probeUrl = (() => {
    const hashIndex = url.indexOf("#");
    const base = hashIndex >= 0 ? url.slice(0, hashIndex) : url;
    const hash = hashIndex >= 0 ? url.slice(hashIndex) : "";
    const separator = base.includes("?") ? "&" : "?";
    return `${base}${separator}v=${Date.now()}${hash}`;
  })();

  return new Promise(resolve => {
    const img = new Image();
    // Use cache-busted URL only for probing existence; callers will apply their own cache policy.
    img.onload = () => resolve(url);
    img.onerror = () => resolve(null);
    img.src = probeUrl;
  });
}

export async function uploadBrokerSymbolLogoFile({
  symbolPreview,
  file,
  logged,
  buildGetHeaders,
}: UploadBrokerSymbolLogoFileParams): Promise<{ logoUrl: string }> {
  const validationMessage = validateBrokerSymbolLogoFile(file);
  if (validationMessage) {
    throw new Error(validationMessage);
  }

  const dimensionValidationMessage =
    await validateBrokerSymbolLogoDimensions(file);
  if (dimensionValidationMessage) {
    throw new Error(dimensionValidationMessage);
  }

  const fileName = getBrokerSymbolLogoFileName(symbolPreview);
  if (!fileName) {
    throw new Error(
      "Cannot derive a logo file name from the current symbol preview. Check listing base and preview."
    );
  }

  if (!logged) {
    throw new Error("Please login.");
  }

  const headers = await buildGetHeaders(ADMIN_INFO_API_URL);
  const body = new FormData();
  body.append("file", file);
  body.append("fileName", fileName);

  const res = await fetch("/api/upload/broker-symbol-logo", {
    method: "POST",
    body,
    headers,
  });
  const json: unknown = await res.json();
  const parsed = json as {
    success?: boolean;
    message?: string;
    data?: { gcsUrl?: string; publicUrl?: string };
  };

  if (!parsed.success || !parsed.data?.publicUrl) {
    throw new Error(
      typeof parsed.message === "string" ? parsed.message : "Upload failed"
    );
  }

  return { logoUrl: parsed.data.publicUrl };
}

export function useBrokerSymbolLogoRemoteUrl(options: {
  symbolPreview: string;
}) {
  const uploadSymbolKey = options.symbolPreview.trim();
  const [objectPathPrefix, setObjectPathPrefix] = useState<string | null>(null);
  const [remoteLogoUrl, setRemoteLogoUrl] = useState<string | null>(null);

  useEffect(() => {
    let cancelled = false;
    (async () => {
      const nextPrefix = await fetchBrokerSymbolLogoObjectPathPrefix();
      if (!cancelled) {
        setObjectPathPrefix(nextPrefix);
      }
    })();

    return () => {
      cancelled = true;
    };
  }, []);

  useEffect(() => {
    let cancelled = false;

    (async () => {
      const nextRemoteLogoUrl = await probeBrokerSymbolLogoUrl({
        symbolPreview: uploadSymbolKey,
        objectPathPrefix,
      });

      if (!cancelled) {
        setRemoteLogoUrl(nextRemoteLogoUrl);
      }
    })();

    return () => {
      cancelled = true;
    };
  }, [uploadSymbolKey, objectPathPrefix]);

  return {
    objectPathPrefix,
    remoteLogoUrl,
  };
}

export function useBrokerSymbolLogoUploader() {
  const { logged } = useAppContext();
  const { buildGetHeaders } = useAdminAuthHeaders();
  const [uploading, setUploading] = useState(false);

  const uploadFile = useCallback(
    async (options: { symbolPreview: string; file: File }) => {
      setUploading(true);
      try {
        return await uploadBrokerSymbolLogoFile({
          symbolPreview: options.symbolPreview,
          file: options.file,
          logged,
          buildGetHeaders,
        });
      } finally {
        setUploading(false);
      }
    },
    [logged, buildGetHeaders]
  );

  return {
    uploading,
    uploadFile,
  };
}

export function useBrokerSymbolLogoUpload(options: {
  /** Full PERP display key (same as Preview); upload basename is derived from this. */
  symbolPreview: string;
}): BrokerSymbolLogoUploadController {
  const { symbolPreview } = options;
  const uploadSymbolKey = symbolPreview.trim();
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [sessionLogoUrl, setSessionLogoUrl] = useState<string | null>(null);
  const [logoUrlVersion, setLogoUrlVersion] = useState<number>(() =>
    Date.now()
  );
  const { remoteLogoUrl } = useBrokerSymbolLogoRemoteUrl({
    symbolPreview: uploadSymbolKey,
  });
  const { uploading, uploadFile } = useBrokerSymbolLogoUploader();

  useEffect(() => {
    setSessionLogoUrl(null);
    setLogoUrlVersion(Date.now());
  }, [uploadSymbolKey]);

  const buildCacheBustedUrl = useCallback((url: string, version: number) => {
    const hashIndex = url.indexOf("#");
    const base = hashIndex >= 0 ? url.slice(0, hashIndex) : url;
    const hash = hashIndex >= 0 ? url.slice(hashIndex) : "";
    const separator = base.includes("?") ? "&" : "?";
    return `${base}${separator}v=${version}${hash}`;
  }, []);

  const onFileChange = useCallback(
    async (e: ChangeEvent<HTMLInputElement>) => {
      const input = e.target;
      const file = input.files?.[0];
      input.value = "";
      if (!file || !uploadSymbolKey.trim()) return;

      setSessionLogoUrl(null);
      try {
        const { logoUrl } = await uploadFile({
          symbolPreview: uploadSymbolKey,
          file,
        });
        const nextVersion = Date.now();
        setLogoUrlVersion(nextVersion);
        setSessionLogoUrl(logoUrl);
        toast.success("Broker symbol logo uploaded.");
      } catch (error) {
        toast.error(
          error instanceof Error
            ? error.message
            : "Upload failed. Please try again."
        );
      }
    },
    [uploadFile, uploadSymbolKey]
  );

  const openFilePicker = useCallback(() => {
    fileInputRef.current?.click();
  }, []);

  const disabled = !uploadSymbolKey.trim() || uploading;

  const baseLogoUrl = sessionLogoUrl ?? remoteLogoUrl;
  const logoUrl = baseLogoUrl
    ? buildCacheBustedUrl(baseLogoUrl, logoUrlVersion)
    : baseLogoUrl;

  return {
    uploading,
    logoUrl,
    fileInputRef,
    onFileChange,
    disabled,
    openFilePicker,
  };
}
