const keepEnvelope =
  <T>() =>
  (d: T) =>
    d;

function applyDefaultRevalidateOnFocus<T extends SWRConfiguration>(
  options?: T
): T {
  if (!options) return { revalidateOnFocus: false } as T;
  return {
    ...options,
    revalidateOnFocus: options.revalidateOnFocus ?? false,
  };
}

/**
 * Dashboard 默认轮询参数集中配置，避免在各 hook 里散落魔法数字。
 * 这些配置仅用于 Dashboard 场景；保持现有 hook 行为（数值不变）。
 */
export const DASHBOARD_BASE_SWR: SWRConfiguration = {
  revalidateOnFocus: true,
  dedupingInterval: 5_000,
};

export const DASHBOARD_OVERVIEW_SWR: SWRConfiguration = {
  revalidateOnFocus: false,
  refreshInterval: 60_000,
  dedupingInterval: 5_000,
};

export const DASHBOARD_SYMBOLS_SWR: SWRConfiguration = {
  revalidateOnFocus: false,
  refreshInterval: 60_000,
  dedupingInterval: 5_000,
};

export const DASHBOARD_RISK_SNAPSHOT_SWR: SWRConfiguration = {
  revalidateOnFocus: false,
  refreshInterval: 10_000,
  dedupingInterval: 5_000,
};

export const DASHBOARD_ACCOUNTS_SWR: SWRConfiguration = {
  ...DASHBOARD_BASE_SWR,
  refreshInterval: 60_000,
};

export const DASHBOARD_EVENT_HISTORY_SWR: SWRConfiguration = {
  revalidateOnFocus: false,
  refreshInterval: 10_000,
  dedupingInterval: 5_000,
};

export function whenDashboardPollingEnabled<T extends SWRConfiguration>(
  enabled: boolean,
  options: T
): T {
  if (enabled) return options;
  const { refreshInterval: _refreshInterval, ...rest } = options as T & {
    refreshInterval?: number;
  };
  return rest as T;
}

