import { useCallback } from "react";
import {
  buildStoredAdminAuthHeaders,
  type MessageFactor,
} from "@/utils/adminKeyAuth";

export type AdminAuthHeaders = Awaited<
  ReturnType<typeof buildStoredAdminAuthHeaders>
>;

export function useAdminAuthHeaders() {
  const buildHeaders = useCallback(
    async (payload: MessageFactor): Promise<AdminAuthHeaders> => {
      return buildStoredAdminAuthHeaders(payload);
    },
    []
  );

  const buildGetHeaders = useCallback(
    async (url: string): Promise<AdminAuthHeaders> =>
      buildHeaders({ method: "GET", url }),
    [buildHeaders]
  );

  return { buildHeaders, buildGetHeaders };
}
