import { useCallback } from "react";
import { toast } from "@/components/toast";
import {
  useBrokerListingDelist,
  useBrokerListingCancel,
  useBrokerListingOverview,
  DASHBOARD_OVERVIEW_SWR,
  whenDashboardPollingEnabled,
} from "../../services";
import type {
  BrokerListingCancelData,
  BrokerListingDelistData,
} from "../../services/types";
import { useSelectListingStore } from "../../store/useListingStore";
import type { DelistMode } from "./types";
import { useListingRefreshActions } from "../../hooks/useListingRefreshActions";

/**
 * Backend submission for delisting:
 * POST /delist + recent event + SWR/Store refresh + error-code mapping.
 */
export function useDelistSubmit(mode: DelistMode) {
  const { targetDelistSymbol, setTargetDelist, addEvent } =
    useSelectListingStore(s => ({
      targetDelistSymbol: s.targetDelistSymbol,
      setTargetDelist: s.setTargetDelist,
      addEvent: s.addEvent,
    }));
  const { refreshListingSymbols, refreshRiskSnapshot } =
    useListingRefreshActions();

  const overview = useBrokerListingOverview(
    whenDashboardPollingEnabled(false, DASHBOARD_OVERVIEW_SWR)
  );

  const [delist] = useBrokerListingDelist();
  const [cancel] = useBrokerListingCancel();

  const closeDelistModal = useCallback(() => {
    setTargetDelist(null);
  }, [setTargetDelist]);

  const onConfirmDelist = useCallback(
    async (delistTimeIso?: string) => {
      if (!targetDelistSymbol) return;
      setTargetDelist(null);
      try {
        const res =
          mode === "cancel"
            ? await cancel({
                symbol: targetDelistSymbol,
              })
            : await delist({
                symbol: targetDelistSymbol,
                delist_time: delistTimeIso as string,
              });

        const resData = res as
          | BrokerListingCancelData
          | BrokerListingDelistData;

        if (mode === "cancel") {
          const statusFrom = (resData as BrokerListingCancelData).status_from;
          const statusTo = (resData as BrokerListingCancelData).status_to;
          addEvent({
            eventTime: new Date().toISOString(),
            time: "Just now",
            description: `Submitted delisting cancel request for ${targetDelistSymbol}. Status: ${statusFrom ?? "?"} -> ${
              statusTo ?? "?"
            }.`,
          });
        } else {
          addEvent({
            eventTime: new Date().toISOString(),
            time: "Just now",
            description: `Submitted delisting request for ${targetDelistSymbol}. Market entered Reduce-only mode.`,
          });
        }

        await Promise.allSettled([
          refreshListingSymbols(),
          overview.mutate(),
          refreshRiskSnapshot(),
        ]);
      } catch (error) {
        toast.error(getDelistApiErrorMessage(error));
        throw error;
      }
    },
    [
      targetDelistSymbol,
      delist,
      cancel,
      mode,
      addEvent,
      setTargetDelist,
      refreshListingSymbols,
      overview,
      refreshRiskSnapshot,
    ]
  );

  return {
    targetDelistSymbol,
    closeDelistModal,
    onConfirmDelist,
  };
}

function getDelistApiErrorMessage(error: unknown): string {
  const message = String(
    (error as { data?: { message?: string } })?.data?.message ??
      (error as { message?: string })?.message ??
      ""
  ).toUpperCase();

  if (message.includes("SYMBOL_NOT_FOUND")) return "Symbol not found.";
  if (message.includes("SYMBOL_NOT_LISTED"))
    return "This symbol is not listed or has been delisted.";
  if (message.includes("DELIST_TIME_INVALID"))
    return "Invalid delist_time (must be >= now + 1 hour and on the hour).";
  if (message.includes("INVALID_STATUS"))
    return "Invalid symbol status. Only NEW/PENDING/POST_ONLY can be cancelled.";
  if (message.includes("ALREADY_DELISTING"))
    return "This symbol is already in the delisting flow.";

  return "Failed to request delisting. Please try again.";
}
