import { useBrokerInfo } from "@/components/provider/BrokerInfoProvider";
import { buildBrokerSymbolLogoSymbolPreview } from "@/utils/brokerSymbolLogoUpload";
import { formatAlertLabelOrDash } from "../dashboard/formatters";
import { useSymbolDetailScript } from "./SymbolDetail.script";
import { SymbolDetailSkeleton } from "./SymbolDetailSkeleton";
import {
  SymbolDetailHeader,
  SymbolDetailListingTimeRow,
} from "./panels/SymbolDetailHeader";
import { SymbolDetailSummaryMetrics } from "./panels/SymbolDetailSummaryMetrics";
import { SymbolDetailDataSourcesPanel } from "./panels/SymbolDetailDataSourcesPanel";
import { SymbolDetailMMPanel } from "./panels/SymbolDetailMMPanel";
import { SymbolDetailTradingParamsPanel } from "./panels/SymbolDetailTradingParamsPanel";
import { SymbolDetailFundingTickPanel } from "./panels/SymbolDetailFundingTickPanel";
import { SymbolDetailDelistPanel } from "./panels/SymbolDetailDelistPanel";

export function SymbolDetailPanel() {
  const { brokerId } = useBrokerInfo();
  const script = useSymbolDetailScript();
  const {
    symbolItem,
    detail,
    prettySymbol,
    isEditable,
    apiHydratedDetail,
    showDetailLoader,
    symbolDetailRequestError,
    getLastPrice,
    onBack,
    onEdit,
    onDelist,
    onUnbindMM,
    onAddAndBindMM,
    isMmBusy,
    isBindBusy,
    isUnbindBusy,
  } = script;

  if (showDetailLoader) {
    return <SymbolDetailSkeleton />;
  }

  if (symbolDetailRequestError) {
    return (
      <div className="flex items-center justify-center h-64 rounded-xl bg-base-200 text-base-contrast-36">
        Unable to load this symbol. It may not exist or the request failed.
      </div>
    );
  }

  if (!detail || !symbolItem) {
    return (
      <div className="flex items-center justify-center h-64 rounded-xl bg-base-200 text-base-contrast-36">
        Symbol not found
      </div>
    );
  }

  const displayName = symbolItem.displayName || prettySymbol;
  const alertLevel = symbolItem.alertLevel ?? null;
  const alertLabel = formatAlertLabelOrDash(alertLevel);

  return (
    <div className="flex flex-col gap-4">
      <SymbolDetailHeader
        displayName={displayName}
        logoSymbolPreview={buildBrokerSymbolLogoSymbolPreview(
          displayName,
          brokerId
        )}
        status={detail.status}
        apiHydratedDetail={apiHydratedDetail}
        alertLabel={alertLabel}
        alertLevel={alertLevel}
        isEditable={isEditable}
        onBack={onBack}
        onDelist={onDelist}
        onEdit={onEdit}
      />

      {detail.listingTime && (
        <SymbolDetailListingTimeRow listingTime={detail.listingTime} />
      )}

      <SymbolDetailSummaryMetrics
        detail={detail}
        symbolItem={symbolItem}
        lastPrice={getLastPrice(symbolItem.symbol)}
        alertLabel={alertLabel}
        alertLevel={alertLevel}
      />

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
        <SymbolDetailDataSourcesPanel indexSources={detail.indexSources} />
        <SymbolDetailMMPanel
          boundAccountIds={detail.mmAccounts}
          isEditable={isEditable}
          onUnbindMM={onUnbindMM}
          onAddAndBindMM={onAddAndBindMM}
          isMmBusy={isMmBusy}
          isBindBusy={isBindBusy}
          isUnbindBusy={isUnbindBusy}
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
        <SymbolDetailTradingParamsPanel
          detail={detail}
          params={detail.params}
        />
        <SymbolDetailFundingTickPanel
          params={detail.params}
          feeShareRate={detail.feeShareRate}
          fundingPeriodPending={detail.fundingPeriodPending}
          fundingPeriodEffectiveAt={detail.fundingPeriodEffectiveAt}
        />
      </div>

      <SymbolDetailDelistPanel detail={detail} />
    </div>
  );
}
