import useSWR, { type SWRResponse } from "swr";
import { getOrderlyEnvConfig } from "@/utils/environment";
import { fetcher, type useQueryOptions } from "./utils/fetcher";

export const useSvQuery = <T>(
  query: Parameters<typeof useSWR>[0],
  options?: useQueryOptions<T>
): SWRResponse<T> => {
  const { formatter, ...swrOptions } = options || {};
  const svUrl = getOrderlyEnvConfig().svUrl;

  return useSWR<T>(
    query,
    (url: string, init?: RequestInit) =>
      fetcher<T>(url.startsWith("http") ? url : `${svUrl}${url}`, init, {
        formatter,
      }),
    swrOptions
  );
};
