import { cn } from "@/utils/css";
import type { SymbolStatus } from "../types";
import { STATUS_CONFIG } from "../constants";

interface StatusBadgeProps {
  status: SymbolStatus;
  className?: string;
  depthPct?: number;
}

export function StatusBadge({
  status,
  className,
  depthPct: _depthPct,
}: StatusBadgeProps) {
  const config = STATUS_CONFIG[status];

  return (
    <span
      className={cn(
        "inline-flex items-center text-3xs font-medium px-2.5 py-0.5 rounded-full",
        config.color,
        config.bgColor,
        className
      )}
    >
      {config.label}
    </span>
  );
}
