import { FC, useMemo, useState } from "react";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogBody,
  DialogFooter,
} from "@/components/dialog";
import { Button } from "@/components/button";
import { toast } from "@/components/toast";
import { cn } from "@/utils/css";
import { delay, floorToUsdcDisplay, fmtNum } from "../utils";
import { formatAccountId } from "@/utils";
import { usdcHoldingForAccount } from "../utils/usdcHolding";
import { useInternalTransfer } from "../services/account";
import type { Holding } from "../services/types";
import { useListingAccountContext } from "../hooks/useListingAccountContext";
import { useListingBalancesData } from "../hooks/useListingBalancesData";

/** Max polls after transfer; nth poll waits n seconds (1s, 2s, …, 10s). */
const HOLDINGS_POLL_MAX_ATTEMPTS = 10;
const USDC_TRANSFER_REFLECTED_EPS = 1e-6;

function isTransferReflectedInHoldings(
  nextHoldings: Holding[],
  targetAccountId: string,
  priorTargetUsdc: number,
  transferAmount: number
): boolean {
  const next = usdcHoldingForAccount(nextHoldings, targetAccountId);
  return next >= priorTargetUsdc + transferAmount - USDC_TRANSFER_REFLECTED_EPS;
}

async function pollHoldingsUntilTransferVisible(params: {
  refreshHoldings: () => Promise<Holding[]>;
  targetAccountId: string;
  priorTargetUsdc: number;
  transferAmount: number;
}): Promise<void> {
  const { refreshHoldings, targetAccountId, priorTargetUsdc, transferAmount } =
    params;

  for (let i = 0; i < HOLDINGS_POLL_MAX_ATTEMPTS; i++) {
    try {
      await delay((i + 1) * 1000);
      const nextHoldings = await refreshHoldings();
      if (
        isTransferReflectedInHoldings(
          nextHoldings,
          targetAccountId,
          priorTargetUsdc,
          transferAmount
        )
      ) {
        toast.success("Transfer received.");
        return;
      }
    } catch (err) {
      console.error("pollHoldingsUntilTransferVisible:", err);
      return;
    }
  }
}

interface TransferModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  /** Target sub-account id to transfer to (set when opening from a specific account card). */
  targetAccountId: string | null;
  /** Optional hook after a successful transfer (e.g. parent-specific side effects). Holdings refresh via polling after close. */
  onConfirm?: (amount: number) => void | Promise<void>;
  /**
   * Total USDC the target sub-account still needs via internal transfer to meet the caller's threshold.
   * Still needed in the UI is max(0, this − amount input).
   */
  requiredTransferAmount?: number;
}

export const TransferModal: FC<TransferModalProps> = ({
  open,
  onOpenChange,
  targetAccountId,
  onConfirm,
  requiredTransferAmount = 0,
}) => {
  const [amount, setAmount] = useState("");

  const { accountId } = useListingAccountContext();
  const { holdings, subAccounts, refreshHoldings, refreshSubAccounts } =
    useListingBalancesData();

  const mainAccountBalance = useMemo(
    () => usdcHoldingForAccount(holdings, accountId),
    [holdings, accountId]
  );

  const flooredMainBalance = useMemo(
    () => floorToUsdcDisplay(mainAccountBalance),
    [mainAccountBalance]
  );

  const [internalTransfer, { isMutating }] = useInternalTransfer();

  const targetAccount = useMemo(
    () =>
      targetAccountId
        ? subAccounts.find(a => a.sub_account_id === targetAccountId)
        : null,
    [subAccounts, targetAccountId]
  );

  const parsedAmount = parseFloat(amount.replace(/,/g, "")) || 0;
  const isValidAmount =
    !isNaN(parsedAmount) &&
    parsedAmount > 0 &&
    parsedAmount <= flooredMainBalance;

  const stillNeeded = Math.max(0, requiredTransferAmount - parsedAmount);
  const showShortfall = stillNeeded > 0;

  const handleMax = () => {
    setAmount(
      new Intl.NumberFormat("en-US", {
        minimumFractionDigits: 2,
        maximumFractionDigits: 2,
      }).format(flooredMainBalance)
    );
  };

  const handleFillShortfall = () => {
    setAmount(
      new Intl.NumberFormat("en-US", { maximumFractionDigits: 2 }).format(
        requiredTransferAmount
      )
    );
  };

  const handleAmountInput = (e: React.ChangeEvent<HTMLInputElement>) => {
    const raw = e.target.value.replace(/,/g, "");
    if (raw === "" || /^\d*\.?\d*$/.test(raw)) {
      setAmount(e.target.value);
    }
  };

  const handleConfirm = async () => {
    if (!targetAccountId || !isValidAmount) return;
    const priorTargetUsdc = usdcHoldingForAccount(holdings, targetAccountId);
    try {
      const res = await internalTransfer({
        token: "USDC",
        receiver_list: [{ account_id: targetAccountId, amount: parsedAmount }],
      });

      if (!res?.success) {
        throw res;
      }

      await Promise.all([refreshHoldings(), refreshSubAccounts()]);
      await onConfirm?.(parsedAmount);
      toast.success("Success! Funds will be available in 15 seconds.");
      setAmount("");
      onOpenChange(false);

      void pollHoldingsUntilTransferVisible({
        refreshHoldings,
        targetAccountId,
        priorTargetUsdc,
        transferAmount: parsedAmount,
      });
    } catch (e: unknown) {
      toast.error((e as { message?: string })?.message ?? "Transfer failed");
    }
  };

  const handleOpenChange = (next: boolean) => {
    if (!next) setAmount("");
    onOpenChange(next);
  };

  return (
    <Dialog open={open} onOpenChange={handleOpenChange}>
      <DialogContent
        className="max-w-[440px] w-[95vw] flex flex-col rounded-xl"
        style={{ backgroundColor: "#190E2C" }}
      >
        <DialogHeader className="h-auto min-h-0 py-5 pb-3 border-b border-base-contrast-12">
          <DialogTitle className="text-lg font-semibold text-base-contrast-98">
            Transfer
          </DialogTitle>
        </DialogHeader>

        <DialogBody className="p-5 flex flex-col gap-0">
          {/* From card — mockup .transfer-card: bg-surface-2 #1E122F */}
          <div
            className="rounded-lg p-4"
            style={{ backgroundColor: "#1E122F" }}
          >
            <div className="text-2xs text-base-contrast-54 mb-0.5">From</div>
            <div className="flex items-baseline gap-1.5">
              <span className="text-xs font-medium text-base-contrast-98">
                Main account
              </span>
              <span className="text-xs text-base-contrast-54 font-medium">
                ({formatAccountId(accountId)})
              </span>
            </div>
            <div className="mt-3.5">
              <label className="text-2xs text-base-contrast-54 block mb-1.5">
                Amount
              </label>
              <div className="flex items-center gap-2">
                <div className="flex-1 relative">
                  <input
                    type="text"
                    inputMode="decimal"
                    placeholder="0.00"
                    value={amount}
                    onChange={handleAmountInput}
                    autoComplete="off"
                    className={cn(
                      "w-full h-11 rounded-lg border border-base-contrast-12",
                      "text-base text-base-contrast-98 font-medium pl-3 pr-[52px] outline-none box-border",
                      "placeholder:text-base-contrast-36 placeholder:font-normal",
                      "focus:border-primary"
                    )}
                    style={{ backgroundColor: "#201532" }}
                  />
                  <span className="absolute right-3 top-1/2 -translate-y-1/2 text-xs text-base-contrast-54 font-medium pointer-events-none">
                    USDC
                  </span>
                </div>
              </div>
            </div>
            <div className="flex items-center justify-start gap-1 mt-2 text-2xs text-base-contrast-54">
              <span>
                Available:{" "}
                <span className="text-base-contrast-80">
                  {fmtNum(flooredMainBalance)}
                </span>{" "}
                USDC
              </span>
              <span
                className="text-primary font-medium cursor-pointer hover:opacity-80 ml-1"
                onClick={handleMax}
              >
                Max
              </span>
            </div>
          </div>

          {/* Separator with icon — match mockup .transfer-separator-icon (16px, text-secondary) */}
          <div className="flex items-center gap-3 my-4">
            <div className="flex-1 h-px bg-base-contrast-12" />
            <span className="shrink-0 text-base text-base-contrast-54 leading-none">
              ⇅
            </span>
            <div className="flex-1 h-px bg-base-contrast-12" />
          </div>

          {/* To card — mockup .transfer-card: bg-surface-2 #1E122F */}
          <div
            className="rounded-lg p-4"
            style={{ backgroundColor: "#1E122F" }}
          >
            <div className="text-2xs text-base-contrast-54 mb-0.5">To</div>
            <div className="flex items-baseline gap-1.5">
              <span className="text-xs font-medium text-base-contrast-98">
                {targetAccount?.description ?? "—"}
              </span>
              {targetAccount && (
                <span className="text-xs text-base-contrast-54 font-medium">
                  ({formatAccountId(targetAccount.sub_account_id)})
                </span>
              )}
            </div>
            <div className="flex justify-between items-center mt-3 text-2xs text-base-contrast-54">
              <span>Current asset value</span>
              <span className="text-base-contrast-80 font-medium">
                {targetAccount
                  ? `${fmtNum(targetAccount.balance)} USDC`
                  : "0 USDC"}
              </span>
            </div>
            <div className="flex justify-between items-center mt-3 text-2xs text-base-contrast-54">
              <span>Still needed</span>
              {showShortfall ? (
                <span
                  className="text-2xs font-medium text-warning cursor-pointer hover:opacity-80"
                  onClick={handleFillShortfall}
                >
                  {fmtNum(stillNeeded)} USDC
                </span>
              ) : (
                <span className="text-base-contrast-80 font-medium">
                  0 USDC
                </span>
              )}
            </div>
          </div>
        </DialogBody>

        <DialogFooter className="p-0 px-5 pb-5 pt-0 border-t-0">
          <Button
            disabled={!targetAccountId || !isValidAmount}
            onClick={handleConfirm}
            className={cn(
              "w-full h-11 rounded-lg border-none text-xs font-medium",
              "bg-[#1E122F] text-base-contrast-54",
              "disabled:opacity-100 disabled:cursor-not-allowed",
              "enabled:bg-primary enabled:text-white enabled:hover:bg-primary/90"
            )}
            loading={isMutating}
          >
            Transfer
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
};
