import { Button } from "@/components/button";
import {
  Dialog,
  DialogBody,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/dialog";
import { ListingAssetType } from "../../types";

function AssetTypeIcon({ assetType }: { assetType: ListingAssetType }) {
  return (
    <div className="flex h-10 w-10 shrink-0 items-center justify-center rounded-[10px] bg-primary/10 text-primary-light">
      {assetType === ListingAssetType.Crypto ? (
        <svg
          width="20"
          height="20"
          viewBox="0 0 24 24"
          fill="none"
          stroke="currentColor"
          strokeWidth="2"
          strokeLinecap="round"
          strokeLinejoin="round"
          aria-hidden="true"
        >
          <circle cx="12" cy="12" r="9" />
          <path d="M8 12h8" />
          <path d="M12 8v8" />
        </svg>
      ) : (
        <svg
          width="20"
          height="20"
          viewBox="0 0 24 24"
          fill="none"
          stroke="currentColor"
          strokeWidth="2"
          strokeLinecap="round"
          strokeLinejoin="round"
          aria-hidden="true"
        >
          <path d="M3 21h18" />
          <path d="M5 21V8l7-5 7 5v13" />
          <path d="M9 9h.01" />
          <path d="M13 9h.01" />
          <path d="M9 13h.01" />
          <path d="M13 13h.01" />
          <path d="M9 17h.01" />
          <path d="M13 17h.01" />
        </svg>
      )}
    </div>
  );
}

function AssetTypeCard({
  assetType,
  title,
  description,
  suffix,
  onSelect,
}: {
  assetType: ListingAssetType;
  title: string;
  description: string;
  suffix?: string;
  onSelect: (assetType: ListingAssetType) => void;
}) {
  return (
    <button
      type="button"
      onClick={() => onSelect(assetType)}
      className="flex w-full items-start gap-3.5 rounded-xl border border-base-contrast-8 bg-base-200 p-4 text-left transition-all hover:border-primary/40 hover:bg-base-300"
    >
      <AssetTypeIcon assetType={assetType} />
      <div className="flex-1">
        <div className="text-xs font-medium leading-[1.2] text-base-contrast-98">
          {title}
          {suffix ? (
            <span className="ml-1 text-[11px] font-normal text-base-contrast-50">
              {suffix}
            </span>
          ) : null}
        </div>
        <p className="mt-1 text-3xs leading-normal text-base-contrast-54">
          {description}
        </p>
      </div>
    </button>
  );
}

export function ListingAssetTypeModal({
  open,
  onCancel,
  onSelect,
}: {
  open: boolean;
  onCancel: () => void;
  onSelect: (assetType: ListingAssetType) => void;
}) {
  return (
    <Dialog
      open={open}
      onOpenChange={nextOpen => {
        if (!nextOpen) onCancel();
      }}
    >
      <DialogContent className="max-w-[520px]">
        <DialogHeader className="h-auto flex-col items-stretch gap-2 border-b-0 px-6 pt-6 pb-0">
          <DialogTitle className="text-lg font-medium leading-[1.2] text-base-contrast-98">
            What are you listing?
          </DialogTitle>
          <DialogDescription className="text-xs leading-normal text-base-contrast-50">
            Choose the asset type. This determines whether market hours and a
            trading session apply.
          </DialogDescription>
        </DialogHeader>
        <DialogBody className="space-y-3 px-6 py-5">
          <AssetTypeCard
            assetType={ListingAssetType.Crypto}
            title="Crypto"
            description="Perpetual on a crypto asset (BTC, ETH, SOL, ...). Trades 24/7 with no market hours."
            onSelect={onSelect}
          />
          <AssetTypeCard
            assetType={ListingAssetType.Rwa}
            title="RWA"
            suffix="(Real-world asset)"
            description="Perpetual on a real-world asset (US stocks, FX, ...). Configurable market hours and holiday schedules."
            onSelect={onSelect}
          />
        </DialogBody>
        <DialogFooter className="justify-end gap-2 px-6 pt-0 pb-6">
          <Button
            type="button"
            variant="outline"
            color="primary"
            rounded="full"
            className="bg-transparent px-5"
            onClick={onCancel}
          >
            Cancel
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}
