import { useEffect } from "react";
import { useSelectListingStore } from "../store/useListingStore";
import { PageView } from "../types";
import { OnboardingPanel } from "./onboarding";
import { DashboardPanel } from "./dashboard";
import { SettingsPanel } from "./settings";
import { Listing } from "./listing";
import { SymbolDetailPanel } from "./symbol-detail";
import { DelistModal } from "./DelistModal";
import { usePermissionlessListingBootstrap } from "../hooks/usePermissionlessListingBootstrap";
import { FadeInEnter } from "@/components/fade-in-enter";
import { CustomOraclePanel } from "./custom-oracle";

export default function ListingBody() {
  usePermissionlessListingBootstrap();
  const { currentPage, forceOnboarding, setPage } = useSelectListingStore(
    s => ({
      currentPage: s.currentPage,
      forceOnboarding: s.forceOnboarding,
      setPage: s.setPage,
    })
  );

  useEffect(() => {
    if (forceOnboarding) {
      setPage(PageView.Onboarding);
    }
  }, [forceOnboarding, setPage]);

  return (
    <div className="flex flex-col">
      <DelistModal />

      <div className="flex-1 min-h-0">
        {currentPage === PageView.Dashboard && (
          <FadeInEnter className="min-h-0">
            <DashboardPanel />
          </FadeInEnter>
        )}
        {currentPage === PageView.Settings && (
          <FadeInEnter className="min-h-0">
            <SettingsPanel />
          </FadeInEnter>
        )}
        {currentPage === PageView.Onboarding && (
          <FadeInEnter className="min-h-0">
            <OnboardingPanel />
          </FadeInEnter>
        )}
        {currentPage === PageView.Listing && <Listing />}
        {currentPage === PageView.CustomOracle && (
          <FadeInEnter className="min-h-0">
            <CustomOraclePanel />
          </FadeInEnter>
        )}
        {currentPage === PageView.SymbolDetail && (
          <FadeInEnter className="min-h-0">
            <SymbolDetailPanel />
          </FadeInEnter>
        )}
      </div>
    </div>
  );
}
