import { useEffect, useMemo, useState } from "react";
import { Button } from "@/components/button";
import {
  Dialog,
  DialogBody,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/dialog";
import { Input } from "@/components/input";
import { toast } from "@/components/toast";
import type { ByokProvider } from "../../types";
import { InfoCircleIcon } from "../CustomOracleIcons";
import {
  footerClassName,
  formLabelClassName,
  getByokSourceId,
  getProviderLabel,
  infoBannerClassName,
} from "./shared";

interface AddByokSymbolModalProps {
  providerId: string | null;
  byokProviders: ByokProvider[];
  isMutating: boolean;
  onClose: () => void;
  onConfirm: (
    providerId: string,
    symbol: string
  ) => Promise<string | null> | string | null;
}

export function AddByokSymbolModal({
  providerId,
  byokProviders,
  isMutating,
  onClose,
  onConfirm,
}: AddByokSymbolModalProps) {
  const [byokSymbol, setByokSymbol] = useState("");

  useEffect(() => {
    if (providerId === null) {
      setByokSymbol("");
    }
  }, [providerId]);

  const providerLabel = useMemo(
    () => getProviderLabel(providerId, byokProviders),
    [providerId, byokProviders]
  );

  return (
    <Dialog
      open={providerId !== null}
      onOpenChange={nextOpen => {
        if (!nextOpen) {
          setByokSymbol("");
          onClose();
        }
      }}
    >
      <DialogContent className="max-w-[480px]">
        <DialogHeader className="h-auto flex-col items-stretch gap-2 border-b-0 px-6 pt-6 pb-0">
          <DialogTitle className="text-lg font-medium text-base-contrast-98">
            Add symbol to {getByokSourceId(providerId)}
          </DialogTitle>
          <DialogDescription className="text-2xs leading-6 text-base-contrast-54">
            Add a new symbol to your {providerLabel} Bring Your Own Key source.
            Orderly will start pulling its price using your API key.
          </DialogDescription>
        </DialogHeader>
        <DialogBody className="space-y-4 px-6 pt-5 pb-0">
          <div>
            <label className={formLabelClassName}>Symbol</label>
            <Input
              value={byokSymbol}
              disabled={isMutating}
              onChange={event => {
                setByokSymbol(event.target.value.toUpperCase());
              }}
              placeholder="e.g. NVDA"
              className="bg-base-500"
            />
            <div className="mt-1.5 text-3xs text-base-contrast-36">
              Symbol is validated against the Oracle API in real-time.
            </div>
          </div>
          <div className={infoBannerClassName}>
            <div className="flex items-start gap-3">
              <div className="mt-0.5 shrink-0 text-primary-light">
                <InfoCircleIcon />
              </div>
              <div>
                New symbols start as{" "}
                <strong className="font-medium text-base-contrast-98">
                  Private
                </strong>{" "}
                so you can verify the price first. Switch to{" "}
                <strong className="font-medium text-base-contrast-98">
                  Public
                </strong>{" "}
                from the symbol row once it looks correct.
              </div>
            </div>
          </div>
        </DialogBody>
        <DialogFooter className={`${footerClassName} mt-6`}>
          <Button
            variant="outline"
            color="primary"
            className="flex-1"
            disabled={isMutating}
            onClick={() => {
              setByokSymbol("");
              onClose();
            }}
          >
            Cancel
          </Button>
          <Button
            className="flex-1"
            loading={isMutating}
            disabled={isMutating}
            onClick={async () => {
              if (!providerId) return;
              const error = await onConfirm(providerId, byokSymbol);
              if (error) {
                toast.error(error);
                return;
              }
              setByokSymbol("");
            }}
          >
            Add symbol
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}
