import { useCallback, useMemo } from "react";
import {
  useClientSubAccounts,
  useGetAggregateHolding,
  type ClientSubAccountRow,
} from "../services/account";
import type { Holding } from "../services/types";
import type { SubAccount } from "../types";

function mergeSubAccountsWithHoldings(
  rows: ClientSubAccountRow[] | undefined,
  holdings: Holding[]
): SubAccount[] {
  if (!Array.isArray(rows)) return [];

  const balancesMap = new Map<string, number>();
  for (const item of holdings) {
    balancesMap.set(item.account_id, item.holding);
  }

  return rows.map(item => {
    const id = item.sub_account_id;
    return {
      sub_account_id: id,
      description: item.description,
      balance: balancesMap.get(id) ?? 0,
    };
  });
}

export function useListingBalancesData() {
  const holdingsQuery = useGetAggregateHolding();
  const subAccountsQuery = useClientSubAccounts();
  const mutateHoldings = holdingsQuery.mutate;
  const holdingsData = holdingsQuery.data;
  const mutateSubAccounts = subAccountsQuery.mutate;

  const holdings = useMemo(() => holdingsData ?? [], [holdingsData]);

  const subAccounts = useMemo(
    () => mergeSubAccountsWithHoldings(subAccountsQuery.data, holdings),
    [subAccountsQuery.data, holdings]
  );

  const refreshHoldings = useCallback(async (): Promise<Holding[]> => {
    const next = await mutateHoldings();
    return Array.isArray(next) ? next : (holdingsData ?? []);
  }, [mutateHoldings, holdingsData]);

  const refreshSubAccounts = useCallback(async () => {
    return mutateSubAccounts();
  }, [mutateSubAccounts]);

  const refreshBalances = useCallback(async () => {
    const [nextHoldings] = await Promise.all([
      refreshHoldings(),
      refreshSubAccounts(),
    ]);
    return nextHoldings;
  }, [refreshHoldings, refreshSubAccounts]);

  return {
    holdings,
    subAccounts,
    holdingsQuery,
    subAccountsQuery,
    isLoading: holdingsQuery.isLoading || subAccountsQuery.isLoading,
    refreshHoldings,
    refreshSubAccounts,
    refreshBalances,
  };
}
