import { Button } from "@/components/button";
import { cn } from "@/utils/css";
import type { BuilderOracleSource, BuilderOracleSymbol } from "../types";
import {
  CopyIcon,
  EyeIcon,
  ExternalLinkIcon,
  LockIcon,
  PencilIcon,
} from "../components/CustomOracleIcons";

function formatPrice(price: number | null) {
  if (price == null) return "—";
  return `$${price.toLocaleString("en-US", {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  })}`;
}

function statusClass(status: BuilderOracleSymbol["status"]) {
  return status === "active"
    ? "bg-success/15 text-success"
    : "bg-danger/15 text-danger";
}

function UptimeToneBar({
  tone,
}: {
  tone: BuilderOracleSymbol["uptimeDays"][number]["tone"];
}) {
  const className =
    tone === "green"
      ? "bg-success"
      : tone === "yellow"
        ? "bg-warning"
        : tone === "red"
          ? "bg-danger"
          : "bg-base-contrast-36";

  return <div className={cn("h-full rounded-[3px]", className)} />;
}

function UptimeStack({
  day,
  compact = false,
}: {
  day: BuilderOracleSymbol["uptimeDays"][number];
  compact?: boolean;
}) {
  return (
    <div
      className={cn(
        "flex h-full flex-col gap-px",
        compact ? "min-h-[20px]" : "min-h-[40px]"
      )}
    >
      <UptimeToneBar tone={day.tone} />
    </div>
  );
}

function VisibilityChip({
  visibility,
}: {
  visibility: BuilderOracleSymbol["visibility"];
}) {
  const isPublic = visibility === "public";

  return (
    <span
      className={cn(
        "inline-flex items-center gap-1 rounded-sm px-2 py-0.5 text-4xs font-medium",
        isPublic
          ? "bg-primary/10 text-primary-light"
          : "border border-base-contrast-12 bg-transparent text-base-contrast-50"
      )}
    >
      {isPublic ? <EyeIcon /> : <LockIcon />}
      {isPublic ? "Public" : "Private"}
    </span>
  );
}

interface BuilderOracleViewProps {
  source: BuilderOracleSource;
  loading?: boolean;
  copiedField: "endpoint" | "topic" | null;
  onCopyField: (field: "endpoint" | "topic", value: string) => void;
  onOpenVisibility: (symbolId: string) => void;
  onOpenRemove: (symbolId: string) => void;
  onOpenAddSymbol: () => void;
}

export function BuilderOracleView({
  source,
  loading = false,
  copiedField,
  onCopyField,
  onOpenVisibility,
  onOpenRemove,
  onOpenAddSymbol: _onOpenAddSymbol,
}: BuilderOracleViewProps) {
  return (
    <div className="flex flex-col gap-5">
      <div className="rounded-xl border border-base-contrast-8 bg-base-200">
        <div className="flex items-center gap-3 px-6 py-5">
          <div className="text-base font-semibold text-base-contrast-98">
            {source.name}
          </div>
          <a
            href={source.guideUrl}
            target="_blank"
            className="ml-auto inline-flex items-center gap-1 text-2xs font-medium text-primary-light hover:underline"
          >
            Integration guide
            <ExternalLinkIcon className="h-3 w-3" />
          </a>
        </div>

        <div className="grid grid-cols-2 overflow-hidden rounded-lg border border-base-contrast-8 mx-6">
          {(
            [
              ["Endpoint", source.endpoint, "endpoint"],
              ["Topic", source.topic, "topic"],
            ] as const
          ).map(([label, value, field], index) => (
            <div
              key={field}
              className={cn(
                "flex flex-col gap-1 bg-base-300 px-4 py-3 text-left transition-colors hover:bg-base-300/90",
                index === 0 && "border-r border-base-contrast-8"
              )}
            >
              <span className="text-2xs font-medium text-base-contrast-50">
                {label}
              </span>
              <span className="flex items-center gap-3 text-xs font-semibold text-base-contrast-98">
                <span className="min-w-0 break-all">{value}</span>
                <button
                  type="button"
                  aria-label={`Copy ${label}`}
                  className="shrink-0 text-base-contrast-50 transition-colors hover:text-base-contrast-72"
                  onClick={event => {
                    event.preventDefault();
                    event.stopPropagation();
                    onCopyField(field, value);
                  }}
                >
                  <CopyIcon copied={copiedField === field} />
                </button>
              </span>
            </div>
          ))}
        </div>

        <div className="my-5 h-px bg-base-contrast-8" />

        {loading ? (
          <div className="px-6 pb-6">
            <div className="animate-pulse">
              <div className="grid grid-cols-3 gap-3">
                {Array.from({ length: 3 }).map((_, i) => (
                  <div key={i} className="rounded-xl bg-base-300 px-5 py-5">
                    <div className="flex items-center gap-2">
                      <div className="h-4 w-24 rounded bg-base-contrast-12" />
                      <div className="h-5 w-14 rounded-sm bg-base-contrast-12" />
                      <div className="h-5 w-5 rounded bg-base-contrast-12" />
                      <div className="ml-auto h-5 w-14 rounded-full bg-base-contrast-12" />
                    </div>

                    <div className="mt-3 h-7 w-28 rounded bg-base-contrast-12" />
                    <div className="mt-2 h-3 w-24 rounded bg-base-contrast-12" />

                    <div className="mt-4">
                      <div className="mb-2 h-3 w-20 rounded bg-base-contrast-12" />
                      <div className="grid grid-cols-7 gap-0.5">
                        {Array.from({ length: 7 }).map((__, dayIndex) => (
                          <div
                            key={dayIndex}
                            className="h-5 rounded-[3px] bg-base-contrast-12"
                          />
                        ))}
                      </div>
                      <div className="mt-1.5 grid grid-cols-7 gap-0.5">
                        {Array.from({ length: 7 }).map((__, labelIndex) => (
                          <div
                            key={labelIndex}
                            className="h-3 rounded bg-base-contrast-12"
                          />
                        ))}
                      </div>
                    </div>

                    <div className="mt-4 flex gap-4">
                      <div className="flex-1 space-y-2">
                        <div className="h-3 w-24 rounded bg-base-contrast-12" />
                        <div className="h-4 w-28 rounded bg-base-contrast-12" />
                      </div>
                      <div className="w-[88px] space-y-2">
                        <div className="h-3 w-16 rounded bg-base-contrast-12" />
                        <div className="h-4 w-12 rounded bg-base-contrast-12" />
                      </div>
                    </div>

                    <div className="mt-4 h-8 w-28 rounded bg-base-contrast-12" />
                  </div>
                ))}
              </div>
            </div>
          </div>
        ) : source.symbols.length === 0 ? (
          <div className="px-6 pb-6 pt-10 text-center">
            <p className="text-xs leading-6 text-base-contrast-50">
              No symbols yet. Add your first symbol to start pushing prices.
            </p>
          </div>
        ) : (
          <div className="px-6 pb-6">
            <div className="grid grid-cols-3 gap-3">
              {source.symbols.map(symbol => (
                <div
                  key={symbol.id}
                  className="rounded-xl bg-base-300 px-5 py-5 text-left"
                >
                  <div className="flex items-center gap-2">
                    <div className="text-base font-bold text-base-contrast-98">
                      {symbol.name}
                    </div>
                    <VisibilityChip visibility={symbol.visibility} />
                    <button
                      type="button"
                      className="inline-flex h-5 w-5 items-center justify-center text-primary"
                      onClick={event => {
                        event.stopPropagation();
                        onOpenVisibility(symbol.id);
                      }}
                    >
                      <PencilIcon />
                    </button>
                    <span
                      className={cn(
                        "ml-auto rounded-full px-2.5 py-0.5 text-4xs font-medium",
                        statusClass(symbol.status)
                      )}
                    >
                      {symbol.status === "active" ? "Active" : "Inactive"}
                    </span>
                  </div>

                  <div
                    className={cn(
                      "mt-3 text-[22px] font-bold",
                      symbol.price == null
                        ? "text-base-contrast-36"
                        : "text-success"
                    )}
                  >
                    {formatPrice(symbol.price)}
                  </div>
                  <div className="mt-1 text-4xs text-base-contrast-50">
                    {symbol.updatedText}
                  </div>

                  <div className="mt-4">
                    <div className="mb-2 text-4xs tracking-[0.04em] text-base-contrast-50">
                      7-day uptime
                    </div>
                    <div className="grid grid-cols-7 gap-0.5">
                      {symbol.uptimeDays.map(day => (
                        <UptimeStack key={day.label} day={day} compact />
                      ))}
                    </div>
                    <div className="mt-1.5 grid grid-cols-7 gap-0.5 text-[10px] text-base-contrast-36">
                      {symbol.uptimeDays.map(day => (
                        <span key={day.label} className="truncate">
                          {day.label}
                        </span>
                      ))}
                    </div>
                  </div>

                  <div className="mt-4 flex gap-4">
                    <div className="text-2xs">
                      <div className="text-3xs text-base-contrast-50">
                        Health / 7d uptime
                      </div>
                      <div
                        className={cn(
                          "mt-0.5 text-xs font-semibold",
                          symbol.uptimePct == null
                            ? "text-base-contrast-50"
                            : symbol.healthTone === "success"
                              ? "text-success"
                              : symbol.healthTone === "warning"
                                ? "text-warning"
                                : symbol.healthTone === "danger"
                                  ? "text-danger"
                                  : "text-base-contrast-50"
                        )}
                      >
                        {symbol.healthLabel}
                        {symbol.uptimePct == null
                          ? " · --%"
                          : ` · ${symbol.uptimePct}%`}
                      </div>
                    </div>
                    <div className="text-2xs">
                      <div className="text-base-contrast-50 text-3xs">
                        7D skips
                      </div>
                      <div className="mt-0.5 text-xs font-semibold text-base-contrast-98">
                        {symbol.skips7d}
                      </div>
                    </div>
                  </div>

                  <Button
                    size="sm"
                    variant="outline"
                    className="mt-4"
                    onClick={event => {
                      event.stopPropagation();
                      onOpenRemove(symbol.id);
                    }}
                    color={symbol.status === "active" ? "danger" : "primary"}
                  >
                    {symbol.status === "active" ? "Deactivate" : "Activate"}
                  </Button>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
