import { FC, useCallback, useEffect, useMemo, useState } from "react";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogBody,
  DialogFooter,
} from "@/components/dialog";
import { Button } from "@/components/button";
import { PLSelectField } from "../components/PLSelect";

interface SubmitModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  symbol: string;
  onConfirm: (listingDate: string) => Promise<boolean> | boolean;
  mode?: "new" | "edit";
  defaultListingDate?: string;
  submitting: boolean;
}

export const SubmitModal: FC<SubmitModalProps> = ({
  open,
  onOpenChange,
  onConfirm,
  mode = "new",
  defaultListingDate,
  submitting,
}) => {
  const [date, setDate] = useState<Date | undefined>(undefined);
  const [hour, setHour] = useState("");
  const [timeError, setTimeError] = useState<string | null>(null);
  const [nowMs, setNowMs] = useState(() => Date.now());
  const [dialogContentEl, setDialogContentEl] = useState<HTMLElement | null>(
    null
  );
  const dialogContentRef = useCallback((node: HTMLElement | null) => {
    setDialogContentEl(node);
  }, []);

  const toDateInputValue = (d: Date) => {
    const y = d.getFullYear();
    const m = String(d.getMonth() + 1).padStart(2, "0");
    const day = String(d.getDate()).padStart(2, "0");
    return `${y}-${m}-${day}`;
  };

  const parseDateInputValue = (value: string): Date | undefined => {
    if (!value) return undefined;
    const [yy, mm, dd] = value.split("-").map(x => Number(x));
    if (!yy || !mm || !dd) return undefined;
    const d = new Date(yy, mm - 1, dd, 0, 0, 0, 0);
    if (Number.isNaN(d.getTime())) return undefined;
    return d;
  };

  // Pre-fill from defaultListingDate when opening in edit mode
  useEffect(() => {
    if (!open) return;
    if (!defaultListingDate) return;
    // defaultListingDate is expected like "2025-01-20T14:00"
    const [d, t] = defaultListingDate.split("T");
    if (d) {
      // Use local midnight to match DatePicker's local calendar behavior.
      const parsed = new Date(`${d}T00:00:00`);
      if (!Number.isNaN(parsed.getTime())) {
        setDate(parsed);
      }
    }
    if (t && t.length >= 2) setHour(t.slice(0, 2));
  }, [open, defaultListingDate]);

  // Keep "system time" based validation up-to-date while the dialog is open.
  useEffect(() => {
    if (!open) return;
    setNowMs(Date.now());
    const id = window.setInterval(() => setNowMs(Date.now()), 30_000);
    return () => window.clearInterval(id);
  }, [open]);

  const listingDateTime = useMemo(() => {
    if (!date || !hour) return "";
    // Native `input[type="date"]` provides a local calendar date.
    // Use local calendar fields to avoid UTC date shifting (off-by-one day).
    const y = date.getFullYear();
    const m = String(date.getMonth() + 1).padStart(2, "0");
    const d = String(date.getDate()).padStart(2, "0");
    return `${y}-${m}-${d}T${hour}:00`;
  }, [date, hour]);

  // Listing time rules:
  // 1) T >= system time + 1 hour
  // 2) T must be on the hour (we only allow selecting whole hours)
  const minAllowedMs = nowMs + 60 * 60 * 1000;
  const minAllowedOnHour = new Date(minAllowedMs);
  minAllowedOnHour.setMinutes(0, 0, 0);
  if (minAllowedOnHour.getTime() < minAllowedMs) {
    minAllowedOnHour.setHours(minAllowedOnHour.getHours() + 1);
  }
  const minDate = toDateInputValue(minAllowedOnHour);

  const isTimeValid = useMemo(() => {
    if (!date || !hour) return false;
    const candidate = new Date(
      date.getFullYear(),
      date.getMonth(),
      date.getDate(),
      Number(hour),
      0,
      0,
      0
    );
    if (Number.isNaN(candidate.getTime())) return false;
    return candidate.getTime() >= minAllowedMs;
  }, [date, hour, minAllowedMs]);

  useEffect(() => {
    if (!date || !hour) {
      setTimeError(null);
      return;
    }
    if (!isTimeValid) {
      setTimeError("Listing time must be at least 1 hour from now");
    } else {
      setTimeError(null);
    }
  }, [date, hour, isTimeValid]);

  const handleConfirm = async () => {
    if (!listingDateTime || !isTimeValid) return;
    const ok = await onConfirm(listingDateTime);
    // Keep the dialog open when caller explicitly returns `false`.
    if (ok === false) return;

    setDate(undefined);
    setHour("");
    onOpenChange(false);
  };

  const handleOpenChange = (next: boolean) => {
    if (!next) {
      setDate(undefined);
      setHour("");
      setTimeError(null);
    }
    onOpenChange(next);
  };

  return (
    <Dialog open={open} onOpenChange={handleOpenChange}>
      <DialogContent ref={dialogContentRef}>
        <DialogHeader>
          <DialogTitle>
            {mode === "edit"
              ? "Update listing schedule"
              : "Submit the listing request ?"}
          </DialogTitle>
        </DialogHeader>

        <DialogBody className="space-y-5">
          <div className="space-y-2">
            <p className="text-xs text-base-contrast-54">
              Listing schedule time
            </p>
            <div className="flex gap-2">
              <input
                type="date"
                value={date ? toDateInputValue(date) : ""}
                onChange={e => {
                  const next = parseDateInputValue(e.target.value);
                  setDate(next);
                }}
                min={minDate}
                className="flex-1 border bg-base-8 focus:ring-0 rounded-md h-10 px-3 text-xs text-base-contrast-98 scheme-dark"
              />
              <PLSelectField
                value={hour || undefined}
                onChange={v => setHour(v)}
                options={Array.from({ length: 24 }).map((_, i) => {
                  const h = i.toString().padStart(2, "0");
                  return {
                    value: h,
                    label: `${h}:00`,
                  };
                })}
                placeholder="Hour"
                portalContainer={dialogContentEl}
                triggerClassName="w-28 h-10 rounded-lg border border-base-contrast-12 bg-base-300 px-3 text-xs text-base-contrast-98"
              />
            </div>
            <p className="text-[11px] text-base-contrast-50">
              Must be at least 1 hour from now, on the hour (e.g. 16:00, 17:00)
            </p>
            {timeError && (
              <p className="text-[11px] text-danger">{timeError}</p>
            )}
          </div>
        </DialogBody>

        <DialogFooter className="justify-end gap-3 border-t border-t-base-contrast-8">
          <Button
            variant="outline"
            color="primary"
            onClick={() => handleOpenChange(false)}
          >
            Cancel
          </Button>
          <Button
            disabled={!listingDateTime || !isTimeValid}
            loading={submitting}
            onClick={handleConfirm}
          >
            {mode === "edit" ? "Save changes" : "Submit"}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
};
