import type {
  IndexSource,
  IndexSourceMeta,
  SourceItem,
  SymbolDetail,
} from "../../../../types";
import {
  getSourceDisplayMeta,
  matchIndexSourceCatalog,
  normalizeSourceKey,
  resolveApiSource,
  sourceKeyToItemId,
} from "../../../../services";

export const SEARCH_DEBOUNCE_MS = 350;
export const SOURCE_SYMBOL_DEBOUNCE_MS = 400;

export function getListingBaseFromSymbol(symbol: string | null): string {
  if (!symbol) return "";
  const parts = symbol.split("_");
  if (parts.length >= 3 && parts[0].toUpperCase() === "PERP") {
    return parts[1].toUpperCase();
  }
  return "";
}

export function isSameListingBaseSearch(
  editMode: boolean,
  editSymbol: string | null,
  searchTermForCompare: string
): boolean {
  if (!editMode || !editSymbol) return false;
  const listingBase = getListingBaseFromSymbol(editSymbol);
  if (!listingBase) return false;
  return searchTermForCompare.trim().toUpperCase() === listingBase;
}

function resolveApiKeyForSavedIndexSource(
  is: IndexSource,
  catalog: IndexSourceMeta[]
): string {
  const catRow = matchIndexSourceCatalog(catalog, is.source);
  const def = getSourceDisplayMeta(catRow?.source ?? is.source);
  return (
    def?.source ??
    catRow?.source ??
    resolveApiSource(is.source) ??
    normalizeSourceKey(is.source)
  );
}

export type SavedRowMerge = {
  sourceSymbol: string;
  feedId?: string;
  multiplier: number;
  price: number;
  volume24h: number;
  weight: number;
};
export function buildSavedMergeMapByRowId(
  detail: SymbolDetail,
  catalog: IndexSourceMeta[]
): Map<string, SavedRowMerge> {
  const baseToken = String(detail.params?.base_token?.value ?? "").trim();
  const m = new Map<string, SavedRowMerge>();
  for (const is of detail.indexSources) {
    const apiKey = resolveApiKeyForSavedIndexSource(is, catalog);
    const isPyth = normalizeSourceKey(apiKey) === "PYTH";
    const id = sourceKeyToItemId(apiKey);
    m.set(id, {
      sourceSymbol: isPyth
        ? baseToken
          ? `${baseToken.toUpperCase()}/USD`
          : is.sourceSymbol
        : is.sourceSymbol,
      feedId: isPyth ? is.sourceSymbol : undefined,
      multiplier: is.priceMultiplier ?? 1,
      price: is.latestPrice,
      volume24h: 0,
      weight: is.weight ?? 0,
    });
  }
  return m;
}

export function normalizeWeightPercentInt(weightPercent: number): number {
  if (!Number.isFinite(weightPercent) || weightPercent <= 0) return 0;
  return Math.max(1, Math.min(100, Math.round(weightPercent)));
}

export function normalizeStoredWeightPercentInt(weight: number): number {
  if (!Number.isFinite(weight) || weight <= 0) return 0;
  // Backend returns 0-1 decimal; internal store uses 1-100 integer percent.
  const pct = weight <= 1 ? Math.round(weight * 100) : Math.round(weight);
  return Math.max(1, Math.min(100, pct));
}

/**
 * Step 1 uses integer percent weights (1~100) in store / payload.
 * This helper generates the default integer-percent split for the currently
 * selected sources.
 */
export function getEqualSplitWeightPercents(count: number): number[] {
  if (!Number.isFinite(count) || count <= 0) return [];
  const base = Math.floor(100 / count);
  const remainder = 100 - base * count;

  return Array.from(
    { length: count },
    (_, index) => base + (index >= count - remainder ? 1 : 0)
  );
}

export enum PriceSourceWeightMode {
  Preserve = "preserve",
  Equal = "equal",
}

/**
 * Normalizes the source list after selection/search changes.
 *
 * - `Preserve`: keep the existing selected weights only when they already form
 *   a valid integer-percent allocation that sums to 100.
 * - `Equal`: always reset the selected sources to the default equal split.
 *
 * Unselected rows are always cleared to `0`.
 */
export function preserveOrRecalcWeights(
  items: SourceItem[],
  mode: PriceSourceWeightMode = PriceSourceWeightMode.Equal
): SourceItem[] {
  const result = items.map(s => ({
    ...s,
    weight: s.selected ? s.weight : 0,
  }));

  const selectedIndices = result.reduce<number[]>((acc, item, index) => {
    if (item.selected) acc.push(index);
    return acc;
  }, []);

  if (selectedIndices.length === 0) return result;

  if (mode === PriceSourceWeightMode.Preserve) {
    const percents = selectedIndices.map(index =>
      normalizeStoredWeightPercentInt(result[index].weight)
    );
    const isValid =
      percents.every(weight => Number.isInteger(weight) && weight >= 1) &&
      percents.reduce((sum, weight) => sum + weight, 0) === 100;

    if (isValid) {
      selectedIndices.forEach((index, idx) => {
        result[index].weight = normalizeWeightPercentInt(percents[idx]);
      });
      return result;
    }
  }

  const equalSplit = getEqualSplitWeightPercents(selectedIndices.length);
  selectedIndices.forEach((index, idx) => {
    result[index].weight = normalizeWeightPercentInt(equalSplit[idx]);
  });

  return result;
}

export function extractBaseFromSearch(
  searchTerm: string,
  sourceSymbol: string
): string {
  const baseFromSearch = searchTerm.trim().toUpperCase();
  if (baseFromSearch) return baseFromSearch;
  const upper = sourceSymbol.trim().toUpperCase();
  const dexSeparator = upper.indexOf(":");
  if (dexSeparator >= 0) {
    return upper.slice(dexSeparator + 1).replace(/[^A-Z0-9]/g, "");
  }
  const normalized = upper.replace(/[-_/]/g, "");
  if (normalized.endsWith("USDT")) return normalized.slice(0, -4);
  if (normalized.endsWith("USDC")) return normalized.slice(0, -4);
  if (normalized.endsWith("USD")) return normalized.slice(0, -3);
  return normalized;
}
