import { IndexSourceType, isSpotIndexSourceType } from "../../../../types";
import type { SourceItem } from "../../../../types";
import {
  PriceSourceWeightMode,
  preserveOrRecalcWeights,
  normalizeWeightPercentInt,
} from "./shared";

export function isBuilderLikeSourceType(sourceType: SourceItem["type"]) {
  return (
    sourceType === IndexSourceType.BuilderOracle ||
    sourceType === IndexSourceType.Byok
  );
}

export function isBuilderLikeSource(source: SourceItem) {
  return isBuilderLikeSourceType(source.type);
}

export function getExclusiveProviderKey(source: SourceItem) {
  const raw = (source.source ?? "").trim().toUpperCase();
  if (raw === "PYTH" || raw.startsWith("PYTH_")) return "PYTH";
  if (raw === "STORK" || raw.startsWith("STORK_")) return "STORK";
  return null;
}

export function isSourceSelectable(source: SourceItem, editMode: boolean) {
  if (source.loading) return false;
  const foundSelectable = Boolean(source.found) && !source.notFound;
  return editMode ? foundSelectable || source.selected : foundSelectable;
}

function getAvailabilityRank(source: SourceItem) {
  const isOracle = source.type === IndexSourceType.Oracle;
  const isBuilderLike = isBuilderLikeSource(source);
  const hasPrice = typeof source.price === "number" && source.price > 0;
  const foundOrPriced = Boolean(source.found) || hasPrice;
  const notFoundLike =
    Boolean(source.notFound) ||
    (!isOracle &&
      !isBuilderLike &&
      !source.priceLoading &&
      !source.loading &&
      !hasPrice);

  return notFoundLike ? 2 : foundOrPriced ? 0 : 1;
}

export function sortSourcesForDisplay(
  items: SourceItem[],
  initialOrderById: Map<string, number>
) {
  const fallbackOrder = new Map(
    items.map((source, index) => [source.id, index])
  );
  const getStableOrder = (id: string) =>
    initialOrderById.get(id) ??
    fallbackOrder.get(id) ??
    Number.MAX_SAFE_INTEGER;

  return [...items].sort((a, b) => {
    const aSelectedRank = a.selected ? 0 : 1;
    const bSelectedRank = b.selected ? 0 : 1;
    if (aSelectedRank !== bSelectedRank) return aSelectedRank - bSelectedRank;

    const aAvailabilityRank = getAvailabilityRank(a);
    const bAvailabilityRank = getAvailabilityRank(b);
    if (aAvailabilityRank !== bAvailabilityRank) {
      return aAvailabilityRank - bAvailabilityRank;
    }

    return getStableOrder(a.id) - getStableOrder(b.id);
  });
}

export function getSelectableSourcePool(
  priceSources: SourceItem[],
  editMode: boolean
) {
  return priceSources.filter(source => isSourceSelectable(source, editMode));
}

export function applyToggleSource(
  priceSources: SourceItem[],
  id: string
): SourceItem[] {
  const clicked = priceSources.find(source => source.id === id);
  if (!clicked) return priceSources;
  if (clicked.notFound && isBuilderLikeSource(clicked)) return priceSources;

  const willSelect = !clicked.selected;
  const exclusiveKey = willSelect ? getExclusiveProviderKey(clicked) : null;

  const updated = priceSources.map(source => {
    if (source.id === id) {
      return {
        ...source,
        selected: willSelect,
        selectedFromDetail: source.selectedFromDetail || willSelect,
      };
    }
    if (!exclusiveKey) return source;

    const otherKey = getExclusiveProviderKey(source);
    if (otherKey === exclusiveKey && source.selected) {
      return { ...source, selected: false };
    }
    return source;
  });

  return preserveOrRecalcWeights(updated, PriceSourceWeightMode.Equal);
}

export function applyToggleAllSources(
  priceSources: SourceItem[],
  editMode: boolean
): SourceItem[] {
  const pool = getSelectableSourcePool(priceSources, editMode);
  const selectedInPool = pool.filter(source => source.selected).length;
  const isHeaderChecked = pool.length > 0 && selectedInPool === pool.length;

  if (isHeaderChecked) {
    return preserveOrRecalcWeights(
      priceSources.map(source => ({ ...source, selected: false, weight: 0 })),
      PriceSourceWeightMode.Equal
    );
  }

  const selectedExclusiveProvider = new Set<string>();
  const updated = priceSources.map(source => {
    if (!isSourceSelectable(source, editMode)) {
      return { ...source, selected: false };
    }
    if (source.notFound && isBuilderLikeSource(source)) {
      return { ...source, selected: false, weight: 0 };
    }
    const exclusiveKey = getExclusiveProviderKey(source);
    if (exclusiveKey) {
      if (selectedExclusiveProvider.has(exclusiveKey)) {
        return { ...source, selected: false };
      }
      selectedExclusiveProvider.add(exclusiveKey);
    }
    return { ...source, selected: true, selectedFromDetail: true };
  });

  return preserveOrRecalcWeights(updated, PriceSourceWeightMode.Equal);
}

export function applyMultiplierUpdate(
  priceSources: SourceItem[],
  id: string,
  multiplier: number
) {
  const clicked = priceSources.find(source => source.id === id);
  const isSpot = clicked ? isSpotIndexSourceType(clicked.type) : false;
  return isSpot
    ? priceSources.map(source =>
        isSpotIndexSourceType(source.type) ? { ...source, multiplier } : source
      )
    : priceSources.map(source =>
        source.id === id ? { ...source, multiplier } : source
      );
}

export function applyWeightUpdate(
  priceSources: SourceItem[],
  id: string,
  weightPercent: number
) {
  const normalizedWeight = Math.max(
    1,
    Math.min(100, Math.round(Number(weightPercent) || 1))
  );
  return priceSources.map(source =>
    source.id === id && source.selected
      ? { ...source, weight: normalizeWeightPercentInt(normalizedWeight) }
      : source.selected
        ? source
        : { ...source, weight: 0 }
  );
}
