import { useState, useMemo, useEffect, useCallback } from "react";
import { useSelectListingStore } from "../../store/useListingStore";
import { PageView, SettingsTab } from "../../types";
import { useListingServerData } from "../../hooks/useListingServerData";
import { useListingRefreshActions } from "../../hooks/useListingRefreshActions";

export function useSettingsScript() {
  const { settingsTab, setPage, setSettingsTab } = useSelectListingStore(s => ({
    settingsTab: s.settingsTab,
    setPage: s.setPage,
    setSettingsTab: s.setSettingsTab,
  }));
  const { listingConfig, listingAccounts } = useListingServerData();
  const { refreshAccounts } = useListingRefreshActions();

  useEffect(() => {
    // update listing accounts to get the latest data when the component mounts
    refreshAccounts();
  }, [refreshAccounts]);

  const [activeTab, setActiveTab] = useState<SettingsTab>(settingsTab);

  // Keep local tab state in sync with global navigation intent.
  useEffect(() => {
    setActiveTab(settingsTab);
  }, [settingsTab]);

  const ifId = listingAccounts?.if_account?.account_id ?? "";

  const accountsIssues = useMemo(() => {
    let issues = 0;
    if (!ifId) issues += 1;
    return issues;
  }, [ifId]);

  const mmIssues = listingConfig.api_gateway ? 0 : 1;
  const notificationsIssues = listingConfig.tg_chat_id ? 0 : 1;

  const tabIssues: Record<SettingsTab, number> = {
    [SettingsTab.If]: accountsIssues,
    [SettingsTab.Mm]: mmIssues,
    [SettingsTab.Tier]: 0,
    [SettingsTab.Notifications]: notificationsIssues,
  };

  const onBack = useCallback(() => {
    setPage(PageView.Dashboard);
  }, [setPage]);

  return {
    activeTab,
    setActiveTab: (tab: SettingsTab) => {
      setActiveTab(tab);
      setSettingsTab(tab);
    },
    tabIssues,
    onBack,
  };
}
