import useSWR, { type SWRResponse } from "swr";
import {
  hasCompleteStoredAdminApiKey,
  signedAdminRequest,
} from "@/utils/adminKeyAuth";
import {
  normalizeOrderlyResponse,
  type useQueryOptions,
} from "./utils/fetcher";

export const usePrivateQuery = <T>(
  query: string | null,
  options?: useQueryOptions<T>
): SWRResponse<T> => {
  const { formatter, ...swrOptions } = options || {};
  return useSWR<T>(
    () => (query && hasCompleteStoredAdminApiKey() ? query : null),
    async (endpoint: string) => {
      const payload = await signedAdminRequest<unknown>({ endpoint });
      return normalizeOrderlyResponse<T>(payload, formatter);
    },
    swrOptions
  );
};
