import type { SWRConfiguration, SWRResponse } from "swr";

import type { useQueryOptions } from "@/hooks/utils/fetcher";
import { usePrivateQuery } from "@/hooks/usePrivateQuery";
import { useMutation } from "@/hooks/useMutation";
import type { ApiEnvelope, ApiSuccess } from "./types";

type MutationState<TData, TError> = {
  data: TData | undefined;
  error: TError | undefined;
  reset: () => void;
  isMutating: boolean;
};

type ApiFailure = {
  success: false;
  message?: string;
};

type ApiMutationResult<TData> = ApiSuccess | ApiEnvelope<TData> | ApiFailure;

function buildQueryString(params?: Record<string, unknown>): string {
  if (!params) return "";
  const usp = new URLSearchParams();

  Object.entries(params).forEach(([key, value]) => {
    if (value === undefined || value === null || value === "") return;
    usp.set(key, String(value));
  });

  const qs = usp.toString();
  return qs ? `?${qs}` : "";
}

function applyDefaultRevalidateOnFocus<T extends SWRConfiguration>(
  options?: T
): T {
  if (!options) return { revalidateOnFocus: false } as T;
  return {
    ...options,
    revalidateOnFocus: options.revalidateOnFocus ?? false,
  };
}

function useTypedPostMutation<TData, TInput extends Record<string, unknown>>(
  url: string
) {
  const [mutation, state] = useMutation<ApiMutationResult<TData>, unknown>(
    url,
    "POST"
  );
  const trigger = (input: TInput) => mutation(input);
  return [trigger, state as MutationState<TData, unknown>] as const;
}

