import { cn } from "@/utils/css";
import type { CustomOracleScriptReturn } from "./CustomOracle.script";
import { BuilderOraclePanel } from "./builder-oracle";
import { ByokProvidersPanel } from "./byok-providers";
import { OnboardingModal } from "./components/modals/OnboardingModal";
import { ArrowBackIcon, InfoCircleIcon } from "./components/CustomOracleIcons";

function PageTabs({
  currentTab,
  onSwitchTab,
}: {
  currentTab: "builder" | "byok";
  onSwitchTab: (tab: "builder" | "byok") => void;
}) {
  return (
    <div className="mb-6 flex items-center">
      <div className="flex flex-1 border-b border-base-contrast-8">
        {[
          { key: "builder", label: "Builder oracle" },
          { key: "byok", label: "Bring your own key" },
        ].map(tab => {
          const active = currentTab === tab.key;
          return (
            <button
              key={tab.key}
              type="button"
              onClick={() => onSwitchTab(tab.key as "builder" | "byok")}
              className={cn(
                "border-b-2 border-transparent px-5 py-2.5 text-xs font-medium transition-colors",
                active
                  ? "border-primary text-base-contrast-98"
                  : "text-base-contrast-54 hover:text-base-contrast-98"
              )}
            >
              {tab.label}
            </button>
          );
        })}
      </div>
    </div>
  );
}

export function CustomOraclePanelUI({
  currentTab,
  onboardingOpen,
  onBack,
  onSwitchTab,
  onOpenOnboarding,
  onCloseOnboarding,
}: CustomOracleScriptReturn) {
  return (
    <div className="flex flex-col pb-8">
      <div className="mb-6 flex items-center gap-4">
        <button
          type="button"
          onClick={onBack}
          className="shrink-0 cursor-pointer text-base-contrast-98 opacity-70 transition-opacity hover:opacity-100"
          aria-label="Back"
        >
          <ArrowBackIcon className="h-6 w-6" />
        </button>
        <div className="flex flex-1 items-center gap-2">
          <span className="text-lg font-medium text-base-contrast-98">
            Add custom oracle
          </span>
          <button
            type="button"
            onClick={onOpenOnboarding}
            className="text-base-contrast-50 transition-colors hover:text-primary-light"
            aria-label="Open custom oracle guide"
          >
            <InfoCircleIcon />
          </button>
        </div>
      </div>

      <PageTabs currentTab={currentTab} onSwitchTab={onSwitchTab} />

      {currentTab === "builder" ? (
        <BuilderOraclePanel />
      ) : (
        <ByokProvidersPanel />
      )}

      <OnboardingModal open={onboardingOpen} onClose={onCloseOnboarding} />
    </div>
  );
}
