import type { ByokProvider } from "../types";
import { Button } from "@/components/button";
import type { BuilderOracleScriptReturn } from "./BuilderOracle.script";
import { BuilderOracleView } from "./BuilderOracleView";
import { BuilderAddSymbolModal } from "../components/modals/BuilderAddSymbolModal";
import { RemoveFeedModal } from "../components/modals/RemoveFeedModal";
import { VisibilityModal } from "../components/modals/VisibilityModal";

const EMPTY_BYOK_PROVIDERS: ByokProvider[] = [];

export function BuilderOraclePanelUI({
  source,
  loading,
  copiedField,
  modal,
  isOracleFeedMutating,
  onCopyField,
  onOpenAddSymbol,
  onOpenVisibility,
  onOpenRemove,
  onCloseAddSymbol,
  onConfirmBuilderAddSymbol,
  onCloseVisibility,
  onSaveVisibility,
  onCloseRemove,
  onConfirmRemove,
}: BuilderOracleScriptReturn) {
  const visibilityTarget =
    modal.visibilityTarget?.source === "builder"
      ? modal.visibilityTarget
      : null;
  const removeTarget =
    modal.removeTarget?.source === "builder" ? modal.removeTarget : null;

  return (
    <div className="relative">
      <div className="absolute right-0 top-[-64px] z-10">
        <Button size="sm" onClick={onOpenAddSymbol}>
          <span className="mr-1 text-sm leading-none">+</span>
          Add symbol
        </Button>
      </div>

      <BuilderOracleView
        source={source}
        loading={loading}
        copiedField={copiedField}
        onCopyField={onCopyField}
        onOpenVisibility={onOpenVisibility}
        onOpenRemove={onOpenRemove}
        onOpenAddSymbol={onOpenAddSymbol}
      />

      <BuilderAddSymbolModal
        open={modal.builderAddSymbolOpen}
        sourceName={source.name}
        isMutating={isOracleFeedMutating}
        onClose={onCloseAddSymbol}
        onConfirm={onConfirmBuilderAddSymbol}
      />

      <VisibilityModal
        target={visibilityTarget}
        builderOracleSource={source}
        byokProviders={EMPTY_BYOK_PROVIDERS}
        isMutating={isOracleFeedMutating}
        onClose={onCloseVisibility}
        onSave={onSaveVisibility}
      />

      <RemoveFeedModal
        target={removeTarget}
        builderOracleSource={source}
        byokProviders={EMPTY_BYOK_PROVIDERS}
        isMutating={isOracleFeedMutating}
        onClose={onCloseRemove}
        onConfirm={onConfirmRemove}
      />
    </div>
  );
}
