import type {
  ByokProvider,
  ByokSymbol,
  CustomOracleModalState,
} from "../../types";
import type {
  ByokFeedRow,
  ByokKeyRow,
  ByokProviderRow,
} from "../../../../services";

export function cloneModal(
  current: CustomOracleModalState,
  patch: Partial<CustomOracleModalState>
): CustomOracleModalState {
  return {
    ...current,
    ...patch,
  };
}

export function formatMaskedKey(apiKey?: string) {
  if (!apiKey) return "Configured";
  if (apiKey.length <= 8) return apiKey;
  return `${apiKey.slice(0, 5)}...${apiKey.slice(-4)}`;
}

function formatUpdatedText(lastUpdate: number | null | undefined) {
  if (!lastUpdate) return "No data yet";
  const delta = Math.max(1, Math.floor((Date.now() - lastUpdate) / 1000));
  if (delta < 60) return `Updated ${delta}s ago`;
  if (delta < 3600) return `Updated ${Math.floor(delta / 60)}m ago`;
  return `Updated ${Math.floor(delta / 3600)}h ago`;
}

export function normalizeProviderId(value: string): string {
  return value.toLowerCase();
}

export function mapByokSymbol(row: ByokFeedRow): ByokSymbol {
  return {
    id: row.base_ccy.toLowerCase(),
    name: row.base_ccy,
    sourceId: row.source_id,
    visibility: row.visibility,
    status: row.status,
    price: row.price,
    updatedText: formatUpdatedText(row.last_update),
    errorCode: row.error_code ?? null,
  };
}

export function mapByokProviders(
  providerRows: ByokProviderRow[],
  keyRows: ByokKeyRow[],
  feedRows: ByokFeedRow[]
): ByokProvider[] {
  const providerMap = new Map<string, ByokProviderRow>();
  providerRows.forEach(row => {
    providerMap.set(normalizeProviderId(row.oracle), row);
  });

  const keyMap = new Map<string, ByokKeyRow>();
  keyRows.forEach(row => {
    keyMap.set(normalizeProviderId(row.oracle), row);
  });

  const allProviderIds = new Set<string>([
    ...providerRows.map(row => normalizeProviderId(row.oracle)),
    ...keyRows.map(row => normalizeProviderId(row.oracle)),
    ...feedRows.map(row => normalizeProviderId(row.oracle)),
  ]);

  return Array.from(allProviderIds).map(providerId => {
    const provider = providerMap.get(providerId);
    const key = keyMap.get(providerId);
    const symbols = feedRows
      .filter(row => normalizeProviderId(row.oracle) === providerId)
      .map(mapByokSymbol);

    return {
      id: providerId,
      providerName: provider?.name ?? providerId.toUpperCase(),
      sourceName: key?.source_id ?? `${providerId.toUpperCase()} source`,
      keyMasked: formatMaskedKey(key?.api_key),
      keyState: !key
        ? "empty"
        : key.status === "inactive"
          ? "deactivated"
          : "configured",
      healthLabel: key?.health ?? undefined,
      symbols,
    };
  });
}

export function getByokFeedIdentity(
  providerId: string,
  symbolId: string,
  providers: ByokProvider[]
) {
  const provider = providers.find(item => item.id === providerId);
  const symbol = provider?.symbols.find(item => item.id === symbolId);

  return {
    base_ccy: symbol?.name ?? symbolId.toUpperCase(),
    oracle: providerId,
  };
}
