import type { ReactNode } from "react";
import Tooltip from "@/components/tooltip";
import { cn } from "@/utils/css";
import { PLSelectField } from "../../../components/PLSelect";

export function InfoIcon({ className }: { className?: string }) {
  return (
    <svg
      width={14}
      height={14}
      viewBox="0 0 14 14"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      className={cn("shrink-0", className)}
      aria-hidden
    >
      <circle cx="7" cy="7" r="6.5" stroke="currentColor" />
      <rect x="6.5" y="6" width="1" height="4" rx="0.5" fill="currentColor" />
      <rect x="6.5" y="4" width="1" height="1" rx="0.5" fill="currentColor" />
    </svg>
  );
}

export function ParamInfoTrigger({
  label,
  tooltip,
}: {
  label: string;
  tooltip: string;
}) {
  return (
    <Tooltip
      content={tooltip}
      side="top"
      sideOffset={6}
      className="max-w-[min(320px,90vw)] whitespace-normal text-left"
    >
      <button
        type="button"
        className="inline-flex p-0.5 -m-0.5 rounded text-base-contrast-50 hover:text-base-contrast-70"
        aria-label={`More information: ${label}`}
      >
        <InfoIcon />
      </button>
    </Tooltip>
  );
}

export function Field({
  label,
  tooltip,
  required,
  value,
  error,
  warning,
  placeholder,
  prefix,
  suffix,
  hint,
  inputMode,
  readOnly,
  disabled,
  onBlurValidate,
  onChange,
}: {
  label: string;
  tooltip: string;
  required?: boolean;
  value: string;
  error?: string;
  warning?: string;
  placeholder?: string;
  prefix?: string;
  suffix?: string;
  hint?: string;
  inputMode?: "numeric" | "decimal";
  readOnly?: boolean;
  disabled?: boolean;
  onBlurValidate?: () => void;
  onChange: (v: string) => void;
}) {
  return (
    <div className="flex flex-col gap-2">
      <div className="flex items-center gap-1">
        <span className="text-xs font-medium text-base-contrast-98">
          {label}
        </span>
        {required && (
          <span className="text-xs font-medium text-primary-light">*</span>
        )}
        <ParamInfoTrigger label={label} tooltip={tooltip} />
      </div>
      <div
        className={cn(
          "flex items-center rounded-lg h-10 px-3",
          "bg-base-300 border",
          error ? "border-danger" : "border-transparent",
          "focus-within:border-primary/50 focus-within:border"
        )}
      >
        {prefix && (
          <span className="text-xs text-base-contrast-36 shrink-0">
            {prefix}
          </span>
        )}
        <input
          value={value}
          onChange={e => onChange(e.target.value)}
          placeholder={placeholder}
          inputMode={inputMode}
          onBlur={onBlurValidate}
          readOnly={readOnly}
          disabled={disabled}
          className={cn(
            "flex-1 min-w-0 text-xs font-medium bg-transparent",
            "text-base-contrast-98 placeholder:text-base-contrast-36",
            "outline-none border-0",
            (readOnly || disabled) && "cursor-not-allowed opacity-50",
            prefix && "pl-1"
          )}
        />
        {suffix && (
          <span className="text-xs text-base-contrast-36 shrink-0 pl-1">
            {suffix}
          </span>
        )}
      </div>
      {error && <span className="text-3xs text-danger">{error}</span>}
      {!error && warning && (
        <span className="text-3xs text-warning">{warning}</span>
      )}
      {hint && !error && !warning && (
        <span className="text-3xs text-base-contrast-36">{hint}</span>
      )}
    </div>
  );
}

export function SelectField(props: {
  label: string;
  tooltip: string;
  value: string;
  options: { value: string; label: ReactNode }[];
  required?: boolean;
  error?: string;
  hint?: string;
  hintClassName?: string;
  disabled?: boolean;
  onChange: (v: string) => void;
  triggerClassName?: string;
}) {
  const {
    label,
    tooltip,
    required,
    error,
    hint,
    hintClassName,
    triggerClassName,
    ...rest
  } = props;
  return (
    <div className="flex flex-col gap-2">
      <div className="flex items-center gap-1">
        <span className="text-xs font-medium text-base-contrast-98">
          {label}
        </span>
        {required && (
          <span className="text-xs font-medium text-primary-light">*</span>
        )}
        <ParamInfoTrigger label={label} tooltip={tooltip} />
      </div>
      <PLSelectField
        {...rest}
        placeholder="-"
        error={error}
        hint={hint}
        hintClassName={hintClassName}
        triggerClassName={cn("min-h-[40px] w-full", triggerClassName)}
      />
    </div>
  );
}

export function TemplateInfoBlock({
  label,
  value,
}: {
  label: string;
  value: string;
}) {
  return (
    <div>
      <div className="mb-1 text-3xs text-base-contrast-50">{label}</div>
      <div className="text-3xs font-medium text-base-contrast-98">{value}</div>
    </div>
  );
}
