import { useCallback, useState } from "react";
import { Button } from "@/components/button";
import { cn } from "@/utils/css";
import type { ByokProvider } from "../types";
import { EyeIcon, LockIcon, PencilIcon } from "../components/CustomOracleIcons";

function formatPrice(price: number | null) {
  if (price == null) return "—";
  return `$${price.toLocaleString("en-US", {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  })}`;
}

function ByokVisibilityChip({
  visibility,
}: {
  visibility: "public" | "private";
}) {
  const isPublic = visibility === "public";

  return (
    <span
      className={cn(
        "inline-flex items-center gap-1 rounded-sm px-2 py-0.5 text-4xs font-medium",
        isPublic
          ? "bg-primary/10 text-primary-light"
          : "border border-base-contrast-12 bg-transparent text-base-contrast-50"
      )}
    >
      {isPublic ? <EyeIcon /> : <LockIcon />}
      {isPublic ? "Public" : "Private"}
    </span>
  );
}

interface ByokProvidersViewProps {
  providers: ByokProvider[];
  loading?: boolean;
  onOpenAddProvider: (providerId: ByokProvider["id"]) => void;
  onOpenUpdateKey: (providerId: ByokProvider["id"]) => void;
  onOpenDeactivateKey: (providerId: ByokProvider["id"]) => void;
  onActivateKey: (providerId: ByokProvider["id"]) => Promise<void>;
  onOpenAddSymbol: (providerId: ByokProvider["id"]) => void;
  onOpenVisibility: (providerId: ByokProvider["id"], symbolId: string) => void;
  onOpenRemove: (providerId: ByokProvider["id"], symbolId: string) => void;
}

export function ByokProvidersView({
  providers,
  loading = false,
  onOpenAddProvider,
  onOpenUpdateKey,
  onOpenDeactivateKey,
  onActivateKey,
  onOpenAddSymbol,
  onOpenVisibility,
  onOpenRemove,
}: ByokProvidersViewProps) {
  const [activatingProviderId, setActivatingProviderId] = useState<
    ByokProvider["id"] | null
  >(null);

  const handleActivateKey = useCallback(
    async (providerId: ByokProvider["id"]) => {
      if (activatingProviderId === providerId) return;
      setActivatingProviderId(providerId);
      try {
        await onActivateKey(providerId);
      } finally {
        setActivatingProviderId(current =>
          current === providerId ? null : current
        );
      }
    },
    [activatingProviderId, onActivateKey]
  );

  return (
    <div className="flex flex-col gap-4">
      {loading ? (
        <div className="space-y-4 animate-pulse">
          {Array.from({ length: 2 }).map((_, i) => (
            <div
              key={i}
              className="rounded-xl border border-base-contrast-8 bg-base-200"
            >
              <div className="flex items-center gap-3 px-6 py-5">
                <div className="h-4 w-44 rounded bg-base-contrast-12" />
                <div className="ml-auto h-8 w-28 rounded bg-base-contrast-12" />
              </div>

              <div className="mx-6 grid grid-cols-2 overflow-hidden rounded-lg border border-base-contrast-8">
                <div className="border-r border-base-contrast-8 bg-base-300 px-4 py-3">
                  <div className="h-3 w-16 rounded bg-base-contrast-12" />
                  <div className="mt-2 h-4 w-28 rounded bg-base-contrast-12" />
                </div>
                <div className="bg-base-300 px-4 py-3">
                  <div className="h-3 w-12 rounded bg-base-contrast-12" />
                  <div className="mt-2 flex items-center gap-3">
                    <div className="h-4 w-32 rounded bg-base-contrast-12" />
                    <div className="ml-auto flex items-center gap-4">
                      <div className="h-3 w-16 rounded bg-base-contrast-12" />
                      <div className="h-3 w-24 rounded bg-base-contrast-12" />
                    </div>
                  </div>
                </div>
              </div>

              <div className="px-6 py-5">
                <div className="mb-5 mx-[-24px] h-px bg-base-contrast-8" />
                <div className="grid grid-cols-3 gap-3">
                  {Array.from({ length: 3 }).map((__, j) => (
                    <div key={j} className="rounded-xl bg-base-300 px-5 py-5">
                      <div className="flex items-start gap-2">
                        <div className="h-5 w-20 rounded bg-base-contrast-12" />
                        <div className="h-4 w-14 rounded bg-base-contrast-12" />
                        <div className="ml-auto h-4 w-12 rounded bg-base-contrast-12" />
                      </div>
                      <div className="mt-3 h-7 w-28 rounded bg-base-contrast-12" />
                      <div className="mt-2 h-3 w-24 rounded bg-base-contrast-12" />
                      <div className="mt-4 h-8 w-28 rounded bg-base-contrast-12" />
                    </div>
                  ))}
                </div>
              </div>
            </div>
          ))}
        </div>
      ) : null}

      {!loading
        ? providers.map(provider => {
            if (provider.keyState === "empty") {
              return (
                <div
                  key={provider.id}
                  role="button"
                  tabIndex={0}
                  onClick={() => onOpenAddProvider(provider.id)}
                  onKeyDown={event => {
                    if (event.key === "Enter" || event.key === " ") {
                      event.preventDefault();
                      onOpenAddProvider(provider.id);
                    }
                  }}
                  className="cursor-pointer rounded-xl border-2 border-dashed border-base-contrast-12 px-8 py-8 text-center transition-colors hover:border-primary/40 hover:bg-primary/5"
                >
                  <div className="text-xs text-base-contrast-50">
                    {provider.providerName} source not configured
                  </div>
                  <div className="mt-1 text-2xs text-primary-light">
                    + Add {provider.providerName} Bring Your Own Key source
                  </div>
                </div>
              );
            }

            const isDeactivated = provider.keyState === "deactivated";
            const isActivating =
              isDeactivated && activatingProviderId === provider.id;

            return (
              <div
                key={provider.id}
                className="rounded-xl border border-base-contrast-8 bg-base-200"
              >
                <div className="flex items-center gap-3 px-6 py-5">
                  <div className="text-base font-semibold text-base-contrast-98">
                    {provider.sourceName}
                  </div>
                  {!isDeactivated ? (
                    <Button
                      size="sm"
                      className="ml-auto"
                      onClick={() => onOpenAddSymbol(provider.id)}
                    >
                      <span className="mr-1 text-sm leading-none">+</span>
                      Add symbol
                    </Button>
                  ) : null}
                </div>

                <div className="mx-6 grid grid-cols-2 overflow-hidden rounded-lg border border-base-contrast-8">
                  <div className="border-r border-base-contrast-8 bg-base-300 px-4 py-3">
                    <div className="text-2xs font-medium text-base-contrast-50">
                      Provider
                    </div>
                    <div className="mt-1 text-xs font-semibold text-base-contrast-98">
                      {provider.providerName}
                    </div>
                  </div>
                  <div className="bg-base-300 px-4 py-3">
                    <div className="text-2xs font-medium text-base-contrast-50">
                      API key
                    </div>
                    <div className="mt-1 flex items-center gap-3">
                      <div
                        className={cn(
                          "text-xs font-semibold",
                          isDeactivated
                            ? "text-base-contrast-36"
                            : "text-base-contrast-98"
                        )}
                      >
                        {isDeactivated ? "Deactivated" : provider.keyMasked}
                      </div>
                      <div className="ml-auto flex items-center gap-4 text-2xs font-medium">
                        <button
                          type="button"
                          disabled={isActivating}
                          aria-busy={isActivating}
                          className={cn(
                            "text-primary-light hover:underline",
                            isActivating && "cursor-not-allowed opacity-60"
                          )}
                          onClick={() =>
                            isDeactivated
                              ? handleActivateKey(provider.id)
                              : onOpenUpdateKey(provider.id)
                          }
                        >
                          {isDeactivated ? (
                            <span className="inline-flex items-center gap-2">
                              {isActivating ? (
                                <span
                                  className="inline-block h-3 w-3 border border-current border-t-transparent rounded-full animate-spin"
                                  aria-hidden
                                />
                              ) : null}
                              Activate key
                            </span>
                          ) : (
                            "Update key"
                          )}
                        </button>
                        {!isDeactivated ? (
                          <button
                            type="button"
                            className="text-danger hover:underline"
                            onClick={() => onOpenDeactivateKey(provider.id)}
                          >
                            Deactivate key
                          </button>
                        ) : null}
                      </div>
                    </div>
                  </div>
                </div>

                {isDeactivated ? (
                  <div className="px-6 py-6 text-xs leading-6 text-base-contrast-50">
                    This source is inactive. Activate the key to restore symbols
                    and continue pulling prices.
                  </div>
                ) : (
                  <div className="px-6 py-5">
                    <div className="mb-5 mx-[-24px] h-px bg-base-contrast-8" />
                    <div className="grid grid-cols-3 gap-3">
                      {provider.symbols.map(symbol => (
                        <div
                          key={symbol.id}
                          className="rounded-xl bg-base-300 px-5 py-5"
                        >
                          <div className="flex items-center gap-2">
                            <div className="text-base font-bold text-base-contrast-98">
                              {symbol.name}
                            </div>
                            <ByokVisibilityChip
                              visibility={symbol.visibility}
                            />
                            <button
                              type="button"
                              className="inline-flex h-5 w-5 shrink-0 items-center justify-center text-primary"
                              onClick={() =>
                                onOpenVisibility(provider.id, symbol.id)
                              }
                            >
                              <PencilIcon />
                            </button>
                            <span
                              className={cn(
                                "ml-auto rounded-full px-2.5 py-0.5 text-4xs font-medium",
                                symbol.status === "active"
                                  ? "bg-success/15 text-success"
                                  : "bg-base-contrast-8 text-base-contrast-50"
                              )}
                            >
                              {symbol.status === "active"
                                ? "Active"
                                : "Inactive"}
                            </span>
                          </div>
                          <div
                            className={cn(
                              "mt-3 text-[22px] font-bold",
                              symbol.price == null
                                ? "text-base-contrast-36"
                                : "text-success"
                            )}
                          >
                            {formatPrice(symbol.price)}
                          </div>
                          <div className="mt-1 text-4xs text-base-contrast-50">
                            {symbol.updatedText}
                          </div>
                          <Button
                            size="sm"
                            variant="outline"
                            className="mt-4"
                            onClick={() => onOpenRemove(provider.id, symbol.id)}
                            color={
                              symbol.status === "active" ? "danger" : "primary"
                            }
                          >
                            {symbol.status === "active"
                              ? "Deactivate"
                              : "Activate"}
                          </Button>
                        </div>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            );
          })
        : null}
    </div>
  );
}
