import { useCallback, useEffect, useRef } from "react";
import {
  ListingAssetType,
  type SourceItem,
  type SymbolDetail,
} from "../../../../types";
import {
  fetchExternalSourceQuote,
  resolveApiSource,
} from "../../../../services";
import {
  PriceSourceWeightMode,
  SOURCE_SYMBOL_DEBOUNCE_MS,
  extractBaseFromSearch,
  isSameListingBaseSearch,
  preserveOrRecalcWeights,
} from "./shared";
import { isBuilderLikeSourceType } from "./rules.helpers";

export type UsePriceSourcesQuotesParams = {
  priceSources: SourceItem[];
  sourcesRef: { current: SourceItem[] };
  setPriceSources: (sources: SourceItem[]) => void;
  searchTerm: string;
  editMode: boolean;
  editSymbol: string | null;
  symbolDetails: Record<string, SymbolDetail>;
  /**
   * Refetch builder-like sources (Builder Oracle / BYOK) so manual symbol edits
   * can re-resolve prices via builder_sources merge.
   */
  refetchBuilderSources?: () => void | Promise<unknown>;
  listingAssetType?: ListingAssetType;
};

export function usePriceSourcesQuotes({
  priceSources,
  sourcesRef,
  setPriceSources,
  searchTerm,
  editMode,
  editSymbol,
  symbolDetails: _symbolDetails,
  refetchBuilderSources,
  listingAssetType,
}: UsePriceSourcesQuotesParams) {
  const sourceSymbolTimersRef = useRef<Record<string, number | null>>({});
  const sourceQuoteReqIdRef = useRef<Record<string, number>>({});
  const lastRequestedSymbolRef = useRef<Record<string, string>>({});

  useEffect(() => {
    const timers = sourceSymbolTimersRef.current;
    return () => {
      for (const id of Object.keys(timers)) {
        const t = timers[id];
        if (t) window.clearTimeout(t);
      }
    };
  }, []);

  useEffect(() => {
    const validIds = new Set(priceSources.map(s => s.id));

    for (const id of Object.keys(sourceQuoteReqIdRef.current)) {
      if (!validIds.has(id)) {
        delete sourceQuoteReqIdRef.current[id];
      }
    }

    for (const id of Object.keys(lastRequestedSymbolRef.current)) {
      if (!validIds.has(id)) {
        delete lastRequestedSymbolRef.current[id];
      }
    }

    for (const id of Object.keys(sourceSymbolTimersRef.current)) {
      if (validIds.has(id)) continue;
      const timer = sourceSymbolTimersRef.current[id];
      if (timer) window.clearTimeout(timer);
      delete sourceSymbolTimersRef.current[id];
    }
  }, [priceSources]);

  const updateRowById = useCallback(
    (
      id: string,
      updater: (row: SourceItem) => SourceItem
    ): { row: SourceItem | undefined; updated: SourceItem[] } => {
      let row: SourceItem | undefined;
      const updated = sourcesRef.current.map(s => {
        if (s.id !== id) return s;
        row = s;
        return updater(s);
      });
      return { row, updated };
    },
    [sourcesRef]
  );

  const refetchSourceQuote = useCallback(
    async (
      id: string,
      sourceSymbol: string,
      sourceName: string,
      sourceType: SourceItem["type"]
    ) => {
      const reqId = (sourceQuoteReqIdRef.current[id] ?? 0) + 1;
      sourceQuoteReqIdRef.current[id] = reqId;

      const { row: rowBefore, updated: loadingUpdated } = updateRowById(
        id,
        s => ({
          ...s,
          sourceSymbol,
          sourceSymbolManual:
            isBuilderLikeSourceType(s.type) && sourceSymbol.trim()
              ? true
              : s.sourceSymbolManual,
          priceLoading: true,
          volumeLoading: true,
          notFound: false,
        })
      );
      const preserveEditListingRow =
        Boolean(rowBefore?.selected) &&
        isSameListingBaseSearch(editMode, editSymbol, searchTerm);

      setPriceSources(loadingUpdated);

      const apiSource = resolveApiSource(sourceName);
      if (isBuilderLikeSourceType(sourceType)) {
        // Builder-like rows don't use external quote fetch; they are resolved
        // by merging `/builder_sources` rows. Support manual symbol input by
        // refetching builder_sources and showing a loading state meanwhile.
        const { updated } = updateRowById(id, s => ({
          ...s,
          sourceSymbol,
          sourceSymbolManual: true,
          priceLoading: true,
          volumeLoading: false,
          notFound: false,
        }));
        setPriceSources(updated);
        await Promise.resolve(refetchBuilderSources?.());
        return;
      }
      if (!apiSource) {
        const { updated } = updateRowById(id, s => ({
          ...s,
          found: preserveEditListingRow,
          notFound: !preserveEditListingRow,
          priceLoading: false,
          volumeLoading: false,
        }));
        setPriceSources(
          preserveOrRecalcWeights(updated, PriceSourceWeightMode.Equal)
        );
        return;
      }

      const base = extractBaseFromSearch(searchTerm, sourceSymbol);
      const quote = await fetchExternalSourceQuote({
        source: apiSource,
        type: sourceType,
        baseSymbol: base,
        sourceSymbol,
        listingAssetType,
      });
      if ((sourceQuoteReqIdRef.current[id] ?? 0) !== reqId) return;

      const { updated } = updateRowById(id, s => ({
        ...s,
        found: preserveEditListingRow || quote.found,
        notFound: preserveEditListingRow ? false : !quote.found,
        price: quote.found ? quote.latestPrice : s.price,
        volume24h: quote.found ? quote.volume24h : s.volume24h,
        sourceSymbol: quote.found ? quote.sourceSymbol : s.sourceSymbol,
        feedId: quote.found ? quote.feedId : s.feedId,
        priceLoading: false,
        volumeLoading: false,
      }));
      setPriceSources(
        preserveOrRecalcWeights(updated, PriceSourceWeightMode.Equal)
      );
    },
    [
      editMode,
      editSymbol,
      searchTerm,
      setPriceSources,
      updateRowById,
      refetchBuilderSources,
      listingAssetType,
    ]
  );

  const updateSourceSymbol = useCallback(
    (id: string, symbol: string) => {
      const { row, updated } = updateRowById(id, s => ({
        ...s,
        sourceSymbol: symbol,
        sourceSymbolManual: isBuilderLikeSourceType(s.type)
          ? Boolean(symbol.trim())
          : s.sourceSymbolManual,
      }));
      setPriceSources(updated);

      const prev = sourceSymbolTimersRef.current[id];
      if (prev) window.clearTimeout(prev);
      sourceSymbolTimersRef.current[id] = window.setTimeout(() => {
        if (!row) return;
        const normalizedSymbol = symbol.trim();
        if (!normalizedSymbol) {
          delete lastRequestedSymbolRef.current[id];
          return;
        }
        if (lastRequestedSymbolRef.current[id] === normalizedSymbol) return;
        lastRequestedSymbolRef.current[id] = normalizedSymbol;
        refetchSourceQuote(id, normalizedSymbol, row.name, row.type);
      }, SOURCE_SYMBOL_DEBOUNCE_MS);
    },
    [setPriceSources, refetchSourceQuote, updateRowById]
  );

  const refetchSourceQuoteNow = useCallback(
    (id: string) => {
      const row = sourcesRef.current.find(s => s.id === id);
      if (!row) {
        delete sourceQuoteReqIdRef.current[id];
        delete lastRequestedSymbolRef.current[id];
        const timer = sourceSymbolTimersRef.current[id];
        if (timer) window.clearTimeout(timer);
        delete sourceSymbolTimersRef.current[id];
        return;
      }
      const symbol = row.sourceSymbol.trim();
      if (!symbol) return;
      lastRequestedSymbolRef.current[id] = symbol;
      refetchSourceQuote(id, symbol, row.name, row.type);
    },
    [refetchSourceQuote, sourcesRef]
  );

  return {
    refetchSourceQuote,
    updateSourceSymbol,
    refetchSourceQuoteNow,
  };
}
