import type {
  BuilderOracleSource,
  ByokProvider,
  CustomOracleSymbolTarget,
  VisibilityMode,
} from "../../types";

export const infoBannerClassName =
  "rounded-xl border border-base-contrast-8 bg-primary/5 px-5 py-4 text-2xs leading-6 text-base-contrast-54";
export const sourceIdClassName = "rounded-lg bg-base-200 px-4 py-3 text-left";
export const formLabelClassName =
  "mb-2 block text-2xs font-medium text-base-contrast-50";
export const footerClassName = "gap-2 border-t-0 pt-1";

export function findTargetName(
  target: CustomOracleSymbolTarget | null,
  builderOracleSource: BuilderOracleSource,
  byokProviders: ByokProvider[]
) {
  if (!target) return "";
  if (target.source === "builder") {
    return (
      builderOracleSource.symbols.find(symbol => symbol.id === target.symbolId)
        ?.name ?? ""
    );
  }
  const provider = byokProviders.find(item => item.id === target.providerId);
  return (
    provider?.symbols.find(symbol => symbol.id === target.symbolId)?.name ?? ""
  );
}

export function findCurrentVisibility(
  target: CustomOracleSymbolTarget | null,
  builderOracleSource: BuilderOracleSource,
  byokProviders: ByokProvider[]
): VisibilityMode {
  if (!target) return "private";
  if (target.source === "builder") {
    return (
      builderOracleSource.symbols.find(symbol => symbol.id === target.symbolId)
        ?.visibility ?? "private"
    );
  }
  const provider = byokProviders.find(item => item.id === target.providerId);
  return (
    provider?.symbols.find(symbol => symbol.id === target.symbolId)
      ?.visibility ?? "private"
  );
}

export function getProviderLabel(
  providerId: string | null,
  byokProviders: ByokProvider[]
) {
  if (!providerId) return "";
  return (
    byokProviders.find(item => item.id === providerId)?.providerName ??
    providerId.toUpperCase()
  );
}

export function getByokSourceId(providerId: string | null) {
  if (!providerId) return "";
  return providerId === "pyth" ? "PYTH_woofi_pro" : "STORK_woofi_pro";
}
