import {
  BalanceBar,
  SubAccountDropdown,
} from "@/permissionless-listing/components";
import { useMergedIfAccounts } from "../hooks/useMergedIfAccounts";
import { useMemo, useState } from "react";
import { CreateSubAccountModal } from "@/permissionless-listing/modals";
import { Button } from "@/components/button";
import {
  useInsuranceFundBind,
  type UseInsuranceFundBindReturn,
} from "../hooks/useInsuranceFundBind";
import { useListingServerData } from "@/permissionless-listing/hooks/useListingServerData";
import { useListingRefreshActions } from "@/permissionless-listing/hooks/useListingRefreshActions";

type InsuranceFundStepProps = {
  /**
   * When set, parent owns `useInsuranceFundBind()` (e.g. onboarding Done).
   * When omitted, this component mounts its own hook (e.g. settings page).
   */
  bind?: UseInsuranceFundBindReturn;
  /** When true, hide the inline Bind button (binding is done elsewhere). */
  hideInlineBind?: boolean;
};

export function InsuranceFundStep({
  bind,
  hideInlineBind,
}: InsuranceFundStepProps) {
  if (bind) {
    return (
      <InsuranceFundStepView bind={bind} hideInlineBind={hideInlineBind} />
    );
  }
  return <InsuranceFundStepWithHook hideInlineBind={hideInlineBind} />;
}

function InsuranceFundStepWithHook({
  hideInlineBind,
}: {
  hideInlineBind?: boolean;
}) {
  const internalBind = useInsuranceFundBind();
  return (
    <InsuranceFundStepView
      bind={internalBind}
      hideInlineBind={hideInlineBind}
    />
  );
}

function InsuranceFundStepView({
  bind,
  hideInlineBind,
}: {
  bind: UseInsuranceFundBindReturn;
  hideInlineBind?: boolean;
}) {
  const { subAccounts } = useListingServerData();
  const { refreshAccounts, refreshBalances } = useListingRefreshActions();

  const { mergedIfAccounts, vaultSpAccountIdSet, mutateAvailableIfAccounts } =
    useMergedIfAccounts(subAccounts);

  const [createOpen, setCreateOpen] = useState(false);

  const {
    pendingIfId,
    setPendingIfId,
    isCompleting,
    bindError,
    clearBindError,
    ifId,
    minIfBalance,
    completeIfBindIfNeeded,
  } = bind;

  const activeIfId = pendingIfId;

  const isVaultSpAccountSelected = useMemo(() => {
    if (!activeIfId) return false;
    return vaultSpAccountIdSet.has(activeIfId);
  }, [activeIfId, vaultSpAccountIdSet]);

  const selectedIfBalance = useMemo(() => {
    const acc = mergedIfAccounts.find(a => a.sub_account_id === pendingIfId);
    return acc?.balance ?? 0;
  }, [mergedIfAccounts, pendingIfId]);

  const onSelect = (id: string) => {
    setPendingIfId(id);
  };

  const onBindPending = () => {
    void completeIfBindIfNeeded();
  };

  const showInlineBind = !hideInlineBind;

  return (
    <>
      <CreateSubAccountModal
        open={createOpen}
        onOpenChange={setCreateOpen}
        onSuccess={() => {
          setCreateOpen(false);
          void refreshAccounts();
          void refreshBalances();
          void mutateAvailableIfAccounts();
        }}
      />

      <div className="flex flex-col gap-2">
        <label className="text-3xs font-medium text-base-contrast-50">
          Account ID
        </label>
        <div className="flex items-start gap-3">
          <div className="flex-1 min-w-0">
            <SubAccountDropdown
              accounts={mergedIfAccounts}
              value={activeIfId}
              disabled={isCompleting}
              invalid={bindError}
              onChange={onSelect}
              onCreate={() => setCreateOpen(true)}
              onOpenChange={open => {
                if (open) clearBindError();
              }}
              placeholder="Select sub-account"
            />
          </div>

          {showInlineBind && (
            <div className="shrink-0">
              <Button
                type="button"
                rounded="lg"
                disabled={isCompleting || pendingIfId === ifId || !pendingIfId}
                loading={isCompleting}
                onClick={onBindPending}
                className="min-w-[75px]"
              >
                Bind
              </Button>
            </div>
          )}
        </div>

        {activeIfId && (
          <BalanceBar
            balance={selectedIfBalance}
            minBalance={minIfBalance}
            targetAccountId={activeIfId}
            transferEnabled={!isVaultSpAccountSelected}
          />
        )}
      </div>
    </>
  );
}
