import { useState, useMemo, useCallback, useEffect } from "react";
import { useBindBrokerListingAccount } from "../../../services/brokerListing";
import { getIfRequired } from "../../../constants";
import { toast } from "@/components/toast";
import { useListingServerData } from "../../../hooks/useListingServerData";
import { useListingRefreshActions } from "../../../hooks/useListingRefreshActions";

const bindErrorMessage = "Failed to bind insurance fund account";
const bindSuccessMessage = "Insurance fund account bound successfully";

export function useInsuranceFundBind() {
  const { listingAccounts, subAccounts, riskSnapshot, listingSymbols } =
    useListingServerData();
  const { refreshAccounts } = useListingRefreshActions();

  const [bindListingAccount, { isMutating: isCompleting }] =
    useBindBrokerListingAccount();

  const [bindError, setBindError] = useState(false);

  const ifId = listingAccounts?.if_account?.account_id ?? "";

  const [pendingIfId, setPendingIfIdState] = useState(ifId);

  useEffect(() => {
    setPendingIfIdState(ifId);
  }, [ifId]);

  const setPendingIfId = useCallback((id: string) => {
    setBindError(false);
    setPendingIfIdState(id);
  }, []);

  const clearBindError = useCallback(() => {
    setBindError(false);
  }, []);

  const minIfBalance = useMemo(
    () => getIfRequired(riskSnapshot, listingSymbols),
    [riskSnapshot, listingSymbols]
  );

  const selectedIfBalance = useMemo(() => {
    const acc = subAccounts.find(a => a.sub_account_id === pendingIfId);
    return acc?.balance ?? 0;
  }, [subAccounts, pendingIfId]);

  const ifBalanceSufficient = selectedIfBalance >= minIfBalance;

  const canCompleteIfBind = useMemo(() => {
    return Boolean(pendingIfId);
  }, [pendingIfId]);

  const completeIfBindIfNeeded = useCallback(async (): Promise<boolean> => {
    if (ifId === pendingIfId) {
      return Boolean(ifId);
    }

    if (!pendingIfId) return false;
    if (isCompleting) return false;

    setBindError(false);

    try {
      const res = await bindListingAccount({
        account_id: pendingIfId,
        scope: "IF",
      });

      if (!res?.success) {
        throw res;
      }

      toast.success(bindSuccessMessage);
      setBindError(false);
      await refreshAccounts();
      return true;
    } catch (error: unknown) {
      setBindError(true);
      const message = error instanceof Error ? error.message : bindErrorMessage;
      toast.error(message);
      return false;
    }
  }, [ifId, pendingIfId, isCompleting, bindListingAccount, refreshAccounts]);

  return {
    pendingIfId,
    setPendingIfId,
    ifId,
    isCompleting,
    bindError,
    clearBindError,
    canCompleteIfBind,
    completeIfBindIfNeeded,
    minIfBalance,
    selectedIfBalance,
    ifBalanceSufficient,
  };
}

export type UseInsuranceFundBindReturn = ReturnType<
  typeof useInsuranceFundBind
>;

/** @deprecated Use useInsuranceFundBind */
export const useOnboardingIfBind = useInsuranceFundBind;
