import { useMemo } from "react";
import { Button } from "@/components/button";
import {
  Dialog,
  DialogBody,
  DialogContent,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/dialog";
import type { ByokProvider } from "../../types";
import { footerClassName, getProviderLabel } from "./shared";

interface DeactivateByokKeyModalProps {
  providerId: string | null;
  byokProviders: ByokProvider[];
  isMutating: boolean;
  onClose: () => void;
  onConfirm: (providerId: string) => Promise<void> | void;
}

export function DeactivateByokKeyModal({
  providerId,
  byokProviders,
  isMutating,
  onClose,
  onConfirm,
}: DeactivateByokKeyModalProps) {
  const providerLabel = useMemo(
    () => getProviderLabel(providerId, byokProviders),
    [providerId, byokProviders]
  );

  return (
    <Dialog
      open={providerId !== null}
      onOpenChange={nextOpen => {
        if (!nextOpen) onClose();
      }}
    >
      <DialogContent className="max-w-[440px]">
        <DialogHeader className="h-auto flex-col items-stretch gap-2 border-b-0 px-6 pt-6 pb-0">
          <DialogTitle className="text-lg font-medium text-base-contrast-98">
            Deactivate {providerLabel} key
          </DialogTitle>
        </DialogHeader>
        <DialogBody className="px-6 pb-0 text-2xs leading-6 text-base-contrast-54">
          Are you sure you want to deactivate the {providerLabel} API key? All
          symbols pulling from this provider will become inactive until you
          activate the key again.
        </DialogBody>
        <DialogFooter className={`${footerClassName} mt-6`}>
          <Button
            variant="outline"
            color="primary"
            className="flex-1"
            disabled={isMutating}
            onClick={onClose}
          >
            Cancel
          </Button>
          <Button
            variant="outline"
            color="danger"
            className="flex-1"
            loading={isMutating}
            disabled={isMutating}
            onClick={() => {
              if (!providerId) return;
              onConfirm(providerId);
            }}
          >
            Deactivate key
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}
