import { useMemo, useState } from "react";
import { useListingStore } from "../../../store/useListingStore";
import type { PeriodFilter } from "../../../types";
import {
  useBrokerListingOverview,
  DASHBOARD_OVERVIEW_SWR,
  whenDashboardPollingEnabled,
} from "../../../services";
import type { BrokerListingOverviewData } from "../../../services/types";
import { calculateAPR } from "./calculateAPR";
import {
  getSymbolListingLimit,
  getSymbolSlotUsedCountFromListingStats,
} from "@/permissionless-listing/constants";
import { PageView } from "../../../types";
import { useListingSymbolsData } from "../../../hooks/useListingSymbolsData";

export type StatGridStats = {
  symbolsUsed: number | null;
  symbolsLimit: number | null;
  totalVolume: number | null;
  totalLiq: number | null;
  totalLiqRevenue: number | null;
  totalFeeRevenue: number | null;
  avgApr: number | null;
};

export function useStatGrid() {
  const [period, setPeriod] = useState<PeriodFilter>("all-time");

  const isDashboardActive = useListingStore(
    s => s.currentPage === PageView.Dashboard
  );
  const { listingSymbols } = useListingSymbolsData();

  const overview = useBrokerListingOverview(
    whenDashboardPollingEnabled(isDashboardActive, DASHBOARD_OVERVIEW_SWR)
  );

  const stats = useMemo<StatGridStats>(() => {
    const symbolsLimit = getSymbolListingLimit();
    const overviewData = overview.data as BrokerListingOverviewData | undefined;

    if (!overviewData) {
      return {
        symbolsUsed: null,
        symbolsLimit,
        totalVolume: null,
        totalLiq: null,
        totalLiqRevenue: null,
        totalFeeRevenue: null,
        avgApr: null,
      };
    }

    const volumeByPeriod =
      period === "24h"
        ? overviewData.volume_24h
        : period === "7d"
          ? overviewData.volume_7d
          : period === "30d"
            ? overviewData.volume_30d
            : (overviewData.volume_all_time ?? null);

    const feeRevenueByPeriod =
      period === "24h"
        ? overviewData.fee_revenue_24h
        : period === "7d"
          ? overviewData.fee_revenue_7d
          : period === "30d"
            ? overviewData.fee_revenue_30d
            : (overviewData.fee_revenue_all_time ??
              overviewData.fee_revenue_cumulative);

    const liquidationRevenueByPeriod =
      period === "24h"
        ? overviewData.liquidation_revenue_24h
        : period === "7d"
          ? overviewData.liquidation_revenue_7d
          : period === "30d"
            ? overviewData.liquidation_revenue_30d
            : (overviewData.liquidation_revenue_all_time ?? null);

    const totalLiqTimes = overviewData.liquidation_count_24h ?? null;

    const MS_DAY = 24 * 60 * 60 * 1000;
    const now = new Date();
    const periodStart =
      period === "24h"
        ? new Date(now.getTime() - 1 * MS_DAY)
        : period === "7d"
          ? new Date(now.getTime() - 7 * MS_DAY)
          : period === "30d"
            ? new Date(now.getTime() - 30 * MS_DAY)
            : new Date(0);
    const periodEnd = now;

    const aprDecimal = calculateAPR(
      feeRevenueByPeriod,
      liquidationRevenueByPeriod,
      listingSymbols,
      periodStart,
      periodEnd
    );

    const symbolsUsed = getSymbolSlotUsedCountFromListingStats(
      overviewData.listing_stats
    );

    return {
      symbolsUsed,
      symbolsLimit,
      totalVolume: volumeByPeriod ?? null,
      totalLiq: totalLiqTimes,
      totalLiqRevenue: liquidationRevenueByPeriod ?? null,
      totalFeeRevenue: feeRevenueByPeriod ?? null,
      avgApr: aprDecimal,
    };
  }, [overview.data, listingSymbols, period]);

  return {
    period,
    setPeriod,
    stats,
    isLoading: overview.isLoading,
  };
}
