import type { ByokProvidersScriptReturn } from "./ByokProviders.script";
import { ByokProvidersView } from "./ByokProvidersView";
import { AddByokSourceModal } from "../components/modals/AddByokSourceModal";
import { AddByokSymbolModal } from "../components/modals/AddByokSymbolModal";
import { DeactivateByokKeyModal } from "../components/modals/DeactivateByokKeyModal";
import { RemoveFeedModal } from "../components/modals/RemoveFeedModal";
import { UpdateByokKeyModal } from "../components/modals/UpdateByokKeyModal";
import { VisibilityModal } from "../components/modals/VisibilityModal";

export function ByokProvidersPanelUI({
  providers,
  loading,
  modal,
  isOracleFeedMutating,
  isByokKeyMutating,
  emptyBuilderOracleSource,
  onOpenAddProvider,
  onOpenUpdateKey,
  onOpenDeactivateKey,
  onActivateKey,
  onOpenAddSymbol,
  onOpenVisibility,
  onOpenRemove,
  onCloseAddByokSource,
  onConfirmAddByokSource,
  onCloseUpdateKey,
  onConfirmUpdateKey,
  onCloseDeactivateKey,
  onConfirmDeactivateKey,
  onCloseAddByokSymbol,
  onConfirmAddByokSymbol,
  onCloseVisibility,
  onSaveVisibility,
  onCloseRemove,
  onConfirmRemove,
}: ByokProvidersScriptReturn) {
  const visibilityTarget =
    modal.visibilityTarget?.source === "byok" ? modal.visibilityTarget : null;
  const removeTarget =
    modal.removeTarget?.source === "byok" ? modal.removeTarget : null;

  return (
    <>
      <ByokProvidersView
        providers={providers}
        loading={loading}
        onOpenAddProvider={onOpenAddProvider}
        onOpenUpdateKey={onOpenUpdateKey}
        onOpenDeactivateKey={onOpenDeactivateKey}
        onActivateKey={onActivateKey}
        onOpenAddSymbol={onOpenAddSymbol}
        onOpenVisibility={onOpenVisibility}
        onOpenRemove={onOpenRemove}
      />

      <AddByokSourceModal
        providerId={modal.addByokSourceProvider}
        byokProviders={providers}
        isMutating={isByokKeyMutating}
        onClose={onCloseAddByokSource}
        onConfirm={onConfirmAddByokSource}
      />

      <UpdateByokKeyModal
        providerId={modal.updateByokKeyProvider}
        byokProviders={providers}
        isMutating={isByokKeyMutating}
        onClose={onCloseUpdateKey}
        onConfirm={onConfirmUpdateKey}
      />

      <DeactivateByokKeyModal
        providerId={modal.deactivateByokKeyProvider}
        byokProviders={providers}
        isMutating={isByokKeyMutating}
        onClose={onCloseDeactivateKey}
        onConfirm={onConfirmDeactivateKey}
      />

      <AddByokSymbolModal
        providerId={modal.addByokSymbolProvider}
        byokProviders={providers}
        isMutating={isOracleFeedMutating}
        onClose={onCloseAddByokSymbol}
        onConfirm={onConfirmAddByokSymbol}
      />

      <VisibilityModal
        target={visibilityTarget}
        builderOracleSource={emptyBuilderOracleSource}
        byokProviders={providers}
        isMutating={isOracleFeedMutating}
        onClose={onCloseVisibility}
        onSave={onSaveVisibility}
      />

      <RemoveFeedModal
        target={removeTarget}
        builderOracleSource={emptyBuilderOracleSource}
        byokProviders={providers}
        isMutating={isOracleFeedMutating}
        onClose={onCloseRemove}
        onConfirm={onConfirmRemove}
      />
    </>
  );
}
