import type { RwaMarketSessionRow } from "../../../services/types";
import type { TradingParamsForm } from "../../../types";
import { SelectField, TemplateInfoBlock } from "./ParamFormFields";

/** API row plus Select control fields (`value` mirrors `market_session`). */
export type RwaMarketSessionOption = RwaMarketSessionRow & {
  value: string;
  label: string;
};

export function RwaMarketSessionSection({
  value,
  options,
  error,
  loading,
  onChange,
}: {
  value: TradingParamsForm["rwa_market_session"];
  options: RwaMarketSessionOption[];
  error?: string;
  loading: boolean;
  onChange: (value: string) => void;
}) {
  const sessionInfo = options.find(item => item.value === value) ?? null;

  return (
    <div className="mt-1 border-t border-base-contrast-8 pt-6">
      <div className="mb-4">
        <div className="text-xs font-medium text-base-contrast-98">
          RWA symbol
        </div>
        <div className="mt-1 text-3xs text-base-contrast-50">
          Configure market hours and holiday schedules for this real-world
          asset.
        </div>
      </div>

      <SelectField
        label="Market session"
        tooltip="Select the market session template that controls the trading calendar for this RWA symbol."
        required
        value={value}
        options={options.map(item => ({
          value: item.value,
          label: item.label,
        }))}
        error={error}
        hint={
          loading
            ? "Loading available market sessions..."
            : "Choose the template that matches the underlying market."
        }
        onChange={onChange}
        triggerClassName="min-h-[40px] w-full"
        disabled={loading || Boolean(error)}
      />

      <div className="mt-3 grid grid-cols-1 gap-3 rounded-lg bg-base-300 px-4 py-3 sm:grid-cols-3">
        <TemplateInfoBlock
          label="Market"
          value={sessionInfo?.name?.trim() ? sessionInfo.name : "—"}
        />
        <TemplateInfoBlock
          label="Timezone"
          value={sessionInfo?.timezone ?? "—"}
        />
        <TemplateInfoBlock
          label="Schedule"
          value={sessionInfo?.trading_hours ?? "—"}
        />
      </div>
    </div>
  );
}
