import type {
  BrokerListingOverviewSymbolRow,
  BrokerListingSymbolDetailData,
  RwaMarketSessionRow,
} from "../services/types";
import { findRwaMarketSessionRow } from "./findRwaMarketSessionRow";
import type { IndexSourceMeta } from "../types";
import { matchIndexSourceCatalog } from "../services/priceSources";
import {
  IndexSourceType,
  type RwaMarketSessionTemplate,
  type SymbolDetail,
  type SymbolStatus,
} from "../types";
import { normalizeStoredWeightPercentInt } from "../sections/listing/price-sources/hooks/shared";
import {
  formatDecimal,
  formatRatePercentFromDecimal,
  trimTrailingZeros,
} from "../sections/listing/trading-params/hooks/shared";

export function formatIsoToUtcDisplay(iso?: string | null): string | null {
  if (!iso) return null;
  const d = new Date(iso);
  if (!Number.isFinite(d.getTime())) return null;
  const yyyy = d.getUTCFullYear();
  const mm = String(d.getUTCMonth() + 1).padStart(2, "0");
  const dd = String(d.getUTCDate()).padStart(2, "0");
  const hh = String(d.getUTCHours()).padStart(2, "0");
  const min = String(d.getUTCMinutes()).padStart(2, "0");
  return `${yyyy}-${mm}-${dd} ${hh}:${min} UTC`;
}

export function deriveBaseSymbolFromPerpKey(perpKey: string): string {
  const parts = perpKey.split("_");
  if (parts.length >= 2) return parts[1];
  return perpKey;
}

/**
 * Maps GET /v1/broker/listing/symbol_detail payload into store/UI `SymbolDetail`.
 * Used by symbol detail page and dashboard Edit (after fetching detail).
 */
export function mapBrokerListingSymbolDetailToSymbolDetail(args: {
  data: BrokerListingSymbolDetailData;
  /** Listing row / URL key; used for base_symbol derivation and store map key. */
  listingSymbolKey: string;
  feeShareRateNum: number;
  overviewRow?: BrokerListingOverviewSymbolRow | null;
  /** Enriched index_sources catalog from store (for display names). */
  indexSourcesCatalog?: IndexSourceMeta[];
  /** RWA market session rows from /v1/public/rwa/market_sessions. */
  rwaMarketSessions?: RwaMarketSessionRow[];
}): SymbolDetail {
  const {
    data: symbolDetailResolved,
    listingSymbolKey,
    feeShareRateNum,
  } = args;
  const overviewRow = args.overviewRow ?? null;
  const indexSourcesCatalog = args.indexSourcesCatalog ?? [];

  const params = (symbolDetailResolved.params ?? {}) as Record<string, unknown>;

  const toNum = (v: unknown): number => {
    const n = typeof v === "string" ? Number(v) : Number(v);
    return Number.isFinite(n) ? n : NaN;
  };

  const formatRateOrDash = (n: number): string =>
    Number.isFinite(n) ? formatRatePercentFromDecimal(String(n)) : "—";

  const listingTime = formatIsoToUtcDisplay(symbolDetailResolved.listing_time);
  const delistTime = formatIsoToUtcDisplay(
    symbolDetailResolved.delist_time ?? null
  );

  const baseSymbol = deriveBaseSymbolFromPerpKey(listingSymbolKey);

  const imr = toNum(params.imr);
  const mmr = toNum(params.mmr);
  const priceRange = toNum(params.price_range);

  const stdLiquidationFee = toNum(params.std_liquidation_fee);
  const claimIfDiscount = toNum(params.claim_IF_discount);

  const fundingPeriodPending =
    typeof params.funding_period_pending === "string"
      ? params.funding_period_pending
      : undefined;
  const fundingPeriodEffectiveAt =
    formatIsoToUtcDisplay(
      params.funding_period_effective_at as string | null | undefined
    ) ?? undefined;
  const isRwa = symbolDetailResolved.is_rwa === true;
  const marketSession =
    typeof symbolDetailResolved.market_session === "string"
      ? (symbolDetailResolved.market_session as RwaMarketSessionTemplate)
      : typeof params.market_session === "string"
        ? (params.market_session as RwaMarketSessionTemplate)
        : null;
  const rwaMarket = findRwaMarketSessionRow(
    marketSession,
    args.rwaMarketSessions ?? null
  );

  const indexSourcesRaw = symbolDetailResolved.index_sources ?? [];
  const indexSources = indexSourcesRaw.map(src => {
    const isBuilderLike =
      src.type === IndexSourceType.BuilderOracle ||
      src.type === IndexSourceType.Byok;

    const catRow = isBuilderLike
      ? undefined
      : matchIndexSourceCatalog(indexSourcesCatalog, src.source);

    return {
      source: isBuilderLike ? src.source : (catRow?.name ?? src.source),
      sourceSymbol: src.source_symbol,
      priceMultiplier: src.price_multiplier ?? 1,
      latestPrice: 0,
      // Some backends omit `type` for CEX rows in symbol_detail. Use the
      // catalog row when available; otherwise keep the legacy value absent.
      type: src.type ?? catRow?.type,
      sourceId: src.source_id,
      weight: normalizeStoredWeightPercentInt(src.weight ?? 0),
    };
  });

  return {
    status: symbolDetailResolved.status as SymbolStatus,
    listingTime: listingTime ?? null,
    delistTime: delistTime ?? null,
    params: {
      Symbol: { value: symbolDetailResolved.symbol, editable: false },
      base_symbol: {
        value: baseSymbol,
        editable: false,
      },
      base_token: { value: baseSymbol, editable: false },
      quote_token: { value: "USDC", editable: false },

      max_leverage: {
        value: (() => {
          const v = toNum(params.max_leverage);
          return Number.isFinite(v) ? `${v}x` : "—";
        })(),
        editable: true,
      },
      global_max_oi: {
        value: (() => {
          const v = toNum(params.global_max_oi);
          return Number.isFinite(v) ? v.toLocaleString("en-US") : "—";
        })(),
        editable: true,
      },
      max_notional_user: {
        value: (() => {
          const v = toNum(params.max_notional_user);
          return Number.isFinite(v) ? `$${v.toLocaleString("en-US")}` : "—";
        })(),
        editable: true,
      },
      funding_period: {
        value: (params.funding_period as string | undefined) ?? "—",
        editable: true,
      },
      std_liquidation_fee: {
        value: formatRateOrDash(stdLiquidationFee),
        editable: true,
      },
      claim_IF_discount: {
        value: formatRateOrDash(claimIfDiscount),
        editable: true,
      },
      market_session: {
        value: marketSession ?? "—",
        editable: true,
      },

      base_imr: {
        value: (() => {
          if (!Number.isFinite(imr) || imr <= 0) return "—";
          const pct = imr * 100;
          const imrStr = trimTrailingZeros(imr.toFixed(4));
          const pctStr = trimTrailingZeros(pct.toFixed(2));
          return `${imrStr} (${pctStr}%)`;
        })(),
        editable: false,
      },
      base_mmr: {
        value: (() => {
          if (!Number.isFinite(mmr) || mmr <= 0) return "—";
          const pct = mmr * 100;
          const mmrStr = trimTrailingZeros(mmr.toFixed(4));
          const pctStr = trimTrailingZeros(pct.toFixed(2));
          return `${mmrStr} (${pctStr}%)`;
        })(),
        editable: false,
      },
      price_range: {
        value: (() => {
          if (!Number.isFinite(priceRange) || priceRange <= 0) return "—";
          return `±${(priceRange * 100).toFixed(1)}%`;
        })(),
        editable: false,
      },
      funding_cap: {
        value: formatRateOrDash(toNum(params.funding_cap)),
        editable: false,
      },
      funding_floor: {
        value: formatRateOrDash(toNum(params.funding_floor)),
        editable: false,
      },
      quote_tick: {
        value: formatDecimal(toNum(params.quote_tick)),
        editable: false,
      },
      base_tick: {
        value: formatDecimal(toNum(params.base_tick)),
        editable: false,
      },
      base_min: {
        value: formatDecimal(toNum(params.base_min)),
        editable: false,
      },
      base_max: {
        value: (() => {
          const v = toNum(params.base_max);
          return Number.isFinite(v) && v > 0 ? v.toLocaleString("en-US") : "—";
        })(),
        editable: false,
      },
    },

    indexSources,
    feeShareRate: feeShareRateNum,

    fundingPeriodPending,
    fundingPeriodEffectiveAt,

    volume24h: toNum(overviewRow?.volume_24h),
    feeRevenue24h: toNum(overviewRow?.fee_revenue_24h),
    liquidationCount24h: toNum(overviewRow?.liquidation_count_24h),
    liquidationRevenue24h: toNum(overviewRow?.liquidation_revenue_24h),

    mmAccounts: symbolDetailResolved.mm_accounts ?? [],
    isRwa,
    marketSession,
    rwaMarket,
  };
}
