import {
  forwardRef,
  useCallback,
  useEffect,
  useImperativeHandle,
  useRef,
  useState,
} from "react";
import { cn } from "@/utils/css";
import { PLInput } from "./Input";
import { useUpdateBrokerListingConfig } from "../services/brokerListing";
import { toast } from "@/components/toast";
import { useListingServerData } from "../hooks/useListingServerData";
import { useListingRefreshActions } from "../hooks/useListingRefreshActions";

export type TelegramChatIdFieldHandle = {
  saveIfDirty: () => Promise<void>;
};

export type TelegramChatIdFieldProps = {
  labelText?: string;
  placeholder?: string;
  labelClassName?: string;
  inputClassName?: string;
  containerClassName?: string;
  /**
   * Called whenever the underlying request is in-flight.
   * Useful for parent buttons to reflect a "Saving..." state.
   */
  onSavingChange?: (isSaving: boolean) => void;
};

export const TelegramChatIdField = forwardRef<
  TelegramChatIdFieldHandle,
  TelegramChatIdFieldProps
>(
  (
    {
      labelText = "Telegram Chat ID",
      placeholder = "e.g. -1001234567890",
      labelClassName,
      inputClassName,
      containerClassName,
      onSavingChange,
    },
    ref
  ) => {
    const { listingConfig } = useListingServerData();
    const { refreshConfig } = useListingRefreshActions();
    const [updateConfig, { isMutating }] = useUpdateBrokerListingConfig();

    const [value, setValue] = useState<string>(
      () => listingConfig.tg_chat_id ?? ""
    );
    const [saveError, setSaveError] = useState(false);

    useEffect(() => {
      setValue(listingConfig.tg_chat_id ?? "");
    }, [listingConfig.tg_chat_id]);

    useEffect(() => {
      onSavingChange?.(isMutating);
    }, [onSavingChange, isMutating]);

    const inFlightRef = useRef<Promise<void> | null>(null);

    const saveIfDirty = useCallback(async () => {
      const next = value.trim();
      const base = (listingConfig.tg_chat_id ?? "").trim();

      // No change -> no request.
      if (next === base) {
        setSaveError(false);
        return;
      }
      // Empty chat id -> skip request (allow disabling would be confusing).
      if (next === "") {
        setSaveError(false);
        return;
      }

      if (inFlightRef.current) return inFlightRef.current;

      const p = (async () => {
        try {
          const res = await updateConfig({ tg_chat_id: next });
          if (!res?.success) {
            throw res;
          }
          await refreshConfig();
          setSaveError(false);
        } catch (e: unknown) {
          toast.error(
            (e as { message?: string })?.message ||
              "Failed to update Telegram chat id"
          );
          setSaveError(true);
        }
      })();

      inFlightRef.current = p;
      try {
        await p;
      } finally {
        inFlightRef.current = null;
      }
    }, [listingConfig.tg_chat_id, refreshConfig, updateConfig, value]);

    useImperativeHandle(ref, () => ({ saveIfDirty }), [saveIfDirty]);

    const handleBlur = () => {
      void saveIfDirty();
    };

    const handleChange = useCallback(
      (e: React.ChangeEvent<HTMLInputElement>) => {
        setSaveError(false);
        setValue(e.target.value.replace(/[^\d-]/g, ""));
      },
      []
    );

    return (
      <div className={cn("flex flex-col gap-2", containerClassName)}>
        <label
          className={cn("font-medium text-base-contrast-50", labelClassName)}
        >
          {labelText}
        </label>
        <PLInput
          type="text"
          value={value}
          onChange={handleChange}
          onBlur={handleBlur}
          placeholder={placeholder}
          error={saveError}
          className={inputClassName}
        />
      </div>
    );
  }
);

TelegramChatIdField.displayName = "TelegramChatIdField";
