import { useAppContext } from "@/components/provider/AppProvider";

export function useListingAccountContext() {
  const { logged, isValidating, getAccountId } = useAppContext();
  const accountId = getAccountId() ?? "";

  return {
    accountId,
    logged,
    isValidating,
    isLoading: !logged || isValidating || !accountId,
  };
}
