import { cn } from "@/utils/css";
import { FadeInEnter } from "@/components/fade-in-enter";
import { SettingsTab } from "../../types";
import { ArrowBackIcon } from "../../components";
import { IFAccountSection } from "./IFAccountSection";
import { MMAccountsSection } from "./MMAccountsSection";
import { NotificationsSection } from "./NotificationsSection";
import { useSettingsScript } from "./Settings.script";
import { BrokerTierStep } from "../onboarding/components/BrokerTierStep";

// Match mockup: left nav labels and order
const TABS: { key: SettingsTab; label: string }[] = [
  { key: SettingsTab.If, label: "Insurance fund account" },
  { key: SettingsTab.Mm, label: "VIP order gateway" },
  { key: SettingsTab.Tier, label: "Builder tier" },
  { key: SettingsTab.Notifications, label: "Notifications" },
];

// Check icon for tab when selected / no warning — match mockup updateSettingsTabBadges checkSvg
function TabCheckIcon({ className }: { className?: string }) {
  return (
    <svg
      width={16}
      height={16}
      viewBox="0 0 16 16"
      fill="none"
      className={className}
      aria-hidden
    >
      <path
        d="M3 8.5L6.5 12L13 4"
        stroke="currentColor"
        strokeWidth="1.5"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </svg>
  );
}

export function SettingsPanel() {
  const { activeTab, setActiveTab, tabIssues, onBack } = useSettingsScript();

  return (
    <div className="flex flex-col">
      {/* Header: match mockup — flex, gap 16px, margin-bottom 24px */}
      <div className="flex items-center gap-4 mb-6">
        <button
          type="button"
          onClick={onBack}
          className="shrink-0 opacity-70 hover:opacity-100 transition-opacity cursor-pointer"
          aria-label="Back"
        >
          <ArrowBackIcon className="w-6 h-6 text-base-contrast-98" />
        </button>
        <div className="flex-1">
          <span className="text-lg font-medium text-base-contrast-98 leading-tight">
            Account settings
          </span>
        </div>
      </div>

      {/* Layout: left nav 400px + content 688px, gap 32px, align-items flex-start */}
      <div className="flex gap-20 items-start">
        <nav className="w-[400px] shrink-0 sticky top-0 pt-1">
          <ul className="list-none m-0 p-0 flex flex-col gap-0.5">
            {TABS.map(tab => {
              const issues = tabIssues[tab.key];
              const isActive = activeTab === tab.key;
              return (
                <li key={tab.key}>
                  <button
                    type="button"
                    onClick={() => setActiveTab(tab.key)}
                    className={cn(
                      "w-full flex items-center py-3.5 px-4 text-xs font-medium rounded-lg border-none cursor-pointer transition-colors text-left font-inherit",
                      isActive
                        ? "text-primary bg-primary/10"
                        : "text-base-contrast-50 hover:text-base-contrast-98 hover:bg-base-200"
                    )}
                  >
                    <span className="min-w-0 flex-1">{tab.label}</span>
                    {issues > 0 ? (
                      <span
                        className={cn(
                          "inline-flex items-center justify-center ml-auto shrink-0 text-3xs font-semibold min-w-5 h-5 rounded-[10px] px-1.5",
                          isActive
                            ? "bg-warning/15 text-warning"
                            : "bg-base-contrast-12 text-base-contrast-50"
                        )}
                      >
                        {issues}
                      </span>
                    ) : (
                      <span className="ml-auto shrink-0 inline-flex items-center justify-center w-5 h-5">
                        <TabCheckIcon
                          className={cn(
                            "w-4 h-4",
                            isActive ? "text-success" : "text-base-contrast-50"
                          )}
                        />
                      </span>
                    )}
                  </button>
                </li>
              );
            })}
          </ul>
        </nav>

        <div className="w-[688px] max-w-full flex flex-col min-h-0">
          {activeTab === SettingsTab.If && (
            <FadeInEnter className="min-h-0 w-full">
              <IFAccountSection />
            </FadeInEnter>
          )}
          {activeTab === SettingsTab.Mm && (
            <FadeInEnter className="min-h-0 w-full">
              <MMAccountsSection />
            </FadeInEnter>
          )}
          {activeTab === SettingsTab.Tier && (
            <FadeInEnter className="min-h-0 w-full">
              <div className="bg-base-200 rounded-xl p-6 flex flex-col">
                <h4 className="text-xs font-semibold text-base-contrast-98 mb-4">
                  Builder tier
                </h4>
                <BrokerTierStep />
              </div>
            </FadeInEnter>
          )}
          {activeTab === SettingsTab.Notifications && (
            <FadeInEnter className="min-h-0 w-full">
              <NotificationsSection />
            </FadeInEnter>
          )}
        </div>
      </div>
    </div>
  );
}
