import { useEffect, useMemo, useState } from "react";
import { Button } from "@/components/button";
import {
  Dialog,
  DialogBody,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/dialog";
import type {
  BuilderOracleSource,
  ByokProvider,
  CustomOracleSymbolTarget,
  VisibilityMode,
} from "../../types";
import {
  findCurrentVisibility,
  findTargetName,
  footerClassName,
  formLabelClassName,
} from "./shared";

interface VisibilityModalProps {
  target: CustomOracleSymbolTarget | null;
  builderOracleSource: BuilderOracleSource;
  byokProviders: ByokProvider[];
  isMutating: boolean;
  onClose: () => void;
  onSave: (
    target: CustomOracleSymbolTarget,
    visibility: VisibilityMode
  ) => Promise<void> | void;
}

export function VisibilityModal({
  target,
  builderOracleSource,
  byokProviders,
  isMutating,
  onClose,
  onSave,
}: VisibilityModalProps) {
  const [visibility, setVisibility] = useState<VisibilityMode>("private");

  useEffect(() => {
    setVisibility(
      findCurrentVisibility(target, builderOracleSource, byokProviders)
    );
  }, [target, builderOracleSource, byokProviders]);

  const targetName = useMemo(
    () => findTargetName(target, builderOracleSource, byokProviders),
    [target, builderOracleSource, byokProviders]
  );

  return (
    <Dialog
      open={target !== null}
      onOpenChange={nextOpen => {
        if (!nextOpen) onClose();
      }}
    >
      <DialogContent className="max-w-[440px]">
        <DialogHeader className="h-auto flex-col items-stretch gap-2 border-b-0 px-6 pt-6 pb-0">
          <DialogTitle className="text-lg font-medium text-base-contrast-98">
            Edit visibility
          </DialogTitle>
          <DialogDescription className="text-2xs leading-6 text-base-contrast-54">
            Control whether other builders can discover and use{" "}
            <strong className="font-medium text-base-contrast-98">
              {targetName}
            </strong>
            .
          </DialogDescription>
        </DialogHeader>
        <DialogBody className="space-y-4 px-6 pt-5 pb-0">
          <div>
            <label className={formLabelClassName}>Visibility</label>
            <div className="grid grid-cols-2 gap-2">
              {(["public", "private"] as const).map(value => (
                <button
                  key={value}
                  type="button"
                  disabled={isMutating}
                  onClick={() => setVisibility(value)}
                  className={`flex-1 rounded-lg border px-4 py-3 text-center text-xs font-medium transition-colors ${
                    visibility === value
                      ? "border-primary bg-primary/10 text-base-contrast-98"
                      : "border-base-contrast-12 bg-base-500 text-base-contrast-50 hover:text-base-contrast-98"
                  }`}
                >
                  {value === "public" ? "Public" : "Private"}
                </button>
              ))}
            </div>
            <div className="mt-2 text-3xs text-base-contrast-36">
              {visibility === "public"
                ? "Public: discoverable and selectable by other builders."
                : "Private: only you can see and use this symbol."}
            </div>
          </div>
        </DialogBody>
        <DialogFooter className={`${footerClassName} mt-6`}>
          <Button
            variant="outline"
            color="primary"
            className="flex-1"
            disabled={isMutating}
            onClick={onClose}
          >
            Cancel
          </Button>
          <Button
            className="flex-1"
            loading={isMutating}
            disabled={isMutating}
            onClick={() => {
              if (!target) return;
              onSave(target, visibility);
            }}
          >
            Save
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}
