import { useCallback, useEffect, useRef, useState } from "react";
import type { SymbolDetail, TradingParamsForm } from "../../../../types";
import { ListingAssetType } from "../../../../types";
import {
  normalizeTradingParamsForm,
  parseRateFormValue,
  type ValidationErrors,
} from "./shared";
import type { BrokerListingSymbolContextData } from "../../../../services";
import {
  useBrokerSymbolLogoRemoteUrl,
  validateBrokerSymbolLogoFile,
} from "./useBrokerSymbolLogoUpload";
import { toast } from "@/components/toast";

type UseTradingParamsFormInput = {
  params: TradingParamsForm;
  editMode: boolean;
  editSymbol: string | null;
  symbolDetails: Record<string, SymbolDetail>;
  symbolContext?: BrokerListingSymbolContextData;
  logoSymbolPreview: string;
};

export function useTradingParamsForm({
  params,
  editMode,
  editSymbol,
  symbolDetails,
  symbolContext,
  logoSymbolPreview,
}: UseTradingParamsFormInput) {
  const [form, setForm] = useState<TradingParamsForm>(() =>
    normalizeTradingParamsForm(params)
  );
  const [errors, setErrors] = useState<ValidationErrors>({});
  const [warnings, setWarnings] = useState<ValidationErrors>({});
  const [symbolIconFile, setSymbolIconFile] = useState<File | null>(null);
  const [symbolIconPreviewUrl, setSymbolIconPreviewUrl] = useState<
    string | null
  >(null);
  const [sessionSymbolIconUrl, setSessionSymbolIconUrl] = useState<
    string | null
  >(null);
  const hydratedCurrentListingSymbolRef = useRef<string | null>(null);
  const symbolIconPreviewObjectUrlRef = useRef<string | null>(null);
  const { remoteLogoUrl } = useBrokerSymbolLogoRemoteUrl({
    symbolPreview: logoSymbolPreview,
  });

  const resetStagedSymbolIcon = useCallback(() => {
    setSymbolIconFile(null);
    setSymbolIconPreviewUrl(prev => {
      if (prev) {
        URL.revokeObjectURL(prev);
      }
      return null;
    });
    symbolIconPreviewObjectUrlRef.current = null;
  }, []);

  useEffect(() => {
    if (editMode && editSymbol) {
      if (hydratedCurrentListingSymbolRef.current === editSymbol) return;
      const detail = symbolDetails[editSymbol];
      if (!detail) return;
      const p = detail.params;
      setForm(
        normalizeTradingParamsForm({
          max_leverage: p.max_leverage?.value.replace("x", ""),
          global_max_oi: p.global_max_oi?.value.replace(/,/g, ""),
          max_notional_user: p.max_notional_user?.value.replace(/[$,]/g, ""),
          funding_period: p.funding_period?.value,
          std_liquidation_fee: parseRateFormValue(p.std_liquidation_fee?.value),
          claim_IF_discount: parseRateFormValue(p.claim_IF_discount?.value),
          base_symbol: p.base_symbol?.value,
          listing_asset_type: detail.isRwa
            ? ListingAssetType.Rwa
            : ListingAssetType.Crypto,
          rwa_market_session: detail.marketSession ?? "",
        })
      );
      hydratedCurrentListingSymbolRef.current = editSymbol;
      return;
    }
    if (hydratedCurrentListingSymbolRef.current !== null) {
      hydratedCurrentListingSymbolRef.current = null;
      setForm(normalizeTradingParamsForm(params));
    }
  }, [editMode, editSymbol, symbolDetails, params]);

  useEffect(() => {
    setForm(prev => {
      if (prev.listing_asset_type === ListingAssetType.Rwa) {
        if (prev.std_liquidation_fee === "0.015") {
          return prev;
        }
        return {
          ...prev,
          std_liquidation_fee: "0.015",
        };
      }

      if (!prev.rwa_market_session) return prev;
      return { ...prev, rwa_market_session: "" };
    });
  }, [form.listing_asset_type, setForm]);

  useEffect(() => {
    resetStagedSymbolIcon();
    setSessionSymbolIconUrl(null);
  }, [editMode, editSymbol, resetStagedSymbolIcon]);

  useEffect(() => {
    return () => {
      if (symbolIconPreviewObjectUrlRef.current) {
        URL.revokeObjectURL(symbolIconPreviewObjectUrlRef.current);
      }
    };
  }, []);

  const stageSymbolIcon = useCallback(async (file: File) => {
    const DIMENSION = 64;
    const validationMessage = validateBrokerSymbolLogoFile(file);
    if (validationMessage) {
      toast.error(validationMessage);
      return false;
    }

    const dimensions = await new Promise<{
      width: number;
      height: number;
    } | null>(resolve => {
      const objectUrl = URL.createObjectURL(file);
      const img = new Image();

      img.onload = () => {
        resolve({
          width: img.naturalWidth,
          height: img.naturalHeight,
        });
        URL.revokeObjectURL(objectUrl);
      };
      img.onerror = () => {
        resolve(null);
        URL.revokeObjectURL(objectUrl);
      };
      img.src = objectUrl;
    });

    if (!dimensions) {
      toast.error("Unable to read the selected image. Please try another PNG.");
      return false;
    }

    if (dimensions.width !== DIMENSION || dimensions.height !== DIMENSION) {
      toast.error(`Please upload a ${DIMENSION}×${DIMENSION} PNG image.`);
      return false;
    }

    const nextPreviewUrl = URL.createObjectURL(file);
    if (symbolIconPreviewObjectUrlRef.current) {
      URL.revokeObjectURL(symbolIconPreviewObjectUrlRef.current);
    }

    symbolIconPreviewObjectUrlRef.current = nextPreviewUrl;
    setSymbolIconFile(file);
    setSymbolIconPreviewUrl(nextPreviewUrl);
    setSessionSymbolIconUrl(null);
    toast.success("Symbol icon staged. It will be uploaded when you submit.");
    return true;
  }, []);

  const markSymbolIconUploaded = useCallback(
    (logoUrl: string) => {
      resetStagedSymbolIcon();
      setSessionSymbolIconUrl(logoUrl);
    },
    [resetStagedSymbolIcon]
  );

  const removeSymbolIcon = useCallback(() => {
    resetStagedSymbolIcon();
    setSessionSymbolIconUrl(null);
  }, [resetStagedSymbolIcon]);

  const updateField = useCallback(
    (field: keyof TradingParamsForm, value: string) => {
      const ctxParamType = symbolContext?.params?.[field as string]?.type;
      const fallbackType =
        field === "global_max_oi" || field === "max_notional_user"
          ? "integer"
          : field === "std_liquidation_fee" || field === "claim_IF_discount"
            ? "decimal"
            : undefined;

      const numericType = ctxParamType ?? fallbackType;

      // For numeric fields: strip letters and keep only numeric chars we care about.
      // - integer: optional leading '-', digits only (no '.').
      // - decimal: optional leading '-', digits + at most one '.', and limit fraction length.
      const nextValue =
        numericType === "integer"
          ? (() => {
              const cleaned = value.replace(/[^0-9\-]/g, "");
              const isNegative = cleaned.startsWith("-");
              const digitsOnly = cleaned.replace(/-/g, "");
              return isNegative ? `-${digitsOnly}` : digitsOnly;
            })()
          : numericType === "decimal"
            ? (() => {
                const cleaned = value.replace(/[^0-9.\-]/g, "");
                const isNegative = cleaned.startsWith("-");
                const withoutSign = cleaned.replace(/-/g, "");

                const firstDot = withoutSign.indexOf(".");
                const ctxParam = symbolContext?.params?.[field as string];
                const maxDecimals =
                  ctxParam?.type === "decimal"
                    ? (ctxParam.max_decimals ?? 4)
                    : 4;

                if (firstDot < 0) {
                  // No dot typed
                  return isNegative ? `-${withoutSign}` : withoutSign;
                }

                const whole = withoutSign.slice(0, firstDot);
                const fracRaw = withoutSign
                  .slice(firstDot + 1)
                  .replace(/\./g, "");
                const frac = fracRaw.slice(0, maxDecimals);

                // Preserve trailing '.' when user typed it (fracRaw === "")
                const hasTrailingDot = fracRaw.length === 0;
                const numberBody =
                  whole + (hasTrailingDot ? "." : frac ? `.${frac}` : "");

                return isNegative ? `-${numberBody}` : numberBody;
              })()
            : value;

      setForm(prev => ({ ...prev, [field]: nextValue }));
      setErrors(prev => ({ ...prev, [field]: undefined }));
      setWarnings(prev => ({ ...prev, [field]: undefined }));
    },
    [symbolContext]
  );

  return {
    form,
    setForm,
    errors,
    setErrors,
    warnings,
    setWarnings,
    updateField,
    symbolIconFile,
    symbolIconPreviewUrl,
    hasStagedSymbolIcon: Boolean(symbolIconFile && symbolIconPreviewUrl),
    symbolIconDisplayUrl:
      symbolIconPreviewUrl ?? sessionSymbolIconUrl ?? remoteLogoUrl,
    stageSymbolIcon,
    removeSymbolIcon,
    markSymbolIconUploaded,
  };
}
