import Decimal from "decimal.js";
import { useEffect, useMemo, useState } from "react";
import { cn } from "@/utils/css";
import { ListingAssetType, type TradingParamsForm } from "../../../types";
import type { BrokerListingSymbolContextData } from "../../../services";
import { Field, SelectField } from "./ParamFormFields";
import { SymbolIconField } from "./SymbolIconField";
import {
  RwaMarketSessionSection,
  type RwaMarketSessionOption,
} from "./RwaMarketSessionSection";

/** Tooltip copy for trading param fields (ⓘ hover). Single source for maintenance. */
const TRADING_PARAM_TOOLTIPS: Record<
  keyof Pick<
    TradingParamsForm,
    | "max_leverage"
    | "global_max_oi"
    | "max_notional_user"
    | "funding_period"
    | "std_liquidation_fee"
    | "claim_IF_discount"
  >,
  string
> = {
  max_leverage:
    "Maximum leverage available to traders. Higher leverage lowers margin requirements but increases liquidation risk. Automatically determines IMR, MMR, and Price Range.",
  global_max_oi:
    "Maximum total open interest (in USDC) across all users for this symbol. Limits overall exposure. If not set, there is no cap.",
  max_notional_user:
    "Maximum position size (in USDC) a single user can hold. Prevents excessive concentration by any one trader.",
  funding_period:
    "How often funding fees are settled between long and short holders. Shorter intervals converge price faster but require more liquidity. Also affects Funding Cap/Floor calculation.",
  std_liquidation_fee:
    "Fee rate charged on position notional value during liquidation. Half goes to the liquidator as execution reward, the other half goes to the Insurance Fund (IF).",
  claim_IF_discount:
    "Discount rate when users claim (take over) liquidated positions from the Insurance Fund. Incentivizes users to help the IF offload risk — the claimer receives the position at a better price.",
};

const FUNDING_PERIODS = [
  { value: "1h", label: "1h" },
  { value: "4h", label: "4h" },
  { value: "8h", label: "8h" },
];

const LEVERAGE_OPTIONS = [
  { value: "5", label: "5x" },
  { value: "10", label: "10x" },
  { value: "20", label: "20x" },
];

interface ParamFormProps {
  form: TradingParamsForm;
  errors: Record<string, string | undefined>;
  warnings: Record<string, string | undefined>;
  fundingPeriodPending?: string;
  fundingPeriodEffectiveAt?: string;
  symbolContext?: BrokerListingSymbolContextData;
  listingAssetType: ListingAssetType;
  rwaMarketSession: TradingParamsForm["rwa_market_session"];
  rwaMarketSessionOptions: RwaMarketSessionOption[];
  rwaMarketSessionError?: string;
  rwaMarketSessionLoading?: boolean;
  hasStagedSymbolIcon: boolean;
  symbolIconDisplayUrl: string | null;
  symbolIconLabel: string;
  onStageSymbolIcon: (file: File) => Promise<boolean>;
  onRemoveSymbolIcon: () => void;
  onFieldChange: (field: keyof TradingParamsForm, value: string) => void;
  onImport: () => void;
  onValidateFields: () => void;
}

function decimalStringToPercentInput(value: string): string {
  const raw = value.trim();
  if (!raw) return raw;
  try {
    const pct = new Decimal(raw).mul(100);
    // Keep percent input readable: at most 2 decimals, and trim trailing zeros.
    return pct.toFixed(2).replace(/\.?0+$/, "");
  } catch {
    return value;
  }
}

function percentInputToDecimalString(value: string): string {
  const raw = value.trim();
  if (!raw) return raw;
  // Allow intermediate user input.
  if (raw === "-" || raw === ".") return raw;
  try {
    // Store rates as decimal (e.g. 1.5 -> 0.015), keep precision for existing validation.
    // Keep consistent with validation max_decimals (defaults to 4 for these fields).
    return new Decimal(raw).div(100).toFixed(4);
  } catch {
    return value;
  }
}

function sanitizePercentInput(value: string, maxDecimals = 2): string {
  const trimmed = value.trim();
  if (!trimmed) return trimmed;
  if (trimmed === "-" || trimmed === ".") return trimmed;

  // Keep only digits/dot/sign characters.
  const cleaned = trimmed.replace(/[^0-9.\-]/g, "");
  const isNegative = cleaned.startsWith("-");
  const unsigned = cleaned.replace(/-/g, "");

  const firstDot = unsigned.indexOf(".");
  if (firstDot < 0) {
    return isNegative ? `-${unsigned}` : unsigned;
  }

  const whole = unsigned.slice(0, firstDot);
  const fracRaw = unsigned.slice(firstDot + 1).replace(/\./g, "");
  const frac = fracRaw.slice(0, maxDecimals);
  const endsWithDot = trimmed.endsWith(".");

  const numberBody =
    whole +
    (endsWithDot || fracRaw.length === 0 ? "." : frac ? `.${frac}` : "");

  return isNegative ? `-${numberBody}` : numberBody;
}

export function ParamForm({
  form,
  errors,
  warnings,
  fundingPeriodPending,
  fundingPeriodEffectiveAt,
  symbolContext,
  listingAssetType,
  rwaMarketSession,
  rwaMarketSessionOptions,
  rwaMarketSessionError,
  rwaMarketSessionLoading = false,
  hasStagedSymbolIcon,
  symbolIconDisplayUrl,
  symbolIconLabel,
  onStageSymbolIcon,
  onRemoveSymbolIcon,
  onFieldChange,
  onImport,
  onValidateFields,
}: ParamFormProps) {
  const fundingPeriodChangePending = Boolean(fundingPeriodPending);
  const fundingPeriodHint = fundingPeriodChangePending
    ? `Changing to ${fundingPeriodPending}${
        fundingPeriodEffectiveAt ? ` at ${fundingPeriodEffectiveAt}` : ""
      }`
    : "Suggested: 8h";

  const stdSuggestedPct = useMemo(() => {
    const suggested = symbolContext?.params?.std_liquidation_fee?.suggested;
    return suggested ? decimalStringToPercentInput(String(suggested)) : "1.5";
  }, [symbolContext]);

  const claimIFDiscountSuggestedPct = useMemo(() => {
    const suggested = symbolContext?.params?.claim_IF_discount?.suggested;
    return suggested ? decimalStringToPercentInput(String(suggested)) : "0.75";
  }, [symbolContext]);

  const [stdLiqFeePct, setStdLiqFeePct] = useState<string>(() =>
    decimalStringToPercentInput(form.std_liquidation_fee)
  );
  const [claimIFDiscountPct, setClaimIFDiscountPct] = useState<string>(() =>
    decimalStringToPercentInput(form.claim_IF_discount)
  );

  // Keep local percent inputs in sync when form values change from outside
  // (e.g. editMode prefill/JSON import). Avoid overriding while the user's
  // percent input already reconstructs the same decimal.
  useEffect(() => {
    const target = form.std_liquidation_fee.trim();
    const targetNorm = (() => {
      if (!target) return target;
      try {
        return new Decimal(target).toString();
      } catch {
        return target;
      }
    })();

    const localReconstructedNorm = (() => {
      const converted = percentInputToDecimalString(stdLiqFeePct);
      if (!converted.trim()) return converted;
      try {
        return new Decimal(converted).toString();
      } catch {
        return converted;
      }
    })();

    if (targetNorm !== localReconstructedNorm) {
      setStdLiqFeePct(decimalStringToPercentInput(form.std_liquidation_fee));
    }
  }, [form.std_liquidation_fee, stdLiqFeePct]);

  useEffect(() => {
    const target = form.claim_IF_discount.trim();
    const targetNorm = (() => {
      if (!target) return target;
      try {
        return new Decimal(target).toString();
      } catch {
        return target;
      }
    })();

    const localReconstructedNorm = (() => {
      const converted = percentInputToDecimalString(claimIFDiscountPct);
      if (!converted.trim()) return converted;
      try {
        return new Decimal(converted).toString();
      } catch {
        return converted;
      }
    })();

    if (targetNorm !== localReconstructedNorm) {
      setClaimIFDiscountPct(
        decimalStringToPercentInput(form.claim_IF_discount)
      );
    }
  }, [form.claim_IF_discount, claimIFDiscountPct]);

  return (
    <div className="flex-1 min-w-0 flex flex-col gap-0">
      <SymbolIconField
        baseSymbol={form.base_symbol}
        hasStagedSymbolIcon={hasStagedSymbolIcon}
        symbolIconDisplayUrl={symbolIconDisplayUrl}
        symbolIconLabel={symbolIconLabel}
        onStageSymbolIcon={onStageSymbolIcon}
        onRemoveSymbolIcon={onRemoveSymbolIcon}
      />

      {/* Section title + Import */}
      <div className="flex justify-between items-start gap-4 mb-5">
        <div>
          <div className="text-base font-medium text-base-contrast-98 mb-1">
            Set up parameters
          </div>
          <div className="text-3xs font-medium text-base-contrast-50">
            Configure trading parameters for this symbol. Fields marked with *
            are required.
          </div>
        </div>
        <button
          type="button"
          onClick={onImport}
          className={cn(
            "shrink-0 inline-flex items-center justify-center",
            "h-8 px-4 py-2 rounded-full text-2xs font-medium",
            "bg-transparent border border-primary text-white/80",
            "hover:bg-primary/10 transition-colors"
          )}
        >
          Import
        </button>
      </div>

      {/* Form: 2-column grid, 3 rows */}
      <div className="flex flex-col gap-5">
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
          <SelectField
            label="Max Leverage"
            tooltip={TRADING_PARAM_TOOLTIPS.max_leverage}
            required
            value={form.max_leverage || "10"}
            options={LEVERAGE_OPTIONS}
            error={errors.max_leverage}
            hint="Suggested: 10x"
            onChange={v => onFieldChange("max_leverage", v)}
            triggerClassName="min-h-[40px] w-full"
          />
          <Field
            label="Global Max OI (USDC)"
            tooltip={TRADING_PARAM_TOOLTIPS.global_max_oi}
            required
            value={form.global_max_oi}
            error={errors.global_max_oi}
            warning={warnings.global_max_oi}
            placeholder="e.g. 1000000"
            hint="Suggested: $1,000,000 (Optional)"
            inputMode="numeric"
            onChange={v => onFieldChange("global_max_oi", v)}
            onBlurValidate={onValidateFields}
          />
        </div>
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
          <Field
            label="Max Notional User (USDC)"
            tooltip={TRADING_PARAM_TOOLTIPS.max_notional_user}
            required
            value={form.max_notional_user}
            error={errors.max_notional_user}
            warning={warnings.max_notional_user}
            placeholder="e.g. 200000"
            hint="Suggested: $200,000"
            inputMode="numeric"
            onChange={v => onFieldChange("max_notional_user", v)}
            onBlurValidate={onValidateFields}
          />
          <SelectField
            label="Funding Period"
            tooltip={TRADING_PARAM_TOOLTIPS.funding_period}
            required
            value={form.funding_period}
            options={FUNDING_PERIODS}
            error={errors.funding_period}
            hint={fundingPeriodHint}
            hintClassName={
              fundingPeriodChangePending
                ? "text-warning bg-warning/10 px-3 py-2 rounded-lg block"
                : undefined
            }
            disabled={fundingPeriodChangePending}
            onChange={v => onFieldChange("funding_period", v)}
            triggerClassName="min-h-[40px] w-full"
          />
        </div>
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
          <Field
            label="Standard liquidation fee"
            tooltip={TRADING_PARAM_TOOLTIPS.std_liquidation_fee}
            required
            value={stdLiqFeePct}
            error={errors.std_liquidation_fee}
            warning={warnings.std_liquidation_fee}
            suffix="%"
            placeholder={`e.g. ${stdSuggestedPct}`}
            hint={
              listingAssetType === ListingAssetType.Rwa
                ? "Fixed at 1.5% for RWA"
                : `Suggested: ${stdSuggestedPct}% for 20x leverage, 2.4% for 10x or below`
            }
            inputMode="decimal"
            readOnly={listingAssetType === ListingAssetType.Rwa}
            disabled={listingAssetType === ListingAssetType.Rwa}
            onChange={v => {
              const next = sanitizePercentInput(v, 2);
              setStdLiqFeePct(next);
              onFieldChange(
                "std_liquidation_fee",
                percentInputToDecimalString(next)
              );
            }}
            onBlurValidate={onValidateFields}
          />
          <Field
            label="Claim IF discount"
            tooltip={TRADING_PARAM_TOOLTIPS.claim_IF_discount}
            required
            value={claimIFDiscountPct}
            error={errors.claim_IF_discount}
            warning={warnings.claim_IF_discount}
            suffix="%"
            placeholder={`e.g. ${claimIFDiscountSuggestedPct}`}
            hint={`Suggested: ${claimIFDiscountSuggestedPct}% for 20x leverage, 1.0% for 10x or below`}
            inputMode="decimal"
            onChange={v => {
              const next = sanitizePercentInput(v, 2);
              setClaimIFDiscountPct(next);
              onFieldChange(
                "claim_IF_discount",
                percentInputToDecimalString(next)
              );
            }}
            onBlurValidate={onValidateFields}
          />
        </div>

        {listingAssetType === ListingAssetType.Rwa ? (
          <RwaMarketSessionSection
            value={rwaMarketSession}
            options={rwaMarketSessionOptions}
            error={errors.rwa_market_session ?? rwaMarketSessionError}
            loading={rwaMarketSessionLoading}
            onChange={v => onFieldChange("rwa_market_session", v)}
          />
        ) : null}
      </div>
    </div>
  );
}
