import { OracleHealthLabel } from "../../types";
import type {
  BuilderOracleSource,
  BuilderOracleSymbol,
  CustomOracleModalState,
  OracleEvent,
} from "../../types";
import type {
  BuilderOracleFeedRow,
  OracleEventRow,
} from "../../../../services";

export function cloneModal(
  current: CustomOracleModalState,
  patch: Partial<CustomOracleModalState>
): CustomOracleModalState {
  return {
    ...current,
    ...patch,
  };
}

function formatUpdatedText(lastUpdate: number | null | undefined) {
  if (!lastUpdate) return "No data yet";
  const delta = Math.max(1, Math.floor((Date.now() - lastUpdate) / 1000));
  if (delta < 60) return `Updated ${delta}s ago`;
  if (delta < 3600) return `Updated ${Math.floor(delta / 60)}m ago`;
  if (delta < 86400) return `Updated ${Math.floor(delta / 3600)}h ago`;
  return `Updated ${Math.floor(delta / 86400)}d ago`;
}

export function toBuilderEvents(
  rows: OracleEventRow[] | undefined
): OracleEvent[] {
  return (rows ?? []).map(row => ({
    time: new Date(row.ts).toLocaleString(),
    type: row.event_type,
    description: row.message,
    tone:
      row.event_type === "TICK_DEVIATION_SKIP"
        ? "warning"
        : row.event_type === "INACTIVE_START"
          ? "danger"
          : "success",
  }));
}

function toUptimeDays(
  rows: Array<{ date: string; uptime_pct: number }> | undefined
): BuilderOracleSymbol["uptimeDays"] {
  const uptimeByDate = new Map(
    (rows ?? []).map(row => [row.date, row.uptime_pct] as const)
  );

  const days: BuilderOracleSymbol["uptimeDays"] = [];
  const today = new Date();

  for (let i = 6; i >= 0; i--) {
    const d = new Date(today);
    d.setDate(today.getDate() - i);
    const isoDate = d.toISOString().slice(0, 10);
    const uptimePct = uptimeByDate.get(isoDate);

    days.push({
      label: i === 0 ? "Today" : isoDate.slice(5),
      tooltip:
        uptimePct == null
          ? `${isoDate} · No data`
          : `${isoDate} · ${uptimePct}% uptime`,
      tone:
        uptimePct == null
          ? "gray"
          : uptimePct >= 100
            ? "green"
            : uptimePct >= 80
              ? "yellow"
              : "red",
    });
  }

  return days;
}

export function mapBuilderSymbol(
  row: BuilderOracleFeedRow,
  sourceId: string,
  events: OracleEvent[]
): BuilderOracleSymbol {
  const isPending = !row.last_update;
  const healthTone =
    row.status === "inactive"
      ? "danger"
      : isPending
        ? "muted"
        : row.uptime_7d_pct != null && row.uptime_7d_pct < 95
          ? "warning"
          : "success";

  return {
    id: row.base_ccy.toLowerCase(),
    name: row.base_ccy,
    sourceId,
    visibility: row.visibility,
    status: row.status,
    price: row.price,
    updatedText: formatUpdatedText(row.last_update),
    uptimePct: row.uptime_7d_pct,
    healthLabel:
      row.status === "inactive"
        ? OracleHealthLabel.Inactive
        : isPending
          ? OracleHealthLabel.Pending
          : row.uptime_7d_pct != null && row.uptime_7d_pct < 95
            ? OracleHealthLabel.Warning
            : OracleHealthLabel.Normal,
    healthTone,
    skips7d: row.skips_7d,
    uptimeDays: toUptimeDays(row.uptime_bars),
    events,
  };
}

export function getBuilderFeedIdentity(
  symbolId: string,
  source: BuilderOracleSource
) {
  const symbol = source.symbols.find(item => item.id === symbolId);

  return {
    base_ccy: symbol?.name ?? symbolId.toUpperCase(),
  };
}
