import { useCallback, useMemo, useState } from "react";
import {
  DASHBOARD_EVENT_HISTORY_SWR,
  useBrokerListingEventHistory,
  whenDashboardPollingEnabled,
} from "../../../services";
import type {
  BrokerListingEventHistoryData,
  BrokerListingEventHistoryRow,
} from "../../../services/types";
import { PageView, type RecentEvent } from "../../../types";
import { useListingStore } from "../../../store/useListingStore";
import { formatRelativeTimeLabel } from "../relativeTime";

export type UseRecentEventsCardResult = {
  events: RecentEvent[];
  page: number;
  pageSize: number;
  total: number;
  onPageChange: (page: number) => void;
  onPageSizeChange: (size: number) => void;
  isLoading: boolean;
};

export function useRecentEventsCard(): UseRecentEventsCardResult {
  const [page, setPage] = useState(1);
  const [pageSize, setPageSize] = useState(10);

  const recentEvents = useListingStore(s => s.recentEvents);
  const isDashboardActive = useListingStore(
    s => s.currentPage === PageView.Dashboard
  );

  const swr = useBrokerListingEventHistory(
    { page, size: pageSize },
    whenDashboardPollingEnabled(isDashboardActive, DASHBOARD_EVENT_HISTORY_SWR)
  );

  const apiEvents = useMemo(() => {
    const rows: BrokerListingEventHistoryRow[] =
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      swr.data?.rows ?? (swr.data as any)?.events ?? [];

    return rows
      .map(
        (row): RecentEvent => ({
          eventTime: row.event_time,
          time: formatRelativeTimeLabel(row.event_time),
          description: row.detail,
        })
      )
      .sort(
        (a, b) => Date.parse(b.eventTime || "") - Date.parse(a.eventTime || "")
      );
  }, [swr.data]);

  const apiTotal = useMemo(() => {
    const value = (swr.data as BrokerListingEventHistoryData | undefined)
      ?.total;
    return typeof value === "number" ? value : apiEvents.length;
  }, [swr.data, apiEvents.length]);

  const mergedEvents = useMemo(() => {
    const combined = [...recentEvents, ...apiEvents];
    const seen = new Set<string>();
    return combined
      .filter(e => {
        const key = `${e.eventTime}::${e.description}`;
        if (seen.has(key)) return false;
        seen.add(key);
        return true;
      })
      .sort((a, b) => Date.parse(b.eventTime) - Date.parse(a.eventTime))
      .slice(0, 20);
  }, [recentEvents, apiEvents]);

  const onPageChange = useCallback((next: number) => setPage(next), []);

  const onPageSizeChange = useCallback((size: number) => {
    setPageSize(size);
    setPage(1);
  }, []);

  return {
    events: mergedEvents,
    total: apiTotal,
    page,
    pageSize,
    onPageChange,
    onPageSizeChange,
    isLoading: swr.isLoading,
  };
}
