import { useCallback, useMemo } from "react";
import { useQuery } from "@/hooks/useQuery";

const PRICE_CHANGES_PATH = "/v1/public/market_info/price_changes";

export type MarketInfoPriceChangeRow = {
  symbol: string;
  last_price: number;
};

function isFiniteNumber(n: unknown): n is number {
  return typeof n === "number" && Number.isFinite(n);
}

export function useMarketInfoPriceChanges() {
  const swr = useQuery<MarketInfoPriceChangeRow[]>(PRICE_CHANGES_PATH, {
    revalidateOnFocus: false,
    dedupingInterval: 60_000,
  });

  const priceBySymbol = useMemo(() => {
    const rows = swr.data ?? [];
    const m = new Map<string, number>();
    for (const row of rows) {
      if (!row?.symbol || !isFiniteNumber(row.last_price)) continue;
      m.set(row.symbol, row.last_price);
    }
    return m;
  }, [swr.data]);

  const getLastPrice = useCallback(
    (symbol: string) => priceBySymbol.get(symbol) ?? 1,
    [priceBySymbol]
  );

  return { ...swr, priceBySymbol, getLastPrice };
}
