import { cn } from "@/utils/css";

import type { SymbolDetail } from "../../../types";
import type { RwaInfoRow, RwaMarketHoliday } from "../../../services/types";
import { useRwaInfo } from "../../../services";
import { DetailRow } from "./SymbolDetailPanel.shared";

type RwaSessionOpenMode = "open" | "closed" | "fallback";

function resolveRwaSessionOpenMode(row: RwaInfoRow): RwaSessionOpenMode {
  const s = row.status?.trim().toLowerCase();
  if (s === "open") return "open";
  if (s === "closed") return "closed";
  if (row.next_open != null && row.next_close != null) {
    const now = Date.now();
    return now >= row.next_open && now < row.next_close ? "open" : "closed";
  }
  return "fallback";
}

function RwaSessionStatusValue(props: { row: RwaInfoRow | undefined }) {
  const { row } = props;

  if (!row) {
    return <span className="tabular-nums">—</span>;
  }

  const mode = resolveRwaSessionOpenMode(row);
  if (mode === "fallback") {
    const raw = row.status?.trim();
    return <span className="tabular-nums">{raw ? raw : "—"}</span>;
  }

  const isOpen = mode === "open";
  return (
    <span className="inline-flex flex-wrap items-center justify-end gap-x-1">
      <span className="inline-flex items-center gap-1.5">
        <span
          className={cn(
            "size-1.5 shrink-0 rounded-full",
            isOpen ? "bg-success" : "bg-base-contrast-36"
          )}
        />
        <span className={isOpen ? "text-success" : "text-base-contrast-50"}>
          {isOpen ? "Open" : "Closed"}
        </span>
      </span>
    </span>
  );
}

function deriveMarketLabel(detail: SymbolDetail): string {
  const session = detail.marketSession?.trim();
  const rwa = detail.rwaMarket;
  const name = rwa?.name?.trim();
  if (session && name) return `${session} · ${name}`;
  if (session) return session;
  if (name) return name;
  if (rwa?.market_session) return rwa.market_session;
  return "—";
}

function formatHolidayDate(dateStr: string): string {
  const d = new Date(`${dateStr}T00:00:00Z`);
  if (!Number.isFinite(d.getTime())) return dateStr;
  return d.toLocaleDateString("en-US", {
    month: "short",
    day: "numeric",
    timeZone: "UTC",
  });
}

function getNextHoliday(holidays: RwaMarketHoliday[] | undefined): string {
  if (!holidays || holidays.length === 0) return "—";
  const todayStr = new Date().toISOString().slice(0, 10);
  const upcoming = holidays
    .filter(h => h.date >= todayStr)
    .sort((a, b) => a.date.localeCompare(b.date));
  if (upcoming.length === 0) return "—";
  const next = upcoming[0];
  const formatted = formatHolidayDate(next.date);
  return next.name ? `${formatted} (${next.name})` : formatted;
}

export function SymbolDetailTradingParamsPanel(props: {
  detail: SymbolDetail;
  params: SymbolDetail["params"];
}) {
  const { detail, params } = props;
  const { data: rwaInfo } = useRwaInfo({ revalidateOnFocus: false });
  const perpSymbol = params.Symbol?.value ?? "";
  const rwaInfoRow = rwaInfo?.find(r => r.symbol === perpSymbol);
  const marketLabel = deriveMarketLabel(detail);
  const tradingHours = detail.rwaMarket?.trading_hours ?? "—";
  const timezone = detail.rwaMarket?.timezone ?? "—";
  const showRwaSection = Boolean(
    detail.isRwa && (detail.marketSession || detail.rwaMarket || rwaInfoRow)
  );

  return (
    <div className="bg-base-200 rounded-xl p-4 flex flex-col gap-3">
      <h3 className="text-xs font-medium text-base-contrast-98">
        Trading parameters
      </h3>
      <DetailRow label="Symbol" value={params.Symbol?.value ?? "—"} />
      <DetailRow label="Leverage" value={params.max_leverage?.value ?? "—"} />
      <DetailRow
        label="IMR / MMR"
        value={`${params.base_imr?.value ?? "—"} / ${
          params.base_mmr?.value ?? "—"
        }`}
      />
      <DetailRow label="Max OI" value={params.global_max_oi?.value ?? "—"} />
      <DetailRow
        label="Max notional"
        value={params.max_notional_user?.value ?? "—"}
      />
      <DetailRow label="Price range" value={params.price_range?.value ?? "—"} />
      {showRwaSection ? (
        <>
          <div className="h-px bg-base-contrast-12" />
          <DetailRow label="Market" value={marketLabel} />
          <DetailRow label="Regular trading hours" value={tradingHours} />
          <DetailRow label="Timezone" value={timezone} />
          <DetailRow
            label="Status"
            value={<RwaSessionStatusValue row={rwaInfoRow} />}
          />
          <DetailRow
            label="Next holiday"
            value={getNextHoliday(detail.rwaMarket?.holidays)}
          />
        </>
      ) : null}
    </div>
  );
}
