import type { Holding } from "../services/types";

/** USDC holding for an account from aggregate `Holding[]`, or null if missing / invalid. */
export function usdcHoldingForAccountOrNull(
  holdings: Holding[],
  accountId: string
): number | null {
  const row = holdings.find(
    h =>
      h.account_id === accountId &&
      (h.token === "USDC" || h.token?.toUpperCase() === "USDC")
  );
  return typeof row?.holding === "number" && Number.isFinite(row.holding)
    ? row.holding
    : null;
}

/** USDC holding for an account; defaults to 0 when missing (e.g. transfer max amount). */
export function usdcHoldingForAccount(
  holdings: Holding[],
  accountId: string
): number {
  return usdcHoldingForAccountOrNull(holdings, accountId) ?? 0;
}
