export const BROKER_SYMBOL_LOGO_MAX_BYTES = 50 * 1024;

const BROKER_SYMBOL_LOGO_GCS_BUCKET = "oss.orderly.network";
const BROKER_SYMBOL_LOGO_PUBLIC_BASE_URL = "https://oss.orderly.network";

export function buildBrokerSymbolLogoGcsUrl(objectPath: string): string {
  const encodedPath = objectPath
    .split("/")
    .map(segment => encodeURIComponent(segment))
    .join("/");
  return `https://storage.googleapis.com/${encodeURIComponent(BROKER_SYMBOL_LOGO_GCS_BUCKET)}/${encodedPath}`;
}

export function buildBrokerSymbolLogoPublicUrl(objectPath: string): string {
  const base = BROKER_SYMBOL_LOGO_PUBLIC_BASE_URL.replace(/\/+$/, "");
  const encodedPath = objectPath
    .split("/")
    .map(segment => encodeURIComponent(segment))
    .join("/");
  return `${base}/${encodedPath}`;
}

export function deriveBrokerSymbolLogoFileBaseName(perpSymbol: string): string {
  const segments = perpSymbol
    .trim()
    .split("_")
    .filter(part => part.length > 0);
  if (segments[0] === "PERP") segments.shift();
  if (segments[0] === "USDC") {
    segments.shift();
  } else {
    const usdcIndex = segments.indexOf("USDC");
    if (usdcIndex >= 0) segments.splice(usdcIndex, 1);
  }
  const raw = segments.join("_");
  return raw
    .replace(/[^a-zA-Z0-9._-]/g, "_")
    .replace(/_+/g, "_")
    .replace(/^\.+|\.+$/g, "")
    .replace(/^_|_$/g, "");
}

export function buildBrokerSymbolLogoSymbolPreview(
  displaySymbol: string,
  brokerId?: string
): string {
  const trimmed = displaySymbol.trim();
  if (!trimmed) return "";
  const safeBrokerId = brokerId?.trim();
  if (!safeBrokerId) return trimmed;
  if (trimmed.endsWith(`_${safeBrokerId}`)) return trimmed;
  return `${trimmed}_${safeBrokerId}`;
}

export function formatBrokerSymbolLogoMaxUploadSize(bytes: number): string {
  if (bytes >= 1024 * 1024 && bytes % (1024 * 1024) === 0)
    return `${bytes / (1024 * 1024)} MB`;
  if (bytes >= 1024 && bytes % 1024 === 0) return `${bytes / 1024} KB`;
  return `${bytes} bytes`;
}

export function brokerSymbolLogoUploadSizeExceededMessage(
  maxBytes: number = BROKER_SYMBOL_LOGO_MAX_BYTES
): string {
  return `File too large (maximum ${formatBrokerSymbolLogoMaxUploadSize(maxBytes)})`;
}
