import { useSymbolCardView } from "./useSymbolCardView";
import { SymbolCardViewUI } from "./SymbolCardView.ui";

export interface SymbolCardViewProps {
  onCreateListing: () => void;
  onEdit?: (symbol: string) => void;
  onDelist?: (symbol: string) => void;
}

export function SymbolCardView({
  onCreateListing,
  onEdit,
  onDelist,
}: SymbolCardViewProps) {
  const { symbols, isEmpty } = useSymbolCardView();

  return (
    <SymbolCardViewUI
      symbols={symbols}
      isEmpty={isEmpty}
      onCreateListing={onCreateListing}
      onEdit={onEdit}
      onDelist={onDelist}
    />
  );
}
