import type React from "react";
import { cn } from "@/utils/css";

interface PLInputProps extends React.InputHTMLAttributes<HTMLInputElement> {
  error?: boolean;
}

export function PLInput({
  className,
  disabled,
  readOnly,
  error,
  ...rest
}: PLInputProps) {
  const isNonInteractive = disabled || readOnly;

  return (
    <input
      disabled={disabled}
      readOnly={readOnly}
      aria-invalid={error || undefined}
      className={cn(
        "w-full px-3 py-2.5 rounded-lg text-xs",
        "bg-base-300 text-base-contrast-98 placeholder:text-base-contrast-36",
        "border border-base-contrast-12 outline-none",
        !error && "focus:border-primary",
        error && "border-danger focus:border-danger",
        isNonInteractive && "hover:cursor-not-allowed",
        className
      )}
      {...rest}
    />
  );
}
