import * as React from "react";
import { Slot } from "@radix-ui/react-slot";
import { cva, type VariantProps } from "class-variance-authority";
import { cn } from "@/utils";

const buttonVariants = cva(
  cn(
    "inline-flex items-center justify-center whitespace-nowrap text-xs font-semibold",
    "cursor-pointer focus-visible:outline-none",
    "disabled:cursor-not-allowed disabled:bg-primary/20 disabled:text-base-contrast-36 disabled:border-base-contrast-36"
  ),
  {
    variants: {
      variant: {
        default: "bg-primary text-primary-foreground hover:bg-primary/90",
        outline: "border bg-transparent hover:bg-primary/5",
        secondary:
          "bg-secondary text-secondary-foreground hover:bg-secondary/80",
        link: "bg-transparent text-primary underline-offset-4 hover:underline",
        ghost: "bg-transparent text-base-contrast-80 hover:bg-base-contrast-8",
        danger: "bg-danger text-white hover:bg-danger/90",
      },
      color: {
        default: "border-base-contrast-54 hover:border-base-contrast",
        primary: "border-primary hover:bg-primary/10",
        danger: "border-danger hover:bg-danger/10",
      },
      size: {
        default: "h-[40px] px-[20px] py-[16px]",
        md: "h-8 px-5",
        sm: "h-8 px-3 text-2xs",
      },
      rounded: {
        full: "rounded-full",
        lg: "rounded-lg",
        md: "rounded-md",
        sm: "rounded-sm",
        none: "rounded-none",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "default",
      rounded: "full",
    },
  }
);

export interface ButtonProps
  extends Omit<React.ButtonHTMLAttributes<HTMLButtonElement>, "color">,
    VariantProps<typeof buttonVariants> {
  asChild?: boolean;
  loading?: boolean;
}

function CircleLoading() {
  const cls = "h-[6.67px] w-[6.67px] rounded-full";
  return (
    <div className="flex items-center gap-x-[4px]">
      <div className={cn(cls, "button-loading-circle-1")} />
      <div className={cn(cls, "button-loading-circle-2")} />
      <div className={cn(cls, "button-loading-circle-3")} />
    </div>
  );
}

const Button = React.forwardRef<HTMLButtonElement, ButtonProps>(
  (
    {
      className,
      variant,
      color,
      size,
      asChild = false,
      rounded,
      children,
      loading,
      disabled,
      ...rest
    },
    ref
  ) => {
    const Comp = asChild ? Slot : "button";
    return (
      <Comp
        ref={ref}
        className={cn(
          buttonVariants({ variant, size, color, className, rounded }),
          disabled &&
            variant === "outline" &&
            "disabled:bg-transparent disabled:text-base-contrast-54 disabled:border-base-contrast-36"
        )}
        disabled={disabled}
        {...rest}
      >
        {loading ? <CircleLoading /> : children}
      </Comp>
    );
  }
);
Button.displayName = "Button";

export { Button, buttonVariants };
