import { useEffect, useMemo, useState } from "react";
import { Button } from "@/components/button";
import {
  Dialog,
  DialogBody,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/dialog";
import { Input } from "@/components/input";
import { toast } from "@/components/toast";
import { ByokProviderId, type ByokProvider } from "../../types";
import {
  footerClassName,
  formLabelClassName,
  getByokSourceId,
  getProviderLabel,
  sourceIdClassName,
} from "./shared";

interface AddByokSourceModalProps {
  providerId: string | null;
  byokProviders: ByokProvider[];
  isMutating: boolean;
  onClose: () => void;
  onConfirm: (
    providerId: string,
    key: string
  ) => Promise<string | null> | string | null;
}

export function AddByokSourceModal({
  providerId,
  byokProviders,
  isMutating,
  onClose,
  onConfirm,
}: AddByokSourceModalProps) {
  const [addSourceKey, setAddSourceKey] = useState("");
  const [addUser, setAddUser] = useState("");
  const [addPassword, setAddPassword] = useState("");

  useEffect(() => {
    // Reset inputs when modal provider changes.
    setAddSourceKey("");
    setAddUser("");
    setAddPassword("");
  }, [providerId]);

  const providerLabel = useMemo(
    () => getProviderLabel(providerId, byokProviders),
    [providerId, byokProviders]
  );

  return (
    <Dialog
      open={providerId !== null}
      onOpenChange={nextOpen => {
        if (!nextOpen) {
          setAddSourceKey("");
          onClose();
        }
      }}
    >
      <DialogContent className="max-w-[520px]">
        <DialogHeader className="h-auto flex-col items-stretch gap-2 border-b-0 px-6 pt-6 pb-0">
          <DialogTitle className="text-lg font-medium text-base-contrast-98">
            Add {providerLabel} Bring Your Own Key source
          </DialogTitle>
          <DialogDescription className="text-2xs leading-6 text-base-contrast-54">
            Provide your {providerLabel} API key. Orderly will pull price data
            on your behalf and no WebSocket infrastructure is needed.
          </DialogDescription>
        </DialogHeader>
        <DialogBody className="space-y-4 px-6 pt-5 pb-0">
          <div className={sourceIdClassName}>
            <div className="text-3xs text-base-contrast-50">
              Source ID (auto-assigned)
            </div>
            <div className="mt-1 font-mono text-[15px] font-semibold text-base-contrast-98">
              {getByokSourceId(providerId)}
            </div>
          </div>
          {providerId === ByokProviderId.Stork ? (
            <>
              <div>
                <label className={formLabelClassName}>User</label>
                <Input
                  value={addUser}
                  disabled={isMutating}
                  onChange={event => {
                    setAddUser(event.target.value);
                  }}
                  placeholder="user"
                  type="text"
                  className="bg-base-500"
                />
              </div>
              <div>
                <label className={formLabelClassName}>Password</label>
                <Input
                  value={addPassword}
                  disabled={isMutating}
                  onChange={event => {
                    setAddPassword(event.target.value);
                  }}
                  placeholder="password"
                  type="password"
                  className="bg-base-500"
                />
              </div>
              <div className="mt-1.5 text-3xs text-base-contrast-36">
                Your key will be validated against the provider and encrypted
                before storage. You can add symbols after the source is created.
              </div>
            </>
          ) : (
            <div>
              <label className={formLabelClassName}>API key</label>
              <Input
                value={addSourceKey}
                disabled={isMutating}
                onChange={event => {
                  setAddSourceKey(event.target.value);
                }}
                placeholder="sk-..."
                type="password"
                className="bg-base-500"
              />
              <div className="mt-1.5 text-3xs text-base-contrast-36">
                Your key will be validated against the provider and encrypted
                before storage. You can add symbols after the source is created.
              </div>
            </div>
          )}
        </DialogBody>
        <DialogFooter className={`${footerClassName} mt-6`}>
          <Button
            variant="outline"
            color="primary"
            className="flex-1"
            disabled={isMutating}
            onClick={() => {
              setAddSourceKey("");
              setAddUser("");
              setAddPassword("");
              onClose();
            }}
          >
            Cancel
          </Button>
          <Button
            className="flex-1"
            loading={isMutating}
            disabled={isMutating}
            onClick={async () => {
              if (!providerId) return;
              const keyToSubmit =
                providerId === ByokProviderId.Stork
                  ? addUser.trim() && addPassword.trim()
                    ? `${addUser.trim()}#${addPassword.trim()}`
                    : ""
                  : addSourceKey;

              const error = await onConfirm(providerId, keyToSubmit);
              if (error) {
                toast.error(error);
                return;
              }
              setAddSourceKey("");
              setAddUser("");
              setAddPassword("");
            }}
          >
            Add provider
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}
