import { DASH } from "../../dashboard/formatters";
import type { SymbolDetail, SymbolStatus } from "../../../types";
import { DetailRow } from "./SymbolDetailPanel.shared";

function getDelistRemainingDisplay(
  status: SymbolStatus,
  delistTime: string | null
): { value: string; valueClassName?: string } {
  const parseDelistDate = (raw: string): Date | null => {
    const d = new Date(raw.replace(" UTC", "Z").replace(" ", "T"));
    return Number.isNaN(d.getTime()) ? null : d;
  };

  const delistDate = delistTime ? parseDelistDate(delistTime) : null;

  if (!delistDate) {
    if (status === "DELISTED") {
      return { value: "Completed", valueClassName: "text-base-contrast-36" };
    }
    return { value: DASH };
  }

  const now = new Date();
  const diffMs = delistDate.getTime() - now.getTime();
  if (diffMs > 0) {
    const days = Math.floor(diffMs / 86400000);
    const hours = Math.floor((diffMs % 86400000) / 3600000);
    const mins = Math.floor((diffMs % 3600000) / 60000);
    const parts: string[] = [];
    if (days > 0) parts.push(`${days}d`);
    if (hours > 0) parts.push(`${hours}h`);
    parts.push(`${mins}m`);
    return { value: parts.join(" "), valueClassName: "text-danger" };
  }
  return { value: "Completed", valueClassName: "text-base-contrast-36" };
}

export function SymbolDetailDelistPanel(props: {
  detail: Pick<SymbolDetail, "status" | "delistTime">;
}) {
  const { detail } = props;
  const showDelistInfo =
    detail.status === "DELISTING" || detail.status === "DELISTED";
  if (!showDelistInfo) return null;

  const delistRemainingDisplay = getDelistRemainingDisplay(
    detail.status,
    detail.delistTime
  );

  return (
    <div className="bg-base-200 rounded-xl p-4 flex flex-col gap-3">
      <h3 className="text-xs font-medium text-base-contrast-98">Delist Info</h3>
      <div className="flex flex-col gap-2">
        <DetailRow label="Delist scheduled" value={detail.delistTime ?? DASH} />
        <DetailRow
          label="Remaining"
          value={delistRemainingDisplay.value}
          valueClassName={delistRemainingDisplay.valueClassName}
        />
      </div>
    </div>
  );
}
