import { InsuranceFundStep } from "../onboarding/components/InsuranceFundStep";
import {
  getIfRequired,
  getActiveIfSymbolCount,
} from "@/permissionless-listing/constants";
import { useMemo } from "react";
import { useListingServerData } from "../../hooks/useListingServerData";

// Info banner icon matching mockup
function InfoIcon() {
  return (
    <svg
      className="shrink-0 mt-0.5 text-primary"
      width={20}
      height={20}
      viewBox="0 0 20 20"
      fill="none"
    >
      <circle cx="10" cy="10" r="9" stroke="currentColor" strokeWidth="1.5" />
      <path
        d="M10 9v4.5"
        stroke="currentColor"
        strokeWidth="1.5"
        strokeLinecap="round"
      />
      <circle cx="10" cy="6.5" r="1" fill="currentColor" />
    </svg>
  );
}

export function IFAccountSection() {
  const { listingSymbols, riskSnapshot } = useListingServerData();
  const minBalance = useMemo(
    () => getIfRequired(riskSnapshot, listingSymbols),
    [riskSnapshot, listingSymbols]
  );
  const activeSymbolsCount = getActiveIfSymbolCount(
    riskSnapshot,
    listingSymbols
  );

  const currencyFormatter = useMemo(
    () =>
      new Intl.NumberFormat("en-US", {
        style: "currency",
        currency: "USD",
        minimumFractionDigits: 0,
        maximumFractionDigits: 0,
      }),
    []
  );
  const fmtCurrency = (v: number) => currencyFormatter.format(v);

  return (
    <div className="flex flex-col gap-4">
      {/* Info banner: balance requirements — match mockup purple-06, border, padding 16px 20px */}
      <div className="bg-primary/6 border border-base-contrast-8 rounded-xl py-4 px-5 flex items-start gap-3">
        <InfoIcon />
        <div className="flex flex-col gap-3 text-2xs text-base-contrast-50 leading-snug">
          <p className="text-base-contrast-98 font-medium">
            Balance requirements scale with the number of listed symbols.
          </p>

          <div className="rounded-lg border border-base-contrast-8 bg-base-contrast-4 p-3">
            <div className="grid gap-3">
              <div>
                <div className="mb-1 text-[10px] font-semibold uppercase tracking-[0.08em] text-primary-light">
                  Current
                </div>
                <p className="text-base-contrast-54">
                  At least $25,000 × number of currently listed symbols.
                </p>
              </div>
              <div>
                <div className="mb-1 text-[10px] font-semibold uppercase tracking-[0.08em] text-primary-light">
                  New symbol
                </div>
                <p className="text-base-contrast-54">
                  If the builder wants to list a new symbol, the requirement is
                  $25,000 × (current symbols + 1).
                </p>
              </div>
            </div>
          </div>

          <p className="text-base-contrast-30">
            New listing checks automatically include the token you are trying to
            add. With {activeSymbolsCount} current symbols, IF requires ≥{" "}
            {fmtCurrency(minBalance)}.
          </p>
        </div>
      </div>

      <div className="bg-base-200 rounded-xl p-6 flex flex-col gap-2">
        <h4 className="text-xs font-semibold text-base-contrast-98 mb-4">
          Insurance fund account
        </h4>
        <InsuranceFundStep />
      </div>
    </div>
  );
}
