import { useMemo } from "react";
import {
  DASHBOARD_RISK_SNAPSHOT_SWR,
  whenDashboardPollingEnabled,
} from "../services";
import { useSelectListingStore } from "../store/useListingStore";
import { getTierRequired } from "../constants";
import { PageView } from "../types";
import { useListingAccountContext } from "./useListingAccountContext";
import { useListingAccountsData } from "./useListingAccountsData";
import { useListingBalancesData } from "./useListingBalancesData";
import { useListingIndexSourcesData } from "./useListingIndexSourcesData";
import { useListingRiskSnapshotData } from "./useListingRiskSnapshotData";
import { useListingSymbolsData } from "./useListingSymbolsData";

export function shouldForceListingOnboarding(input: {
  brokerType?: string;
  hasIfAccount: boolean;
  symbolCount: number;
}) {
  const tierRequired = getTierRequired(input.brokerType);
  return (!tierRequired || !input.hasIfAccount) && input.symbolCount === 0;
}

export function useListingServerData() {
  const account = useListingAccountContext();
  const isDashboardActive = useSelectListingStore(
    state => state.currentPage === PageView.Dashboard
  );

  const accounts = useListingAccountsData();
  const balances = useListingBalancesData();
  const indexSourcesQuery = useListingIndexSourcesData();
  const symbolsQuery = useListingSymbolsData();
  const riskSnapshotQuery = useListingRiskSnapshotData(
    undefined,
    whenDashboardPollingEnabled(isDashboardActive, DASHBOARD_RISK_SNAPSHOT_SWR)
  );

  const forceOnboardingReady = Boolean(
    accounts.brokerInfo &&
      accounts.listingAccounts &&
      symbolsQuery.listingSymbols
  );

  const forceOnboarding = useMemo(() => {
    if (!forceOnboardingReady) return false;
    return shouldForceListingOnboarding({
      brokerType: accounts.brokerInfo?.type,
      hasIfAccount: Boolean(accounts.listingAccounts?.if_account?.account_id),
      symbolCount: symbolsQuery.listingSymbols?.length ?? 0,
    });
  }, [
    accounts.brokerInfo?.type,
    accounts.listingAccounts?.if_account?.account_id,
    forceOnboardingReady,
    symbolsQuery.listingSymbols?.length,
  ]);

  const isLoading =
    account.isLoading ||
    accounts.isLoading ||
    balances.isLoading ||
    indexSourcesQuery.isLoading ||
    symbolsQuery.isLoadingListingSymbols ||
    riskSnapshotQuery.isLoading;

  return {
    ...account,
    ...accounts,
    holdings: balances.holdings,
    subAccounts: balances.subAccounts,
    holdingsQuery: balances.holdingsQuery,
    subAccountsQuery: balances.subAccountsQuery,
    indexSources: indexSourcesQuery.indexSources,
    indexSourcesQuery,
    listingSymbols: symbolsQuery.listingSymbols,
    listingSymbolsQuery: symbolsQuery,
    riskSnapshot: riskSnapshotQuery.riskSnapshot,
    riskSnapshotQuery,
    forceOnboarding,
    forceOnboardingReady,
    isLoading,
  };
}
