import { cn } from "@/utils/css";
import { ListingSubStep } from "../types";

interface StepIndicatorProps {
  listingStep: ListingSubStep;
}

export function StepIndicator({ listingStep }: StepIndicatorProps) {
  return (
    <div className="flex items-start px-6 pb-10 mb-10 mt-5 border-b border-base-contrast-6">
      <StepItem
        step={1}
        label="Price Sources"
        active={listingStep === ListingSubStep.PriceSources}
        completed={listingStep === ListingSubStep.TradingParams}
      />
      <div
        className={cn(
          "flex-1 h-0.5 min-w-4 mt-[15px] self-start shrink-0",
          listingStep === ListingSubStep.TradingParams
            ? "bg-primary"
            : "bg-base-contrast-12"
        )}
        aria-hidden
      />
      <StepItem
        step={2}
        label="Trading Params"
        active={listingStep === ListingSubStep.TradingParams}
        completed={false}
      />
    </div>
  );
}

function StepItem({
  step,
  label,
  active,
  completed,
}: {
  step: number;
  label: string;
  active: boolean;
  completed: boolean;
}) {
  const isActiveOrCompleted = active || completed;
  return (
    <div className="flex flex-col items-center gap-2.5 shrink-0">
      <div
        className={cn(
          "w-8 h-8 rounded-full flex items-center justify-center text-xs font-medium border-2 shrink-0 transition-colors",
          isActiveOrCompleted &&
            "bg-primary border-base-contrast-12 text-white",
          !isActiveOrCompleted &&
            "bg-base-200 border-base-contrast-12 text-base-contrast-98"
        )}
      >
        {step}
      </div>
      <span
        className={cn(
          "text-xs font-medium whitespace-nowrap text-center",
          isActiveOrCompleted
            ? "text-base-contrast-98"
            : "text-base-contrast-50"
        )}
      >
        {label}
      </span>
    </div>
  );
}
