import { useEffect, useMemo, useRef, useState } from "react";
import { Button } from "@/components/button";
import {
  Dialog,
  DialogBody,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/dialog";
import { Input } from "@/components/input";
import { toast } from "@/components/toast";
import { ByokProviderId, type ByokProvider } from "../../types";
import {
  footerClassName,
  formLabelClassName,
  getProviderLabel,
} from "./shared";

interface UpdateByokKeyModalProps {
  providerId: string | null;
  byokProviders: ByokProvider[];
  isMutating: boolean;
  onClose: () => void;
  onConfirm: (
    providerId: string,
    key: string
  ) => Promise<string | null> | string | null;
}

export function UpdateByokKeyModal({
  providerId,
  byokProviders,
  isMutating,
  onClose,
  onConfirm,
}: UpdateByokKeyModalProps) {
  const [updateKey, setUpdateKey] = useState("");
  const [updateUser, setUpdateUser] = useState("");
  const [updatePassword, setUpdatePassword] = useState("");

  const hasHydratedRef = useRef(false);

  useEffect(() => {
    // Reset modal inputs when provider changes.
    setUpdateKey("");
    setUpdateUser("");
    setUpdatePassword("");
    hasHydratedRef.current = false;
  }, [providerId]);

  useEffect(() => {
    if (!providerId || providerId !== ByokProviderId.Stork) return;
    if (hasHydratedRef.current) return;

    // Do not backfill credentials in edit mode.
    hasHydratedRef.current = true;
  }, [providerId, byokProviders]);

  const providerLabel = useMemo(
    () => getProviderLabel(providerId, byokProviders),
    [providerId, byokProviders]
  );

  return (
    <Dialog
      open={providerId !== null}
      onOpenChange={nextOpen => {
        if (!nextOpen) {
          setUpdateKey("");
          setUpdateUser("");
          setUpdatePassword("");
          onClose();
        }
      }}
    >
      <DialogContent className="max-w-[440px]">
        <DialogHeader className="h-auto flex-col items-stretch gap-2 border-b-0 px-6 pt-6 pb-0">
          <DialogTitle className="text-lg font-medium text-base-contrast-98">
            Update {providerLabel} API key
          </DialogTitle>
          <DialogDescription className="text-2xs leading-6 text-base-contrast-54">
            Replace the API key Orderly uses to pull prices from{" "}
            <strong className="font-medium text-base-contrast-98">
              {providerLabel}
            </strong>
            . The new key is validated before storage.
          </DialogDescription>
        </DialogHeader>
        <DialogBody className="space-y-4 px-6 pt-5 pb-0">
          {providerId === ByokProviderId.Stork ? (
            <>
              <div>
                <label className={formLabelClassName}>User</label>
                <Input
                  value={updateUser}
                  disabled={isMutating}
                  onChange={event => {
                    // User started editing; stop any pending backfill.
                    hasHydratedRef.current = true;
                    setUpdateUser(event.target.value);
                  }}
                  placeholder="user"
                  type="text"
                  className="bg-base-500"
                />
              </div>
              <div>
                <label className={formLabelClassName}>Password</label>
                <Input
                  value={updatePassword}
                  disabled={isMutating}
                  onChange={event => {
                    // User started editing; stop any pending backfill.
                    hasHydratedRef.current = true;
                    setUpdatePassword(event.target.value);
                  }}
                  placeholder="password"
                  type="password"
                  className="bg-base-500"
                />
              </div>
              <div className="mt-1.5 text-3xs text-base-contrast-36">
                Your key will be encrypted before storage.
              </div>
            </>
          ) : (
            <div>
              <label className={formLabelClassName}>New API key</label>
              <Input
                value={updateKey}
                disabled={isMutating}
                onChange={event => {
                  setUpdateKey(event.target.value);
                }}
                placeholder="sk-..."
                type="password"
                className="bg-base-500"
              />
              <div className="mt-1.5 text-3xs text-base-contrast-36">
                Your key will be encrypted before storage.
              </div>
            </div>
          )}
        </DialogBody>
        <DialogFooter className={`${footerClassName} mt-6`}>
          <Button
            variant="outline"
            color="primary"
            className="flex-1"
            disabled={isMutating}
            onClick={() => {
              setUpdateKey("");
              setUpdateUser("");
              setUpdatePassword("");
              onClose();
            }}
          >
            Cancel
          </Button>
          <Button
            className="flex-1"
            loading={isMutating}
            disabled={isMutating}
            onClick={async () => {
              if (!providerId) return;

              if (
                providerId === ByokProviderId.Stork &&
                (!updateUser.trim() || !updatePassword.trim())
              ) {
                toast.error("Please enter both user and password.");
                return;
              }

              const keyToSubmit =
                providerId === ByokProviderId.Stork
                  ? updateUser.trim() && updatePassword.trim()
                    ? `${updateUser.trim()}#${updatePassword.trim()}`
                    : ""
                  : updateKey;

              const error = await onConfirm(providerId, keyToSubmit);
              if (error) {
                toast.error(error);
                return;
              }

              setUpdateKey("");
              setUpdateUser("");
              setUpdatePassword("");
            }}
          >
            Update key
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}
