import type { SymbolItem, SymbolStatus } from "../types";
import type {
  BrokerListingOverviewData,
  BrokerListingRiskSnapshotData,
  BrokerListingSymbolsRow,
} from "../services/types";

const DASHBOARD_STATUSES: SymbolStatus[] = [
  "NEW",
  "PENDING",
  "POST_ONLY",
  "ACTIVE",
  "REDUCE_ONLY",
  "DELISTING",
  "DELISTED",
];

export function isDashboardStatus(status: string): status is SymbolStatus {
  return (DASHBOARD_STATUSES as string[]).includes(status);
}

export function formatSymbolDisplayName(symbolKey: string): string {
  const parts = symbolKey.split("_");
  if (parts.length >= 3 && parts[0] === "PERP" && parts[2] === "USDC") {
    return `${parts[0]}_${parts[1]}_${parts[2]}`;
  }
  return symbolKey;
}

function openInterestFromRisk(
  risk: BrokerListingRiskSnapshotData["symbols"][number] | null | undefined
): number | null {
  if (risk == null) return null;
  return Math.max(risk.long_oi, risk.short_oi);
}

export function buildListingSymbolItem(args: {
  row: BrokerListingSymbolsRow;
  overviewBySymbol: Map<string, BrokerListingOverviewData["symbols"][number]>;
  riskBySymbol: Map<string, BrokerListingRiskSnapshotData["symbols"][number]>;
}): SymbolItem | null {
  const { row, overviewBySymbol, riskBySymbol } = args;
  if (!isDashboardStatus(row.status)) return null;

  const ov = overviewBySymbol.get(row.symbol);
  const risk = riskBySymbol.get(row.symbol);

  const sourcesFromRisk =
    risk?.index_sources?.length != null ? risk.index_sources.length : null;

  return {
    symbol: row.symbol,
    displayName: formatSymbolDisplayName(row.symbol),
    status: row.status,
    listedAt: row.listing_time ?? null,
    marketSession: row.market_session ?? null,

    sources: sourcesFromRisk ?? null,
    alertLevel: risk?.alert_level ?? null,

    vol: ov?.volume_24h ?? null,
    feeRevenue: ov?.fee_revenue_24h ?? null,
    liqCount: ov?.liquidation_count_24h ?? null,
    liqRevenue: ov?.liquidation_revenue_24h ?? null,

    depthBid: risk?.depth_bid_2pct ?? null,
    depthAsk: risk?.depth_ask_2pct ?? null,
    targetDepth: risk?.target_depth ?? null,
    depthQualifyingSince: risk?.depth_qualifying_since ?? null,

    openInterest: openInterestFromRisk(risk),
  };
}

/*Symbol detail header card */
export function buildListingSymbolItemFromRiskOverview(args: {
  symbol: string;
  listedAt: string | null;
  risk: BrokerListingRiskSnapshotData["symbols"][number] | null | undefined;
  overview: BrokerListingOverviewData["symbols"][number] | null | undefined;
}): SymbolItem {
  const { symbol, listedAt, risk, overview } = args;
  const status = (risk?.status ?? "NEW") as SymbolStatus;

  return {
    symbol,
    displayName: formatSymbolDisplayName(symbol),
    status,
    listedAt,
    marketSession: null,

    sources:
      risk?.index_sources?.length != null ? risk.index_sources.length : null,
    alertLevel: risk?.alert_level ?? null,

    vol: overview?.volume_24h ?? null,
    feeRevenue: overview?.fee_revenue_24h ?? null,
    liqCount: overview?.liquidation_count_24h ?? null,
    liqRevenue: overview?.liquidation_revenue_24h ?? null,

    depthBid: risk?.depth_bid_2pct ?? null,
    depthAsk: risk?.depth_ask_2pct ?? null,
    targetDepth: risk?.target_depth ?? null,
    depthQualifyingSince: risk?.depth_qualifying_since ?? null,

    openInterest: openInterestFromRisk(risk),
  };
}
