export function normalizeTradingParamsForm(
  partial: Partial<TradingParamsForm>,
  base: TradingParamsForm = DEFAULT_TRADING_PARAMS_FORM
): TradingParamsForm {
  const pick = (key: keyof TradingParamsForm): string => {
    const raw = partial[key];
    if (typeof raw === "string" && raw.trim().length > 0) return raw;
    return base[key];
  };

  return {
    max_leverage: pick("max_leverage"),
    global_max_oi: pick("global_max_oi"),
    max_notional_user: pick("max_notional_user"),
    funding_period: pick("funding_period"),
    std_liquidation_fee: pick("std_liquidation_fee"),
    claim_IF_discount: pick("claim_IF_discount"),
    base_symbol: pick("base_symbol"),
    listing_asset_type:
      pick("listing_asset_type") === ListingAssetType.Rwa
        ? ListingAssetType.Rwa
        : ListingAssetType.Crypto,
    rwa_market_session:
      (pick("rwa_market_session") as RwaMarketSessionTemplate | "") || "",
  };
}

export function getBaseSymbol(
  formBaseSymbol: string,
  sources: SourceItem[]
): string {
  const direct = formBaseSymbol.trim().toUpperCase();
  if (direct) return direct;
  const fallback = sources[0]?.sourceSymbol ?? "";
  return fallback.replace(/[-_]?USDT?$|\/USD$/i, "").toUpperCase();
}

export function getPriceRangePct(leverage: number): number {
  if (leverage === 5) return 10;
  if (leverage === 10) return 5;
  if (leverage === 20) return 3;
  return 5;
}

export function clamp(value: number, min: number, max: number): number {
  if (value < min) return min;
  if (value > max) return max;
  return value;
}

export function normalizeSourceName(name: string): string {
  return name.trim().toUpperCase().replace(/\s+/g, "");
}

export function trimTrailingZeros(value: string): string {
  if (!value.includes(".")) return value;
  return value.replace(/\.?0+$/, "");
}

export function formatDecimal(value: number, maxDecimals = 8): string {
  if (!Number.isFinite(value) || value <= 0) return "—";
  // Avoid rounding tiny positives to "0" (e.g. 1e-9 with toFixed(8)).
  const minNonZero = Math.pow(10, -maxDecimals);
  const decimals = value < minNonZero ? Math.max(18, maxDecimals) : maxDecimals;
  return trimTrailingZeros(value.toFixed(decimals));
}

export function formatRatePercentFromDecimal(value: string): string {
  const num = Number(value);
  if (!Number.isFinite(num)) return value || "—";
  return `${trimTrailingZeros((num * 100).toFixed(4))}%`;
}

export function parseRateFormValue(
  value: string | undefined
): string | undefined {
  if (!value) return value;
  const trimmed = value.trim();
  if (!trimmed) return trimmed;
  if (trimmed.endsWith("%")) {
    const num = Number(trimmed.replace("%", "").trim());
    if (!Number.isFinite(num)) return trimmed;
    return trimTrailingZeros((num / 100).toFixed(8));
  }
  return trimmed;
}

export function alignDownToStep(value: number, step: number): number {
  if (!Number.isFinite(value) || value <= 0) return 0;
  if (!Number.isFinite(step) || step <= 0) return value;
  const aligned = Math.floor(value / step) * step;
  return Number.isFinite(aligned) && aligned > 0 ? aligned : step;
}

export function alignUpToStep(value: number, step: number): number {
  if (!Number.isFinite(value) || value <= 0) return 0;
  if (!Number.isFinite(step) || step <= 0) return value;
  const aligned = Math.ceil(value / step) * step;
  return Number.isFinite(aligned) && aligned > 0 ? aligned : step;
}

/**
 * Stabilize quote-derived base_tick: snap to the largest power of 10 not greater than raw
 * (i.e. 10^floor(log10(raw))), avoiding float noise.
 */
export function normalizeBaseTickForFallback(raw: number): number {
  if (!Number.isFinite(raw) || raw <= 0) return 0;
  const d = new Decimal(raw);
  if (!d.isFinite() || d.lte(0)) return 0;
  const log10v = Math.log10(Number(d.toString()));
  if (!Number.isFinite(log10v)) return 0;
  const k = Math.floor(log10v);
  const pow = new Decimal(10).pow(k);
  if (!pow.isFinite() || pow.lte(0)) return 0;
  return Number(pow.toSignificantDigits(12).toString());
}

/** True when base_min is (within tolerance) an integer multiple of base_tick. */
export function isBaseMinAlignedToBaseTick(
  baseMin: number,
  baseTick: number
): boolean {
  if (!Number.isFinite(baseMin) || baseMin <= 0) return true;
  if (!Number.isFinite(baseTick) || baseTick <= 0) return true;
  const q = new Decimal(baseMin).div(baseTick);
  const nearest = q.toDecimalPlaces(0, Decimal.ROUND_HALF_UP);
  const diff = q.minus(nearest).abs();
  const tol = Decimal.max(nearest.abs().mul(1e-12), new Decimal("1e-12"));
  return diff.lte(tol);
}

/**
 * PRD fallback: when minQty is missing (or only oracle sources exist), derive base_min from 1 / askPrice precision.
 */
export function inferBaseMinFromAskPrice(askPrice: number): number {
  if (!Number.isFinite(askPrice) || askPrice <= 0) return 0;

  const inv = new Decimal(1).div(askPrice);
  if (!inv.isFinite() || inv.lte(0)) return 0;

  // For values >= 1, keep only order-of-magnitude precision (e.g. 5 -> 1, 50 -> 10).
  if (inv.gte(1)) {
    const p = Math.floor(Math.log10(Number(inv.toString())));
    return Number(new Decimal(10).pow(p).toString());
  }

  // For fractional values, keep one significant digit when meaningful.
  const oneSigFloor = inv.toSignificantDigits(1, Decimal.ROUND_FLOOR);
  if (oneSigFloor.gte(0.01)) {
    return Number(oneSigFloor.toString());
  }

  // For tiny fractions (< 0.01), use order-of-magnitude precision (e.g. 0.0099 -> 0.001).
  const p = Math.floor(Math.log10(Number(inv.toString())));
  return Number(new Decimal(10).pow(p).toString());
}

/** PRD: base_min × index price between $0.02 and $5 (USD). */
export const BASE_MIN_NOTIONAL_MIN_USD = 0.02;
export const BASE_MIN_NOTIONAL_MAX_USD = 5;

/**
 * After taking max(minQty) across CEXes, align to base_tick and clamp notional USD.
 */
export function alignBaseMinToNotionalUsd(
  rawMaxBaseMin: number,
  priceRef: number,
  baseTick: number
): number {
  if (!Number.isFinite(rawMaxBaseMin) || rawMaxBaseMin <= 0) return 0;
  if (!Number.isFinite(priceRef) || priceRef <= 0) return 0;
  if (!Number.isFinite(baseTick) || baseTick <= 0) return 0;

  let x = alignUpToStep(rawMaxBaseMin, baseTick);
  if (x <= 0) return 0;

  const notional = (v: number) => v * priceRef;

  if (notional(x) < BASE_MIN_NOTIONAL_MIN_USD) {
    x = alignUpToStep(BASE_MIN_NOTIONAL_MIN_USD / priceRef, baseTick);
  }
  if (notional(x) > BASE_MIN_NOTIONAL_MAX_USD) {
    x = alignDownToStep(BASE_MIN_NOTIONAL_MAX_USD / priceRef, baseTick);
  }
  if (notional(x) < BASE_MIN_NOTIONAL_MIN_USD) {
    x = alignUpToStep(BASE_MIN_NOTIONAL_MIN_USD / priceRef, baseTick);
  }
  if (notional(x) > BASE_MIN_NOTIONAL_MAX_USD) {
    x = alignDownToStep(BASE_MIN_NOTIONAL_MAX_USD / priceRef, baseTick);
  }

  return Number.isFinite(x) && x > 0 ? Number(x.toPrecision(12)) : 0;
}

export function inferQuoteTickFromPrice(price: number): number {
  if (!Number.isFinite(price) || price <= 0) return 0;
  // PRD: infer tick size from index price decimals; ensure quote_tick / price < 1%.
  // Normalize to meaningful significant digits first so floating-point artifacts
  // (e.g. 3.5400000000000003e-7) don't explode decimal-place inference.
  const normalizedPrice = new Decimal(price).toSignificantDigits(12);
  const decimals = Math.max(0, normalizedPrice.decimalPlaces());

  let tick = new Decimal(10).pow(-decimals);
  while (tick.div(normalizedPrice).gte(0.01)) {
    tick = tick.div(10);
  }

  return Number(tick.toSignificantDigits(12).toString());
}

export function toIsoStringFromLocalInput(value: string): string {
  const localDate = new Date(value);
  if (Number.isNaN(localDate.getTime())) {
    throw new Error("LISTING_TIME_INVALID");
  }
  return localDate.toISOString();
}

// eslint-disable-next-line @typescript-eslint/no-explicit-any
export function getTradingParamsApiErrorMessage(error: any): string {
  if (error?.message === "LISTING_TIME_INVALID") {
    return "Invalid listing schedule time. Please pick a valid date and hour.";
  }
  return (
    error?.message || "Failed to submit trading parameters. Please try again."
  );
}

export function parseSuggestedNumber(
  param: BrokerListingSymbolParam | undefined
): number | null {
  if (!param) return null;
  const raw = param.suggested;
  if (typeof raw === "number") return Number.isFinite(raw) ? raw : null;
  if (typeof raw === "string") {
    const n = Number(raw);
    return Number.isFinite(n) ? n : null;
  }
  return null;
}
