import { useCallback, useMemo } from "react";
import { useState } from "react";
import { useSelectListingStore } from "../../store/useListingStore";
import { toast } from "@/components/toast";
import {
  PageView,
  SettingsTab,
  ListingAssetType,
  type MMAccount,
  type SourceItem,
} from "../../types";
import { ListingOrigin } from "../../store/useListingStore";
import { useNavigate } from "react-router-dom";
import {
  getSourceDisplayMeta,
  matchIndexSourceCatalog,
  normalizeSourceKey,
  resolveApiSource,
  sourceKeyToItemId,
  useBrokerListingMMBinding,
} from "../../services";
import { useMarketInfoPriceChanges } from "../../hooks/useMarketInfoPriceChanges";
import { formatAccountId } from "@/utils";
import { IndexSourceType } from "../../types";
import { normalizeStoredWeightPercentInt } from "../listing/price-sources/hooks/shared";
import { useListingServerData } from "../../hooks/useListingServerData";
import { useListingSymbolDetailData } from "../../hooks/useListingSymbolDetailData";
import { useListingRefreshActions } from "../../hooks/useListingRefreshActions";

export function useSymbolDetailScript() {
  const navigate = useNavigate();
  const {
    currentDetailSymbol,
    symbolDetails,
    setPage,
    setTargetDelist,
    updateSymbolDetail,
  } = useSelectListingStore(s => ({
    currentDetailSymbol: s.currentDetailSymbol,
    symbolDetails: s.symbolDetails,
    setPage: s.setPage,
    setTargetDelist: s.setTargetDelist,
    updateSymbolDetail: s.updateSymbolDetail,
  }));
  const {
    logged,
    isValidating,
    listingAccounts,
    subAccounts,
    riskSnapshot,
    indexSources,
  } = useListingServerData();
  const { refreshListingSymbols } = useListingRefreshActions();

  // Only used to show "loading" state on bind/add UI. Unbind should not trigger it.
  const [isBindBusy, setIsBindBusy] = useState(false);
  const [isUnbindBusy, setIsUnbindBusy] = useState(false);

  const {
    detail: apiDetail,
    emptyDetail,
    symbolItem,
    symbolDetailQuery,
    mutateSymbolDetail,
    error: symbolDetailRequestError,
  } = useListingSymbolDetailData({
    symbol: currentDetailSymbol,
    indexSources,
    riskSnapshot,
  });

  const mmAccounts: MMAccount[] = useMemo(() => {
    const rows = listingAccounts?.mm_accounts ?? [];
    return rows.map(row => ({
      account_id: row.account_id,
      balance:
        subAccounts.find(s => s.sub_account_id === row.account_id)?.balance ??
        0,
    }));
  }, [listingAccounts?.mm_accounts, subAccounts]);

  const { getLastPrice } = useMarketInfoPriceChanges();

  const [bindMm, { isMutating: isMmBusy }] = useBrokerListingMMBinding();

  const symbolDetailResolved = symbolDetailQuery.data;
  const apiHydratedDetail = Boolean(apiDetail);

  const showDetailLoader = useMemo(() => {
    if (!currentDetailSymbol) return false;
    if (symbolDetailRequestError) return false;
    return (
      !logged ||
      isValidating ||
      symbolDetailQuery.isLoading ||
      !symbolDetailResolved ||
      !apiHydratedDetail
    );
  }, [
    currentDetailSymbol,
    symbolDetailRequestError,
    logged,
    isValidating,
    symbolDetailQuery.isLoading,
    symbolDetailResolved,
    apiHydratedDetail,
  ]);

  const detail = useMemo(() => {
    if (!currentDetailSymbol) return null;
    if (!symbolDetailResolved || !apiHydratedDetail) return emptyDetail;
    return symbolDetails[currentDetailSymbol] ?? apiDetail ?? emptyDetail;
  }, [
    apiDetail,
    currentDetailSymbol,
    apiHydratedDetail,
    emptyDetail,
    symbolDetailResolved,
    symbolDetails,
  ]);

  const isEditable = useMemo(() => {
    if (!detail) return false;
    if (!apiHydratedDetail) return false;
    return ["NEW", "PENDING", "POST_ONLY", "ACTIVE"].includes(detail.status);
  }, [detail, apiHydratedDetail]);

  const onBack = useCallback(() => {
    setPage(PageView.Dashboard);
    navigate("/permissionless-listing");
  }, [navigate, setPage]);

  const onEdit = useCallback(() => {
    if (!currentDetailSymbol || !detail) return;

    const sourceItems: SourceItem[] = detail.indexSources.map(is => {
      const catRow = matchIndexSourceCatalog(indexSources, is.source);
      const def = getSourceDisplayMeta(catRow?.source ?? is.source);
      const apiKey =
        def?.source ??
        catRow?.source ??
        resolveApiSource(is.source) ??
        normalizeSourceKey(is.source);
      return {
        id: sourceKeyToItemId(apiKey),
        source: apiKey,
        sourceId: is.sourceId,
        name: catRow?.name ?? def?.name ?? is.source,
        type:
          (is.type as SourceItem["type"]) ??
          catRow?.type ??
          IndexSourceType.Cex,
        found: true,
        sourceSymbol: is.sourceSymbol,
        multiplier: is.priceMultiplier,
        price: is.latestPrice,
        volume24h: 0,
        weight:
          is.weight != null
            ? normalizeStoredWeightPercentInt(is.weight)
            : Math.round(100 / detail.indexSources.length),
        selected: true,
        loading: false,
      };
    });

    const resolvedAssetType = detail.isRwa
      ? ListingAssetType.Rwa
      : ListingAssetType.Crypto;

    updateSymbolDetail(currentDetailSymbol, detail);
    setPage(PageView.Listing, {
      editMode: true,
      editSymbol: currentDetailSymbol,
      priceSources: sourceItems,
      listingAssetType: resolvedAssetType,
      listingOrigin: ListingOrigin.SymbolDetail,
    });
  }, [currentDetailSymbol, detail, indexSources, setPage, updateSymbolDetail]);

  const onDelist = useCallback(() => {
    if (!currentDetailSymbol) return;
    setTargetDelist(currentDetailSymbol);
  }, [currentDetailSymbol, setTargetDelist]);

  const onManage = useCallback(() => {
    setPage(PageView.Settings, { settingsTab: SettingsTab.Mm });
  }, [setPage]);

  const onAddAndBindMM = useCallback(
    async (mmAddress: string): Promise<boolean> => {
      if (!currentDetailSymbol || !detail) return false;

      const addr = mmAddress.trim();
      if (!addr || isMmBusy || isBindBusy) return false;

      if (detail.mmAccounts.includes(addr)) {
        toast.error(
          `MM account ${formatAccountId(addr)} is already bound to this symbol.`
        );
        return false;
      }

      try {
        setIsBindBusy(true);
        const res = await bindMm({
          symbol: currentDetailSymbol,
          account_id: addr,
          action: "bind",
        });
        if (!res?.success) {
          throw res;
        }
        toast.success(`MM account ${formatAccountId(addr)} bound`);
        await Promise.allSettled([
          mutateSymbolDetail(),
          refreshListingSymbols(),
        ]);
        return true;
      } catch (e: unknown) {
        toast.error(
          e instanceof Error ? e.message : "Failed to bind MM account."
        );
        return false;
      } finally {
        setIsBindBusy(false);
      }
    },
    [
      currentDetailSymbol,
      detail,
      bindMm,
      mutateSymbolDetail,
      refreshListingSymbols,
      isMmBusy,
      isBindBusy,
    ]
  );

  const onBindMM = useCallback(
    (mmAddress: string) => {
      void onAddAndBindMM(mmAddress);
    },
    [onAddAndBindMM]
  );

  const onUnbindMM = useCallback(
    async (mmAddress: string) => {
      if (!currentDetailSymbol || !detail || isUnbindBusy) return;
      try {
        setIsUnbindBusy(true);
        const res = await bindMm({
          symbol: currentDetailSymbol,
          account_id: mmAddress,
          action: "unbind",
        });
        if (!res?.success) {
          throw res;
        }
        toast.success(`MM account ${formatAccountId(mmAddress)} unbound`);
        await Promise.allSettled([
          mutateSymbolDetail(),
          refreshListingSymbols(),
        ]);
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
      } catch (e: any) {
        toast.error(e?.message || "Failed to unbind MM account.");
        throw e;
      } finally {
        setIsUnbindBusy(false);
      }
    },
    [
      currentDetailSymbol,
      detail,
      isUnbindBusy,
      mutateSymbolDetail,
      refreshListingSymbols,
      bindMm,
    ]
  );

  const prettySymbol = currentDetailSymbol?.replace(/_broker\d+.*$/, "") ?? "";

  return {
    symbolItem,
    detail,
    prettySymbol,
    isEditable,
    apiHydratedDetail,
    showDetailLoader,
    symbolDetailRequestError,
    getLastPrice,
    mmAccounts,
    onBack,
    onEdit,
    onDelist,
    onManage,
    onBindMM,
    onUnbindMM,
    onAddAndBindMM,
    isMmBusy,
    isBindBusy,
    isUnbindBusy,
  };
}
