import type { BrokerListingSymbolsRow } from "../../../services/types";

const MS_PER_DAY = 24 * 60 * 60 * 1000;
/** Per spec: each listed day counts as this much notional for capital_days. */
const LISTED_DAY_CAPITAL_WEIGHT = 50_000;

export type APRSymbolInput = Pick<
  BrokerListingSymbolsRow,
  "listing_time" | "delist_time"
>;

/**
 * capital_days = Σ_i (days_listed_in_period_for_symbol_i × 50_000)
 *
 * For each symbol:
 * - effectiveStart = max(listing_time, periodStart)
 * - effectiveEnd = min(delist_time ?? currentDate, periodEnd)
 * - days = max(effectiveEnd − effectiveStart, 0) in calendar days
 */
function sumCapitalDays(
  symbols: APRSymbolInput[],
  periodStart: Date,
  periodEnd: Date
): number {
  return symbols.reduce((sum, row) => {
    const listingTime = new Date(row.listing_time);
    // delist_time missing → treat as still listed through period end ("current date" at window end).
    const delistOrNow = row.delist_time ? new Date(row.delist_time) : periodEnd;

    const effectiveStart =
      listingTime > periodStart ? listingTime : periodStart;
    const effectiveEnd = delistOrNow < periodEnd ? delistOrNow : periodEnd;

    const days = Math.max(
      (effectiveEnd.getTime() - effectiveStart.getTime()) / MS_PER_DAY,
      0
    );
    return sum + days * LISTED_DAY_CAPITAL_WEIGHT;
  }, 0);
}

/**
 * APR = (fee_revenue_period + liquidation_revenue_period) / (capital_days / 365)
 *
 * Image spec ends with × 100% for percentage display; this returns a **decimal**
 * rate (e.g. 0.12 → 12%) so callers can pass the value to `fmtPct`.
 */
export function calculateAPR(
  feeRevenue: number | null | undefined,
  liquidationRevenue: number | null | undefined,
  symbols: APRSymbolInput[] | undefined,
  periodStart: Date,
  periodEnd: Date
): number | null {
  if (feeRevenue == null || liquidationRevenue == null) return null;

  const capitalDays = sumCapitalDays(symbols ?? [], periodStart, periodEnd);
  const denominator = capitalDays / 365;
  if (!(denominator > 0)) return null;

  return (feeRevenue + liquidationRevenue) / denominator;
}
