import useSWRMutation, { type SWRMutationConfiguration } from "swr/mutation";
import { signedAdminRequest, type AdminApiMethod } from "@/utils/adminKeyAuth";

type HTTP_METHOD = Extract<AdminApiMethod, "POST" | "PUT" | "DELETE" | "GET">;

function appendParams(url: string, params?: Record<string, unknown>) {
  if (!params || Object.keys(params).length === 0) return url;
  const search = new URLSearchParams();
  Object.entries(params).forEach(([key, value]) => {
    if (value === undefined || value === null) return;
    search.set(key, String(value));
  });
  const qs = search.toString();
  if (!qs) return url;
  return `${url}${url.includes("?") ? "&" : "?"}${qs}`;
}

export const useMutation = <T, E>(
  url: string,
  method: HTTP_METHOD = "POST",
  options?: SWRMutationConfiguration<T, E>
) => {
  const { trigger, data, error, reset, isMutating } = useSWRMutation<
    T,
    E,
    string,
    { data?: Record<string, unknown> | null; endpoint: string }
  >(
    url,
    async (_key, { arg }) =>
      signedAdminRequest<T>({
        endpoint: arg.endpoint,
        method,
        data: method === "GET" ? null : (arg.data ?? null),
      }),
    options as never
  );

  const mutation = async (
    data: Record<string, unknown> | null,
    params?: Record<string, unknown>,
    triggerOptions?: SWRMutationConfiguration<T, E>
  ): Promise<T> => {
    return trigger(
      { data, endpoint: appendParams(url, params) },
      triggerOptions as never
    );
  };

  return [mutation, { data, error, reset, isMutating }] as const;
};
