import { useQuery } from "@/hooks/useQuery";
import type { SWRConfiguration, SWRResponse } from "swr";

import type {
  RwaInfoRow,
  RwaMarketSessionRow,
  RwaSymbolListData,
} from "./types";

function applyDefaultRevalidateOnFocus<T extends SWRConfiguration>(
  options?: T
): T {
  if (!options) return { revalidateOnFocus: false } as T;
  return {
    ...options,
    revalidateOnFocus: options.revalidateOnFocus ?? false,
  };
}

export function useRwaMarketSessions(
  options?: SWRConfiguration
): SWRResponse<RwaMarketSessionRow[]> {
  return useQuery<RwaMarketSessionRow[]>(
    "/v1/public/rwa/market_sessions",
    applyDefaultRevalidateOnFocus(options)
  );
}

export function useRwaInfo(
  options?: SWRConfiguration
): SWRResponse<RwaInfoRow[]> {
  return useQuery<RwaInfoRow[]>(
    "/v1/public/rwa/info",
    applyDefaultRevalidateOnFocus(options)
  );
}

export function useRwaSymbolList(
  options?: SWRConfiguration
): SWRResponse<RwaSymbolListData> {
  return useQuery<RwaSymbolListData>(
    "/v1/broker/listing/rwa/symbol_list",
    applyDefaultRevalidateOnFocus(options)
  );
}
