import { useId, useMemo, useState } from "react";
import { cn } from "@/utils/css";
import { getIfRequired } from "../../../constants";
import { formatBalance } from "../../../utils";
import { TransferModal } from "../../../modals";
import { useListingServerData } from "../../../hooks/useListingServerData";
import { useMergedIfAccounts } from "../../onboarding/hooks/useMergedIfAccounts";

export function AccountHealth() {
  const { riskSnapshot, subAccounts, listingAccounts, listingSymbols } =
    useListingServerData();
  const { mergedIfAccounts, vaultSpAccountIdSet } =
    useMergedIfAccounts(subAccounts);

  const { ifAccountId, ifBalance, ifBalanceMissing } = useMemo(() => {
    const ifAccountId = listingAccounts?.if_account?.account_id ?? null;
    const sub = ifAccountId
      ? mergedIfAccounts.find(a => a.sub_account_id === ifAccountId)
      : undefined;
    return {
      ifAccountId,
      ifBalance: sub?.balance ?? 0,
      ifBalanceMissing: Boolean(ifAccountId && !sub),
    };
  }, [listingAccounts, mergedIfAccounts]);

  const [transferOpen, setTransferOpen] = useState(false);
  const idPrefix = useId().replace(/:/g, "");

  const ifRequired = getIfRequired(riskSnapshot, listingSymbols);
  const balanceMissing = ifBalanceMissing ?? false;
  const belowRequirement = balanceMissing ? true : ifBalance < ifRequired;
  const healthy = !belowRequirement;
  const isVaultIfAccount = ifAccountId
    ? vaultSpAccountIdSet.has(ifAccountId)
    : false;
  const showTransfer =
    belowRequirement && !!ifAccountId && !balanceMissing && !isVaultIfAccount;
  const transferTargetAccountId = showTransfer ? ifAccountId : null;
  const showTransferButton =
    Boolean(transferTargetAccountId) && transferTargetAccountId !== "";

  const balanceText = balanceMissing ? "-" : formatBalance(ifBalance);
  const pct =
    ifRequired > 0 ? Math.min((ifBalance / ifRequired) * 100, 100) : 100;

  const neutralIcon = healthy ? (
    <svg
      className="w-8 h-8 shrink-0"
      viewBox="0 0 32 32"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      aria-hidden
    >
      <rect width="32" height="32" rx="12" fill="white" fillOpacity="0.04" />
      <path
        d="M14.8047 19.375L20.3828 13.8203L19.1875 12.625L14.8047 16.9844L12.8125 15.0156L11.6172 16.2109L14.8047 19.375ZM16 25C14.7656 25 13.6016 24.7657 12.5078 24.2969C11.4141 23.8281 10.457 23.1836 9.63672 22.3632C8.8164 21.543 8.17188 20.586 7.70312 19.4922C7.23437 18.3984 7 17.2344 7 16C7 14.75 7.23437 13.582 7.70312 12.4961C8.17188 11.4102 8.8164 10.457 9.63672 9.63672C10.457 8.8164 11.4141 8.17188 12.5078 7.70312C13.6016 7.23437 14.7656 7 16 7C17.25 7 18.418 7.23437 19.5039 7.70312C20.5899 8.17188 21.543 8.8164 22.3632 9.63672C23.1836 10.457 23.8281 11.4102 24.2969 12.4961C24.7657 13.582 25 14.75 25 16C25 17.2344 24.7657 18.3984 24.2969 19.4922C23.8281 20.586 23.1836 21.543 22.3632 22.3632C21.543 23.1836 20.5899 23.8281 19.5039 24.2969C18.418 24.7657 17.25 25 16 25Z"
        fill={`url(#health-chk-${idPrefix})`}
      />
      <defs>
        <linearGradient
          id={`health-chk-${idPrefix}`}
          x1="22.6169"
          y1="24.9731"
          x2="18.5642"
          y2="6.92633"
          gradientUnits="userSpaceOnUse"
        >
          <stop stopColor="rgb(var(--orderly-color-success))" />
          <stop offset="1" stopColor="rgba(91, 217, 111, 0.85)" />
        </linearGradient>
      </defs>
    </svg>
  ) : (
    <svg
      className="w-8 h-8 shrink-0"
      viewBox="0 0 32 32"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      aria-hidden
    >
      <rect width="32" height="32" rx="12" fill="white" fillOpacity="0.04" />
      <path
        d="M8.47 25H23.53C25.07 25 26.03 23.33 25.26 22L17.73 8.98999C16.96 7.65999 15.04 7.65999 14.27 8.98999L6.74 22C5.97 23.33 6.93 25 8.47 25ZM16 18C15.45 18 15 17.55 15 17V15C15 14.45 15.45 14 16 14C16.55 14 17 14.45 17 15V17C17 17.55 16.55 18 16 18ZM17 22H15V20H17V22Z"
        fill={`url(#health-wrn-${idPrefix})`}
      />
      <defs>
        <linearGradient
          id={`health-wrn-${idPrefix}`}
          x1="23.0075"
          y1="24.9746"
          x2="19.5573"
          y2="7.75423"
          gradientUnits="userSpaceOnUse"
        >
          <stop stopColor="#F6AE1D" />
          <stop offset="1" stopColor="#EDCB86" />
        </linearGradient>
      </defs>
    </svg>
  );

  return (
    <>
      <div className="p-4 rounded-xl bg-base-200 mb-6">
        <div className="flex justify-between items-center mb-4">
          <span className="text-xs font-medium text-base-contrast-98">
            Account health
          </span>
        </div>
        <div className="flex gap-4">
          <div className="flex items-center gap-2 p-4 rounded-lg flex-1 min-w-0 bg-base-300">
            <div className="flex items-center justify-center w-8 h-8 shrink-0 rounded-xl">
              {neutralIcon}
            </div>
            <div className="flex-1 min-w-0 flex flex-col gap-1">
              <div className="flex items-center gap-2 text-xs">
                <span className="font-medium text-base-contrast-98">
                  Insurance fund account
                </span>
              </div>
              <div className="text-3xs">
                <span
                  className={
                    healthy
                      ? "text-success font-medium"
                      : "text-warning font-medium"
                  }
                >
                  Balance ${balanceText}
                </span>
                <span className="text-base-contrast-54">
                  {" "}
                  / Requirement: ${formatBalance(ifRequired)}
                </span>
              </div>
              <div className="w-full h-1 mt-0.5 rounded-sm bg-base-contrast-8 overflow-hidden">
                <div
                  className={cn(
                    "h-full rounded-sm transition-all",
                    healthy ? "bg-success" : "bg-warning"
                  )}
                  style={{ width: `${pct}%` }}
                />
              </div>
            </div>
            {showTransferButton && (
              <button
                type="button"
                onClick={() => setTransferOpen(true)}
                className="text-3xs text-primary-light hover:underline shrink-0"
              >
                Transfer
              </button>
            )}
          </div>
        </div>
      </div>

      <TransferModal
        open={transferOpen}
        onOpenChange={setTransferOpen}
        targetAccountId={transferTargetAccountId ?? null}
        requiredTransferAmount={
          balanceMissing ? ifRequired : Math.max(0, ifRequired - ifBalance)
        }
      />
    </>
  );
}
