import { useState } from "react";
import { FadeInEnter } from "@/components/fade-in-enter";
import { type OnboardingScriptReturn } from "./Onboarding.script";
import { OnboardingCard } from "./components/OnboardingCard";
import { OnboardingCompleteView } from "./components/OnboardingCompleteView";
import { Button } from "@/components/button";

export function OnboardingPanelUI({
  steps,
  completedCount,
  progress,
  canCompleteOnboarding,
  completeOnboardingIfNeeded,
  isCompleting,
  ifBind,
  toggleExpand,
  onDone,
}: OnboardingScriptReturn) {
  const [showComplete, setShowComplete] = useState(false);

  const handleDone = async () => {
    if (!canCompleteOnboarding) return;
    const ok = await completeOnboardingIfNeeded();
    if (ok) setShowComplete(true);
  };

  const handleSkip = () => onDone();

  if (showComplete) {
    return (
      <FadeInEnter className="min-h-0 w-full">
        <OnboardingCompleteView onSkip={handleSkip} onViewDashboard={onDone} />
      </FadeInEnter>
    );
  }

  return (
    <div className="max-w-[784px] mx-auto mb-20">
      <div className="mt-5 mb-6">
        <div className="flex justify-between items-center">
          <span className="text-base font-medium text-base-contrast-98">
            Set up your broker account to start listing
          </span>
          <span className="text-base font-medium text-base-contrast-50">
            {completedCount} / {steps.length} completed
          </span>
        </div>
        <div className="h-3 rounded-md bg-base-contrast-8 mt-3 overflow-hidden">
          <div
            className="h-full rounded-sm bg-primary transition-[width] duration-400 ease-out"
            style={{ width: `${progress}%` }}
          />
        </div>
      </div>

      <div className="flex flex-col gap-5">
        {steps.map(step => (
          <OnboardingCard
            key={step.key}
            step={step}
            ifBind={ifBind}
            onToggle={() => toggleExpand(step.key)}
          />
        ))}
      </div>

      <div className="flex justify-end mt-4">
        <Button
          size="md"
          disabled={!canCompleteOnboarding || isCompleting}
          loading={isCompleting}
          onClick={() => void handleDone()}
        >
          Done
        </Button>
      </div>
    </div>
  );
}
