import { useCallback, useEffect, useRef, useState } from "react";
import type { SourceItem } from "../../../../types";

export function useSearchRequestLifecycle({
  priceSources,
  setPriceSources,
}: {
  priceSources: SourceItem[];
  setPriceSources: (sources: SourceItem[]) => void;
}) {
  const [searching, setSearching] = useState(false);
  const lastTriggeredSearchRef = useRef<string>("");
  const searchReqIdRef = useRef(0);
  const searchTimerRef = useRef<number | null>(null);
  const sourcesRef = useRef(priceSources);
  const editSearchHydratedForSymbolRef = useRef<string | null>(null);
  const initialOrderByIdRef = useRef<Map<string, number>>(new Map());

  useEffect(() => {
    sourcesRef.current = priceSources;
  }, [priceSources]);

  const publishSources = useCallback(
    (nextSources: SourceItem[]) => {
      sourcesRef.current = nextSources;
      setPriceSources(nextSources);
    },
    [setPriceSources]
  );

  const beginSearchRequest = useCallback(() => {
    const reqId = searchReqIdRef.current + 1;
    searchReqIdRef.current = reqId;
    setSearching(true);
    return reqId;
  }, []);

  const cancelCurrentSearch = useCallback(() => {
    searchReqIdRef.current += 1;
    setSearching(false);
  }, []);

  const isCurrentRequest = useCallback(
    (reqId: number) => reqId === searchReqIdRef.current,
    []
  );

  return {
    searching,
    setSearching,
    lastTriggeredSearchRef,
    searchReqIdRef,
    searchTimerRef,
    sourcesRef,
    editSearchHydratedForSymbolRef,
    initialOrderByIdRef,
    publishSources,
    beginSearchRequest,
    cancelCurrentSearch,
    isCurrentRequest,
  };
}
