import Decimal from "decimal.js";

export function formatBalance(val: number): string {
  const [integerPart, decimalPart] = new Decimal(val || 0)
    .toFixed(2)
    .split(".");
  return `${integerPart.replace(/\B(?=(\d{3})+(?!\d))/g, ",")}.${decimalPart}`;
}

/** USDC display / max input cap: floor to 2 decimal places (never round up). */
export function floorToUsdcDisplay(val: number): number {
  return new Decimal(val || 0)
    .toDecimalPlaces(2, Decimal.ROUND_FLOOR)
    .toNumber();
}

export function fmtUSDShort(val: number): string {
  if (val >= 1e9) return "$" + (val / 1e9).toFixed(2) + "B";
  if (val >= 1e6) return "$" + (val / 1e6).toFixed(2) + "M";
  if (val >= 1e3) return "$" + (val / 1e3).toFixed(2) + "K";
  return "$" + val.toFixed(2);
}

export function fmtNum(val: number): string {
  return new Intl.NumberFormat("en-US").format(val);
}

export function fmtPct(val: number, decimals = 2): string {
  return `${(val * 100).toFixed(decimals)}%`;
}

export function delay(ms: number): Promise<void> {
  return new Promise(res => setTimeout(res, ms));
}
