import { useCallback, useState } from "react";
import { toast } from "@/components/toast";
import { useNavigate } from "react-router-dom";
import { PageView } from "../../../../types";
import type {
  ListingAssetType,
  RecentEvent,
  RwaMarketSessionTemplate,
  SourceItem,
  SymbolDetail,
  SymbolItem,
  TradingParamsForm,
} from "../../../../types";
import {
  useBrokerListingSubmit,
  useBrokerListingUpdateParams,
} from "../../../../services";
import type { RwaMarketSessionRow } from "../../../../services/types";
import {
  getTradingParamsApiErrorMessage,
  toIsoStringFromLocalInput,
  type SubmitMode,
} from "./shared";
import { type ListingStore } from "@/permissionless-listing/store/useListingStore";
import { useListingRefreshActions } from "@/permissionless-listing/hooks/useListingRefreshActions";
import { useBrokerSymbolLogoUploader } from "./useBrokerSymbolLogoUpload";
import {
  buildNewSymbolItem,
  buildFinalNewSymbolDetail,
  buildRecentEvent,
  buildSubmitPayload,
  buildSymbolStoreKey,
  buildTradingSubmitInputs,
  buildTradingSubmitSources,
  buildTradingSymbolDetail,
  buildUpdateParamsPayload,
  getDefaultListingDateInput,
  getListingTimeLabel,
  isScheduledDraftStatus,
  mergeUpdatedTradingSymbolDetail,
} from "./submit.helpers";

type SubmitInputs = NonNullable<ReturnType<typeof buildTradingSubmitInputs>>;

type UseTradingParamsSubmitInput = {
  form: TradingParamsForm;
  selectedSources: SourceItem[];
  editMode: boolean;
  editSymbol: string | null;
  symbolDetails: Record<string, SymbolDetail>;
  listedSymbols: SymbolItem[];
  /** Base-filtered index sources catalog from store (contains source_symbol/source_id from API). */
  indexSourcesCatalog: ListingStore["indexSources"];
  brokerId?: string;
  updateSymbolDetail: (symbol: string, detail: SymbolDetail) => void;
  addEvent: (event: RecentEvent) => void;
  setPage: ListingStore["setPage"];
  setSymbols: (symbols: SymbolItem[]) => void;
  validate: () => boolean;
  fundingCap: number;
  fundingFloor: number;
  quoteTick: number;
  baseTick: number;
  baseMin: number;
  baseMax: number;
  prettySymbol: string;
  /** Listing base for symbol_context / preview / submit (edit: from editSymbol). */
  listingBase: string;
  listingAssetType: ListingAssetType;
  rwaMarketSession: RwaMarketSessionTemplate | "";
  /** RWA market session rows from /v1/public/rwa/market_sessions. */
  rwaMarketSessions: RwaMarketSessionRow[];
  symbolIconFile: File | null;
  logoSymbolPreview: string;
  markSymbolIconUploaded: (logoUrl: string) => void;
};

export function useTradingParamsSubmit({
  form,
  selectedSources,
  editMode,
  editSymbol,
  symbolDetails,
  listedSymbols,
  indexSourcesCatalog,
  brokerId,
  updateSymbolDetail,
  addEvent,
  setPage,
  setSymbols,
  validate,
  fundingCap,
  fundingFloor,
  quoteTick,
  baseTick,
  baseMin,
  baseMax,
  prettySymbol,
  listingBase,
  listingAssetType,
  rwaMarketSession,
  rwaMarketSessions,
  symbolIconFile,
  logoSymbolPreview,
  markSymbolIconUploaded,
}: UseTradingParamsSubmitInput) {
  const [submitting, setSubmitting] = useState(false);
  const [submitModalOpen, setSubmitModalOpen] = useState(false);
  const [submitMode, setSubmitMode] = useState<SubmitMode | null>(null);
  const [submitSymbolLabel, setSubmitSymbolLabel] = useState<string>("");
  const [defaultListingDate, setDefaultListingDate] = useState<string>("");
  const [submitListing] = useBrokerListingSubmit();
  const [updateListingParams] = useBrokerListingUpdateParams();

  const { refreshListingSymbols } = useListingRefreshActions();
  const { uploadFile: uploadSymbolIconFile } = useBrokerSymbolLogoUploader();

  const navigate = useNavigate();

  const buildSymbolDetail = useCallback((): SymbolDetail => {
    return buildTradingSymbolDetail({
      form,
      selectedSources,
      listingBase,
      listingAssetType,
      rwaMarketSession,
      rwaMarketSessions,
      fundingCap,
      fundingFloor,
      quoteTick,
      baseTick,
      baseMin,
      baseMax,
    });
  }, [
    form,
    selectedSources,
    listingBase,
    listingAssetType,
    rwaMarketSession,
    rwaMarketSessions,
    fundingCap,
    fundingFloor,
    quoteTick,
    baseTick,
    baseMin,
    baseMax,
  ]);

  const buildSubmitInputs = useCallback(
    () => buildTradingSubmitInputs(form),
    [form]
  );

  const buildSubmitSources = useCallback(
    () =>
      buildTradingSubmitSources({
        selectedSources,
        indexSourcesCatalog,
      }),
    [indexSourcesCatalog, selectedSources]
  );

  const uploadStagedSymbolIconIfNeeded = useCallback(async () => {
    if (!symbolIconFile) return true;
    if (!logoSymbolPreview.trim()) {
      toast.error(
        "Cannot upload symbol icon before submit because the preview symbol is empty."
      );
      return false;
    }

    try {
      const { logoUrl } = await uploadSymbolIconFile({
        symbolPreview: logoSymbolPreview,
        file: symbolIconFile,
      });
      markSymbolIconUploaded(logoUrl);
      return true;
    } catch (error) {
      toast.error(
        error instanceof Error
          ? error.message
          : "Symbol icon upload failed. Please try again."
      );
      return false;
    }
  }, [
    symbolIconFile,
    logoSymbolPreview,
    uploadSymbolIconFile,
    markSymbolIconUploaded,
  ]);

  const navigateToSymbolDetail = useCallback(
    (symbol: string) => {
      setPage(PageView.SymbolDetail, { symbol });
      navigate(`/permissionless-listing/${encodeURIComponent(symbol)}`);
    },
    [navigate, setPage]
  );

  const handleActiveEditSubmit = useCallback(
    async (input: {
      symbol: string;
      existing: SymbolDetail;
      submitInputs: SubmitInputs;
    }) => {
      const updatePayload = buildUpdateParamsPayload({
        symbol: input.symbol,
        params: input.submitInputs,
        sources: buildSubmitSources(),
        listingAssetType,
        rwaMarketSession,
      });

      try {
        const iconUploaded = await uploadStagedSymbolIconIfNeeded();
        if (!iconUploaded) {
          setSubmitting(false);
          return;
        }

        const res = await updateListingParams(updatePayload);
        if (!res.success) {
          throw res;
        }
        const updated = buildSymbolDetail();
        const merged = mergeUpdatedTradingSymbolDetail({
          existing: input.existing,
          updated,
        });
        updateSymbolDetail(input.symbol, merged);
        addEvent(
          buildRecentEvent(
            `Successfully updated trading parameters for ${prettySymbol}`
          )
        );
        navigateToSymbolDetail(input.symbol);
        toast.success(`Trading parameters updated for ${prettySymbol}`);
        await refreshListingSymbols();
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
      } catch (error: any) {
        toast.error(getTradingParamsApiErrorMessage(error));
      } finally {
        setSubmitting(false);
      }
    },
    [
      buildSubmitSources,
      listingAssetType,
      rwaMarketSession,
      uploadStagedSymbolIconIfNeeded,
      updateListingParams,
      buildSymbolDetail,
      updateSymbolDetail,
      addEvent,
      prettySymbol,
      navigateToSymbolDetail,
      refreshListingSymbols,
    ]
  );

  const submitNewListingFromModal = useCallback(
    async (input: {
      listingDate: string;
      listingTimeStr: string | null;
    }): Promise<boolean> => {
      const baseToken = listingBase.trim().toUpperCase();
      if (!baseToken) {
        toast.error("Please enter a base symbol in Step 1.");
        setSubmitting(false);
        return false;
      }

      try {
        const submitInputs = buildSubmitInputs();
        if (!submitInputs) {
          toast.error(
            "Invalid trading parameters. Please check the form inputs."
          );
          setSubmitting(false);
          return false;
        }

        const iconUploaded = await uploadStagedSymbolIconIfNeeded();
        if (!iconUploaded) {
          setSubmitting(false);
          return false;
        }

        const submitPayload = buildSubmitPayload({
          symbol: baseToken,
          listingTime: toIsoStringFromLocalInput(input.listingDate),
          listingAssetType,
          rwaMarketSession,
          inputs: submitInputs,
          sources: buildSubmitSources(),
        });

        const res = await submitListing(submitPayload);
        if (!res?.success) {
          throw res;
        }
        const detail = buildSymbolDetail();
        const symbolKey = buildSymbolStoreKey({
          symbolValue: detail.params.Symbol.value,
          brokerId,
          nowMs: Date.now(),
        });
        const finalDetail = buildFinalNewSymbolDetail({
          detail,
          listingTime: input.listingTimeStr,
        });

        const newSymbolItem = buildNewSymbolItem({
          symbolKey,
          baseToken,
          selectedSourceCount: selectedSources.length,
        });

        setSymbols([...listedSymbols, newSymbolItem]);
        updateSymbolDetail(symbolKey, finalDetail);
        addEvent(buildRecentEvent(`New symbol listed: PERP_${baseToken}_USDC`));
        setPage(PageView.Dashboard);
        toast.success(`PERP_${baseToken}_USDC has been submitted`);
        await refreshListingSymbols();
        return true;
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
      } catch (error: any) {
        toast.error(getTradingParamsApiErrorMessage(error));
        setSubmitting(false);
        return false;
      }
    },
    [
      listingBase,
      buildSubmitInputs,
      uploadStagedSymbolIconIfNeeded,
      listingAssetType,
      rwaMarketSession,
      buildSubmitSources,
      submitListing,
      buildSymbolDetail,
      brokerId,
      selectedSources.length,
      setSymbols,
      listedSymbols,
      updateSymbolDetail,
      addEvent,
      setPage,
      refreshListingSymbols,
    ]
  );

  const submitScheduledEditFromModal = useCallback(
    async (input: {
      symbol: string;
      listingTimeStr: string | null;
    }): Promise<boolean> => {
      const existing = symbolDetails[input.symbol];
      if (!existing) {
        toast.error(
          "Unable to find existing symbol details. Please refresh and try again."
        );
        setSubmitting(false);
        return false;
      }
      const submitInputs = buildSubmitInputs();
      if (!submitInputs) {
        toast.error(
          "Invalid trading parameters. Please check the form inputs."
        );
        setSubmitting(false);
        return false;
      }

      const iconUploaded = await uploadStagedSymbolIconIfNeeded();
      if (!iconUploaded) {
        setSubmitting(false);
        return false;
      }

      const updatePayload = buildUpdateParamsPayload({
        symbol: input.symbol,
        params: submitInputs,
        sources: buildSubmitSources(),
        listingAssetType,
        rwaMarketSession,
      });

      try {
        const res = await updateListingParams(updatePayload);
        if (!res?.success) {
          throw res;
        }
      } catch (error) {
        toast.error(getTradingParamsApiErrorMessage(error));
        setSubmitting(false);
        return false;
      }

      const updated = buildSymbolDetail();
      const merged = mergeUpdatedTradingSymbolDetail({
        existing,
        updated,
        listingTime: input.listingTimeStr,
        resetMmAccounts: true,
      });
      updateSymbolDetail(input.symbol, merged);
      addEvent(
        buildRecentEvent(
          `Updated trading parameters and schedule for ${prettySymbol}`
        )
      );
      navigateToSymbolDetail(input.symbol);
      toast.success(`Trading parameters updated for ${prettySymbol}`);
      await refreshListingSymbols();
      return true;
    },
    [
      symbolDetails,
      buildSubmitInputs,
      uploadStagedSymbolIconIfNeeded,
      buildSubmitSources,
      listingAssetType,
      rwaMarketSession,
      updateListingParams,
      buildSymbolDetail,
      updateSymbolDetail,
      addEvent,
      prettySymbol,
      navigateToSymbolDetail,
      refreshListingSymbols,
    ]
  );

  const onPrimarySubmitClick = useCallback(async () => {
    if (submitting) return;
    if (!validate()) return;

    const submitInputs = buildSubmitInputs();
    if (!submitInputs) {
      toast.error("Invalid trading parameters. Please check the form inputs.");
      return;
    }
    setSubmitting(true);

    if (editMode && editSymbol) {
      const existing = symbolDetails[editSymbol];
      if (!existing) {
        toast.error(
          "Unable to find existing symbol details. Please refresh and try again."
        );
        setSubmitting(false);
        return;
      }
      if (isScheduledDraftStatus(existing.status)) {
        setSubmitMode({ kind: "edit-new", symbol: editSymbol });
        setSubmitSymbolLabel(existing.params.Symbol?.value ?? prettySymbol);
        setDefaultListingDate(getDefaultListingDateInput(existing.listingTime));
        setSubmitModalOpen(true);
        setSubmitting(false);
        return;
      }
      await handleActiveEditSubmit({
        symbol: editSymbol,
        existing,
        submitInputs,
      });
      return;
    }

    const preview = buildSymbolDetail();
    setSubmitMode({ kind: "new" });
    setSubmitSymbolLabel(preview.params.Symbol.value);
    setDefaultListingDate("");
    setSubmitModalOpen(true);
    setSubmitting(false);
  }, [
    submitting,
    validate,
    buildSubmitInputs,
    editMode,
    editSymbol,
    symbolDetails,
    prettySymbol,
    buildSymbolDetail,
    handleActiveEditSubmit,
  ]);

  const onSubmitFromModal = useCallback(
    async (listingDate: string) => {
      if (submitting) return false;
      if (!submitMode) return false;
      setSubmitting(true);

      try {
        const listingTimeStr = getListingTimeLabel(listingDate);

        if (submitMode.kind === "new") {
          const success = await submitNewListingFromModal({
            listingDate,
            listingTimeStr,
          });
          if (!success) return false;
        } else if (submitMode.kind === "edit-new") {
          const success = await submitScheduledEditFromModal({
            symbol: submitMode.symbol,
            listingTimeStr,
          });
          if (!success) return false;
        }

        setSubmitting(false);
        setSubmitModalOpen(false);
        setSubmitMode(null);
      } catch (error) {
        // Keep the dialog open on unexpected errors, so users can retry.
        toast.error(getTradingParamsApiErrorMessage(error));
        setSubmitting(false);
        return false;
      }

      return true;
    },
    [
      submitMode,
      submitting,
      submitNewListingFromModal,
      submitScheduledEditFromModal,
    ]
  );

  return {
    submitting,
    submitModalOpen,
    setSubmitModalOpen,
    submitSymbolLabel,
    defaultListingDate,
    onPrimarySubmitClick,
    onSubmitFromModal,
  };
}
