import { Loader } from "@/components/loader";
import { fmtNum } from "../../../utils";
import {
  ListingAssetType,
  RwaMarketSessionTemplate,
  type TradingParamsForm,
  type SourceItem,
} from "../../../types";
import { getFormattedSourceType } from "../price-sources/SourceRowParts";
import {
  formatDecimal,
  formatRatePercentFromDecimal,
  getPriceRangePct,
  trimTrailingZeros,
} from "./hooks/shared";
import { getPrefixedListingBase } from "./hooks/derived.helpers";
import type { RwaMarketSessionOption } from "./RwaMarketSessionSection";

interface PreviewPanelProps {
  form: TradingParamsForm;
  /** Listing base (edit: derived from editSymbol upstream). */
  listingBaseSymbol: string;
  brokerId?: string;
  leverage: number;
  imr: number;
  mmr: number;
  fundingCap: number;
  fundingFloor: number;
  quoteTick: number;
  baseTick: number;
  baseMin: number;
  baseMax: number;
  selectedSources: SourceItem[];
  cexFundingParamsLoading?: boolean;
  cexTickParamsLoading?: boolean;
  listingAssetType: ListingAssetType;
  rwaMarketSession: RwaMarketSessionTemplate | "";
  rwaMarketSessionOptions: RwaMarketSessionOption[];
}

function formatPctFromDecimal(value: number, maxDecimals = 2): string {
  if (!Number.isFinite(value)) return "—";
  return `${trimTrailingZeros((value * 100).toFixed(maxDecimals))}%`;
}

export function PreviewPanel({
  form,
  listingBaseSymbol,
  brokerId,
  leverage,
  imr,
  mmr,
  fundingCap,
  fundingFloor,
  quoteTick,
  baseTick,
  baseMin,
  baseMax,
  selectedSources,
  cexFundingParamsLoading = false,
  cexTickParamsLoading = false,
  listingAssetType,
  rwaMarketSession,
  rwaMarketSessionOptions,
}: PreviewPanelProps) {
  const prefixedBase = listingBaseSymbol
    ? getPrefixedListingBase({
        base: listingBaseSymbol,
        selectedSources,
      })
    : "";
  const symbolPreview = listingBaseSymbol
    ? brokerId
      ? `PERP_${prefixedBase}_USDC_${brokerId}`
      : `PERP_${prefixedBase}_USDC`
    : "—";
  const priceRangePct = getPriceRangePct(leverage);
  const rwaSessionInfo =
    rwaMarketSessionOptions.find(item => item.value === rwaMarketSession) ??
    null;

  return (
    <div className="flex-1 min-w-[420px] flex flex-col gap-4">
      <div className="text-base font-medium text-base-contrast-98">Preview</div>

      {/* 6 info cards in 2x3 grid */}
      <div className="bg-base-200 rounded-xl p-4">
        <div className="grid grid-cols-2 gap-4">
          <PreviewCard label="Symbol" value={symbolPreview} />
          <PreviewCard
            label="Leverage"
            value={leverage > 0 ? `${leverage}x` : "—"}
          />
          <PreviewCard
            label="IMR / MMR"
            value={
              imr > 0
                ? `${(imr * 100).toFixed(2)}% / ${(mmr * 100).toFixed(2)}%`
                : "—"
            }
          />
          <PreviewCard
            label="Max OI"
            value={
              form.global_max_oi
                ? `${fmtNum(Number(form.global_max_oi))} USDC`
                : "—"
            }
          />
          <PreviewCard
            label="Max Notional"
            value={
              form.max_notional_user
                ? `${fmtNum(Number(form.max_notional_user))} USDC`
                : "—"
            }
          />
          <PreviewCard
            label="Price Range"
            value={`±${priceRangePct.toFixed(1)}%`}
          />
        </div>
      </div>

      {/* Bottom two columns: Funding/Liquidation/Tick Size | Data sources */}
      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
        <div className="bg-base-200 rounded-xl p-4 flex flex-col gap-4">
          <SectionBlock title="Funding">
            <KeyValue label="Period" value={form.funding_period} />
            <KeyValue
              label="Cap"
              value={
                cexFundingParamsLoading ? (
                  <Loader className="w-4 h-4" />
                ) : (
                  formatPctFromDecimal(fundingCap)
                )
              }
            />
            <KeyValue
              label="Floor"
              value={
                cexFundingParamsLoading ? (
                  <Loader className="w-4 h-4" />
                ) : (
                  formatPctFromDecimal(fundingFloor)
                )
              }
            />
          </SectionBlock>
          <div className="h-px bg-base-contrast-20" />
          <SectionBlock title="Liquidation">
            <KeyValue
              label="Fee"
              value={formatRatePercentFromDecimal(form.std_liquidation_fee)}
            />
            <KeyValue
              label="Claim fee"
              value={formatRatePercentFromDecimal(form.claim_IF_discount)}
            />
            <KeyValue label="Min notional" value="10 USDC" />
          </SectionBlock>
          <div className="h-px bg-base-contrast-20" />
          <SectionBlock title="Tick Size">
            <KeyValue label="Quote tick" value={formatDecimal(quoteTick)} />
            <KeyValue
              label="Base tick"
              value={
                cexTickParamsLoading ? (
                  <Loader className="w-4 h-4" />
                ) : (
                  formatDecimal(baseTick)
                )
              }
            />
            <KeyValue
              label="Base min"
              value={
                cexTickParamsLoading ? (
                  <Loader className="w-4 h-4" />
                ) : (
                  formatDecimal(baseMin)
                )
              }
            />
            <KeyValue
              label="Base max"
              value={
                baseMax > 0 ? Number(baseMax).toLocaleString("en-US") : "—"
              }
            />
          </SectionBlock>
        </div>

        <div className="flex flex-col gap-4">
          <div className="bg-base-200 rounded-xl p-4 flex flex-col gap-3">
            <div className="text-xs font-medium text-base-contrast-98">
              Data sources{" "}
              <span className="text-base-contrast-98">
                ({selectedSources.length})
              </span>
            </div>
            {selectedSources.length === 0 ? (
              <span className="text-3xs text-base-contrast-50">
                No sources selected
              </span>
            ) : (
              <div className="overflow-hidden">
                <table className="w-full text-xs">
                  <tbody>
                    {selectedSources.map(s => (
                      <tr key={s.id}>
                        <td className="px-3 py-2 text-base-contrast-54 font-medium">
                          {s.name}
                        </td>
                        <td className="px-3 py-2 text-base-contrast-54 font-medium">
                          {getFormattedSourceType(s)}
                        </td>
                        <td className="px-3 py-2 text-right text-base-contrast-98 font-medium tabular-nums">
                          {s.weight > 0 ? `${Math.round(s.weight)}%` : "—"}
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}
          </div>
          {listingAssetType === ListingAssetType.Rwa ? (
            <div className="bg-base-200 rounded-xl p-4 flex flex-col gap-1.5">
              <div className="text-xs font-medium text-base-contrast-98">
                RWA market session
              </div>
              <div className="text-xs font-medium text-primary-light">
                {rwaSessionInfo?.label ?? rwaMarketSession}
              </div>
            </div>
          ) : null}
        </div>
      </div>
    </div>
  );
}

function SectionBlock({
  title,
  children,
}: {
  title: string;
  children: React.ReactNode;
}) {
  return (
    <div className="flex flex-col gap-2">
      <div className="text-xs font-medium text-base-contrast-98">{title}</div>
      <div className="flex flex-col gap-2">{children}</div>
    </div>
  );
}

function KeyValue({ label, value }: { label: string; value: React.ReactNode }) {
  return (
    <div className="flex justify-between items-center">
      <span className="text-xs font-medium text-base-contrast-50">{label}</span>
      <span className="text-xs font-medium text-base-contrast-98 flex items-center justify-end">
        {value}
      </span>
    </div>
  );
}

function PreviewCard({ label, value }: { label: string; value: string }) {
  return (
    <div className="bg-base-300 rounded-xl p-4 flex flex-col gap-2 min-w-0">
      <span className="text-xs font-medium text-base-contrast-98">{label}</span>
      <span className="text-base font-medium text-primary-light whitespace-normal wrap-break-word">
        {value}
      </span>
    </div>
  );
}
