import { useBrokerListingAccounts, useBrokerListingConfig } from "../services";
import { useGetBrokerInfo } from "../services/account";

export function useListingAccountsData() {
  const listingConfigQuery = useBrokerListingConfig();
  const listingAccountsQuery = useBrokerListingAccounts();
  const brokerInfoQuery = useGetBrokerInfo();

  return {
    listingConfig: listingConfigQuery.data ?? {
      api_gateway: null,
      ip_whitelist: null,
      tg_chat_id: null,
    },
    listingAccounts: listingAccountsQuery.data,
    brokerInfo: brokerInfoQuery.data,
    listingConfigQuery,
    listingAccountsQuery,
    brokerInfoQuery,
    isLoading:
      listingConfigQuery.isLoading ||
      listingAccountsQuery.isLoading ||
      brokerInfoQuery.isLoading,
  };
}
