import { useMemo } from "react";
import { useBrokerListingIndexSources } from "../services";
import { enrichIndexSources } from "../services/priceSources";

export function useListingIndexSourcesData() {
  const query = useBrokerListingIndexSources();

  const indexSources = useMemo(() => {
    const filterSources = query.data?.filter(
      source =>
        source.source !== "HYPERLIQUID" &&
        source.type !== "builder_oracle" &&
        source.type !== "byok_oracle"
    );
    return enrichIndexSources(filterSources ?? []);
  }, [query.data]);

  return {
    ...query,
    indexSources,
  };
}
