import { Button } from "@/components/button";
import { SymbolCard } from "./SymbolCard";
import type { SymbolItem } from "../../../types";
import { useMarketInfoPriceChanges } from "../../../hooks/useMarketInfoPriceChanges";
import { formatListedAtLabel } from "../formatters";

interface SymbolCardViewUIProps {
  symbols: SymbolItem[];
  isEmpty: boolean;
  onCreateListing: () => void;
  onEdit?: (symbol: string) => void;
  onDelist?: (symbol: string) => void;
}

export function SymbolCardViewUI({
  symbols,
  isEmpty,
  onCreateListing,
  onEdit,
  onDelist,
}: SymbolCardViewUIProps) {
  const { getLastPrice } = useMarketInfoPriceChanges();

  if (isEmpty) {
    return <EmptyState onCreateListing={onCreateListing} />;
  }

  if (symbols.length === 0) {
    return (
      <div className="flex items-center justify-center h-32 rounded-xl bg-base-200 text-sm text-base-contrast-36">
        No symbols match the current filter.
      </div>
    );
  }

  return (
    <div className="grid grid-cols-3 gap-4 items-stretch">
      {symbols.map(s => (
        <SymbolCard
          key={s.symbol}
          symbol={s}
          href={`/permissionless-listing/${encodeURIComponent(s.symbol)}`}
          listedAtLabel={formatListedAtLabel(s.listedAt)}
          lastPrice={getLastPrice(s.symbol)}
          onEdit={onEdit ? () => onEdit(s.symbol) : undefined}
          onDelist={onDelist ? () => onDelist(s.symbol) : undefined}
        />
      ))}
    </div>
  );
}

function EmptyState({ onCreateListing }: { onCreateListing: () => void }) {
  return (
    <div className="flex flex-col items-center justify-center gap-4 py-16 px-4 rounded-xl bg-base-200 text-center">
      <p className="text-sm font-medium leading-tight text-base-contrast-98">
        No symbol listed yet
      </p>
      <p className="text-sm font-medium leading-snug text-base-contrast-50 max-w-[400px]">
        Create your first Perpetual contract to provide users with more trading
        options and expand your platform business and fee revenue.
      </p>
      <Button
        onClick={onCreateListing}
        size="md"
        rounded="full"
        className="flex items-center gap-1.5 px-5 h-8 text-sm font-medium"
      >
        <span className="text-base leading-none">+</span>
        Create listing
      </Button>
    </div>
  );
}
