import type { SymbolDetail } from "../../../types";
import { DetailSection } from "./SymbolDetailPanel.shared";

export function SymbolDetailFundingTickPanel(props: {
  params: SymbolDetail["params"];
  feeShareRate: SymbolDetail["feeShareRate"];
  fundingPeriodPending?: string;
  fundingPeriodEffectiveAt?: string;
}) {
  const {
    params,
    feeShareRate,
    fundingPeriodPending,
    fundingPeriodEffectiveAt,
  } = props;

  return (
    <div className="bg-base-200 rounded-xl p-4 flex flex-col gap-4">
      <DetailSection
        title="Funding"
        rows={[
          { label: "Period", value: params.funding_period?.value ?? "—" },
          { label: "Cap", value: params.funding_cap?.value ?? "—" },
          { label: "Floor", value: params.funding_floor?.value ?? "—" },
        ]}
      />
      {fundingPeriodPending && (
        <p className="text-3xs text-warning bg-warning/10 px-3 py-2 rounded-lg -mt-2">
          Changing to {fundingPeriodPending}
          {fundingPeriodEffectiveAt && ` at ${fundingPeriodEffectiveAt}`}
        </p>
      )}
      <div className="h-px bg-base-contrast-12" />
      <DetailSection
        title="Liquidation"
        rows={[
          {
            label: "Fee",
            value: params.std_liquidation_fee?.value ?? "—",
          },
          {
            label: "Claim fee",
            value: params.claim_IF_discount?.value ?? "—",
          },
        ]}
      />
      <div className="h-px bg-base-contrast-12" />
      <DetailSection
        title="Tick size"
        rows={[
          { label: "Quote tick", value: params.quote_tick?.value ?? "—" },
          { label: "Base tick", value: params.base_tick?.value ?? "—" },
          { label: "Base min", value: params.base_min?.value ?? "—" },
          { label: "Base max", value: params.base_max?.value ?? "—" },
        ]}
      />
      <div className="h-px bg-base-contrast-12" />
      <DetailSection
        title="Fee Revenue Share"
        rows={[
          {
            label: "Fee Share rate",
            value: Number.isFinite(feeShareRate)
              ? `${(feeShareRate * 100).toFixed(0)}%`
              : "—",
          },
        ]}
      />
    </div>
  );
}
