import { useCallback } from "react";
import type { Dispatch, SetStateAction } from "react";
import { toast } from "@/components/toast";
import {
  ListingAssetType,
  type SourceItem,
  type TradingParamsForm,
} from "../../../../types";
import type { BrokerListingSymbolContextData } from "../../../../services";
import { formatRatePercentFromDecimal, type ValidationErrors } from "./shared";

type UseTradingParamsValidationInput = {
  form: TradingParamsForm;
  selectedSources: SourceItem[];
  setErrors: Dispatch<SetStateAction<ValidationErrors>>;
  setWarnings: Dispatch<SetStateAction<ValidationErrors>>;
  symbolContext?: BrokerListingSymbolContextData;
};

export function useTradingParamsValidation({
  form,
  selectedSources,
  setErrors,
  setWarnings,
  symbolContext,
}: UseTradingParamsValidationInput) {
  const validateCommon = useCallback(
    (options: { showToast: boolean; requireSources: boolean }): boolean => {
      const errs: ValidationErrors = {};
      const warns: ValidationErrors = {};

      const getCtxParam = (key: string) => symbolContext?.params?.[key];

      const parseSuggestedNumber = (
        raw: number | string | undefined
      ): number | null => {
        if (raw === undefined) return null;
        const n = typeof raw === "number" ? raw : Number(raw);
        return Number.isFinite(n) ? n : null;
      };

      const validateMaxLeverage = () => {
        const raw = form.max_leverage.trim();
        const allowed = [5, 10, 20];
        if (!raw) {
          errs.max_leverage = "Required";
          return;
        }

        const leverage = Number(raw);
        if (!allowed.includes(leverage)) {
          errs.max_leverage = "Must be one of 5x / 10x / 20x";
        }
      };

      const validateEnum = (field: keyof TradingParamsForm) => {
        const ctxParam = getCtxParam(field as string);
        if (!ctxParam || ctxParam.type !== "enum") return;

        const raw = form[field].trim();
        const required = Boolean(ctxParam.required);
        if (!raw) {
          if (required) errs[field] = "Required";
          return;
        }

        const allowed = ctxParam.values.map(v => String(v));
        if (!allowed.includes(raw)) {
          if (field === "max_leverage") {
            errs[field] = `Must be one of ${allowed
              .map(v => `${v}x`)
              .join(" / ")}`;
          } else {
            errs[field] = `Must be one of ${allowed.join(" / ")}`;
          }
        }
      };

      const validateInteger = (field: keyof TradingParamsForm) => {
        const ctxParam = getCtxParam(field as string);
        if (!ctxParam || ctxParam.type !== "integer") return;

        const raw = form[field].trim();
        const required = Boolean(ctxParam.required);
        if (!raw) {
          if (required) errs[field] = "Required";
          return;
        }

        // Allow user to type intermediate values like "-" (we'll mark invalid).
        if (!/^-?\d+$/.test(raw)) {
          errs[field] = "Must be a number";
          return;
        }

        const n = Number(raw);
        if (!Number.isFinite(n)) {
          errs[field] = "Must be a number";
          return;
        }
        if (!Number.isInteger(n)) {
          errs[field] = "Must be an integer";
          return;
        }
        if (n < ctxParam.min) {
          errs[field] = `Must be >= ${ctxParam.min}`;
          return;
        }

        const suggested = parseSuggestedNumber(ctxParam.suggested);
        if (suggested != null && n > suggested) {
          warns[field] = `Above suggested: ${Math.trunc(
            suggested
          ).toLocaleString("en-US")} USDC`;
        }
      };

      const validateDecimal = (field: keyof TradingParamsForm) => {
        const ctxParam = getCtxParam(field as string);
        if (!ctxParam || ctxParam.type !== "decimal") return;

        const raw = form[field].trim();
        const required = Boolean(ctxParam.required);
        if (!raw) {
          if (required) errs[field] = "Required";
          return;
        }

        if (!/^-?(?:\d+(\.\d*)?|\.\d+)$/.test(raw)) {
          errs[field] = "Must be a number";
          return;
        }

        const n = Number(raw);
        if (!Number.isFinite(n)) {
          errs[field] = "Must be a number";
          return;
        }

        const frac = raw.includes(".") ? (raw.split(".")[1] ?? "") : "";
        if (frac.length > ctxParam.max_decimals) {
          errs[field] =
            `Must have at most ${ctxParam.max_decimals} decimal places`;
          return;
        }

        if (n < ctxParam.min || n > ctxParam.max) {
          errs[field] = `Must be between ${ctxParam.min} and ${ctxParam.max}`;
          return;
        }

        const suggested = parseSuggestedNumber(ctxParam.suggested);
        if (suggested != null && n > suggested) {
          warns[field] = `Above suggested: ${formatRatePercentFromDecimal(
            String(suggested)
          )}`;
        }
      };

      // Enum
      validateMaxLeverage();
      validateEnum("funding_period");

      // Integers
      validateInteger("global_max_oi");
      validateInteger("max_notional_user");

      // Decimals
      validateDecimal("std_liquidation_fee");
      validateDecimal("claim_IF_discount");

      if (
        form.listing_asset_type === ListingAssetType.Rwa &&
        !form.rwa_market_session.trim()
      ) {
        errs.rwa_market_session = "Required";
      }

      if (
        options.showToast &&
        options.requireSources &&
        selectedSources.length === 0
      ) {
        toast.error("Please select at least one valid index source.");
      }

      setErrors(errs);
      setWarnings(warns);

      const hasFieldErrors = Object.keys(errs).length > 0;
      const sourcesOk = options.requireSources
        ? selectedSources.length > 0
        : true;

      return !hasFieldErrors && sourcesOk;
    },
    [form, selectedSources, setErrors, setWarnings, symbolContext]
  );

  const validateFields = useCallback(
    () => validateCommon({ showToast: false, requireSources: false }),
    [validateCommon]
  );

  const validateForSubmit = useCallback(
    () => validateCommon({ showToast: true, requireSources: true }),
    [validateCommon]
  );

  return { validateFields, validateForSubmit };
}
