import { useCallback } from "react";
import { useSWRConfig } from "swr";
import {
  BROKER_AVAILABLE_IF_ACCOUNTS_KEY,
  BROKER_LISTING_ACCOUNTS_KEY,
  BROKER_LISTING_CONFIG_KEY,
  BROKER_LISTING_EVENT_HISTORY_KEY,
  BROKER_LISTING_OVERVIEW_KEY,
  BROKER_LISTING_RISK_SNAPSHOT_KEY,
  BROKER_LISTING_SYMBOLS_KEY,
} from "../services";
import {
  BROKER_INFO_KEY,
  CLIENT_AGGREGATE_HOLDING_KEY,
  CLIENT_SUB_ACCOUNTS_KEY,
} from "../services/account";

function getPrivateQueryPath(key: unknown): string | null {
  if (!Array.isArray(key)) return null;
  const [path] = key;
  return typeof path === "string" ? path : null;
}

function matchesAnyPrivatePath(key: unknown, paths: string[]) {
  const path = getPrivateQueryPath(key);
  if (!path) return false;
  return paths.some(target => path === target || path.startsWith(`${target}?`));
}

export function useListingRefreshActions() {
  const { mutate } = useSWRConfig();

  const refreshPrivatePaths = useCallback(
    (paths: string[]) =>
      mutate(key => matchesAnyPrivatePath(key, paths), undefined, {
        revalidate: true,
      }),
    [mutate]
  );

  const refreshAccounts = useCallback(
    () =>
      refreshPrivatePaths([
        BROKER_LISTING_ACCOUNTS_KEY,
        BROKER_AVAILABLE_IF_ACCOUNTS_KEY,
      ]),
    [refreshPrivatePaths]
  );

  const refreshConfig = useCallback(
    () => refreshPrivatePaths([BROKER_LISTING_CONFIG_KEY]),
    [refreshPrivatePaths]
  );

  const refreshBrokerInfo = useCallback(
    () => refreshPrivatePaths([BROKER_INFO_KEY]),
    [refreshPrivatePaths]
  );

  const refreshBalances = useCallback(
    () =>
      refreshPrivatePaths([
        CLIENT_AGGREGATE_HOLDING_KEY,
        CLIENT_SUB_ACCOUNTS_KEY,
      ]),
    [refreshPrivatePaths]
  );

  const refreshListingSymbols = useCallback(
    () => refreshPrivatePaths([BROKER_LISTING_SYMBOLS_KEY]),
    [refreshPrivatePaths]
  );

  const refreshRiskSnapshot = useCallback(
    () => refreshPrivatePaths([BROKER_LISTING_RISK_SNAPSHOT_KEY]),
    [refreshPrivatePaths]
  );

  const refreshDashboard = useCallback(
    () =>
      refreshPrivatePaths([
        BROKER_LISTING_SYMBOLS_KEY,
        BROKER_LISTING_RISK_SNAPSHOT_KEY,
        BROKER_LISTING_OVERVIEW_KEY,
        BROKER_LISTING_EVENT_HISTORY_KEY,
      ]),
    [refreshPrivatePaths]
  );

  return {
    refreshAccounts,
    refreshConfig,
    refreshBrokerInfo,
    refreshBalances,
    refreshListingSymbols,
    refreshRiskSnapshot,
    refreshDashboard,
  };
}
