const MULTIPLIER_OPTIONS = [1, 10, 100, 1000, 10000, 100000, 1000000];

export const MULTIPLIER_SELECT_OPTIONS = MULTIPLIER_OPTIONS.map(m => ({
  value: m,
  label: `${m}x`,
}));

export const SPOT_MULTIPLIER_TOOLTIP =
  "Spot sources must share the same price multiplier, which also sets the symbol prefix on your DEX (e.g. 1000x → 1000SHIB).";

export const THIRD_PARTY_SOURCE_TOOLTIP =
  "3rd party source. The provider may take it offline at any time — use at your own risk.";

function TypeBadge({
  className,
  children,
}: {
  className?: string;
  children: ReactNode;
}) {
  return (
    <span
      className={cn(
        "inline-flex items-center rounded-sm px-2 py-0.5",
        "text-4xs font-semibold leading-normal whitespace-nowrap",
        "bg-primary/10 text-primary-light",
        className
      )}
    >
      {children}
    </span>
  );
}

