function UptimeDot({
  uptime7dPct,
  className,
}: {
  uptime7dPct?: number | null;
  className?: string;
}) {
  const n = typeof uptime7dPct === "number" ? uptime7dPct : null;
  const tone =
    n == null
      ? "bg-base-contrast-36"
      : n >= 100
        ? "bg-success"
        : n >= 80
          ? "bg-warning"
          : "bg-danger";
  const tip =
    n == null
      ? "7d uptime: -"
      : `7d uptime: ${n.toFixed(1).replace(/\.0$/, "")}%`;

  return (
    <Tooltip content={tip} side="top" sideOffset={6}>
      <span
        className={cn("inline-block h-2.5 w-2.5 rounded-full", tone, className)}
      />
    </Tooltip>
  );
}

export function getFormattedSourceType(item: SourceItem): ReactNode {
  if (item.type === IndexSourceType.BuilderOracle) {
    return <TypeBadge>Builder Oracle</TypeBadge>;
  }
  if (item.type === IndexSourceType.Byok) {
    return <TypeBadge>BYOK</TypeBadge>;
  }
  if (item.type === IndexSourceType.Cex) {
    return "CEX-Spot";
  }
  if (item.type === IndexSourceType.Futures) {
    return "CEX-Futures";
  }
  if (item.type === IndexSourceType.Oracle) {
    return "ORACLE-Spot";
  }
  return item.type;
}

