export function SourceNameCell({
  item,
  isBuilderOracle,
  isBuilderLike,
  isOwnCustom,
  isThirdPartyCustom,
}: {
  item: SourceItem;
  isBuilderOracle: boolean;
  isBuilderLike: boolean;
  isOwnCustom: boolean;
  isThirdPartyCustom: boolean;
}) {
  return (
    <td className="px-6 py-4 align-middle text-xs text-base-contrast-98 font-medium border-b border-base-contrast-6">
      <div className="inline-flex items-center gap-2">
        {isBuilderOracle ? <UptimeDot uptime7dPct={item.uptime7dPct} /> : null}
        <span>{item.name}</span>
        {isBuilderLike ? (
          <span className="inline-flex items-center gap-1.5 text-3xs font-medium text-base-contrast-36 whitespace-nowrap shrink-0">
            {isOwnCustom ? "(yours)" : "(other builder)"}
            {isThirdPartyCustom ? (
              <Tooltip
                content={item.riskNotice ?? THIRD_PARTY_SOURCE_TOOLTIP}
                side="top"
                sideOffset={6}
                className="max-w-[min(320px,90vw)] whitespace-normal text-left text-base-contrast-98"
              >
                <span className="inline-flex items-center text-warning">
                  <ExclamationFillIcon />
                </span>
              </Tooltip>
            ) : null}
          </span>
        ) : null}
      </div>
    </td>
  );
}

export function SourceTypeCell({ children }: { children: ReactNode }) {
  return (
    <td className="px-6 py-4 align-middle text-xs text-base-contrast-98 border-b border-base-contrast-6 whitespace-nowrap">
      {children}
    </td>
  );
}

export function SourceSymbolInputCell({
  value,
  hasError = false,
  onChange,
  onBlur,
}: {
  value: string;
  hasError?: boolean;
  onChange: (value: string) => void;
  onBlur?: () => void;
}) {
  return (
    <td className="px-6 py-4 align-middle border-b border-base-contrast-6">
      <input
        value={value}
        onChange={e => onChange(e.target.value)}
        onBlur={onBlur}
        readOnly={false}
        className={cn(
          "w-full px-2 py-1 rounded text-3xs",
          "bg-base-300 text-base-contrast-98",
          "border outline-none",
          hasError
            ? "border-danger focus:border-danger"
            : "border-base-contrast-12 focus:border-primary/50"
        )}
        placeholder={hasError ? "Enter symbol..." : undefined}
      />
    </td>
  );
}

export function NotFoundSourceRow({
  item,
  canSelect,
  isBuilderOracle,
  isBuilderLike,
  isOwnCustom,
  isThirdPartyCustom,
  formattedItemType,
  onToggle,
  onSymbolChange,
  onSymbolBlur,
}: {
  item: SourceItem;
  canSelect: boolean;
  isBuilderOracle: boolean;
  isBuilderLike: boolean;
  isOwnCustom: boolean;
  isThirdPartyCustom: boolean;
  formattedItemType: ReactNode;
  onToggle: (id: string) => void;
  onSymbolChange: (id: string, symbol: string) => void;
  onSymbolBlur: (id: string) => void;
}) {
  return (
    <tr
      className={cn(
        "h-[52px] transition-colors",
        canSelect && item.selected
          ? "bg-primary/5 hover:bg-primary/[0.07]"
          : "hover:bg-base-contrast-4"
      )}
    >
      <td className="px-6 py-4 align-middle border-b border-base-contrast-6">
        <span className="inline-flex items-center h-[32px]">
          <OdsCheckbox
            checked={canSelect ? item.selected : false}
            disabled={!canSelect}
            onCheckedChange={canSelect ? () => onToggle(item.id) : undefined}
            aria-label={`Select ${item.name}`}
          />
        </span>
      </td>
      <SourceNameCell
        item={item}
        isBuilderOracle={isBuilderOracle}
        isBuilderLike={isBuilderLike}
        isOwnCustom={isOwnCustom}
        isThirdPartyCustom={isThirdPartyCustom}
      />
      <SourceTypeCell>{formattedItemType}</SourceTypeCell>
      <SourceSymbolInputCell
        value={item.sourceSymbol}
        hasError
        onChange={value => onSymbolChange(item.id, value)}
        onBlur={() => onSymbolBlur(item.id)}
      />
      <td className="px-6 py-4 align-middle text-3xs text-base-contrast-36 border-b border-base-contrast-6">
        -
      </td>
      <td className="px-6 py-4 align-middle text-xs text-danger border-b border-base-contrast-6">
        Not found on {item.name}
      </td>
      <td className="px-6 py-4 align-middle text-3xs text-base-contrast-36 border-b border-base-contrast-6">
        -
      </td>
      <td className="px-6 py-4 align-middle text-3xs text-base-contrast-36 border-b border-base-contrast-6">
        -
      </td>
    </tr>
  );
}
