import type { SWRConfiguration } from "swr";
import {
  useBrokerListingRiskSnapshot,
  type BrokerListingRiskSnapshotQuery,
} from "../services";

export function useListingRiskSnapshotData(
  query?: BrokerListingRiskSnapshotQuery,
  options?: SWRConfiguration
) {
  const riskSnapshotQuery = useBrokerListingRiskSnapshot(query, options);

  return {
    ...riskSnapshotQuery,
    riskSnapshot: riskSnapshotQuery.data,
  };
}
