import { useEffect } from "react";
import { useSelectListingStore } from "../store/useListingStore";
import { useListingServerData } from "./useListingServerData";

export function usePermissionlessListingBootstrap() {
  const { forceOnboarding, forceOnboardingReady, isLoading } =
    useListingServerData();
  const { setForceOnboarding } = useSelectListingStore(state => ({
    setForceOnboarding: state.setForceOnboarding,
  }));

  useEffect(() => {
    if (!forceOnboardingReady) return;
    setForceOnboarding(forceOnboarding);
  }, [forceOnboarding, forceOnboardingReady, setForceOnboarding]);

  return {
    isLoading,
    forceOnboarding,
    forceOnboardingReady,
  };
}
