import { useEffect, useState } from "react";
import { Button } from "@/components/button";
import {
  Dialog,
  DialogBody,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/dialog";
import { Input } from "@/components/input";
import { toast } from "@/components/toast";
import { InfoCircleIcon } from "../CustomOracleIcons";
import {
  footerClassName,
  formLabelClassName,
  infoBannerClassName,
  sourceIdClassName,
} from "./shared";

interface BuilderAddSymbolModalProps {
  open: boolean;
  sourceName: string;
  isMutating: boolean;
  onClose: () => void;
  onConfirm: (symbol: string) => Promise<string | null> | string | null;
}

export function BuilderAddSymbolModal({
  open,
  sourceName,
  isMutating,
  onClose,
  onConfirm,
}: BuilderAddSymbolModalProps) {
  const [builderSymbol, setBuilderSymbol] = useState("");

  useEffect(() => {
    if (!open) {
      setBuilderSymbol("");
    }
  }, [open]);

  return (
    <Dialog
      open={open}
      onOpenChange={nextOpen => {
        if (!nextOpen) {
          setBuilderSymbol("");
          onClose();
        }
      }}
    >
      <DialogContent className="max-w-[480px]">
        <DialogHeader className="h-auto flex-col items-stretch gap-2 border-b-0 px-6 pt-6 pb-0">
          <DialogTitle className="text-lg font-medium text-base-contrast-98">
            Add symbol
          </DialogTitle>
          <DialogDescription className="text-2xs leading-6 text-base-contrast-54">
            Push your own index price for any asset. One symbol per request. The
            source is auto-created on the first symbol.
          </DialogDescription>
        </DialogHeader>
        <DialogBody className="space-y-4 px-6 pt-5 pb-0">
          <div className={sourceIdClassName}>
            <div className="text-3xs text-base-contrast-50">
              Source ID (auto-assigned)
            </div>
            <div className="mt-1 font-mono text-[15px] font-semibold text-base-contrast-98">
              {sourceName}
            </div>
          </div>
          <div>
            <label className={formLabelClassName}>Symbol</label>
            <Input
              value={builderSymbol}
              disabled={isMutating}
              onChange={event => {
                setBuilderSymbol(event.target.value.toUpperCase());
              }}
              placeholder="e.g. SOL"
              className="bg-base-500"
            />
          </div>
          <div className={infoBannerClassName}>
            <div className="flex items-start gap-3">
              <div className="mt-0.5 shrink-0 text-primary-light">
                <InfoCircleIcon />
              </div>
              <div>
                New symbols start as{" "}
                <strong className="font-medium text-base-contrast-98">
                  Private
                </strong>{" "}
                so you can verify the price feed first. Once the data looks
                correct, switch the visibility to{" "}
                <strong className="font-medium text-base-contrast-98">
                  Public
                </strong>
                .
              </div>
            </div>
          </div>
        </DialogBody>
        <DialogFooter className={`${footerClassName} mt-6`}>
          <Button
            variant="outline"
            color="primary"
            className="flex-1"
            disabled={isMutating}
            onClick={() => {
              setBuilderSymbol("");
              onClose();
            }}
          >
            Cancel
          </Button>
          <Button
            className="flex-1"
            loading={isMutating}
            disabled={isMutating}
            onClick={async () => {
              const error = await onConfirm(builderSymbol);
              if (error) {
                toast.error(error);
                return;
              }
              setBuilderSymbol("");
            }}
          >
            Add symbol
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}
