import { useMemo } from "react";
import { cn } from "@/utils/css";
import { OnboardCheckIcon } from "@/permissionless-listing/components/icons";
import { PublicTier } from "@/permissionless-listing/components/icons/tier/PublicTier";
import { Sliver } from "@/permissionless-listing/components/icons/tier/Sliver";
import { GoldTier } from "@/permissionless-listing/components/icons/tier/GoldTier";
import { PlatinumTier } from "@/permissionless-listing/components/icons/tier/PlatinumTier";
import { DImond as DiamondTier } from "@/permissionless-listing/components/icons/tier/DImond";
import {
  getTierRequired,
  TIER_REQUIREMENT_WAIVED,
} from "@/permissionless-listing/constants";
import { useListingServerData } from "@/permissionless-listing/hooks/useListingServerData";

export const BROKER_TIER_UPGRADE_URL =
  "https://orderly.network/docs/introduction/trade-on-orderly/trading-basics/trading-fees#builder-staking-programme";

export enum TierKey {
  PUBLIC = "PUBLIC",
  SILVER = "SILVER",
  GOLD = "GOLD",
  PLATINUM = "PLATINUM",
  DIAMOND = "DIAMOND",
}

export function formatTierLabel(tier: TierKey) {
  const tierStr = String(tier);
  // Display requirement: only first letter uppercase, e.g. DIAMOND -> Diamond.
  return tierStr.charAt(0) + tierStr.slice(1).toLowerCase();
}

export function WarningTriangleIcon({ className }: { className?: string }) {
  return (
    <svg
      className={cn("shrink-0", className)}
      width="16"
      height="16"
      viewBox="0 0 16 16"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      aria-hidden
    >
      <path
        d="M7.21769 2.73202C7.61302 1.99988 8.38698 1.99988 8.78231 2.73202L15.078 14.251C15.4733 14.9832 15.0118 15.8376 14.1736 15.8376H1.82639C0.988197 15.8376 0.526671 14.9832 0.921993 14.251L7.21769 2.73202Z"
        fill="currentColor"
      />
      <path
        d="M8.00113 5.5C8.31075 5.5 8.5567 5.74595 8.5567 6.05556V9.44444C8.5567 9.75405 8.31075 10 8.00113 10C7.69152 10 7.44557 9.75405 7.44557 9.44444V6.05556C7.44557 5.74595 7.69152 5.5 8.00113 5.5Z"
        fill="#110623"
      />
      <path
        d="M8.00067 11C8.41488 11 8.75067 11.3358 8.75067 11.75C8.75067 12.1642 8.41488 12.5 8.00067 12.5C7.58645 12.5 7.25067 12.1642 7.25067 11.75C7.25067 11.3358 7.58645 11 8.00067 11Z"
        fill="#110623"
      />
    </svg>
  );
}

export function TierIcon({
  tier,
  className,
}: {
  tier: TierKey;
  className?: string;
}) {
  switch (tier) {
    case TierKey.PUBLIC:
      return <PublicTier className={className} />;
    case TierKey.SILVER:
      return <Sliver className={className} />;
    case TierKey.GOLD:
      return <GoldTier className={className} />;
    case TierKey.PLATINUM:
      return <PlatinumTier className={className} />;
    case TierKey.DIAMOND:
      return <DiamondTier className={className} />;
    default:
      return <PublicTier className={className} />;
  }
}

export function BrokerTierStep() {
  const { brokerInfo } = useListingServerData();

  const tier = useMemo(() => brokerInfo?.type as TierKey, [brokerInfo?.type]);

  const isDone = getTierRequired(tier);

  const effectiveTier = tier ?? TierKey.PUBLIC;
  const effectiveTierLabel = formatTierLabel(effectiveTier);
  const diamondLabel = formatTierLabel(TierKey.DIAMOND);
  const showTierWaiverOffer =
    TIER_REQUIREMENT_WAIVED && effectiveTier !== TierKey.DIAMOND;

  return (
    <div className="flex flex-col gap-[12px] items-start overflow-clip">
      <div className="flex flex-col gap-[var(--spacing-md,8px)] items-start relative shrink-0 w-full">
        <div className="flex gap-[4px] items-center relative shrink-0 w-full">
          <div className="flex flex-col justify-center leading-0 not-italic relative shrink-0 text-base-contrast-50 whitespace-nowrap">
            <p className="leading-[1.2] text-xs">Current tier</p>
          </div>
        </div>

        <div className="flex gap-[8px] items-center relative shrink-0 w-full">
          <div className="flex gap-[4px] items-center relative shrink-0">
            <div className="relative shrink-0 size-[20px]">
              <TierIcon tier={effectiveTier} className="size-[20px]" />
            </div>

            <p
              className={cn(
                "font-medium leading-[1.2] not-italic relative shrink-0 text-base-contrast-98 whitespace-nowrap",
                getTierRequired(effectiveTier) ? "text-lg" : "text-base"
              )}
            >
              {effectiveTierLabel}
            </p>
          </div>

          {isDone ? (
            <OnboardCheckIcon className="w-4 h-4 text-success" />
          ) : (
            <WarningTriangleIcon className="text-warning" />
          )}
        </div>
      </div>

      {showTierWaiverOffer && (
        <div className="w-full rounded-xl border border-success/20 bg-success/6 px-4 py-3">
          <div className="flex items-start gap-3">
            <div className="space-y-1">
              <div className="flex items-center gap-2">
                <p className="text-xs font-medium text-base-contrast-98">
                  Tier requirement waived
                </p>
                <span className="inline-flex items-center rounded-full bg-success/15 px-2 py-0.5 text-3xs font-medium text-success">
                  Any tier
                </span>
              </div>
              <p className="text-3xs leading-relaxed text-base-contrast-54">
                We are temporarily waiving all builder tier requirements for
                permissionless listings. Create your listings today, regardless
                of your current {effectiveTierLabel} tier.
              </p>
            </div>
          </div>
        </div>
      )}

      {!TIER_REQUIREMENT_WAIVED && !isDone && (
        <div className="flex flex-col items-start overflow-clip relative shrink-0 w-full">
          <div className="flex items-start justify-between leading-[1.2] not-italic overflow-clip relative shrink-0 text-3xs w-full whitespace-nowrap">
            <p className="relative shrink-0 text-[#d9ab52]">
              Your builder must be {diamondLabel} tier to proceed.
            </p>
            <a
              href={BROKER_TIER_UPGRADE_URL}
              target="_blank"
              rel="noopener noreferrer"
              className="relative shrink-0 text-primary-light font-medium hover:underline"
            >
              Learn how to upgrade
            </a>
          </div>
        </div>
      )}
    </div>
  );
}
