import { useMemo } from "react";
import type { BrokerListingSymbolContextData } from "../../../../services";
import { resolveApiSource, type TradingParam } from "../../../../services";
import { IndexSourceType, type SourceItem } from "../../../../types";
import {
  alignBaseMinToNotionalUsd,
  alignDownToStep,
  alignUpToStep,
  inferQuoteTickFromPrice,
  inferBaseMinFromAskPrice,
  normalizeBaseTickForFallback,
  parseSuggestedNumber,
} from "./shared";

type UseTickAndLimitsInput = {
  symbolContext?: BrokerListingSymbolContextData;
  selectedSources: SourceItem[];
  globalMaxOi: string;
  baseSymbol: string;
  cexTickParamsLoading: boolean;
  cexMetasForTick: TradingParam[];
  cexStepSizeCandidates: number[];
};

export function useTickAndLimits({
  symbolContext,
  selectedSources,
  globalMaxOi,
  baseSymbol: _baseSymbol,
  cexTickParamsLoading,
  cexMetasForTick,
  cexStepSizeCandidates,
}: UseTickAndLimitsInput) {
  const cexSelected = useMemo(
    () =>
      selectedSources.filter(s => s.selected && s.type === IndexSourceType.Cex),
    [selectedSources]
  );

  return useMemo(() => {
    const adjustedPrices = selectedSources
      .map(
        source => source.price * (source.multiplier > 0 ? source.multiplier : 1)
      )
      .filter(price => Number.isFinite(price) && price > 0);

    const nonOracleAdjustedPrices = selectedSources
      .filter(s => s.type !== IndexSourceType.Oracle)
      .map(
        source => source.price * (source.multiplier > 0 ? source.multiplier : 1)
      )
      .filter(price => Number.isFinite(price) && price > 0);

    // Oracle quotes may be unreliable for inferring quote_tick. Prefer non-oracle sources
    // when available; fallback to all sources if only oracle quotes exist.
    const pricesForQuoteTick =
      nonOracleAdjustedPrices.length > 0
        ? nonOracleAdjustedPrices
        : adjustedPrices;

    const quoteTicks = pricesForQuoteTick
      .map(price => inferQuoteTickFromPrice(price))
      .filter(tick => tick > 0);
    const computedQuoteTick =
      quoteTicks.length > 0 ? Math.min(...quoteTicks) : 0;

    const avgIndexPrice =
      adjustedPrices.length > 0
        ? adjustedPrices.reduce((sum, n) => sum + n, 0) / adjustedPrices.length
        : 0;

    const baseMaxFromContext = parseSuggestedNumber(
      symbolContext?.params?.["base_max"]
    );

    const computedBaseTickFromCex =
      cexMetasForTick.length > 0
        ? Math.min(...cexMetasForTick.map(m => m.baseTick))
        : 0;
    const fallbackBaseTickFromCexStepSize =
      cexStepSizeCandidates.length > 0 ? Math.min(...cexStepSizeCandidates) : 0;

    const selectedAdjustedPriceBySource = new Map<string, number>();
    for (const source of cexSelected) {
      const adjustedPrice =
        source.price * (source.multiplier > 0 ? source.multiplier : 1);
      if (!Number.isFinite(adjustedPrice) || adjustedPrice <= 0) continue;
      const resolvedSource = resolveApiSource(source.name)
        ?.trim()
        .toUpperCase();
      if (!resolvedSource) continue;
      if (!selectedAdjustedPriceBySource.has(resolvedSource)) {
        selectedAdjustedPriceBySource.set(resolvedSource, adjustedPrice);
      }
    }

    const cexBaseMinCandidates = cexMetasForTick
      .map(meta => {
        if (meta.baseMin > 0) return meta.baseMin;
        const sourcePrice = selectedAdjustedPriceBySource.get(meta.source);
        return inferBaseMinFromAskPrice(sourcePrice ?? 0);
      })
      .filter(v => Number.isFinite(v) && v > 0);

    const rawBaseMinMax =
      cexBaseMinCandidates.length > 0 ? Math.max(...cexBaseMinCandidates) : 0;

    const computedBaseMinFromCex =
      computedBaseTickFromCex > 0 && rawBaseMinMax > 0 && avgIndexPrice > 0
        ? (() => {
            const aligned = alignBaseMinToNotionalUsd(
              rawBaseMinMax,
              avgIndexPrice,
              computedBaseTickFromCex
            );
            const floorByRawMinQty = alignUpToStep(
              rawBaseMinMax,
              computedBaseTickFromCex
            );
            // Keep compatibility with all selected CEX minQty constraints.
            return Math.max(aligned, floorByRawMinQty);
          })()
        : 0;

    const oracleOnlyBaseMinFallback =
      cexMetasForTick.length === 0
        ? selectedSources
            .filter(s => s.selected)
            .map(s =>
              inferBaseMinFromAskPrice(
                s.price * (s.multiplier > 0 ? s.multiplier : 1)
              )
            )
            .filter(v => Number.isFinite(v) && v > 0)
        : [];

    const implicitBaseTickFromQuoteRaw =
      computedQuoteTick > 0 && avgIndexPrice > 0
        ? computedQuoteTick / avgIndexPrice
        : 0;

    const normalizedQuoteDerivedBaseTick =
      implicitBaseTickFromQuoteRaw > 0
        ? normalizeBaseTickForFallback(implicitBaseTickFromQuoteRaw)
        : 0;

    const computedBaseTickFromCexOrFallback =
      computedBaseTickFromCex > 0
        ? computedBaseTickFromCex
        : fallbackBaseTickFromCexStepSize;

    const computedBaseTick =
      computedBaseTickFromCexOrFallback > 0
        ? computedBaseTickFromCexOrFallback
        : normalizedQuoteDerivedBaseTick > 0
          ? normalizedQuoteDerivedBaseTick
          : 0;

    const rawOracleBaseMinMax =
      oracleOnlyBaseMinFallback.length > 0
        ? Math.max(...oracleOnlyBaseMinFallback)
        : 0;

    const computedBaseMinFromOracleAligned =
      computedBaseMinFromCex <= 0 &&
      computedBaseTick > 0 &&
      rawOracleBaseMinMax > 0 &&
      avgIndexPrice > 0
        ? (() => {
            const aligned = alignBaseMinToNotionalUsd(
              rawOracleBaseMinMax,
              avgIndexPrice,
              computedBaseTick
            );
            const floorByRaw = alignUpToStep(
              rawOracleBaseMinMax,
              computedBaseTick
            );
            return Math.max(aligned, floorByRaw);
          })()
        : 0;

    const computedBaseMin =
      computedBaseMinFromCex > 0
        ? computedBaseMinFromCex
        : computedBaseMinFromOracleAligned > 0
          ? computedBaseMinFromOracleAligned
          : 0;

    const implicitBaseTickForMax =
      normalizedQuoteDerivedBaseTick > 0
        ? normalizedQuoteDerivedBaseTick
        : implicitBaseTickFromQuoteRaw > 0
          ? implicitBaseTickFromQuoteRaw
          : computedQuoteTick;

    const effectiveBaseTickForMax =
      computedBaseTick > 0 ? computedBaseTick : implicitBaseTickForMax;

    const globalOi = Number(globalMaxOi);
    const fallbackBaseMax =
      Number.isFinite(globalOi) && globalOi > 0 && avgIndexPrice > 0
        ? globalOi / avgIndexPrice
        : 0;

    const rawBaseMax =
      baseMaxFromContext && baseMaxFromContext > 0
        ? baseMaxFromContext
        : fallbackBaseMax;

    const computedBaseMax =
      effectiveBaseTickForMax > 0
        ? (() => {
            const aligned = alignDownToStep(
              rawBaseMax,
              effectiveBaseTickForMax
            );
            // Never raise base_max above raw input/context value when raw is smaller than one step.
            return aligned > rawBaseMax ? 0 : aligned;
          })()
        : 0;

    const needsCexPerpMeta = selectedSources.some(
      s => s.selected && s.type === IndexSourceType.Cex
    );
    const hasCexPerpMeta =
      !needsCexPerpMeta || (computedBaseTick > 0 && computedBaseMin > 0);

    return {
      quoteTick: computedQuoteTick,
      baseTick: computedBaseTick,
      baseMin: computedBaseMin,
      baseMax: computedBaseMax,
      cexTickParamsLoading,
      needsCexPerpMeta,
      hasCexPerpMeta,
    };
  }, [
    symbolContext,
    selectedSources,
    cexSelected,
    globalMaxOi,
    cexMetasForTick,
    cexStepSizeCandidates,
    cexTickParamsLoading,
  ]);
}
