import type { SWRConfiguration } from "swr";

export type useQueryOptions<T> = SWRConfiguration & {
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  formatter?: (data: any) => T;
};

export function normalizeOrderlyResponse<T>(
  payload: unknown,
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  formatter?: (data: any) => T
): T {
  if (formatter) return formatter(payload);

  const envelope = payload as { data?: unknown; rows?: unknown } | null;
  const data =
    envelope && typeof envelope === "object" ? envelope.data : undefined;
  if (
    data &&
    typeof data === "object" &&
    Array.isArray((data as { rows?: unknown }).rows)
  ) {
    return (data as { rows: unknown[] }).rows as T;
  }
  if (data !== undefined) return data as T;
  if (envelope && Array.isArray(envelope.rows)) return envelope.rows as T;
  return payload as T;
}

export async function fetcher<T>(
  url: string,
  init: RequestInit = {},
  queryOptions?: useQueryOptions<T>
) {
  let response: Response;
  try {
    response = await fetch(url, init);
  } catch (networkError) {
    throw new Error(
      `Network request failed: ${networkError instanceof Error ? networkError.message : String(networkError)}`
    );
  }

  let payload: unknown;
  try {
    const contentType = response.headers.get("content-type") || "";
    payload = contentType.includes("application/json")
      ? await response.json()
      : await response.text();
  } catch (parseError) {
    if (!response.ok) {
      throw new Error(`Request failed with ${response.status}`);
    }
    throw new Error(
      `Failed to parse response: ${parseError instanceof Error ? parseError.message : String(parseError)}`
    );
  }

  if (!response.ok) {
    const message =
      payload && typeof payload === "object" && "message" in payload
        ? String((payload as { message?: unknown }).message)
        : `Request failed with ${response.status}`;
    throw new Error(message);
  }
  return normalizeOrderlyResponse<T>(payload, queryOptions?.formatter);
}
