import { cn } from "@/utils/css";
import {
  DASH,
  formatDepthOrDash,
  formatIntOrDash,
  formatUsdShortOrDash,
  openInterestUsdValue,
} from "../../dashboard/formatters";
import { AlertLevel } from "../../../types";
import type { SymbolDetail, SymbolItem } from "../../../types";
import { MetricCard } from "./SymbolDetailPanel.shared";

export function SymbolDetailSummaryMetrics(props: {
  detail: Pick<
    SymbolDetail,
    | "volume24h"
    | "feeRevenue24h"
    | "liquidationCount24h"
    | "liquidationRevenue24h"
  >;
  symbolItem: Pick<
    SymbolItem,
    "openInterest" | "depthBid" | "depthAsk" | "sources"
  >;
  /** Mark price from public market_info/price_changes for OI notional. */
  lastPrice: number;
  alertLabel: string;
  alertLevel: AlertLevel | null;
}) {
  const { detail, symbolItem, lastPrice, alertLabel, alertLevel } = props;

  return (
    <div className="grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-4 gap-4">
      <MetricCard
        label="24h volume"
        value={formatUsdShortOrDash(detail.volume24h)}
      />
      <MetricCard
        label="24h trading fee"
        value={formatUsdShortOrDash(detail.feeRevenue24h)}
        valueClassName="text-success"
      />
      <MetricCard
        label="24h liquidations"
        value={formatIntOrDash(detail.liquidationCount24h)}
      />
      <MetricCard
        label="24h liquidation fee"
        value={formatUsdShortOrDash(detail.liquidationRevenue24h)}
      />
      <MetricCard
        label="Open interest"
        value={formatUsdShortOrDash(
          openInterestUsdValue(symbolItem.openInterest, lastPrice)
        )}
      />
      <MetricCard
        label="Depth"
        value={formatDepthOrDash({
          bid: symbolItem.depthBid,
          ask: symbolItem.depthAsk,
        })}
      />
      <MetricCard
        label="Index source"
        value={symbolItem.sources != null ? String(symbolItem.sources) : DASH}
      />
      <MetricCard
        label="Alert"
        value={alertLabel}
        valueClassName={cn(
          !alertLevel && "text-base-contrast-50",
          alertLevel === AlertLevel.Normal && "text-success",
          alertLevel === AlertLevel.Warning && "text-warning",
          alertLevel === AlertLevel.Limit && "text-danger"
        )}
      />
    </div>
  );
}
