import { useCallback, useEffect, useState } from "react";
import { ListingAssetType } from "../../../../types";
import type {
  IndexSourceMeta,
  SourceItem,
  SymbolDetail,
} from "../../../../types";
import { useSelectListingStore } from "../../../../store/useListingStore";
import {
  sourceKeyToItemId,
  useGetBrokerListingIndexSources,
  useGetBuilderSources,
  useCheckBrokerListingSymbolContext,
} from "../../../../services";
import type {
  BrokerListingBuilderSourceRow,
  BrokerListingIndexSourceRow,
} from "../../../../services";
import { enrichIndexSources } from "../../../../services/priceSources";
import { mergeBuilderSourceRows } from "../../../../services";
import {
  PriceSourceWeightMode,
  SEARCH_DEBOUNCE_MS,
  buildSavedMergeMapByRowId,
  getListingBaseFromSymbol,
  preserveOrRecalcWeights,
} from "./shared";
import {
  isBuilderLikeSourceType,
  sortSourcesForDisplay,
} from "./rules.helpers";
import { useSearchRequestLifecycle } from "./useSearchRequestLifecycle";
import {
  applySourcePatch,
  buildInitialSourceRows,
  fetchQuotePatchForSource,
  getSearchEditContext,
  getSearchWeightMode,
  normalizeIndexSourceApiRows,
} from "./search.helpers";
import { toast } from "@/components/toast";

export type GetBrokerListingSymbolContextFn = (input: {
  symbol: string;
}) => Promise<{ success: boolean } & Record<string, unknown>>;

export type UsePriceSourcesSearchParams = {
  priceSources: SourceItem[];
  setPriceSources: (sources: SourceItem[]) => void;
  editMode: boolean;
  editSymbol: string | null;
  symbolDetails: Record<string, SymbolDetail>;
  indexSources: IndexSourceMeta[];
};

type RowsEnvelope<T> = {
  data?: T[] | { rows?: T[] };
  rows?: T[];
};

function extractRows<T>(response: unknown): T[] {
  if (Array.isArray(response)) return response as T[];
  if (typeof response !== "object" || response === null) return [];

  const envelope = response as RowsEnvelope<T>;
  if (Array.isArray(envelope.rows)) return envelope.rows;
  if (Array.isArray(envelope.data)) return envelope.data;
  if (
    typeof envelope.data === "object" &&
    envelope.data !== null &&
    Array.isArray(envelope.data.rows)
  ) {
    return envelope.data.rows;
  }
  return [];
}

function getApiErrorMessage(error: unknown): string | undefined {
  if (error instanceof Error) return error.message;
  if (typeof error !== "object" || error === null) return undefined;
  const message = (error as { message?: unknown }).message;
  return typeof message === "string" ? message : undefined;
}

export function usePriceSourcesSearch({
  priceSources,
  setPriceSources,
  editMode,
  editSymbol,
  symbolDetails,
  indexSources,
}: UsePriceSourcesSearchParams) {
  const {
    currentListingBase,
    listingAssetType,
    setCurrentListingBase,
    setIndexSources,
  } = useSelectListingStore(s => ({
    currentListingBase: s.currentListingBase,
    listingAssetType: s.listingAssetType,
    setCurrentListingBase: s.setCurrentListingBase,
    setIndexSources: s.setIndexSources,
  }));

  const [searchTerm, setSearchTerm] = useState(currentListingBase);
  const [fetchIndexSourcesByBase] = useGetBrokerListingIndexSources();
  const [fetchBuilderSourcesByBase, { isMutating: _isBuilderSourcesMutating }] =
    useGetBuilderSources();

  const {
    searching,
    setSearching,
    lastTriggeredSearchRef,
    searchReqIdRef,
    searchTimerRef,
    sourcesRef,
    editSearchHydratedForSymbolRef,
    initialOrderByIdRef,
    publishSources,
    beginSearchRequest,
    cancelCurrentSearch,
    isCurrentRequest,
  } = useSearchRequestLifecycle({ priceSources, setPriceSources });

  const [checkSymbolContext] = useCheckBrokerListingSymbolContext();

  const sortDisplaySources = useCallback(
    (items: SourceItem[]) =>
      sortSourcesForDisplay(items, initialOrderByIdRef.current),
    [initialOrderByIdRef]
  );

  const publishNormalizedSources = useCallback(
    (items: SourceItem[], weightMode: PriceSourceWeightMode) => {
      publishSources(
        sortDisplaySources(preserveOrRecalcWeights(items, weightMode))
      );
    },
    [publishSources, sortDisplaySources]
  );

  const fetchAndMergeBuilderSources = useCallback(
    async (input: {
      baseSymbol: string;
      reqId: number;
      toastOnError: boolean;
    }) => {
      const normalizedBase = input.baseSymbol.trim().toUpperCase();
      if (!normalizedBase) return;

      try {
        const res = await fetchBuilderSourcesByBase({
          base_ccy: normalizedBase,
        });
        const safeRows = extractRows<BrokerListingBuilderSourceRow>(res);
        if (!isCurrentRequest(input.reqId)) return;

        const merged = mergeBuilderSourceRows(sourcesRef.current, safeRows);
        publishSources(sortDisplaySources(merged));
      } catch {
        if (!isCurrentRequest(input.reqId)) return;
        if (input.toastOnError) {
          toast.error("Failed to fetch builder sources. Please try again.");
        }
        const merged = mergeBuilderSourceRows(sourcesRef.current, []);
        publishSources(sortDisplaySources(merged));
      }
    },
    [
      fetchBuilderSourcesByBase,
      isCurrentRequest,
      publishSources,
      sortDisplaySources,
      sourcesRef,
    ]
  );

  const refetchBuilderSources = useCallback(
    async (baseSymbol?: string) => {
      const normalizedBase = (baseSymbol ?? searchTerm).trim().toUpperCase();
      if (!normalizedBase) return;
      await fetchAndMergeBuilderSources({
        baseSymbol: normalizedBase,
        reqId: searchReqIdRef.current,
        toastOnError: false,
      });
    },
    [fetchAndMergeBuilderSources, searchReqIdRef, searchTerm]
  );

  useEffect(() => {
    if (editMode) return;
    setCurrentListingBase(searchTerm.trim().toUpperCase());
  }, [editMode, searchTerm, setCurrentListingBase]);

  const onError = useCallback(
    (e: unknown) => {
      setSearching(false);
      publishSources([]);
      toast.error(
        getApiErrorMessage(e) || "Failed to validate symbol. Please try again."
      );
    },
    [publishSources, setSearching]
  );

  const searchSources = useCallback(
    async (
      baseSymbol: string,
      options?: { preserveExistingWeights?: boolean }
    ) => {
      const normalizedBase = baseSymbol.trim().toUpperCase();
      if (!normalizedBase) return;
      const preserveExistingWeights = options?.preserveExistingWeights ?? false;
      const reqId = beginSearchRequest();

      // Keep the base-filtered index source catalog fresh on re-search.
      // This is intentionally tied to the current `searchTerm` query key.
      let refreshedIndexSourcesByBase: unknown = undefined;
      try {
        refreshedIndexSourcesByBase = await fetchIndexSourcesByBase({
          base_ccy: normalizedBase,
        });
      } catch {
        if (!isCurrentRequest(reqId)) return;
        setSearching(false);
        publishSources([]);
        toast.error("Failed to fetch index sources. Please try again.");
        return;
      }

      const { detail, mergeDetail } = getSearchEditContext({
        editMode,
        editSymbol,
        symbolDetails,
        normalizedBase,
      });

      // In edit mode we already have the symbol details from store, so we
      // don't need to fetch broker listing symbol context again.
      if (!editMode) {
        try {
          const res = await checkSymbolContext({ symbol: normalizedBase });
          const isRwaSymbol = res?.is_rwa === true;
          const effectiveAssetType =
            listingAssetType ?? ListingAssetType.Crypto;
          if (effectiveAssetType === ListingAssetType.Crypto && isRwaSymbol) {
            throw new Error(
              "Invalid symbol: this is an RWA symbol. Please switch Asset Type to RWA."
            );
          }
          if (effectiveAssetType === ListingAssetType.Rwa && !isRwaSymbol) {
            throw new Error(
              "Invalid symbol: this is a Crypto symbol. Please switch Asset Type to Crypto."
            );
          }
        } catch (e: unknown) {
          if (!isCurrentRequest(reqId)) return;
          onError(e);
          return;
        }
      }

      // Must rely on base-filtered API rows (contains source_symbol/source_id).
      // If missing, stop search and surface an actionable error.
      const baseRowsRaw = extractRows<BrokerListingIndexSourceRow>(
        refreshedIndexSourcesByBase
      );

      const apiRows = normalizeIndexSourceApiRows(baseRowsRaw);
      if (apiRows.length === 0) {
        if (isCurrentRequest(reqId)) {
          setSearching(false);
          publishSources([]);
          toast.error("Failed to fetch index sources. Please try again.");
        }
        return;
      }

      // Keep the global catalog in sync with base-filtered results for
      // downstream pages within the listing flow.
      const newIndexSources = enrichIndexSources(apiRows);
      setIndexSources(newIndexSources);

      const savedMap =
        mergeDetail && detail
          ? buildSavedMergeMapByRowId(detail, indexSources)
          : null;

      const items = buildInitialSourceRows({
        apiRows,
        normalizedBase,
        savedMap,
      });

      initialOrderByIdRef.current = new Map(items.map((s, idx) => [s.id, idx]));

      const weightMode = getSearchWeightMode({
        mergeDetail,
        preserveExistingWeights,
      });

      publishNormalizedSources(items, weightMode);

      // Builder Oracle / BYOK rows are resolved by merging builder_sources rows.
      // Trigger it after candidates are set so l·oading placeholders can be replaced.
      await Promise.allSettled([
        fetchAndMergeBuilderSources({
          baseSymbol: normalizedBase,
          reqId,
          toastOnError: true,
        }),
        newIndexSources
          .filter(row => !isBuilderLikeSourceType(row.type))
          .map(async row => {
            const rowId = sourceKeyToItemId(row.source);
            const saved = savedMap?.get(rowId);
            const result = await fetchQuotePatchForSource({
              row,
              normalizedBase,
              saved,
              mergeDetail,
              listingAssetType: listingAssetType ?? undefined,
            });
            if (!isCurrentRequest(reqId)) return;
            const updated = applySourcePatch({
              sources: sourcesRef.current,
              rowId: result.rowId,
              patch: result.patch,
            });
            publishNormalizedSources(updated, weightMode);
          }),
      ]);

      if (isCurrentRequest(reqId)) {
        setSearching(false);
      }
    },
    [
      editMode,
      editSymbol,
      checkSymbolContext,
      beginSearchRequest,
      initialOrderByIdRef,
      indexSources,
      isCurrentRequest,
      listingAssetType,
      onError,
      publishSources,
      publishNormalizedSources,
      symbolDetails,
      sourcesRef,
      fetchIndexSourcesByBase,
      fetchAndMergeBuilderSources,
      setIndexSources,
      setSearching,
    ]
  );

  useEffect(() => {
    if (!editMode) {
      editSearchHydratedForSymbolRef.current = null;
    }
  }, [editMode, editSearchHydratedForSymbolRef]);

  useEffect(() => {
    if (!editMode || !editSymbol) return;
    const detail = symbolDetails[editSymbol];
    if (!detail) return;
    if (editSearchHydratedForSymbolRef.current === editSymbol) return;
    const base = getListingBaseFromSymbol(editSymbol);
    if (!base) return;
    editSearchHydratedForSymbolRef.current = editSymbol;
    lastTriggeredSearchRef.current = base.trim().toUpperCase();
    setSearchTerm(base);
    void searchSources(base, { preserveExistingWeights: true });
  }, [
    editMode,
    editSymbol,
    editSearchHydratedForSymbolRef,
    lastTriggeredSearchRef,
    symbolDetails,
    searchSources,
  ]);

  useEffect(() => {
    const term = searchTerm.trim();
    if (!term) {
      cancelCurrentSearch();
      lastTriggeredSearchRef.current = "";
      if (!(editMode && editSymbol) && sourcesRef.current.length > 0) {
        publishSources([]);
      }
      return;
    }

    if (term === lastTriggeredSearchRef.current) return;

    if (searchTimerRef.current) window.clearTimeout(searchTimerRef.current);
    searchTimerRef.current = window.setTimeout(() => {
      lastTriggeredSearchRef.current = term;
      searchSources(term);
    }, SEARCH_DEBOUNCE_MS);

    return () => {
      if (searchTimerRef.current) window.clearTimeout(searchTimerRef.current);
    };
  }, [
    searchTerm,
    editMode,
    editSymbol,
    cancelCurrentSearch,
    lastTriggeredSearchRef,
    publishSources,
    searchSources,
    searchTimerRef,
    sourcesRef,
  ]);

  return {
    searchTerm,
    setSearchTerm,
    searching,
    searchSources,
    sourcesRef,
    refetchBuilderSources,
  };
}
