import { useCallback, useMemo, useState } from "react";
import { toast } from "@/components/toast";
import { useSelectListingStore } from "../../../store/useListingStore";
import type {
  BuilderOracleSource,
  CustomOracleSymbolTarget,
  VisibilityMode,
} from "../types";
import { useBuilderOracleFeeds, useUpsertOracleFeed } from "../../../services";
import {
  cloneModal,
  getBuilderFeedIdentity,
  mapBuilderSymbol,
} from "./hooks/shared";
import { PERMISSIONLESS_LISTING_CUSTOM_ORACLE_FLOW_DOC_URL } from "../docsLinks";

export function useBuilderOracleScript() {
  const [copiedField, setCopiedField] = useState<"endpoint" | "topic" | null>(
    null
  );

  const { modal, setCustomOracleModal } = useSelectListingStore(state => ({
    modal: state.customOracleModal,
    setCustomOracleModal: state.setCustomOracleModal,
  }));

  const builderFeedsQuery = useBuilderOracleFeeds({
    revalidateOnFocus: false,
    refreshInterval: 5000,
  });
  const [upsertOracleFeed, { isMutating: isOracleFeedMutating }] =
    useUpsertOracleFeed();

  const closeModal = useCallback(
    (patch: Partial<typeof modal>) => {
      setCustomOracleModal(cloneModal(modal, patch));
    },
    [modal, setCustomOracleModal]
  );

  const loading = Boolean(
    !builderFeedsQuery.data &&
      !builderFeedsQuery.error &&
      (builderFeedsQuery.isLoading || builderFeedsQuery.isValidating)
  );

  const source = useMemo<BuilderOracleSource>(() => {
    const sourceId = builderFeedsQuery.data?.source_id ?? "ORACLE";

    return {
      name: sourceId,
      endpoint: "wss://ws-oracle.orderly.org",
      topic: "indexpricefeed",
      guideUrl: PERMISSIONLESS_LISTING_CUSTOM_ORACLE_FLOW_DOC_URL,
      symbols: (builderFeedsQuery.data?.rows ?? []).map(row =>
        mapBuilderSymbol(row, sourceId, [])
      ),
    };
  }, [builderFeedsQuery.data]);

  const onCopyField = useCallback(
    (field: "endpoint" | "topic", value: string) => {
      navigator.clipboard?.writeText(value).catch(() => undefined);
      setCopiedField(field);
      toast.success(`Copied to clipboard: ${value}`);
      window.setTimeout(() => setCopiedField(null), 1200);
    },
    []
  );

  const withErrorToast = useCallback((error: unknown, fallback: string) => {
    toast.error((error as { message?: string })?.message || fallback);
  }, []);

  const onConfirmBuilderAddSymbol = useCallback(
    async (rawSymbol: string) => {
      const symbol = rawSymbol.trim().toUpperCase();
      if (!symbol) return "Symbol cannot be empty.";

      try {
        const res = await upsertOracleFeed({ base_ccy: symbol });
        if (!res?.success) throw res;
        closeModal({ builderAddSymbolOpen: false });
        toast.success(`${symbol} added as Private`);
        await builderFeedsQuery.mutate();
        return null;
      } catch (error: unknown) {
        return (
          (error as { message?: string })?.message ||
          "Failed to add builder feed."
        );
      }
    },
    [builderFeedsQuery, closeModal, upsertOracleFeed]
  );

  const onSaveVisibility = useCallback(
    async (target: CustomOracleSymbolTarget, visibility: VisibilityMode) => {
      try {
        const res = await upsertOracleFeed({
          ...getBuilderFeedIdentity(target.symbolId, source),
          visibility,
        });
        if (!res?.success) throw res;
        closeModal({ visibilityTarget: null });
        toast.success(`Visibility updated to ${visibility}`);
        await builderFeedsQuery.mutate();
      } catch (error: unknown) {
        withErrorToast(error, "Failed to update visibility.");
      }
    },
    [builderFeedsQuery, closeModal, source, upsertOracleFeed, withErrorToast]
  );

  const onConfirmRemove = useCallback(
    async (target: CustomOracleSymbolTarget) => {
      const identity = getBuilderFeedIdentity(target.symbolId, source);
      const currentStatus = source.symbols.find(
        item => item.id === target.symbolId
      )?.status;
      const nextStatus = currentStatus === "inactive" ? "active" : "inactive";

      try {
        const res = await upsertOracleFeed({
          ...identity,
          status: nextStatus,
        });
        if (!res?.success) throw res;
        closeModal({ removeTarget: null });
        toast.success(
          `${identity.base_ccy} ${
            nextStatus === "inactive" ? "deactivated" : "activated"
          }`
        );
        await builderFeedsQuery.mutate();
      } catch (error: unknown) {
        withErrorToast(
          error,
          `Failed to ${
            nextStatus === "inactive" ? "deactivate" : "activate"
          } feed.`
        );
      }
    },
    [builderFeedsQuery, closeModal, source, upsertOracleFeed, withErrorToast]
  );

  return {
    source,
    loading,
    copiedField,
    modal,
    isOracleFeedMutating,
    onCopyField,
    onOpenAddSymbol: () => closeModal({ builderAddSymbolOpen: true }),
    onOpenVisibility: (symbolId: string) =>
      closeModal({
        visibilityTarget: {
          source: "builder",
          symbolId,
        },
      }),
    onOpenRemove: (symbolId: string) =>
      closeModal({
        removeTarget: {
          source: "builder",
          symbolId,
        },
      }),
    onCloseAddSymbol: () => closeModal({ builderAddSymbolOpen: false }),
    onConfirmBuilderAddSymbol,
    onCloseVisibility: () => closeModal({ visibilityTarget: null }),
    onSaveVisibility,
    onCloseRemove: () => closeModal({ removeTarget: null }),
    onConfirmRemove,
  };
}

export type BuilderOracleScriptReturn = ReturnType<
  typeof useBuilderOracleScript
>;
