import { FC, useState, useMemo } from "react";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogBody,
} from "@/components/dialog";
import { cn } from "@/utils/css";
import { PLInput } from "../components/Input";
import { useAddClientSubAccount } from "../services/account";
import { useBindBrokerListingAccount } from "../services/brokerListing";
import type { BrokerListingAccountScope } from "../services/types";
import { toast } from "@/components/toast";
import { Button } from "@/components/button";
import { useListingBalancesData } from "../hooks/useListingBalancesData";

const NICKNAME_REGEX = /^[a-zA-Z0-9@,_ \-]*$/;
const NICKNAME_MAX_LENGTH = 20;

const MAX_SUB_ACCOUNTS = 10;

interface CreateSubAccountModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onSuccess?: (subAccountId?: string) => void;
}

export const CreateSubAccountModal: FC<CreateSubAccountModalProps> = ({
  open,
  onOpenChange,
  onSuccess,
}) => {
  const [label, setLabel] = useState("");

  const { subAccounts } = useListingBalancesData();

  const subAccountCount = subAccounts?.length ?? 0;

  const [addSubAccount, { isMutating: addSubLoading }] =
    useAddClientSubAccount();

  const [bindAccount, { isMutating: bindLoading }] =
    useBindBrokerListingAccount();

  const trimmed = label.trim();
  const validLength =
    trimmed.length >= 1 && trimmed.length <= NICKNAME_MAX_LENGTH;
  const validChars = NICKNAME_REGEX.test(trimmed);
  const isValid = validLength && validChars;
  const showError = trimmed.length > 0 && !isValid;

  const countText = useMemo(() => {
    if (subAccountCount == null) return null;
    const current = subAccountCount;
    const remaining = Math.max(0, MAX_SUB_ACCOUNTS - current);
    return `You have ${current} sub-accounts. ${remaining} more can be created.`;
  }, [subAccountCount]);

  const loading = addSubLoading || bindLoading;

  const handleConfirm = async () => {
    if (!isValid || loading) return;

    const description = trimmed || undefined;

    try {
      const createRes = await addSubAccount({ description });

      if (!createRes?.success) {
        toast.error("Failed to create sub-account.");
        return;
      }

      const createdAccountId = createRes.data?.sub_account_id;
      if (!createdAccountId) {
        toast.error("Failed to create sub-account.");
        return;
      }

      setLabel("");
      onOpenChange(false);

      if (onSuccess) {
        onSuccess(String(createdAccountId));
      }

      const scope: BrokerListingAccountScope = "IF";
      const bindRes = await bindAccount({
        account_id: String(createdAccountId),
        scope,
      });
      if (!bindRes?.success) {
        toast.error("Failed to bind account");
        return;
      }
    } catch (error: unknown) {
      const msg = (error as { message?: string })?.message;
      if (msg) toast.error(msg);
    }
  };

  const handleOpenChange = (next: boolean) => {
    if (!next) setLabel("");
    onOpenChange(next);
  };

  return (
    <Dialog open={open} onOpenChange={handleOpenChange}>
      <DialogContent className="w-[440px] max-w-[95vw] bg-base-300 rounded-xl border-none flex flex-col p-0">
        <DialogHeader className="h-auto flex-col items-stretch border-0 px-5 pt-5 pb-3">
          <DialogTitle className="text-lg font-semibold text-base-contrast-98">
            Create sub-account
          </DialogTitle>
          {countText != null && (
            <p className="text-2xs text-base-contrast-50 mt-1">{countText}</p>
          )}
        </DialogHeader>
        <div className="h-px bg-base-contrast-12 shrink-0" />
        <DialogBody className="flex flex-col gap-2 px-5 py-5 pt-5">
          <label className="text-xs font-medium text-base-contrast-98">
            Sub-account nickname
          </label>
          <PLInput
            type="text"
            disabled={loading}
            value={label}
            onChange={e =>
              setLabel(e.target.value.slice(0, NICKNAME_MAX_LENGTH))
            }
            placeholder="Sub-account"
            maxLength={NICKNAME_MAX_LENGTH}
            onKeyDown={e => {
              if (e.key === "Enter") handleConfirm();
            }}
            className={cn(showError && "border-danger")}
          />
          <p
            className={cn(
              "text-3xs leading-normal pl-1",
              showError ? "text-danger" : "text-base-contrast-50"
            )}
          >
            • 1-20 characters. Only letters, numbers, and @ , _ - (space)
            allowed.
          </p>
        </DialogBody>
        <div className="px-5 pb-5 pt-0">
          <Button
            rounded="lg"
            onClick={handleConfirm}
            disabled={!isValid || loading}
            loading={loading}
            className="w-full"
          >
            Confirm
          </Button>
        </div>
      </DialogContent>
    </Dialog>
  );
};
