import { useCallback, useEffect, useMemo, useState } from "react";
import { toast } from "@/components/toast";
import type { DelistModalProps } from "./types";

export type UseDelistFormResult = {
  confirmText: string;
  setConfirmText: (v: string) => void;
  date: string;
  setDate: (v: string) => void;
  hour: string;
  setHour: (v: string) => void;
  timeError: string | null;
  minDate: string;
  submitting: boolean;
  canConfirm: boolean;
  handleConfirm: () => Promise<void>;
  handleOpenChange: (open: boolean) => void;
};

/**
 * Frontend form state + validation for delisting.
 * Does not perform API calls; it delegates submission to `onConfirm`.
 */
export function useDelistForm({
  open,
  symbol,
  mode,
  onConfirm,
  onOpenChange,
}: DelistModalProps): UseDelistFormResult {
  const [confirmText, setConfirmText] = useState("");
  const [date, setDate] = useState("");
  const [hour, setHour] = useState("");
  const [submitting, setSubmitting] = useState(false);
  const [timeError, setTimeError] = useState<string | null>(null);

  const candidateDate = useMemo(() => {
    if (!date || !hour) return null;
    const candidate = new Date(`${date}T${hour}:00:00`);
    if (Number.isNaN(candidate.getTime())) return null;
    return candidate;
  }, [date, hour]);

  const delistTimeIso = candidateDate ? candidateDate.toISOString() : "";

  const isTimeValid = useMemo(() => {
    if (mode !== "delist") return false;
    if (!candidateDate) return false;

    // Backend rule: must be >= now + 1 hour and must be on an hour boundary.
    const minTs = Date.now() + 60 * 60 * 1000;
    const isOnTheHourUtc =
      candidateDate.getUTCMinutes() === 0 &&
      candidateDate.getUTCSeconds() === 0;

    return candidateDate.getTime() >= minTs && isOnTheHourUtc;
  }, [candidateDate, mode]);

  useEffect(() => {
    if (mode !== "delist") {
      setTimeError(null);
      return;
    }
    if (!candidateDate) {
      setTimeError(null);
      return;
    }

    const minTs = Date.now() + 60 * 60 * 1000;
    if (candidateDate.getTime() < minTs) {
      setTimeError("Delisting time must be at least 1 hour from now.");
      return;
    }

    if (
      candidateDate.getUTCMinutes() !== 0 ||
      candidateDate.getUTCSeconds() !== 0
    ) {
      setTimeError(
        "Delisting time must be on the hour (minutes/seconds = 00)."
      );
      return;
    }

    setTimeError(null);
  }, [candidateDate, mode]);

  const canConfirm =
    mode === "cancel"
      ? confirmText === symbol && !submitting
      : confirmText === symbol && !!delistTimeIso && isTimeValid && !submitting;

  const reset = useCallback(() => {
    setConfirmText("");
    setDate("");
    setHour("");
    setTimeError(null);
    setSubmitting(false);
  }, []);

  useEffect(() => {
    if (!open) reset();
  }, [open, reset]);

  const handleConfirm = useCallback(async () => {
    if (!canConfirm) return;
    setSubmitting(true);
    try {
      if (mode === "delist") {
        if (!candidateDate) return;
        await onConfirm(candidateDate.toISOString());
        toast.success(`${symbol} scheduled for delisting`);
      } else {
        await onConfirm(undefined);
        toast.success(`${symbol} delisting requested`);
      }
      onOpenChange(false);
    } catch (error) {
      setSubmitting(false);
      throw error;
    }
  }, [canConfirm, candidateDate, mode, onConfirm, onOpenChange, symbol]);

  const handleOpenChange = useCallback(
    (next: boolean) => {
      if (!next) reset();
      onOpenChange(next);
    },
    [onOpenChange, reset]
  );

  const minDate = useMemo(() => {
    const d = new Date();
    d.setHours(d.getHours() + 1, 0, 0, 0);
    const y = d.getFullYear();
    const m = String(d.getMonth() + 1).padStart(2, "0");
    const day = String(d.getDate()).padStart(2, "0");
    return `${y}-${m}-${day}`;
  }, []);

  return {
    confirmText,
    setConfirmText,
    date,
    setDate,
    hour,
    setHour,
    timeError,
    minDate,
    submitting,
    canConfirm,
    handleConfirm,
    handleOpenChange,
  };
}
