import type { SourceItem } from "../types";
import { inferDefaultSymbols } from "./priceSources";

const SOURCE_TO_PROVIDER: Record<
  string,
  | "binance"
  | "bybit"
  | "okx"
  | "gateio"
  | "kucoin"
  | "coinbase"
  | "mexc"
  | "bitget"
  | "bingx"
  | "hyperliquid"
  | "lbank"
> = {
  BINANCE: "binance",
  BYBIT: "bybit",
  OKX: "okx",
  GATEIO: "gateio",
  KUCOIN: "kucoin",
  COINBASE: "coinbase",
  MEXC: "mexc",
  BITGET: "bitget",
  BINGX: "bingx",
  HYPERLIQUID: "hyperliquid",
  LBANK: "lbank",
};

function normalizeSource(sourceName: string): string {
  return sourceName.trim().toUpperCase().replace(/\s+/g, "");
}

function normalizeBase(raw: string): string {
  return raw.trim().toUpperCase().replace(/[-_/]/g, "");
}

function extractBaseFromSpotSymbol(sourceSymbol: string): string {
  const cleaned = normalizeBase(sourceSymbol);
  if (cleaned.endsWith("USDT")) return cleaned.slice(0, -4);
  if (cleaned.endsWith("USDC")) return cleaned.slice(0, -4);
  if (cleaned.endsWith("USD")) return cleaned.slice(0, -3);
  return cleaned;
}

function getCandidateBases(input: {
  baseSymbol: string;
  sourceSymbol?: string;
}): string[] {
  const primary = normalizeBase(input.baseSymbol);
  const derived = input.sourceSymbol
    ? extractBaseFromSpotSymbol(input.sourceSymbol)
    : "";
  return Array.from(new Set([primary, derived].filter(Boolean)));
}

function asNumber(value: unknown): number {
  const n = Number(value);
  return Number.isFinite(n) ? n : 0;
}

export type TradingParam = {
  found: boolean;
  source:
    | "BINANCE"
    | "BYBIT"
    | "OKX"
    | "GATEIO"
    | "KUCOIN"
    | "COINBASE"
    | "MEXC"
    | "BITGET"
    | "BINGX"
    | "HYPERLIQUID"
    | "LBANK";
  sourceSymbol: string;
  quoteTick: number;
  baseTick: number;
  baseMin: number;
  baseMax: number;
  fundingCap: number | null;
  fundingFloor: number | null;
  fundingIntervalSec: number | null;
};

function normalizeTradingParam(raw: unknown): TradingParam | null {
  if (!raw || typeof raw !== "object") return null;
  const obj = raw as Record<string, unknown>;
  const source = String(obj.source ?? "").toUpperCase();
  if (
    ![
      "BINANCE",
      "BYBIT",
      "OKX",
      "GATEIO",
      "KUCOIN",
      "COINBASE",
      "MEXC",
      "BITGET",
      "BINGX",
      "HYPERLIQUID",
      "LBANK",
    ].includes(source)
  )
    return null;

  return {
    found: Boolean(obj.found),
    source: source as TradingParam["source"],
    sourceSymbol: String(obj.sourceSymbol ?? ""),
    quoteTick: asNumber(obj.quoteTick),
    baseTick: asNumber(obj.baseTick),
    baseMin: asNumber(obj.baseMin),
    baseMax: asNumber(obj.baseMax),
    fundingCap: obj.fundingCap == null ? null : asNumber(obj.fundingCap),
    fundingFloor: obj.fundingFloor == null ? null : asNumber(obj.fundingFloor),
    fundingIntervalSec:
      obj.fundingIntervalSec == null ? null : asNumber(obj.fundingIntervalSec),
  };
}

export async function fetchTradingParamForSource(input: {
  sourceName: string;
  baseSymbol: string;
  sourceSymbol?: string;
}): Promise<TradingParam | null> {
  const normalizedSource = normalizeSource(input.sourceName);
  const provider = SOURCE_TO_PROVIDER[normalizedSource];
  if (!provider) return null;

  const bases = getCandidateBases({
    baseSymbol: input.baseSymbol,
    sourceSymbol: input.sourceSymbol,
  });
  if (bases.length === 0) return null;

  let lastValid: TradingParam | null = null;
  for (const base of bases) {
    try {
      const symbol =
        input.sourceSymbol?.trim() ||
        inferDefaultSymbols(normalizedSource, base).perp;
      const search = new URLSearchParams({ base });
      if (symbol) search.set("symbol", symbol);
      const response = await fetch(
        `/api/trading-params/${provider}?${search.toString()}`,
        {
          method: "GET",
          cache: "no-store",
        }
      );
      if (!response.ok) continue;
      const json = (await response.json()) as unknown;
      const meta = normalizeTradingParam(json);
      if (!meta) continue;
      lastValid = meta;
      if (meta.found) return meta;
    } catch {
      continue;
    }
  }

  return lastValid;
}

export function getTradingParamLookup(
  selectedSources: SourceItem[],
  metas: TradingParam[]
): Map<string, TradingParam> {
  const map = new Map<string, TradingParam>();
  for (const source of selectedSources) {
    const normalizedSource = normalizeSource(source.name);
    const matched = metas.find(meta => meta.source === normalizedSource);
    if (matched) {
      map.set(source.id, matched);
    }
  }
  return map;
}
