import { Loader } from "@/components/loader";
import type { RecentEvent } from "../../../types";

interface RecentEventsUIProps {
  events: RecentEvent[];
  page: number;
  pageSize: number;
  total: number;
  loading: boolean;
  onPageChange: (page: number) => void;
  onPageSizeChange: (size: number) => void;
}

function listAreaMinHeightPx(pageSize: number): number {
  const paddingY = 32;
  const rowGap = 16;
  const rowMin = 56;
  return paddingY + pageSize * rowMin + Math.max(0, pageSize - 1) * rowGap;
}

function RecentEventsPaginationBar(props: {
  loading: boolean;
  page: number;
  pageSize: number;
  total: number;
  pageTotal: number;
  safePage: number;
  startIndex: number;
  endIndex: number;
  onPageChange: (page: number) => void;
  onPageSizeChange: (size: number) => void;
}) {
  const {
    loading,
    page,
    pageSize,
    total,
    pageTotal,
    safePage,
    startIndex,
    endIndex,
    onPageChange,
    onPageSizeChange,
  } = props;

  return (
    <div className="px-4 pb-4 pt-2 flex items-center justify-between border-t border-base-contrast-12">
      <div className="flex items-center gap-2 text-2xs text-base-contrast-54">
        <span>Rows per page</span>
        <select
          className="h-7 rounded-md bg-base-300 border border-base-contrast-12 px-2 text-base sm:text-2xs text-base-contrast-98 outline-none disabled:opacity-40"
          value={pageSize}
          disabled={loading}
          onChange={e => onPageSizeChange(Number(e.target.value))}
        >
          {[5, 10, 20].map(size => (
            <option key={size} value={size}>
              {size}
            </option>
          ))}
        </select>
      </div>

      <div className="flex items-center gap-3 text-2xs text-base-contrast-54">
        <span>
          {loading
            ? "Loading…"
            : `Showing ${startIndex}-${endIndex} of ${total}`}
        </span>
        <button
          type="button"
          className="h-7 min-w-7 px-2 rounded-md bg-base-300 border border-base-contrast-12 text-base-contrast-98 disabled:opacity-40"
          disabled={loading || safePage <= 1}
          onClick={() => onPageChange(Math.max(1, safePage - 1))}
        >
          Prev
        </button>
        <span className="text-base-contrast-80">
          {loading ? `${page}/…` : `${safePage}/${pageTotal}`}
        </span>
        <button
          type="button"
          className="h-7 min-w-7 px-2 rounded-md bg-base-300 border border-base-contrast-12 text-base-contrast-98 disabled:opacity-40"
          disabled={loading || safePage >= pageTotal}
          onClick={() => onPageChange(Math.min(pageTotal, safePage + 1))}
        >
          Next
        </button>
      </div>
    </div>
  );
}

export function RecentEventsUI({
  events,
  page,
  pageSize,
  total,
  loading,
  onPageChange,
  onPageSizeChange,
}: RecentEventsUIProps) {
  const pageTotal = Math.max(1, Math.ceil(total / pageSize));
  const safePage = Math.min(page, pageTotal);
  const startIndex = total === 0 ? 0 : (safePage - 1) * pageSize + 1;
  const endIndex = Math.min(safePage * pageSize, total);

  return (
    <div className="rounded-xl bg-base-200 mb-6">
      <div className="text-xs font-medium text-base-contrast-98 p-4 border-b border-base-contrast-12">
        Recent events
      </div>

      {!loading && total === 0 ? (
        <div className="px-4 py-10 text-center">
          <div className="text-xs text-base-contrast-54">
            No recent events yet.
          </div>
          <div className="mt-2 text-2xs text-base-contrast-36">
            New risk and status events will appear here.
          </div>
        </div>
      ) : loading ? (
        <>
          <div
            className="flex items-center justify-center p-4"
            style={{ minHeight: listAreaMinHeightPx(pageSize) }}
          >
            <Loader />
          </div>
          <RecentEventsPaginationBar
            loading
            page={page}
            pageSize={pageSize}
            total={total}
            pageTotal={pageTotal}
            safePage={safePage}
            startIndex={startIndex}
            endIndex={endIndex}
            onPageChange={onPageChange}
            onPageSizeChange={onPageSizeChange}
          />
        </>
      ) : (
        <>
          <div className="flex flex-col gap-4 p-4">
            {events.map((evt, i) => (
              <div
                key={`${evt.eventTime}-${i}`}
                className="flex items-center gap-4 p-4 rounded-lg bg-base-300"
              >
                <span className="shrink-0 text-3xs font-medium text-primary-light whitespace-nowrap">
                  {evt.time}
                </span>
                <span className="text-xs text-base-contrast-98 leading-relaxed">
                  {evt.description}
                </span>
              </div>
            ))}
          </div>

          <RecentEventsPaginationBar
            loading={false}
            page={page}
            pageSize={pageSize}
            total={total}
            pageTotal={pageTotal}
            safePage={safePage}
            startIndex={startIndex}
            endIndex={endIndex}
            onPageChange={onPageChange}
            onPageSizeChange={onPageSizeChange}
          />
        </>
      )}
    </div>
  );
}
