import { useEffect, useMemo, useRef, useState } from "react";
import {
  fetchTradingParamForSource,
  resolveApiSource,
  type TradingParam,
} from "../../../../services";
import { IndexSourceType, type SourceItem } from "../../../../types";
import { MAIN_CEX_PRIORITY } from "./shared";

type UseCexPerpMetasInput = {
  priceSources: SourceItem[];
  baseSymbol: string;
};

function getSourceSymbolForMainCex(
  priceSources: SourceItem[],
  apiSource: TradingParam["source"]
): string | undefined {
  const row = priceSources.find(
    s =>
      s.type === IndexSourceType.Cex && resolveApiSource(s.name) === apiSource
  );
  const sym = row?.sourceSymbol?.trim();
  return sym || undefined;
}

function mainCexSymbolSignature(priceSources: SourceItem[]): string {
  return MAIN_CEX_PRIORITY.map(
    src => `${src}:${getSourceSymbolForMainCex(priceSources, src) ?? ""}`
  ).join(";");
}

export function useCexPerpMetas({
  priceSources,
  baseSymbol,
}: UseCexPerpMetasInput) {
  const [cexFundingParamsLoading, setCexFundingParamsLoading] = useState(false);
  const [cexTickParamsLoading, setCexTickParamsLoading] = useState(false);
  const [cexMetasForTick, setCexMetasForTick] = useState<TradingParam[]>([]);
  const [cexFundingMetas, setCexFundingMetas] = useState<TradingParam[]>([]);
  const [cexStepSizeCandidates, setCexStepSizeCandidates] = useState<number[]>(
    []
  );
  const fetchTickGenRef = useRef(0);
  const fetchFundingGenRef = useRef(0);

  const trimmedBaseSymbol = useMemo(() => baseSymbol.trim(), [baseSymbol]);

  const cexSelected = useMemo(
    () =>
      priceSources.filter(s => s.selected && s.type === IndexSourceType.Cex),
    [priceSources]
  );

  const cexSelectedSignature = useMemo(() => {
    return cexSelected
      .map(s => `${s.id}|${s.name}|${s.sourceSymbol}`)
      .sort()
      .join(";");
  }, [cexSelected]);

  const mainCexSymbolSig = useMemo(
    () => mainCexSymbolSignature(priceSources),
    [priceSources]
  );

  useEffect(() => {
    const gen = ++fetchFundingGenRef.current;
    const trimmedBase = trimmedBaseSymbol;

    if (!trimmedBase) {
      setCexFundingMetas([]);
      setCexFundingParamsLoading(false);
      return;
    }

    setCexFundingParamsLoading(true);

    void (async () => {
      const settled = await Promise.allSettled(
        MAIN_CEX_PRIORITY.map(async apiSource => {
          return fetchTradingParamForSource({
            sourceName: apiSource,
            baseSymbol: trimmedBase,
            sourceSymbol: getSourceSymbolForMainCex(priceSources, apiSource),
          });
        })
      );

      if (gen !== fetchFundingGenRef.current) return;

      const metas: TradingParam[] = [];
      for (const s of settled) {
        if (s.status !== "fulfilled" || !s.value) continue;
        metas.push(s.value);
      }

      setCexFundingMetas(metas);
      setCexFundingParamsLoading(false);
    })();
  }, [trimmedBaseSymbol, mainCexSymbolSig, priceSources]);

  useEffect(() => {
    const gen = ++fetchTickGenRef.current;
    const trimmedBase = trimmedBaseSymbol;

    if (!trimmedBase || cexSelected.length === 0) {
      setCexMetasForTick([]);
      setCexStepSizeCandidates([]);
      setCexTickParamsLoading(false);
      return;
    }

    setCexTickParamsLoading(true);

    void (async () => {
      const settled = await Promise.allSettled(
        cexSelected.map(async source => {
          const apiSource = resolveApiSource(source.name);
          if (!apiSource) return null;
          return fetchTradingParamForSource({
            sourceName: apiSource,
            baseSymbol: trimmedBase,
            sourceSymbol: source.sourceSymbol,
          });
        })
      );

      if (gen !== fetchTickGenRef.current) return;

      const metasForTick: TradingParam[] = [];
      const stepSizes: number[] = [];

      for (const s of settled) {
        if (s.status !== "fulfilled" || !s.value) continue;
        const m = s.value;
        if (m.found && m.baseTick > 0) {
          stepSizes.push(m.baseTick);
          metasForTick.push(m);
        }
      }

      setCexMetasForTick(metasForTick);
      setCexStepSizeCandidates(stepSizes);
      setCexTickParamsLoading(false);
    })();
  }, [trimmedBaseSymbol, cexSelected, cexSelectedSignature]);

  return {
    cexFundingParamsLoading,
    cexTickParamsLoading,
    cexMetasForTick,
    cexFundingMetas,
    cexStepSizeCandidates,
  };
}
