import { useState } from "react";
import type { KeyboardEvent as ReactKeyboardEvent } from "react";
import { cn } from "@/utils/css";
import { Button } from "@/components/button";
import { PLInput } from "../../../components/Input";
import { formatAccountId } from "@/utils";

export function SymbolDetailMMPanel(props: {
  boundAccountIds: string[];
  isEditable: boolean;
  onUnbindMM: (mmAddress: string) => void;
  onAddAndBindMM: (mmAddress: string) => Promise<boolean>;
  isMmBusy: boolean;
  isBindBusy: boolean;
  isUnbindBusy: boolean;
}) {
  const {
    boundAccountIds,
    isEditable,
    onUnbindMM,
    onAddAndBindMM,
    isMmBusy,
    isBindBusy,
    isUnbindBusy,
  } = props;

  const [accountInput, setAccountInput] = useState("");

  return (
    <div className="bg-base-200 rounded-xl p-4 flex flex-col gap-3">
      <h3 className="text-xs font-medium text-base-contrast-98">MM accounts</h3>
      {boundAccountIds.length > 0 ? (
        <div className="overflow-x-auto">
          <table className="w-full border-collapse">
            <thead>
              <tr className="border-b border-base-contrast-6">
                <th className="py-2 pr-3 text-left text-3xs font-semibold text-base-contrast-50">
                  Account ID
                </th>

                {isEditable && (
                  <th className="py-2 pl-3 text-right text-3xs font-semibold text-base-contrast-50">
                    Action
                  </th>
                )}
              </tr>
            </thead>
            <tbody>
              {boundAccountIds.map(accountId => {
                return (
                  <tr
                    key={accountId}
                    className="border-b border-base-contrast-6 last:border-b-0"
                  >
                    <td className="py-2.5 pr-3 text-xs font-medium text-base-contrast-98 font-mono truncate max-w-[200px]">
                      {formatAccountId(accountId)}
                    </td>
                    {isEditable && (
                      <td className="py-2.5 pl-3 text-right">
                        <Button
                          onClick={() => onUnbindMM(accountId)}
                          type="button"
                          variant="link"
                          size="sm"
                          disabled={isUnbindBusy}
                          className={cn(
                            "text-3xs text-primary-light hover:underline px-0 h-auto",
                            isUnbindBusy
                              ? "opacity-50 cursor-not-allowed hover:no-underline disabled:bg-transparent"
                              : ""
                          )}
                        >
                          Unbind
                        </Button>
                      </td>
                    )}
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      ) : (
        <p className="text-xs text-base-contrast-50">No MM accounts bound.</p>
      )}
      {isEditable && (
        <div className="mt-4 pt-4 border-t border-base-contrast-12">
          <label className="block text-xs text-base-contrast-50 mb-1.5">
            MM Account ID
          </label>
          <div className="flex gap-2">
            <PLInput
              type="text"
              value={accountInput}
              onChange={e => setAccountInput(e.target.value)}
              onKeyDown={(e: ReactKeyboardEvent<HTMLInputElement>) => {
                if (e.key === "Enter") {
                  e.preventDefault();
                  void (async () => {
                    const value = accountInput.trim();
                    if (!value || isMmBusy) return;
                    const ok = await onAddAndBindMM(value);
                    if (ok) setAccountInput("");
                  })();
                }
              }}
              placeholder="Enter MM account ID"
              disabled={isMmBusy}
              className="text-sm text-base-contrast-80 font-inherit placeholder:text-base-contrast-30"
            />
            <Button
              type="button"
              rounded="lg"
              disabled={!accountInput.trim() || isMmBusy}
              loading={isBindBusy}
              className="h-11"
              onClick={() => {
                void (async () => {
                  const value = accountInput.trim();
                  if (!value || isMmBusy) return;
                  const ok = await onAddAndBindMM(value);
                  if (ok) setAccountInput("");
                })();
              }}
            >
              Bind
            </Button>
          </div>
        </div>
      )}
    </div>
  );
}
