import { findRwaMarketSessionRow } from "../../../../utils/findRwaMarketSessionRow";
import {
  AlertLevel,
  IndexSourceType,
  ListingAssetType as ListingAssetTypeEnum,
} from "../../../../types";
import type {
  IndexSource,
  ListingAssetType,
  RwaMarketSessionTemplate,
  SourceItem,
  SymbolDetail,
  SymbolItem,
  SymbolStatus,
  TradingParamsForm,
} from "../../../../types";
import type {
  BrokerListingSubmitInput,
  BrokerListingUpdateParamsInput,
  RwaMarketSessionRow,
} from "../../../../services";
import type { ListingStore } from "../../../../store/useListingStore";
import { normalizeSourceKey } from "../../../../services/priceSources";
import {
  formatDecimal,
  formatRatePercentFromDecimal,
  getPriceRangePct,
  trimTrailingZeros,
} from "./shared";

export function getValidatedLeverage(form: TradingParamsForm): number | null {
  const leverage = Number(form.max_leverage);
  if (!Number.isFinite(leverage) || leverage <= 0) return null;
  return leverage;
}

export function buildTradingSymbolDetail(input: {
  form: TradingParamsForm;
  selectedSources: SourceItem[];
  listingBase: string;
  listingAssetType: ListingAssetType;
  rwaMarketSession: RwaMarketSessionTemplate | "";
  rwaMarketSessions: RwaMarketSessionRow[];
  fundingCap: number;
  fundingFloor: number;
  quoteTick: number;
  baseTick: number;
  baseMin: number;
  baseMax: number;
}): SymbolDetail {
  const {
    form,
    selectedSources,
    listingBase,
    listingAssetType,
    rwaMarketSession,
    rwaMarketSessions,
    fundingCap,
    fundingFloor,
    quoteTick,
    baseTick,
    baseMin,
    baseMax,
  } = input;
  const leverage = getValidatedLeverage(form);
  const imrVal = leverage ? 1 / leverage : 0;
  const mmrVal = leverage ? imrVal / 2 : 0;
  const baseSymbol = listingBase;
  const priceRangePct = leverage ? getPriceRangePct(leverage) : 0;
  const isRwa = listingAssetType === ListingAssetTypeEnum.Rwa;
  const rwaMarket = findRwaMarketSessionRow(
    rwaMarketSession,
    rwaMarketSessions
  );

  const indexSources: IndexSource[] = selectedSources.map(source => ({
    source: source.name,
    sourceSymbol: source.sourceSymbol,
    priceMultiplier: source.multiplier,
    latestPrice: source.price,
    type: source.type,
    sourceId: source.sourceId,
    weight: source.weight,
  }));

  return {
    status: "NEW",
    listingTime: null,
    params: {
      Symbol: {
        value: `PERP_${baseSymbol.toUpperCase()}_USDC`,
        editable: false,
      },
      base_token: { value: baseSymbol.toUpperCase(), editable: false },
      quote_token: { value: "USDC", editable: false },
      base_imr: {
        value: `${imrVal.toFixed(4)} (${(imrVal * 100).toFixed(2)}%)`,
        editable: false,
      },
      base_mmr: {
        value: leverage
          ? `${mmrVal.toFixed(4)} (${(mmrVal * 100).toFixed(2)}%)`
          : "—",
        editable: false,
      },
      max_leverage: { value: leverage ? `${leverage}x` : "—", editable: true },
      global_max_oi: {
        value: form.global_max_oi.trim()
          ? Number(form.global_max_oi).toLocaleString("en-US")
          : "—",
        editable: true,
      },
      max_notional_user: {
        value: `$${Number(form.max_notional_user).toLocaleString("en-US")}`,
        editable: true,
      },
      funding_period: { value: form.funding_period, editable: true },
      std_liquidation_fee: {
        value: formatRatePercentFromDecimal(form.std_liquidation_fee),
        editable: true,
      },
      claim_IF_discount: {
        value: formatRatePercentFromDecimal(form.claim_IF_discount),
        editable: true,
      },
      market_session: {
        value: rwaMarketSession || "—",
        editable: true,
      },
      price_range: {
        value: leverage ? `±${priceRangePct.toFixed(1)}%` : "—",
        editable: false,
      },
      funding_cap: {
        value: `${trimTrailingZeros((fundingCap * 100).toFixed(2))}%`,
        editable: false,
      },
      funding_floor: {
        value: `${trimTrailingZeros((fundingFloor * 100).toFixed(2))}%`,
        editable: false,
      },
      quote_tick: { value: formatDecimal(quoteTick), editable: false },
      base_tick: { value: formatDecimal(baseTick), editable: false },
      base_min: { value: formatDecimal(baseMin), editable: false },
      base_max: {
        value: baseMax > 0 ? Number(baseMax).toLocaleString("en-US") : "—",
        editable: false,
      },
    },
    indexSources,
    feeShareRate: 0.6,
    volume24h: 0,
    feeRevenue24h: 0,
    liquidationCount24h: 0,
    liquidationRevenue24h: 0,
    mmAccounts: [],
    delistTime: null,
    isRwa,
    marketSession: isRwa ? rwaMarketSession || null : null,
    rwaMarket: isRwa ? rwaMarket : null,
  };
}

export function buildTradingSubmitInputs(
  form: TradingParamsForm
): BrokerListingSubmitInput["inputs"] | null {
  const leverage = getValidatedLeverage(form);
  if (!leverage) return null;

  const maxNotionalUser = Number(form.max_notional_user);
  const stdLiqFee = Number(form.std_liquidation_fee);
  const claimIFDiscount = Number(form.claim_IF_discount);
  if (
    !Number.isFinite(maxNotionalUser) ||
    !Number.isFinite(stdLiqFee) ||
    !Number.isFinite(claimIFDiscount)
  ) {
    return null;
  }

  const payload: BrokerListingSubmitInput["inputs"] = {
    max_leverage: leverage,
    max_notional_user: maxNotionalUser,
    funding_period: form.funding_period,
    std_liquidation_fee: stdLiqFee,
    claim_IF_discount: claimIFDiscount,
  };

  if (form.global_max_oi.trim()) {
    const globalMaxOi = Number(form.global_max_oi);
    if (!Number.isFinite(globalMaxOi)) return null;
    payload.global_max_oi = globalMaxOi;
  }

  return payload;
}

export function buildTradingSubmitSources(input: {
  selectedSources: SourceItem[];
  indexSourcesCatalog: ListingStore["indexSources"];
}): BrokerListingSubmitInput["sources"] {
  const { selectedSources, indexSourcesCatalog } = input;

  return selectedSources.map(source => {
    const isBuilderLike =
      source.type === IndexSourceType.BuilderOracle ||
      source.type === IndexSourceType.Byok;

    const matchedCatalogRow = isBuilderLike
      ? indexSourcesCatalog.find(
          row =>
            normalizeSourceKey(row.source) === normalizeSourceKey(source.source)
        )
      : undefined;

    const catalogSourceSymbol =
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      (matchedCatalogRow as any)?.source_symbol ??
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      (matchedCatalogRow as any)?.sourceSymbol;

    return {
      source: source.source,
      type: source.type,
      source_symbol:
        isBuilderLike && catalogSourceSymbol
          ? String(catalogSourceSymbol)
          : source.sourceSymbol,
      price_multiplier: source.multiplier || 1,
      weight: Number(((source.weight ?? 0) / 100).toFixed(2)),
    };
  });
}

export function isScheduledDraftStatus(status: SymbolStatus): boolean {
  return status === "NEW" || status === "PENDING";
}

export function getDefaultListingDateInput(listingTime: string | null): string {
  if (!listingTime) return "";
  return listingTime.replace(" UTC", "").replace(" ", "T");
}

export function getListingTimeLabel(listingDate: string): string | null {
  return listingDate ? `${listingDate.replace("T", " ")} UTC` : null;
}

export function buildUpdateParamsPayload(input: {
  symbol: string;
  listingAssetType: ListingAssetType;
  rwaMarketSession: RwaMarketSessionTemplate | "";
  params: BrokerListingUpdateParamsInput["params"];
  sources: BrokerListingUpdateParamsInput["sources"];
}): BrokerListingUpdateParamsInput {
  const { symbol, listingAssetType, rwaMarketSession, params, sources } = input;
  return {
    symbol,
    market_session:
      listingAssetType === ListingAssetTypeEnum.Rwa && rwaMarketSession
        ? rwaMarketSession
        : undefined,
    params,
    sources,
  };
}

export function buildSubmitPayload(input: {
  symbol: string;
  listingTime: string;
  listingAssetType: ListingAssetType;
  rwaMarketSession: RwaMarketSessionTemplate | "";
  inputs: BrokerListingSubmitInput["inputs"];
  sources: BrokerListingSubmitInput["sources"];
}): BrokerListingSubmitInput {
  const {
    symbol,
    listingTime,
    listingAssetType,
    rwaMarketSession,
    inputs,
    sources,
  } = input;
  return {
    symbol,
    listing_time: listingTime,
    market_session:
      listingAssetType === ListingAssetTypeEnum.Rwa && rwaMarketSession
        ? rwaMarketSession
        : undefined,
    inputs,
    sources,
  };
}

export function buildSymbolStoreKey(input: {
  symbolValue: string;
  brokerId?: string;
  nowMs: number;
}): string {
  const safeBrokerId = (input.brokerId || "unknown").replace(
    /[^a-zA-Z0-9_-]/g,
    ""
  );
  return `${input.symbolValue}_broker_${safeBrokerId}_${input.nowMs}`;
}

export function buildNewSymbolItem(input: {
  symbolKey: string;
  baseToken: string;
  selectedSourceCount: number;
}): SymbolItem {
  return {
    symbol: input.symbolKey,
    displayName: `PERP_${input.baseToken}_USDC`,
    status: "NEW",
    sources: input.selectedSourceCount,
    vol: 0,
    alertLevel: AlertLevel.Normal,
    feeRevenue: 0,
    liqCount: 0,
    liqRevenue: 0,
    depthBid: 0,
    depthAsk: 0,
  };
}

export function mergeUpdatedTradingSymbolDetail(input: {
  existing: SymbolDetail;
  updated: SymbolDetail;
  listingTime?: string | null;
  resetMmAccounts?: boolean;
}): SymbolDetail {
  const { existing, updated, listingTime, resetMmAccounts } = input;
  return {
    ...existing,
    params: { ...existing.params, ...updated.params },
    indexSources: updated.indexSources,
    ...(listingTime !== undefined
      ? { listingTime: listingTime ?? existing.listingTime }
      : {}),
    ...(resetMmAccounts ? { mmAccounts: [] } : {}),
  };
}

export function buildFinalNewSymbolDetail(input: {
  detail: SymbolDetail;
  listingTime: string | null;
}): SymbolDetail {
  return {
    ...input.detail,
    listingTime: input.listingTime,
    mmAccounts: [],
  };
}

export function buildRecentEvent(description: string) {
  return {
    eventTime: new Date().toISOString(),
    time: "Just now",
    description,
  };
}
