import type { SWRConfiguration } from "swr";
import { usePrivateQuery } from "@/hooks/usePrivateQuery";
import { useMutation } from "@/hooks/useMutation";

import type { ApiEnvelope, Holding } from "./types";
import type { BrokerInfo } from "../types";

export const CLIENT_SUB_ACCOUNTS_KEY = "/v1/client/sub_account";
export const CLIENT_AGGREGATE_HOLDING_KEY = "/v1/client/aggregate/holding";
export const BROKER_INFO_KEY = "/v1/broker/broker_info";

type MutationState<TData, TError> = {
  data: TData | undefined;
  error: TError | undefined;
  reset: () => void;
  isMutating: boolean;
};

// ---- GET /v1/client/sub_account ----

export type ClientSubAccountRow = {
  sub_account_id: string;
  description: string;
};

/**
 * Get sub-account list.
 */
export function useClientSubAccounts(options?: SWRConfiguration) {
  return usePrivateQuery<ClientSubAccountRow[]>(CLIENT_SUB_ACCOUNTS_KEY, {
    ...options,
    revalidateOnFocus: false,
  });
}

// ---- POST /v1/client/add_sub_account ----

export type AddClientSubAccountInput = {
  description?: string;
};

export type AddClientSubAccountData = {
  sub_account_id: number;
  description: string;
};

/**
 * Add sub-account.
 */
export function useAddClientSubAccount() {
  const [mutation, state] = useMutation<
    ApiEnvelope<AddClientSubAccountData>,
    unknown
  >("/v1/client/add_sub_account", "POST");
  const trigger = (input: AddClientSubAccountInput) => mutation(input);
  return [
    trigger,
    state as MutationState<ApiEnvelope<AddClientSubAccountData>, unknown>,
  ] as const;
}

export function useGetAccountInfo(accountId?: string) {
  return usePrivateQuery<ApiEnvelope<Record<string, unknown>>>(
    accountId ? `/v1/public/account/?account_id=${accountId}` : null,
    {
      revalidateOnFocus: false,
    }
  );
}

export type CreateInternalTransferInput = {
  token: string;
  receiver_list: {
    account_id: string;
    amount: number;
  }[];
};

export function useInternalTransfer() {
  const [mutation, state] = useMutation<ApiEnvelope<unknown>, unknown>(
    "/v1/internal_transfer",
    "POST"
  );
  const trigger = (input: CreateInternalTransferInput) => mutation(input);
  return [
    trigger,
    state as MutationState<ApiEnvelope<unknown>, unknown>,
  ] as const;
}

/** includes main account and sub-accounts holdings */
export function useGetAggregateHolding() {
  return usePrivateQuery<Holding[]>(CLIENT_AGGREGATE_HOLDING_KEY, {
    revalidateOnFocus: false,
  });
}

export function useGetBrokerInfo() {
  return usePrivateQuery<BrokerInfo>(BROKER_INFO_KEY, {
    revalidateOnFocus: false,
  });
}
