import { RecentEventsUI } from "./RecentEvents.ui";
import { useRecentEventsCard } from "./useRecentEventsCard";

export function RecentEvents() {
  const {
    events,
    page,
    pageSize,
    total,
    onPageChange,
    onPageSizeChange,
    isLoading,
  } = useRecentEventsCard();

  return (
    <RecentEventsUI
      events={events}
      page={page}
      pageSize={pageSize}
      total={total}
      loading={isLoading}
      onPageChange={onPageChange}
      onPageSizeChange={onPageSizeChange}
    />
  );
}
