export const PLSelectTrigger = React.forwardRef<
  React.ElementRef<typeof SelectTrigger>,
  React.ComponentPropsWithoutRef<typeof SelectTrigger> & {
    withChevronDown?: boolean;
    size?: "sm" | "md" | "lg";
  }
>(({ className, withChevronDown = true, size = "md", ...props }, ref) => (
  <SelectTrigger
    ref={ref}
    className={cn(
      "box-border gap-2 px-3 rounded-lg border bg-base-300 group",
      "enabled:cursor-pointer disabled:cursor-not-allowed",
      size === "sm" && "h-7",
      size === "md" && "h-8",
      size === "lg" && "h-10",
      "border-[rgba(255,255,255,0.06)] enabled:hover:border-primary transition-[border-color] duration-150",
      "text-xs text-base-contrast-98 font-normal",
      "[&>div>span]:flex [&>div>span]:items-center [&>div>span]:justify-between [&>div>span]:w-full [&>div>span]:min-w-0 [&>div>span]:flex-1",
      "[&>div>span>*]:min-w-0 [&>div>span>*]:flex-1 [&>div>span>*]:overflow-visible [&>div>span>*]:whitespace-nowrap",
      "focus:ring-0 focus:ring-offset-0",
      className
    )}
    suffix={withChevronDown ? <PLChevronDownIcon /> : undefined}
    {...props}
  />
));
PLSelectTrigger.displayName = "PLSelectTrigger";

export const PLSelectContent = React.forwardRef<
  React.ElementRef<typeof SelectContent>,
  React.ComponentPropsWithoutRef<typeof SelectContent>
>(
  (
    {
      className,
      position = "popper",
      sideOffset = 6,
      align = "start",
      container,
      ...props
    },
    ref
  ) => (
    <SelectContent
      ref={ref}
      container={container}
      className={cn(
        "rounded-lg border border-base-contrast-12 bg-base-200 py-1 overflow-hidden",
        "min-w-(--radix-select-trigger-width)",
        "shadow-[4px_4px_24px_rgba(9,6,16,0.8)]",
        // ui/select SelectContent uses tailwindcss-animate (animate-in / zoom / slide).
        "motion-reduce:data-[state=open]:animate-none motion-reduce:data-[state=closed]:animate-none",
        className
      )}
      position={position}
      sideOffset={sideOffset}
      align={align}
      {...props}
    />
  )
);
PLSelectContent.displayName = "PLSelectContent";

export const PLSelectItem = React.forwardRef<
  React.ElementRef<typeof SelectItem>,
  React.ComponentPropsWithoutRef<typeof SelectItem>
>(({ className, ...props }, ref) => (
  <SelectItem
    ref={ref}
    className={cn(
      "flex items-center py-2.5 px-3 pl-3 text-2xs cursor-pointer rounded-none",
      "[&>span:first-child]:hidden [&>span:last-child]:flex [&>span:last-child]:w-full [&>span:last-child]:min-w-0",
      "hover:bg-[rgba(255,255,255,0.06)] focus:bg-primary/6 focus:text-base-contrast-98 focus:outline-none",
      className
    )}
    {...props}
  />
));
PLSelectItem.displayName = "PLSelectItem";

type PLSelectFieldOption<TValue extends string | number> = {
  value: TValue;
  label: React.ReactNode;
};

export interface PLSelectFieldProps<TValue extends string | number = string> {
  size?: "sm" | "md" | "lg";
  label?: string;
  value: TValue | undefined;
  onChange: (value: TValue) => void;
  options: PLSelectFieldOption<TValue>[];
  placeholder?: string;
  error?: string;
  hint?: string;
  className?: string;
  triggerClassName?: string;
  itemClassName?: string;
  disabled?: boolean;
  hintClassName?: string;
  /** Portal dropdown into this element (e.g. dialog content) so scrolling works inside modal scroll lock. */
  portalContainer?: HTMLElement | null;
}

export function PLSelectField<TValue extends string | number = string>({
  size = "md",
  label,
  value,
  onChange,
  options,
  placeholder = "—",
  error,
  hint,
  className,
  triggerClassName,
  itemClassName,
  disabled,
  hintClassName,
  portalContainer,
}: PLSelectFieldProps<TValue>) {
  const stringOptions = React.useMemo(
    () =>
      options.map(opt => ({
        ...opt,
        stringValue: String(opt.value),
      })),
    [options]
  );

  const stringValue =
    value != null
      ? stringOptions.find(o => o.value === value)?.stringValue
      : undefined;

  const handleValueChange = (next: string) => {
    const matched = stringOptions.find(o => o.stringValue === next);
    if (!matched) return;
    // Cast is safe because we only ever map back from existing options
    onChange(matched.value as TValue);
  };

  return (
    <div className={cn("flex flex-col gap-2", className)}>
      {label && (
        <div className="flex items-center gap-1">
          <span className="text-xs font-medium text-base-contrast-98">
            {label}
          </span>
        </div>
      )}
      <Select
        value={stringValue}
        onValueChange={handleValueChange}
        disabled={disabled}
      >
        <PLSelectTrigger
          size={size}
          className={cn(
            error && "border-danger enabled:hover:border-danger",
            !stringValue && "data-placeholder:text-base-contrast-50",
            triggerClassName
          )}
        >
          <SelectValue placeholder={placeholder} />
        </PLSelectTrigger>
        <PLSelectContent container={portalContainer ?? undefined}>
          {stringOptions.map(opt => (
            <PLSelectItem
              key={opt.stringValue}
              value={opt.stringValue}
              className={itemClassName}
            >
              {opt.label}
            </PLSelectItem>
          ))}
        </PLSelectContent>
      </Select>
      {error && <span className="text-3xs text-danger">{error}</span>}
      {hint && !error && (
        <span
          className={cn("text-3xs", hintClassName ?? "text-base-contrast-36")}
        >
          {hint}
        </span>
      )}
    </div>
  );
}
