export type CustomOracleTab = "builder" | "byok";

export type CustomOracleOrigin = "dashboard" | "listing-price-sources";

export type VisibilityMode = "public" | "private";

export type OracleHealthTone = "success" | "warning" | "danger" | "muted";

export enum OracleHealthLabel {
  Normal = "Normal",
  Warning = "Warning",
  Pending = "Pending",
  Inactive = "Inactive",
}

export type OracleStatus = "active" | "inactive";

export enum ByokProviderId {
  Pyth = "pyth",
  Stork = "stork",
}

export type ByokKeyState = "configured" | "empty" | "deactivated";

export interface OracleUptimeSegment {
  tone: "green" | "yellow" | "red" | "gray";
  weight: number;
}

export interface OracleUptimeDay {
  label: string;
  tooltip: string;
  tone: OracleUptimeSegment["tone"];
  segments?: OracleUptimeSegment[];
}

export interface OracleEvent {
  time: string;
  type: string;
  description: string;
  tone: OracleHealthTone | "primary";
}

export interface BuilderOracleSymbol {
  id: string;
  name: string;
  sourceId?: string;
  visibility: VisibilityMode;
  status: OracleStatus;
  price: number | null;
  updatedText: string;
  uptimePct: number | null;
  healthLabel: OracleHealthLabel;
  healthTone: OracleHealthTone;
  skips7d: number;
  uptimeDays: OracleUptimeDay[];
  events: OracleEvent[];
}

export interface BuilderOracleSource {
  name: string;
  endpoint: string;
  topic: string;
  guideUrl: string;
  symbols: BuilderOracleSymbol[];
}

export interface ByokSymbol {
  id: string;
  name: string;
  sourceId?: string;
  visibility: VisibilityMode;
  status: OracleStatus;
  price: number | null;
  updatedText: string;
  errorCode?: string | null;
}

export interface ByokProvider {
  id: string;
  providerName: string;
  sourceName: string;
  keyMasked: string;
  keyState: ByokKeyState;
  healthLabel?: string;
  symbols: ByokSymbol[];
}

export interface CustomOracleSymbolTarget {
  source: "builder" | "byok";
  symbolId: string;
  providerId?: string;
}

export interface CustomOracleModalState {
  onboardingOpen: boolean;
  builderAddSymbolOpen: boolean;
  addByokSourceProvider: string | null;
  updateByokKeyProvider: string | null;
  deactivateByokKeyProvider: string | null;
  addByokSymbolProvider: string | null;
  visibilityTarget: CustomOracleSymbolTarget | null;
  removeTarget: CustomOracleSymbolTarget | null;
}
